export type Message = {
  id: string
  roomId: string
  sender: string
  text: string
  timestamp: number
}

export type Room = {
  id: string
  name: string
  createdAt: number
  members: string[]
}

export type RoomSummary = {
  room: Room
  unreadCount: number
  lastMessage: Message | null
}

export type TypingState = {
  roomId: string
  user: string
  active: boolean
}

export type ReadReceipt = {
  [roomId: string]: {
    [userId: string]: number
  }
}

import { h } from 'plaited'
import type { TemplateObject } from 'plaited'

const BOLD_RE = /\*([^*]+)\*/g
const ITALIC_RE = /_([^_]+)_/g

export const formatText = (raw: string): TemplateObject[] => {
  const parts: TemplateObject[] = []
  let remaining = raw

  const combined = /(\*[^*]+\*)|(_[^_]+_)/g
  let lastIndex = 0
  let match: RegExpExecArray | null

  while ((match = combined.exec(remaining)) !== null) {
    if (match.index > lastIndex) {
      parts.push(h('span', {}, remaining.slice(lastIndex, match.index)))
    }

    const token = match[0]
    if (token.startsWith('*')) {
      parts.push(h('strong', {}, token.slice(1, -1)))
    } else if (token.startsWith('_')) {
      parts.push(h('em', {}, token.slice(1, -1)))
    }

    lastIndex = match.index + token.length
  }

  if (lastIndex < remaining.length) {
    parts.push(h('span', {}, remaining.slice(lastIndex)))
  }

  return parts.length > 0 ? parts : [h('span', {}, raw)]
}

import type { Message, Room, ReadReceipt } from './types'

const DATA_DIR = './data'

const roomsPath = `${DATA_DIR}/rooms.json`
const readReceiptsPath = `${DATA_DIR}/read-receipts.json`

const messagesPath = (roomId: string) => `${DATA_DIR}/messages-${roomId}.jsonl`

const ensureDataDir = async () => {
  const dir = Bun.file(roomsPath)
  if (!(await dir.exists())) {
    await Bun.write(roomsPath, '[]')
  }
}

export const loadRooms = async (): Promise<Room[]> => {
  await ensureDataDir()
  const file = Bun.file(roomsPath)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as Room[]
}

export const saveRooms = async (rooms: Room[]): Promise<void> => {
  await Bun.write(roomsPath, JSON.stringify(rooms, null, 2))
}

export const loadMessages = async (roomId: string): Promise<Message[]> => {
  const file = Bun.file(messagesPath(roomId))
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Message)
}

export const appendMessage = async (message: Message): Promise<void> => {
  const path = messagesPath(message.roomId)
  const file = Bun.file(path)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(path, existing + JSON.stringify(message) + '\n')
}

export const loadReadReceipts = async (): Promise<ReadReceipt> => {
  const file = Bun.file(readReceiptsPath)
  if (!(await file.exists())) return {}
  const text = await file.text()
  return JSON.parse(text) as ReadReceipt
}

export const saveReadReceipts = async (receipts: ReadReceipt): Promise<void> => {
  await Bun.write(readReceiptsPath, JSON.stringify(receipts, null, 2))
}

import type { Room, RoomSummary } from './types'
import { loadRooms, saveRooms, loadMessages, loadReadReceipts, saveReadReceipts } from './store'

const generateId = (): string => crypto.randomUUID()

export const createRoom = async (name: string, creator: string): Promise<Room> => {
  const rooms = await loadRooms()
  const existing = rooms.find((r) => r.name === name)
  if (existing) return existing

  const room: Room = {
    id: generateId(),
    name,
    createdAt: Date.now(),
    members: [creator],
  }

  rooms.push(room)
  await saveRooms(rooms)
  return room
}

export const joinRoom = async (roomName: string, userId: string): Promise<Room | null> => {
  const rooms = await loadRooms()
  const room = rooms.find((r) => r.name === roomName)
  if (!room) return null

  if (!room.members.includes(userId)) {
    room.members.push(userId)
    await saveRooms(rooms)
  }

  return room
}

export const listRooms = async (userId: string): Promise<RoomSummary[]> => {
  const rooms = await loadRooms()
  const receipts = await loadReadReceipts()

  const summaries: RoomSummary[] = []

  for (const room of rooms) {
    const messages = await loadMessages(room.id)
    const lastMessage = messages.length > 0 ? messages[messages.length - 1] : null
    const lastReadTimestamp = receipts[room.id]?.[userId] ?? 0
    const unreadCount = messages.filter((m) => m.timestamp > lastReadTimestamp && m.sender !== userId).length

    summaries.push({ room, unreadCount, lastMessage })
  }

  return summaries
}

export const markRoomRead = async (roomId: string, userId: string): Promise<void> => {
  const receipts = await loadReadReceipts()
  if (!receipts[roomId]) {
    receipts[roomId] = {}
  }
  receipts[roomId][userId] = Date.now()
  await saveReadReceipts(receipts)
}

export const getRoom = async (roomName: string): Promise<Room | null> => {
  const rooms = await loadRooms()
  return rooms.find((r) => r.name === roomName) ?? null
}

import type { Message } from './types'
import { appendMessage, loadMessages } from './store'

const generateId = (): string => crypto.randomUUID()

export const sendMessage = async (
  roomId: string,
  sender: string,
  text: string
): Promise<Message> => {
  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text: text.trim(),
    timestamp: Date.now(),
  }

  await appendMessage(message)
  return message
}

export const getRoomMessages = async (
  roomId: string,
  limit?: number
): Promise<Message[]> => {
  const all = await loadMessages(roomId)
  if (limit && limit > 0) {
    return all.slice(-limit)
  }
  return all
}

