import { h } from '@plaited/template';
import type { TemplateObject } from '@plaited/template';

/**
 * Parses markdown-style bold (**text**) and italic (*text*) into
 * template objects. Handles nested formatting.
 */
export const formatMessageText = (text: string): (string | TemplateObject)[] => {
  const tokens: (string | TemplateObject)[] = [];
  let remaining = text;

  const boldRe = /\*\*(.+?)\*\*/;
  const italicRe = /(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/;

  while (remaining.length > 0) {
    const boldMatch = boldRe.exec(remaining);
    const italicMatch = italicRe.exec(remaining);

    let nextMatch: RegExpExecArray | null = null;
    let tag: 'strong' | 'em' = 'strong';

    if (boldMatch && italicMatch) {
      if (boldMatch.index <= italicMatch.index) {
        nextMatch = boldMatch;
        tag = 'strong';
      } else {
        nextMatch = italicMatch;
        tag = 'em';
      }
    } else if (boldMatch) {
      nextMatch = boldMatch;
      tag = 'strong';
    } else if (italicMatch) {
      nextMatch = italicMatch;
      tag = 'em';
    }

    if (!nextMatch) {
      tokens.push(remaining);
      break;
    }

    if (nextMatch.index > 0) {
      tokens.push(remaining.slice(0, nextMatch.index));
    }

    tokens.push(h(tag, {}, nextMatch[1]));
    remaining = remaining.slice(nextMatch.index + nextMatch[0].length);
  }

  return tokens;
};

import type { Message, Room, RoomMeta, UserRoomPrefs } from './types';

const DATA_DIR = './data';
const ROOMS_FILE = `${DATA_DIR}/rooms.json`;
const PREFS_FILE = `${DATA_DIR}/prefs.json`;

const roomMessagesPath = (roomId: string): string =>
  `${DATA_DIR}/${roomId}.jsonl`;

const generateId = (): string =>
  crypto.randomUUID();

// --- Room operations ---

const readRoomMeta = async (): Promise<RoomMeta> => {
  const file = Bun.file(ROOMS_FILE);
  if (await file.exists()) {
    return file.json() as Promise<RoomMeta>;
  }
  return { rooms: [] };
};

const writeRoomMeta = async (meta: RoomMeta): Promise<void> => {
  await Bun.write(ROOMS_FILE, JSON.stringify(meta, null, 2));
};

export const listRooms = async (): Promise<Room[]> => {
  const meta = await readRoomMeta();
  return meta.rooms;
};

export const getRoom = async (roomId: string): Promise<Room | undefined> => {
  const meta = await readRoomMeta();
  return meta.rooms.find((r) => r.id === roomId);
};

export const createRoom = async (name: string, creator: string): Promise<Room> => {
  const meta = await readRoomMeta();
  const room: Room = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
    members: [creator],
  };
  meta.rooms.push(room);
  await writeRoomMeta(meta);
  return room;
};

export const joinRoom = async (roomId: string, username: string): Promise<Room | undefined> => {
  const meta = await readRoomMeta();
  const room = meta.rooms.find((r) => r.id === roomId);
  if (!room) return undefined;
  if (!room.members.includes(username)) {
    room.members.push(username);
    await writeRoomMeta(meta);
  }
  return room;
};

// --- Message operations ---

export const getMessages = async (roomId: string): Promise<Message[]> => {
  const file = Bun.file(roomMessagesPath(roomId));
  if (!(await file.exists())) return [];

  const content = await file.text();
  return content
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as Message);
};

export const postMessage = async (
  roomId: string,
  sender: string,
  text: string,
): Promise<Message> => {
  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: new Date().toISOString(),
  };
  const path = roomMessagesPath(roomId);
  const file = Bun.file(path);
  const existing = (await file.exists()) ? await file.text() : '';
  const newContent = existing + JSON.stringify(message) + '\n';
  await Bun.write(path, newContent);
  return message;
};

// --- User prefs (unread tracking) ---

const readPrefs = async (): Promise<UserRoomPrefs> => {
  const file = Bun.file(PREFS_FILE);
  if (await file.exists()) {
    return file.json() as Promise<UserRoomPrefs>;
  }
  return {};
};

const writePrefs = async (prefs: UserRoomPrefs): Promise<void> => {
  await Bun.write(PREFS_FILE, JSON.stringify(prefs, null, 2));
};

export const markRoomRead = async (roomId: string): Promise<void> => {
  const prefs = await readPrefs();
  prefs[roomId] = { lastReadTimestamp: new Date().toISOString() };
  await writePrefs(prefs);
};

export const getUnreadCount = async (roomId: string): Promise<number> => {
  const prefs = await readPrefs();
  const lastRead = prefs[roomId]?.lastReadTimestamp ?? null;
  const messages = await getMessages(roomId);

  if (!lastRead) return messages.length;

  return messages.filter((m) => m.timestamp > lastRead).length;
};

