  const sidebar = h('div', { style: styles.sidebar },
    h('div', { style: styles.sidebarHeader }, 'Chat Rooms'),
    h('div', { style: styles.roomList },
      ...roomStates.map((rs) => renderRoomItem(rs, rs.room.id === activeRoomId)),
    ),
    h('button', {
      style: styles.createRoomBtn,
      'p-trigger': 'click:create-room',
    }, '+ New Room'),
  );

  const chatContent = activeRoom
    ? h(Fragment, {},
        h('div', { style: styles.chatHeader }, `# ${activeRoom.room.name}`),
        h('div', { style: styles.messageList, 'p-target': 'message-list' },
          ...messages.map(renderMessage),
        ),
        renderTypingIndicator(typingUsers),
        h('div', { style: styles.inputArea },
          h('input', {
            style: styles.textInput,
            type: 'text',
            placeholder: 'Type a message... (*italic*, **bold**)',
            'p-target': 'message-input',
