  ${head}
  <style>* { margin: 0; padding: 0; box-sizing: border-box; }</style>
</head>
<body>${body}</body>
</html>`;
};

import type { RoomState } from './types';
import {
  listRooms,
  getRoom,
  createRoom,
  joinRoom,
  getMessages,
  postMessage,
  markRoomRead,
  getUnreadCount,
} from './store';
import { renderChat } from './render';

export const getRoomStates = async (): Promise<RoomState[]> => {
  const rooms = await listRooms();
  const states: RoomState[] = await Promise.all(
    rooms.map(async (room) => ({
      room,
      unreadCount: await getUnreadCount(room.id),
      lastReadTimestamp: null,
      typingUsers: [],
    })),
  );
  return states;
};

export const handleCreateRoom = async (name: string, username: string) => {
  const room = await createRoom(name, username);
  return room;
};

export const handleJoinRoom = async (roomId: string, username: string) => {
  const room = await joinRoom(roomId, username);
  return room;
};

export const handleSendMessage = async (
  roomId: string,
  sender: string,
  text: string,
) => {
  const message = await postMessage(roomId, sender, text);
  return message;
};

export const handleSelectRoom = async (roomId: string) => {
  await markRoomRead(roomId);
  const room = await getRoom(roomId);
  const messages = await getMessages(roomId);
  return { room, messages };
};

export const renderView = async (
  activeRoomId: string | null,
  typingUsers: string[] = [],
): Promise<string> => {
  const roomStates = await getRoomStates();
  const messages = activeRoomId ? await getMessages(activeRoomId) : [];
  return renderChat(roomStates, activeRoomId, messages, typingUsers);
};

// Default export for module entry point
export default {
  getRoomStates,
  handleCreateRoom,
  handleJoinRoom,
  handleSendMessage,
  handleSelectRoom,
  renderView,
};

