import { h } from 'plaited';
import type { TemplateObject } from 'plaited';

/**
 * Parses markdown-style bold (**text**) and italic (*text*) into
 * plaited template nodes. Returns an array of string and element nodes.
 */
export const formatMessage = (text: string): (string | TemplateObject)[] => {
  const tokens: (string | TemplateObject)[] = [];
  let remaining = text;

  // Process bold first (**), then italic (*)
  const pattern = /\*\*(.+?)\*\*|\*(.+?)\*/g;
  let lastIndex = 0;
  let match: RegExpExecArray | null;

  while ((match = pattern.exec(remaining)) !== null) {
    // Push preceding plain text
    if (match.index > lastIndex) {
      tokens.push(remaining.slice(lastIndex, match.index));
    }

    if (match[1] !== undefined) {
      // Bold match
      tokens.push(h('strong', {}, match[1]));
    } else if (match[2] !== undefined) {
      // Italic match
      tokens.push(h('em', {}, match[2]));
    }

    lastIndex = match.index + match[0].length;
  }

  // Push trailing plain text
  if (lastIndex < remaining.length) {
    tokens.push(remaining.slice(lastIndex));
  }

  if (tokens.length === 0) {
    tokens.push(text);
  }

  return tokens;
};

/**
 * Formats a unix timestamp into a readable time string.
 */
export const formatTimestamp = (ts: number): string => {
  const date = new Date(ts);
  const now = new Date();
  const isToday =
    date.getFullYear() === now.getFullYear() &&
    date.getMonth() === now.getMonth() &&
    date.getDate() === now.getDate();

  const time = date.toLocaleTimeString(undefined, {
    hour: '2-digit',
    minute: '2-digit',
  });

  if (isToday) return time;

  const dateStr = date.toLocaleDateString(undefined, {
    month: 'short',
    day: 'numeric',
  });
  return `${dateStr} ${time}`;
};

import type { Message, Room, RoomMeta } from './types';

const DATA_DIR = `${import.meta.dir}/data`;
const ROOMS_FILE = `${DATA_DIR}/rooms.json`;
const READ_STATE_FILE = `${DATA_DIR}/read-state.json`;

// --- Room persistence ---

const loadRooms = async (): Promise<Room[]> => {
  const file = Bun.file(ROOMS_FILE);
  if (await file.exists()) {
    return file.json();
  }
  return [];
};

const saveRooms = async (rooms: Room[]): Promise<void> => {
  await Bun.write(ROOMS_FILE, JSON.stringify(rooms, null, 2));
};

export const getRooms = async (): Promise<Room[]> => {
  return loadRooms();
};

export const createRoom = async (name: string): Promise<Room> => {
  const rooms = await loadRooms();
  const existing = rooms.find((r) => r.name.toLowerCase() === name.toLowerCase());
  if (existing) return existing;

  const room: Room = {
    id: crypto.randomUUID(),
    name,
    createdAt: Date.now(),
  };
  rooms.push(room);
  await saveRooms(rooms);
  return room;
};

export const getRoom = async (roomId: string): Promise<Room | undefined> => {
  const rooms = await loadRooms();
  return rooms.find((r) => r.id === roomId);
};

// --- Message persistence (JSONL per room) ---

const messagesPath = (roomId: string): string => `${DATA_DIR}/${roomId}.jsonl`;

export const getMessages = async (roomId: string): Promise<Message[]> => {
  const file = Bun.file(messagesPath(roomId));
  if (!(await file.exists())) return [];

  const content = await file.text();
  return content
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as Message);
};

export const addMessage = async (
  roomId: string,
  sender: string,
  text: string
): Promise<Message> => {
  const message: Message = {
    id: crypto.randomUUID(),
    roomId,
    sender,
    text,
    timestamp: Date.now(),
  };

  const filePath = messagesPath(roomId);
  const file = Bun.file(filePath);
  const existing = (await file.exists()) ? await file.text() : '';
  const newContent = existing.endsWith('\n') || existing === ''
    ? `${existing}${JSON.stringify(message)}\n`
    : `${existing}\n${JSON.stringify(message)}\n`;

  await Bun.write(filePath, newContent);
  return message;
};

// --- Read state / unread tracking ---

type ReadState = Record<string, number>; // roomId -> last-read timestamp

const loadReadState = async (): Promise<ReadState> => {
  const file = Bun.file(READ_STATE_FILE);
  if (await file.exists()) {
    return file.json();
  }
  return {};
};

const saveReadState = async (state: ReadState): Promise<void> => {
  await Bun.write(READ_STATE_FILE, JSON.stringify(state, null, 2));
};

export const markRoomRead = async (roomId: string): Promise<void> => {
  const state = await loadReadState();
  state[roomId] = Date.now();
  await saveReadState(state);
};

export const getUnreadCount = async (roomId: string): Promise<number> => {
  const state = await loadReadState();
  const lastRead = state[roomId] ?? 0;
  const messages = await getMessages(roomId);
  return messages.filter((m) => m.timestamp > lastRead).length;
};

export const getRoomMetas = async (): Promise<RoomMeta[]> => {
  const rooms = await loadRooms();
  const state = await loadReadState();

  const metas: RoomMeta[] = [];
  for (const room of rooms) {
    const lastRead = state[room.id] ?? 0;
    const messages = await getMessages(room.id);
    const unreadCount = messages.filter((m) => m.timestamp > lastRead).length;
    metas.push({ room, lastRead, unreadCount });
  }

  return metas;
};

