import {
  getRoomMetas,
  createRoom,
  getRoom,
  getMessages,
  addMessage,
  markRoomRead,
} from './store';
import { renderRoomList, renderRoom } from './render';

export type ChatAction =
  | { type: 'list-rooms' }
  | { type: 'create-room'; name: string }
  | { type: 'join-room'; roomId: string }
  | { type: 'send-message'; roomId: string; sender: string; text: string }
  | { type: 'set-typing'; roomId: string; sender: string; active: boolean };

// In-memory typing state per room
const typingUsers = new Map<string, string | undefined>();

/**
 * Main action handler — processes a chat action and returns rendered HTML.
 */
export const handleAction = async (action: ChatAction): Promise<string> => {
  switch (action.type) {
    case 'list-rooms': {
      const metas = await getRoomMetas();
      return renderRoomList(metas);
    }

    case 'create-room': {
      const name = action.name.trim();
      if (!name) return renderRoomList(await getRoomMetas());
      await createRoom(name);
      const metas = await getRoomMetas();
      return renderRoomList(metas);
    }

    case 'join-room': {
      const room = await getRoom(action.roomId);
      if (!room) {
        const metas = await getRoomMetas();
        return renderRoomList(metas);
      }
      await markRoomRead(room.id);
      const messages = await getMessages(room.id);
      const typing = typingUsers.get(room.id);
      return renderRoom(room.name, room.id, messages, typing);
    }

    case 'send-message': {
      const { roomId, sender, text } = action;
      if (!text.trim()) {
        const room = await getRoom(roomId);
        const messages = await getMessages(roomId);
        return renderRoom(room?.name ?? 'Unknown', roomId, messages);
      }
      await addMessage(roomId, sender, text);
      typingUsers.delete(roomId);
      await markRoomRead(roomId);
      const room = await getRoom(roomId);
      const messages = await getMessages(roomId);
      return renderRoom(room?.name ?? 'Unknown', roomId, messages);
    }

    case 'set-typing': {
      const { roomId, sender, active } = action;
      if (active) {
        typingUsers.set(roomId, sender);
      } else if (typingUsers.get(roomId) === sender) {
        typingUsers.delete(roomId);
      }
      const room = await getRoom(roomId);
      const messages = await getMessages(roomId);
      const typing = typingUsers.get(roomId);
      return renderRoom(room?.name ?? 'Unknown', roomId, messages, typing);
    }
  }
};

/**
 * Quick start: renders the room list view.
 */
export const init = async (): Promise<string> => {
  return handleAction({ type: 'list-rooms' });
};

