export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber';

export type FoodItem = {
  name: string;
  calories: number;
  categories: FoodCategory[];
};

export type Meal = {
  id: string;
  name: string;
  items: FoodItem[];
  timestamp: string; // ISO 8601
  totalCalories: number;
};

export type DailySummary = {
  date: string; // YYYY-MM-DD
  meals: Meal[];
  totalCalories: number;
  categoryBreakdown: Record<FoodCategory, number>;
  goal: number;
  remaining: number;
};

export type WeeklyData = {
  days: {
    date: string;
    label: string;
    totalCalories: number;
  }[];
  goal: number;
  maxCalories: number;
};

export type UserSettings = {
  dailyGoal: number;
};

import type { Meal, UserSettings } from './types';

const DATA_DIR = import.meta.dir + '/data';
const MEALS_FILE = `${DATA_DIR}/meals.jsonl`;
const SETTINGS_FILE = `${DATA_DIR}/settings.json`;

const DEFAULT_SETTINGS: UserSettings = {
  dailyGoal: 2000,
};

export const loadSettings = async (): Promise<UserSettings> => {
  const file = Bun.file(SETTINGS_FILE);
  if (await file.exists()) {
    return await file.json();
  }
  return { ...DEFAULT_SETTINGS };
};

export const saveSettings = async (settings: UserSettings): Promise<void> => {
  await Bun.write(SETTINGS_FILE, JSON.stringify(settings, null, 2));
};

export const loadAllMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_FILE);
  if (!(await file.exists())) {
    return [];
  }
  const text = await file.text();
  return text
    .split('\n')
    .filter((line) => line.trim() !== '')
    .map((line) => JSON.parse(line) as Meal);
};

export const appendMeal = async (meal: Meal): Promise<void> => {
  const file = Bun.file(MEALS_FILE);
  const existing = (await file.exists()) ? await file.text() : '';
  const line = JSON.stringify(meal) + '\n';
  await Bun.write(MEALS_FILE, existing + line);
};

export const deleteMeal = async (mealId: string): Promise<boolean> => {
  const meals = await loadAllMeals();
  const filtered = meals.filter((m) => m.id !== mealId);
  if (filtered.length === meals.length) return false;
  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length > 0 ? '\n' : '');
  await Bun.write(MEALS_FILE, content);
  return true;
};

export const loadMealsForDate = async (date: string): Promise<Meal[]> => {
  const meals = await loadAllMeals();
  return meals.filter((m) => m.timestamp.startsWith(date));
};

export const loadMealsForDateRange = async (startDate: string, endDate: string): Promise<Meal[]> => {
  const meals = await loadAllMeals();
  return meals.filter((m) => {
    const d = m.timestamp.slice(0, 10);
    return d >= startDate && d <= endDate;
  });
};

import type { Meal, FoodItem, FoodCategory, DailySummary, WeeklyData } from './types';
import { loadMealsForDate, loadMealsForDateRange, appendMeal, deleteMeal, loadSettings, saveSettings } from './store';

const generateId = (): string => crypto.randomUUID();

const toDateString = (date: Date): string => date.toISOString().slice(0, 10);

export const logMeal = async (
  name: string,
  items: FoodItem[],
  timestamp?: string,
): Promise<Meal> => {
  const totalCalories = items.reduce((sum, item) => sum + item.calories, 0);
  const meal: Meal = {
    id: generateId(),
    name,
    items,
    timestamp: timestamp ?? new Date().toISOString(),
    totalCalories,
  };
  await appendMeal(meal);
  return meal;
};

export const removeMeal = async (mealId: string): Promise<boolean> => {
  return deleteMeal(mealId);
};

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? toDateString(new Date());
  const meals = await loadMealsForDate(targetDate);
  const settings = await loadSettings();

  const totalCalories = meals.reduce((sum, m) => sum + m.totalCalories, 0);

  const categoryBreakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  };

  for (const meal of meals) {
    for (const item of meal.items) {
      for (const cat of item.categories) {
        categoryBreakdown[cat] += item.calories;
      }
    }
  }

  return {
    date: targetDate,
    meals,
    totalCalories,
    categoryBreakdown,
    goal: settings.dailyGoal,
    remaining: Math.max(0, settings.dailyGoal - totalCalories),
  };
};

export const getWeeklyData = async (endDate?: string): Promise<WeeklyData> => {
  const end = endDate ? new Date(endDate) : new Date();
  const start = new Date(end);
  start.setDate(start.getDate() - 6);

  const startStr = toDateString(start);
  const endStr = toDateString(end);
  const meals = await loadMealsForDateRange(startStr, endStr);
  const settings = await loadSettings();

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const days: WeeklyData['days'] = [];

  for (let i = 0; i < 7; i++) {
    const d = new Date(start);
    d.setDate(d.getDate() + i);
    const dateStr = toDateString(d);
    const dayMeals = meals.filter((m) => m.timestamp.startsWith(dateStr));
    const totalCalories = dayMeals.reduce((sum, m) => sum + m.totalCalories, 0);
    days.push({
      date: dateStr,
      label: `${dayNames[d.getDay()]} ${d.getMonth() + 1}/${d.getDate()}`,
      totalCalories,
    });
  }

  const maxCalories = Math.max(settings.dailyGoal, ...days.map((d) => d.totalCalories));

  return { days, goal: settings.dailyGoal, maxCalories };
};

