import type { Meal, DailyGoal } from './types';

const DATA_DIR = `${import.meta.dir}/data`;
const MEALS_FILE = `${DATA_DIR}/meals.jsonl`;
const GOAL_FILE = `${DATA_DIR}/goal.json`;

export const loadMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_FILE);
  if (!(await file.exists())) return [];

  const text = await file.text();
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Meal);
};

export const appendMeal = async (meal: Meal): Promise<void> => {
  const file = Bun.file(MEALS_FILE);
  const existing = (await file.exists()) ? await file.text() : '';
  await Bun.write(MEALS_FILE, existing + JSON.stringify(meal) + '\n');
};

export const deleteMeal = async (id: string): Promise<boolean> => {
  const meals = await loadMeals();
  const filtered = meals.filter((m) => m.id !== id);
  if (filtered.length === meals.length) return false;

  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length ? '\n' : '');
  await Bun.write(MEALS_FILE, content);
  return true;
};

export const loadGoal = async (): Promise<DailyGoal | null> => {
  const file = Bun.file(GOAL_FILE);
  if (!(await file.exists())) return null;

  const text = await file.text();
  return JSON.parse(text) as DailyGoal;
};

export const saveGoal = async (goal: DailyGoal): Promise<void> => {
  await Bun.write(GOAL_FILE, JSON.stringify(goal, null, 2));
};

import type { FoodCategory, FoodItem, Meal, DailyGoal, DailySummary, WeeklyData } from './types';
import { loadMeals, appendMeal, deleteMeal, loadGoal, saveGoal } from './store';

const generateId = (): string => crypto.randomUUID();

const toDateString = (iso: string): string => iso.slice(0, 10);

const today = (): string => new Date().toISOString().slice(0, 10);

export const logMeal = async (
  name: string,
  items: FoodItem[],
  timestamp?: string,
): Promise<Meal> => {
  const meal: Meal = {
    id: generateId(),
    name,
    items,
    timestamp: timestamp ?? new Date().toISOString(),
    totalCalories: items.reduce((sum, item) => sum + item.calories, 0),
  };

  await appendMeal(meal);
  return meal;
};

export const removeMeal = async (id: string): Promise<boolean> => {
  return deleteMeal(id);
};

export const setDailyGoal = async (calories: number): Promise<DailyGoal> => {
  const goal: DailyGoal = {
    calories,
    updatedAt: new Date().toISOString(),
  };
  await saveGoal(goal);
  return goal;
};

export const getDailyGoal = async (): Promise<DailyGoal | null> => {
  return loadGoal();
};

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? today();
  const meals = await loadMeals();
  const dayMeals = meals.filter((m) => toDateString(m.timestamp) === targetDate);

  const totalCalories = dayMeals.reduce((sum, m) => sum + m.totalCalories, 0);

  const categoryBreakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  };

  for (const meal of dayMeals) {
    for (const item of meal.items) {
      for (const cat of item.categories) {
        categoryBreakdown[cat] += item.calories;
      }
    }
  }

  const goal = await loadGoal();
  const goalCalories = goal?.calories ?? null;
  const goalProgress = goalCalories ? Math.round((totalCalories / goalCalories) * 100) : null;

  return {
    date: targetDate,
    meals: dayMeals,
    totalCalories,
    categoryBreakdown,
    goal: goalCalories,
    goalProgress,
  };
};

export const getWeeklyData = async (endDate?: string): Promise<WeeklyData> => {
  const end = endDate ? new Date(endDate) : new Date();
  const meals = await loadMeals();
  const goal = await loadGoal();

  const days: WeeklyData['days'] = [];

  for (let i = 6; i >= 0; i--) {
    const d = new Date(end);
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);
    const dayMeals = meals.filter((m) => toDateString(m.timestamp) === dateStr);
    const totalCalories = dayMeals.reduce((sum, m) => sum + m.totalCalories, 0);

    days.push({
      date: dateStr,
      totalCalories,
      goal: goal?.calories ?? null,
    });
  }

  return { days };
};

import { h } from 'plaited';
import type { WeeklyData } from './types';

const CHART_HEIGHT = 200;
const BAR_WIDTH = 40;
const GAP = 12;
const LABEL_HEIGHT = 24;
const PADDING = 20;

const COLORS = {
  bar: '#4ade80',
  barOver: '#f87171',
  goal: '#facc15',
  label: '#94a3b8',
  axis: '#334155',
  bg: '#0f172a',
};

export const renderWeeklyChart = (data: WeeklyData) => {
  const maxCalories = Math.max(
    ...data.days.map((d) => d.totalCalories),
    ...data.days.map((d) => d.goal ?? 0),
    1,
  );

  const chartWidth = data.days.length * (BAR_WIDTH + GAP) - GAP + PADDING * 2;
  const totalHeight = CHART_HEIGHT + LABEL_HEIGHT + PADDING * 2;
  const scale = CHART_HEIGHT / (maxCalories * 1.1);

  const bars = data.days.map((day, i) => {
    const barHeight = Math.max(day.totalCalories * scale, 1);
    const x = PADDING + i * (BAR_WIDTH + GAP);
    const y = PADDING + CHART_HEIGHT - barHeight;
    const isOver = day.goal !== null && day.totalCalories > day.goal;
    const dayLabel = day.date.slice(5); // MM-DD

    return h('g', {},
      h('rect', {
        x: String(x),
        y: String(y),
        width: String(BAR_WIDTH),
        height: String(barHeight),
        fill: isOver ? COLORS.barOver : COLORS.bar,
        rx: '4',
      }),
      h('text', {
        x: String(x + BAR_WIDTH / 2),
        y: String(PADDING + CHART_HEIGHT + 16),
        fill: COLORS.label,
        'text-anchor': 'middle',
        'font-size': '11',
        'font-family': 'monospace',
      }, dayLabel),
      h('text', {
        x: String(x + BAR_WIDTH / 2),
        y: String(y - 4),
        fill: COLORS.label,
        'text-anchor': 'middle',
        'font-size': '10',
        'font-family': 'monospace',
      }, String(day.totalCalories)),
    );
  });

  const goalLine = data.days[0]?.goal != null
    ? (() => {
        const goalY = PADDING + CHART_HEIGHT - (data.days[0].goal! * scale);
        return h('g', {},
          h('line', {
            x1: String(PADDING - 5),
            y1: String(goalY),
            x2: String(chartWidth - PADDING + 5),
            y2: String(goalY),
            stroke: COLORS.goal,
            'stroke-width': '2',
            'stroke-dasharray': '6,4',
          }),
          h('text', {
            x: String(chartWidth - PADDING + 8),
            y: String(goalY + 4),
            fill: COLORS.goal,
            'font-size': '10',
            'font-family': 'monospace',
          }, `Goal: ${data.days[0].goal}`),
        );
      })()
    : null;

  return h('div', {
    style: `background:${COLORS.bg};border-radius:12px;padding:16px;display:inline-block`,
  },
    h('h3', {
      style: `color:#e2e8f0;font-family:sans-serif;margin:0 0 12px 0;font-size:14px`,
    }, 'Weekly Calorie Intake'),
    h('svg', {
      width: String(chartWidth + 60),
      height: String(totalHeight),
      viewBox: `0 0 ${chartWidth + 60} ${totalHeight}`,
    },
      h('line', {
        x1: String(PADDING),
        y1: String(PADDING + CHART_HEIGHT),
        x2: String(chartWidth - PADDING),
        y2: String(PADDING + CHART_HEIGHT),
        stroke: COLORS.axis,
        'stroke-width': '1',
      }),
      ...bars,
      ...(goalLine ? [goalLine] : []),
    ),
  );
};

