      ...summary.meals.map(renderMealItem),
    ),
    summary.meals.length === 0
      ? h('p', { style: 'color:#64748b;text-align:center;font-size:13px;padding:24px 0' },
          'No meals logged for this day.',
        )
      : h('span', {}),
  );

  return ssr(template);
};

export const renderWeeklyView = (data: WeeklyData): string => {
  const { ssr } = createSSR();
  const template = renderWeeklyChart(data);
  return ssr(template);
};

