import type { Meal, Settings } from './types';

const DATA_DIR = new URL('./data/', import.meta.url).pathname;
const MEALS_PATH = `${DATA_DIR}meals.jsonl`;
const SETTINGS_PATH = `${DATA_DIR}settings.json`;

const DEFAULT_SETTINGS: Settings = { dailyGoal: 2000 };

export const readMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_PATH);
  if (!(await file.exists())) return [];

  const text = await file.text();
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Meal);
};

export const appendMeal = async (meal: Meal): Promise<void> => {
  const file = Bun.file(MEALS_PATH);
  const existing = (await file.exists()) ? await file.text() : '';
  const line = JSON.stringify(meal) + '\n';
  await Bun.write(MEALS_PATH, existing + line);
};

export const deleteMeal = async (id: string): Promise<boolean> => {
  const meals = await readMeals();
  const filtered = meals.filter((m) => m.id !== id);
  if (filtered.length === meals.length) return false;

  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length ? '\n' : '');
  await Bun.write(MEALS_PATH, content);
  return true;
};

export const readSettings = async (): Promise<Settings> => {
  const file = Bun.file(SETTINGS_PATH);
  if (!(await file.exists())) return { ...DEFAULT_SETTINGS };

  const text = await file.text();
  return JSON.parse(text) as Settings;
};

export const writeSettings = async (settings: Settings): Promise<void> => {
  await Bun.write(SETTINGS_PATH, JSON.stringify(settings, null, 2) + '\n');
};

import type { Meal, MealInput, DailySummary, WeekDay } from './types';
import { readMeals, appendMeal, deleteMeal, readSettings, writeSettings } from './store';

const generateId = (): string => crypto.randomUUID().slice(0, 8);

const toDateString = (iso: string): string => iso.slice(0, 10);

export const logMeal = async (input: MealInput): Promise<Meal> => {
  const meal: Meal = {
    id: generateId(),
    name: input.name,
    calories: input.calories,
    categories: input.categories,
    timestamp: input.timestamp ?? new Date().toISOString(),
  };
  await appendMeal(meal);
  return meal;
};

export const removeMeal = async (id: string): Promise<boolean> => {
  return deleteMeal(id);
};

export const getMealsForDate = async (date: string): Promise<Meal[]> => {
  const meals = await readMeals();
  return meals.filter((m) => toDateString(m.timestamp) === date);
};

export const getDailySummary = async (date: string): Promise<DailySummary> => {
  const meals = await getMealsForDate(date);
  const settings = await readSettings();
  const totalCalories = meals.reduce((sum, m) => sum + m.calories, 0);

  return {
    date,
    meals,
    totalCalories,
    goal: settings.dailyGoal,
    remaining: Math.max(0, settings.dailyGoal - totalCalories),
  };
};

export const getWeekData = async (endDate: string): Promise<WeekDay[]> => {
  const end = new Date(endDate + 'T00:00:00');
  const meals = await readMeals();
  const days: WeekDay[] = [];

  for (let i = 6; i >= 0; i--) {
    const d = new Date(end);
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);
    const dayLabel = d.toLocaleDateString('en-US', { weekday: 'short' });
    const dayMeals = meals.filter((m) => toDateString(m.timestamp) === dateStr);
    const totalCalories = dayMeals.reduce((sum, m) => sum + m.calories, 0);

    days.push({ date: dateStr, label: dayLabel, totalCalories });
  }

  return days;
};

export const setDailyGoal = async (goal: number): Promise<void> => {
  const settings = await readSettings();
  settings.dailyGoal = goal;
  await writeSettings(settings);
};

export const getDailyGoal = async (): Promise<number> => {
  const settings = await readSettings();
  return settings.dailyGoal;
};

