const BAR_MAX_WIDTH = 300;

const categoryColor = (ratio: number): string => {
  if (ratio <= 0.7) return '#4caf50';
  if (ratio <= 0.9) return '#ff9800';
  return '#f44336';
};

export const renderWeeklyChart = (days: WeekDay[], goal: number) => {
  const maxCal = Math.max(goal, ...days.map((d) => d.totalCalories));

  const bars = days.map((day) => {
    const ratio = goal > 0 ? day.totalCalories / goal : 0;
    const width = maxCal > 0 ? Math.round((day.totalCalories / maxCal) * BAR_MAX_WIDTH) : 0;
    const color = categoryColor(ratio);

    return h('div', {
      style: {
        display: 'flex',
        alignItems: 'center',
        gap: '8px',
        marginBottom: '6px',
      },
    },
      h('span', {
        style: {
          width: '36px',
          fontSize: '13px',
          color: '#aaa',
          textAlign: 'right',
          flexShrink: '0',
        },
      }, day.label),
      h('div', {
        style: {
          width: `${BAR_MAX_WIDTH}px`,
          height: '22px',
          background: '#2a2a2a',
          borderRadius: '4px',
          position: 'relative',
          overflow: 'hidden',
        },
      },
        h('div', {
          style: {
            width: `${width}px`,
            height: '100%',
            background: color,
            borderRadius: '4px',
            transition: 'width 0.3s ease',
          },
        }),
        goal > 0
          ? h('div', {
              style: {
                position: 'absolute',
                left: `${Math.round((goal / maxCal) * BAR_MAX_WIDTH)}px`,
                top: '0',
                width: '2px',
                height: '100%',
                background: '#fff',
                opacity: '0.4',
              },
            })
          : null,
      ),
      h('span', {
        style: {
          fontSize: '13px',
          color: '#ccc',
          minWidth: '60px',
        },
      }, `${day.totalCalories} cal`),
    );
  });

  return h('div', {
    style: {
      fontFamily: 'system-ui, sans-serif',
      padding: '16px',
      background: '#1a1a1a',
      borderRadius: '8px',
    },
  },
    h('div', {
      style: {
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: '14px',
      },
    },
      h('h3', {
        style: { margin: '0', color: '#fff', fontSize: '16px' },
      }, 'Weekly Calorie Intake'),
      h('span', {
        style: { fontSize: '12px', color: '#888' },
      }, `Goal: ${goal} cal/day`),
    ),
    ...bars,
  );
};

