import type { Book, BookInput, FilterOptions, ReadingStats, ReadingStatus } from './types'

const DATA_PATH = './data/books.json'

const loadBooks = async (): Promise<Book[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const saveBooks = async (books: Book[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(books, null, 2))
}

const generateId = (): string =>
  crypto.randomUUID()

export const addBook = async (input: BookInput): Promise<Book> => {
  const books = await loadBooks()
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    coverUrl: input.coverUrl,
    currentPage: 0,
    status: 'want-to-read',
    addedAt: new Date().toISOString(),
    completedAt: null,
  }
  books.push(book)
  await saveBooks(books)
  return book
}

export const updateProgress = async (
  bookId: string,
  currentPage: number,
): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === bookId)
  if (!book) return null

  book.currentPage = Math.min(Math.max(0, currentPage), book.pageCount)
  if (book.currentPage === book.pageCount) {
    book.status = 'completed'
    book.completedAt = new Date().toISOString()
  } else if (book.currentPage > 0 && book.status === 'want-to-read') {
    book.status = 'reading'
  }
  await saveBooks(books)
  return book
}

export const updateStatus = async (
  bookId: string,
  status: ReadingStatus,
): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === bookId)
  if (!book) return null

  book.status = status
  if (status === 'completed') {
    book.currentPage = book.pageCount
    book.completedAt = new Date().toISOString()
  } else if (status === 'want-to-read') {
    book.currentPage = 0
    book.completedAt = null
  }
  await saveBooks(books)
  return book
}

export const removeBook = async (bookId: string): Promise<boolean> => {
  const books = await loadBooks()
  const idx = books.findIndex((b) => b.id === bookId)
  if (idx === -1) return false
  books.splice(idx, 1)
  await saveBooks(books)
  return true
}

export const getBooks = async (filters?: FilterOptions): Promise<Book[]> => {
  const books = await loadBooks()
  return books.filter((book) => {
    if (filters?.status && book.status !== filters.status) return false
    if (filters?.genre && book.genre.toLowerCase() !== filters.genre.toLowerCase()) return false
    return true
  })
}

export const getBook = async (bookId: string): Promise<Book | null> => {
  const books = await loadBooks()
  return books.find((b) => b.id === bookId) ?? null
}

export const getStats = async (): Promise<ReadingStats> => {
  const books = await loadBooks()
  const genreSet = new Set(books.map((b) => b.genre))
  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0)
  const totalPages = books.reduce((sum, b) => sum + b.pageCount, 0)
  const averageProgress =
    books.length > 0
      ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) /
        books.length
      : 0

  return {
    totalBooks: books.length,
    booksCompleted: books.filter((b) => b.status === 'completed').length,
    booksReading: books.filter((b) => b.status === 'reading').length,
    booksWantToRead: books.filter((b) => b.status === 'want-to-read').length,
    totalPagesRead,
    totalPages,
    averageProgress: Math.round(averageProgress * 100),
    genres: [...genreSet].sort(),
  }
}

