import { createSSR } from 'plaited'
import {
  addBook,
  getBooks,
  getBook,
  getStats,
  updateProgress,
  updateStatus,
  removeBook,
} from './data'
import {
  renderPage,
  renderBookCard,
  renderStats,
} from './render'
import type { BookInput, FilterOptions, ReadingStatus } from './types'

export const handleAddBook = async (input: BookInput) => {
  const book = await addBook(input)
  return { ok: true, book }
}

export const handleUpdateProgress = async (bookId: string, currentPage: number) => {
  const book = await updateProgress(bookId, currentPage)
  if (!book) return { ok: false, error: 'Book not found' }
  return { ok: true, book }
}

export const handleSetStatus = async (bookId: string, status: ReadingStatus) => {
  const book = await updateStatus(bookId, status)
  if (!book) return { ok: false, error: 'Book not found' }
  return { ok: true, book }
}

export const handleRemoveBook = async (bookId: string) => {
  const removed = await removeBook(bookId)
  if (!removed) return { ok: false, error: 'Book not found' }
  return { ok: true }
}

export const handleGetBooks = async (filters?: FilterOptions) => {
  const books = await getBooks(filters)
  return { ok: true, books }
}

export const handleGetStats = async () => {
  const stats = await getStats()
  return { ok: true, stats }
}

export const renderView = async (filters: FilterOptions = {}) => {
  const [books, stats] = await Promise.all([
    getBooks(filters),
    getStats(),
  ])
  const ssr = createSSR()
  return ssr(renderPage(books, stats, filters))
}

export const renderBookDetail = async (bookId: string) => {
  const book = await getBook(bookId)
  if (!book) return null
  const ssr = createSSR()
  return ssr(renderBookCard(book))
}

export const renderStatsView = async () => {
  const stats = await getStats()
  const ssr = createSSR()
  return ssr(renderStats(stats))
}

