export type ReadingStatus = 'want-to-read' | 'reading' | 'completed';

export type Book = {
  id: string;
  title: string;
  author: string;
  genre: string;
  pageCount: number;
  currentPage: number;
  coverImageUrl: string;
  status: ReadingStatus;
  dateAdded: string;
  dateCompleted: string | null;
};

export type BookInput = {
  title: string;
  author: string;
  genre: string;
  pageCount: number;
  coverImageUrl?: string;
};

export type BookFilter = {
  status?: ReadingStatus;
  genre?: string;
};

export type ReadingStats = {
  totalBooks: number;
  booksCompleted: number;
  booksReading: number;
  booksWantToRead: number;
  totalPagesRead: number;
  averageProgress: number;
};

import type { Book, BookFilter, BookInput, ReadingStats, ReadingStatus } from './types';

const DATA_PATH = `${import.meta.dir}/data/books.json`;

const loadBooks = async (): Promise<Book[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  return file.json();
};

const saveBooks = async (books: Book[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(books, null, 2));
};

const generateId = (): string => crypto.randomUUID();

export const addBook = async (input: BookInput): Promise<Book> => {
  const books = await loadBooks();
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    currentPage: 0,
    coverImageUrl: input.coverImageUrl ?? '',
    status: 'want-to-read',
    dateAdded: new Date().toISOString(),
    dateCompleted: null,
  };
  books.push(book);
  await saveBooks(books);
  return book;
};

export const updateProgress = async (bookId: string, currentPage: number): Promise<Book | null> => {
  const books = await loadBooks();
  const book = books.find((b) => b.id === bookId);
  if (!book) return null;

  book.currentPage = Math.max(0, Math.min(currentPage, book.pageCount));

  if (book.currentPage > 0 && book.status === 'want-to-read') {
    book.status = 'reading';
  }
  if (book.currentPage >= book.pageCount) {
    book.status = 'completed';
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString();
  }

  await saveBooks(books);
  return book;
};

export const updateStatus = async (bookId: string, status: ReadingStatus): Promise<Book | null> => {
  const books = await loadBooks();
  const book = books.find((b) => b.id === bookId);
  if (!book) return null;

  book.status = status;
  if (status === 'completed') {
    book.currentPage = book.pageCount;
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString();
  } else if (status === 'want-to-read') {
    book.currentPage = 0;
    book.dateCompleted = null;
  }

  await saveBooks(books);
  return book;
};

export const removeBook = async (bookId: string): Promise<boolean> => {
  const books = await loadBooks();
  const idx = books.findIndex((b) => b.id === bookId);
  if (idx === -1) return false;
  books.splice(idx, 1);
  await saveBooks(books);
  return true;
};

export const getBooks = async (filter?: BookFilter): Promise<Book[]> => {
  let books = await loadBooks();
  if (filter?.status) {
    books = books.filter((b) => b.status === filter.status);
  }
  if (filter?.genre) {
    books = books.filter((b) => b.genre.toLowerCase() === filter.genre!.toLowerCase());
  }
  return books;
};

export const getStats = async (): Promise<ReadingStats> => {
  const books = await loadBooks();
  const completed = books.filter((b) => b.status === 'completed');
  const reading = books.filter((b) => b.status === 'reading');
  const wantToRead = books.filter((b) => b.status === 'want-to-read');

  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0);
  const averageProgress =
    books.length > 0
      ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) / books.length
      : 0;

  return {
    totalBooks: books.length,
    booksCompleted: completed.length,
    booksReading: reading.length,
    booksWantToRead: wantToRead.length,
    totalPagesRead,
    averageProgress: Math.round(averageProgress * 100),
  };
};

export const getGenres = async (): Promise<string[]> => {
  const books = await loadBooks();
  return [...new Set(books.map((b) => b.genre))].sort();
};

