  const base = styles.badge;
  const variant =
    status === 'completed'
      ? styles.badgeCompleted
      : status === 'reading'
        ? styles.badgeReading
        : styles.badgeWantToRead;
  return { ...base, ...variant };
};

const statusLabel = (status: Book['status']): string => {
  if (status === 'want-to-read') return 'Want to Read';
  if (status === 'reading') return 'Reading';
  return 'Completed';
};

const ProgressBar = ({ currentPage, pageCount }: { currentPage: number; pageCount: number }) => {
  const pct = pageCount > 0 ? Math.round((currentPage / pageCount) * 100) : 0;
  return h(
    'div',
    { style: styles.progressContainer },
    h('div', { style: styles.progressTrack }, h('div', { style: styles.progressFill(pct) })),
    h('span', { style: styles.progressText }, `${currentPage} / ${pageCount} pages (${pct}%)`),
  );
};

