export { addBook, updateProgress, updateStatus, removeBook, getBooks, getStats, getGenres } from './store';
export { renderPage } from './render';
export type { Book, BookInput, BookFilter, ReadingStats, ReadingStatus } from './types';

import { addBook, getBooks, getGenres, getStats, removeBook, updateProgress, updateStatus } from './store';
import { renderPage } from './render';
import type { BookFilter, BookInput, ReadingStatus } from './types';

const parseBody = async (req: Request): Promise<Record<string, string>> => {
  const contentType = req.headers.get('content-type') ?? '';
  if (contentType.includes('application/json')) {
    return req.json();
  }
  const formData = await req.formData();
  const result: Record<string, string> = {};
  formData.forEach((value, key) => {
    result[key] = String(value);
  });
  return result;
};

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const htmlResponse = (html: string) =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });

const handleRoutes = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const { pathname } = url;
  const method = req.method;

  // GET / — render full page
  if (method === 'GET' && pathname === '/') {
    const status = (url.searchParams.get('status') as ReadingStatus | null) ?? undefined;
    const genre = url.searchParams.get('genre') ?? undefined;
    const filter: BookFilter = { status, genre };
    const [books, stats, genres] = await Promise.all([getBooks(filter), getStats(), getGenres()]);
    const html = renderPage({ books, stats, genres, filter });
    return htmlResponse(html);
  }

  // GET /api/books — list books with optional filters
  if (method === 'GET' && pathname === '/api/books') {
    const status = (url.searchParams.get('status') as ReadingStatus | null) ?? undefined;
    const genre = url.searchParams.get('genre') ?? undefined;
    const books = await getBooks({ status, genre });
    return jsonResponse(books);
  }

  // POST /api/books — add a book
  if (method === 'POST' && pathname === '/api/books') {
    const body = await parseBody(req);
    const input: BookInput = {
      title: body.title ?? '',
      author: body.author ?? '',
      genre: body.genre ?? '',
      pageCount: Number(body.pageCount) || 0,
      coverImageUrl: body.coverImageUrl || undefined,
    };
    if (!input.title || !input.author || input.pageCount < 1) {
      return jsonResponse({ error: 'Title, author, and valid page count are required' }, 400);
    }
    const book = await addBook(input);
    return jsonResponse(book, 201);
  }

  // PATCH /api/books/:id/progress — update reading progress
  if (method === 'PATCH' && pathname.match(/^\/api\/books\/[^/]+\/progress$/)) {
    const bookId = pathname.split('/')[3];
    const body = await parseBody(req);
    const currentPage = Number(body.currentPage);
    if (isNaN(currentPage) || currentPage < 0) {
      return jsonResponse({ error: 'Valid currentPage is required' }, 400);
    }
    const book = await updateProgress(bookId, currentPage);
    if (!book) return jsonResponse({ error: 'Book not found' }, 404);
    return jsonResponse(book);
  }

  // PATCH /api/books/:id/status — update reading status
  if (method === 'PATCH' && pathname.match(/^\/api\/books\/[^/]+\/status$/)) {
    const bookId = pathname.split('/')[3];
    const body = await parseBody(req);
    const status = body.status as ReadingStatus;
    const valid: ReadingStatus[] = ['want-to-read', 'reading', 'completed'];
    if (!valid.includes(status)) {
      return jsonResponse({ error: 'Status must be want-to-read, reading, or completed' }, 400);
    }
    const book = await updateStatus(bookId, status);
    if (!book) return jsonResponse({ error: 'Book not found' }, 404);
    return jsonResponse(book);
  }

  // DELETE /api/books/:id — remove a book
  if (method === 'DELETE' && pathname.match(/^\/api\/books\/[^/]+$/)) {
    const bookId = pathname.split('/')[3];
    const removed = await removeBook(bookId);
    if (!removed) return jsonResponse({ error: 'Book not found' }, 404);
    return jsonResponse({ success: true });
  }

  // GET /api/stats — reading statistics
  if (method === 'GET' && pathname === '/api/stats') {
    const stats = await getStats();
    return jsonResponse(stats);
  }

  // GET /api/genres — list unique genres
  if (method === 'GET' && pathname === '/api/genres') {
    const genres = await getGenres();
    return jsonResponse(genres);
  }

  return jsonResponse({ error: 'Not found' }, 404);
};

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: handleRoutes,
});

console.log(`Reading List running at http://localhost:${server.port}`);

export default server;

