export type ReadingStatus = 'want-to-read' | 'reading' | 'completed';

export type Book = {
  id: string;
  title: string;
  author: string;
  genre: string;
  pageCount: number;
  coverImageUrl: string;
  currentPage: number;
  status: ReadingStatus;
  dateAdded: string;
  dateCompleted: string | null;
};

export type BookInput = {
  title: string;
  author: string;
  genre: string;
  pageCount: number;
  coverImageUrl: string;
};

export type BookFilter = {
  status?: ReadingStatus;
  genre?: string;
};

export type ReadingStats = {
  totalBooks: number;
  booksCompleted: number;
  booksReading: number;
  booksWantToRead: number;
  totalPagesRead: number;
  averageProgress: number;
};

export type BookStore = {
  books: Book[];
};

import type { Book, BookInput, BookStore, ReadingStatus, BookFilter } from './types';

const DATA_PATH = `${import.meta.dir}/data/books.json`;

const generateId = (): string => crypto.randomUUID();

export const loadStore = async (): Promise<BookStore> => {
  const file = Bun.file(DATA_PATH);
  if (await file.exists()) {
    return file.json();
  }
  return { books: [] };
};

export const saveStore = async (store: BookStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2));
};

export const addBook = async (input: BookInput): Promise<Book> => {
  const store = await loadStore();
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    coverImageUrl: input.coverImageUrl,
    currentPage: 0,
    status: 'want-to-read',
    dateAdded: new Date().toISOString(),
    dateCompleted: null,
  };
  store.books.push(book);
  await saveStore(store);
  return book;
};

export const removeBook = async (id: string): Promise<boolean> => {
  const store = await loadStore();
  const index = store.books.findIndex((b) => b.id === id);
  if (index === -1) return false;
  store.books.splice(index, 1);
  await saveStore(store);
  return true;
};

export const updateProgress = async (id: string, currentPage: number): Promise<Book | null> => {
  const store = await loadStore();
  const book = store.books.find((b) => b.id === id);
  if (!book) return null;

  book.currentPage = Math.max(0, Math.min(currentPage, book.pageCount));

  if (book.currentPage === book.pageCount) {
    book.status = 'completed';
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString();
  } else if (book.currentPage > 0) {
    book.status = 'reading';
    book.dateCompleted = null;
  }

  await saveStore(store);
  return book;
};

export const updateStatus = async (id: string, status: ReadingStatus): Promise<Book | null> => {
  const store = await loadStore();
  const book = store.books.find((b) => b.id === id);
  if (!book) return null;

  book.status = status;

  if (status === 'completed') {
    book.currentPage = book.pageCount;
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString();
  } else if (status === 'want-to-read') {
    book.currentPage = 0;
    book.dateCompleted = null;
  } else {
    book.dateCompleted = null;
  }

  await saveStore(store);
  return book;
};

export const getBooks = async (filter?: BookFilter): Promise<Book[]> => {
  const store = await loadStore();
  let books = store.books;

  if (filter?.status) {
    books = books.filter((b) => b.status === filter.status);
  }
  if (filter?.genre) {
    books = books.filter((b) => b.genre.toLowerCase() === filter.genre!.toLowerCase());
  }

  return books;
};

export const getBook = async (id: string): Promise<Book | null> => {
  const store = await loadStore();
  return store.books.find((b) => b.id === id) ?? null;
};

export const getGenres = async (): Promise<string[]> => {
  const store = await loadStore();
  const genres = new Set(store.books.map((b) => b.genre));
  return [...genres].sort();
};

import type { Book, ReadingStats } from './types';

export const computeStats = (books: Book[]): ReadingStats => {
  const booksCompleted = books.filter((b) => b.status === 'completed').length;
  const booksReading = books.filter((b) => b.status === 'reading').length;
  const booksWantToRead = books.filter((b) => b.status === 'want-to-read').length;

  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0);

  const averageProgress =
    books.length > 0
      ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) /
        books.length
      : 0;

  return {
    totalBooks: books.length,
    booksCompleted,
    booksReading,
    booksWantToRead,
    totalPagesRead,
    averageProgress: Math.round(averageProgress * 100),
  };
};

export const bookProgress = (book: Book): number => {
  if (book.pageCount === 0) return 0;
  return Math.round((book.currentPage / book.pageCount) * 100);
};

