import { type Expense, type ExpenseInput, type FilterParams } from './types';

const DATA_PATH = new URL('./data/expenses.jsonl', import.meta.url).pathname;

const generateId = (): string => crypto.randomUUID();

const readAllExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  if (!text.trim()) return [];
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Expense);
};

const appendExpense = async (expense: Expense): Promise<void> => {
  const file = Bun.file(DATA_PATH);
  const existing = (await file.exists()) ? await file.text() : '';
  const line = JSON.stringify(expense) + '\n';
  await Bun.write(DATA_PATH, existing + line);
};

const writeAllExpenses = async (expenses: Expense[]): Promise<void> => {
  const content = expenses.map((e) => JSON.stringify(e)).join('\n') + (expenses.length ? '\n' : '');
  await Bun.write(DATA_PATH, content);
};

export const addExpense = async (input: ExpenseInput): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(input.amount * 100) / 100,
    category: input.category,
    date: input.date,
    notes: input.notes ?? '',
    createdAt: new Date().toISOString(),
  };
  await appendExpense(expense);
  return expense;
};

export const getExpenses = async (filters?: FilterParams): Promise<Expense[]> => {
  const all = await readAllExpenses();
  return all.filter((e) => {
    if (filters?.startDate && e.date < filters.startDate) return false;
    if (filters?.endDate && e.date > filters.endDate) return false;
    if (filters?.category && e.category !== filters.category) return false;
    return true;
  });
};

export const deleteExpense = async (id: string): Promise<boolean> => {
  const all = await readAllExpenses();
  const filtered = all.filter((e) => e.id !== id);
  if (filtered.length === all.length) return false;
  await writeAllExpenses(filtered);
  return true;
};

export const getExpensesByMonth = async (month: string): Promise<Expense[]> => {
  const all = await readAllExpenses();
  return all.filter((e) => e.date.startsWith(month));
};

import { h } from '@plaited/template';
import type { CategorySummary } from './types';

const COLORS: Record<string, string> = {
  food: '#ef4444',
  transport: '#3b82f6',
  housing: '#22c55e',
  entertainment: '#a855f7',
  utilities: '#f59e0b',
  other: '#6b7280',
};

type SliceData = {
  category: string;
  percentage: number;
  color: string;
  startAngle: number;
  endAngle: number;
};

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = ((angleDeg - 90) * Math.PI) / 180;
  return { x: cx + r * Math.cos(rad), y: cy + r * Math.sin(rad) };
};

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle);
  const end = polarToCartesian(cx, cy, r, startAngle);
  const largeArc = endAngle - startAngle > 180 ? 1 : 0;
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y} Z`;
};

const buildSlices = (categories: CategorySummary[]): SliceData[] => {
  const slices: SliceData[] = [];
  let currentAngle = 0;
  for (const cat of categories) {
    if (cat.percentage === 0) continue;
    const sweep = (cat.percentage / 100) * 360;
    slices.push({
      category: cat.category,
      percentage: cat.percentage,
      color: COLORS[cat.category] ?? '#6b7280',
      startAngle: currentAngle,
      endAngle: currentAngle + sweep,
    });
    currentAngle += sweep;
  }
  return slices;
};

export const renderPieChart = (categories: CategorySummary[], total: number) => {
  const slices = buildSlices(categories);
  const cx = 120;
  const cy = 120;
  const r = 100;

  if (slices.length === 0) {
    return h('div', { style: { textAlign: 'center', padding: '2rem', color: '#9ca3af' } }, 'No expense data to chart');
  }

  const paths =
    slices.length === 1
      ? [h('circle', { cx: String(cx), cy: String(cy), r: String(r), fill: slices[0].color })]
      : slices.map((s) => h('path', { d: describeArc(cx, cy, r, s.startAngle, s.endAngle), fill: s.color }));

  const svg = h(
    'svg',
    { viewBox: '0 0 240 240', width: '240', height: '240', xmlns: 'http://www.w3.org/2000/svg' },
    ...paths,
  );

  const legendItems = slices.map((s) =>
    h(
      'div',
      { style: { display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.875rem' } },
      h('span', {
        style: {
          width: '12px',
          height: '12px',
          borderRadius: '2px',
          backgroundColor: s.color,
          display: 'inline-block',
          flexShrink: '0',
        },
      }),
      h('span', {}, `${s.category}: ${s.percentage.toFixed(1)}%`),
    ),
  );

  return h(
    'div',
    { style: { display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem' } },
    h('h3', { style: { margin: '0', fontSize: '1.125rem' } }, `Total: $${total.toFixed(2)}`),
    svg,
    h('div', { style: { display: 'flex', flexDirection: 'column', gap: '0.25rem' } }, ...legendItems),
  );
};

