const escapeField = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`;
  }
  return value;
};

export const expensesToCsv = (expenses: Expense[]): string => {
  const header = 'id,date,amount,category,notes';
  const rows = expenses.map(
    (e) =>
      `${escapeField(e.id)},${escapeField(e.date)},${e.amount.toFixed(2)},${escapeField(e.category)},${escapeField(e.notes)}`,
  );
  return [header, ...rows].join('\n') + '\n';
};

import { CATEGORIES, type Category, type CategorySummary, type Expense, type MonthlySummary } from './types';

export const computeMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month));
  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0);

  const categoryTotals = new Map<Category, { total: number; count: number }>();
  for (const cat of CATEGORIES) {
    categoryTotals.set(cat, { total: 0, count: 0 });
  }
  for (const e of monthExpenses) {
    const entry = categoryTotals.get(e.category)!;
    entry.total += e.amount;
    entry.count += 1;
  }

  const categories: CategorySummary[] = CATEGORIES.map((cat) => {
    const entry = categoryTotals.get(cat)!;
    return {
      category: cat,
      total: Math.round(entry.total * 100) / 100,
      count: entry.count,
      percentage: total > 0 ? (entry.total / total) * 100 : 0,
    };
  });

  return {
    month,
    total: Math.round(total * 100) / 100,
    categories,
  };
};

