const isValidCategory = (val: unknown): val is Category =>
  typeof val === 'string' && CATEGORIES.includes(val as Category);

const isValidDate = (val: unknown): val is string =>
  typeof val === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(val);

const parseFilters = (url: URL): FilterParams => {
  const filters: FilterParams = {};
  const startDate = url.searchParams.get('startDate');
  const endDate = url.searchParams.get('endDate');
  const category = url.searchParams.get('category');
  if (startDate && isValidDate(startDate)) filters.startDate = startDate;
  if (endDate && isValidDate(endDate)) filters.endDate = endDate;
  if (category && isValidCategory(category)) filters.category = category;
  return filters;
};

const currentMonth = (): string => {
  const now = new Date();
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
};

const htmlResponse = (body: string): Response =>
  new Response(
    `<!DOCTYPE html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Expense Logger</title></head><body>${body}</body></html>`,
    { headers: { 'Content-Type': 'text/html; charset=utf-8' } },
  );

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

export default {
  async fetch(request: Request): Promise<Response> {
    const url = new URL(request.url);
    const method = request.method;

    // POST /expenses — add a new expense
    if (method === 'POST' && url.pathname === '/expenses') {
      const body = (await request.json()) as Record<string, unknown>;
      const { amount, category, date, notes } = body;

      if (typeof amount !== 'number' || amount <= 0) {
        return jsonResponse({ error: 'amount must be a positive number' }, 400);
      }
      if (!isValidCategory(category)) {
        return jsonResponse({ error: `category must be one of: ${CATEGORIES.join(', ')}` }, 400);
      }
      if (!isValidDate(date)) {
        return jsonResponse({ error: 'date must be in YYYY-MM-DD format' }, 400);
      }

      const input: ExpenseInput = {
        amount,
        category,
        date,
        notes: typeof notes === 'string' ? notes : undefined,
      };
      const expense = await addExpense(input);
      return jsonResponse(expense, 201);
    }

    // DELETE /expenses/:id — delete an expense
    if (method === 'DELETE' && url.pathname.startsWith('/expenses/')) {
      const id = url.pathname.slice('/expenses/'.length);
      const deleted = await deleteExpense(id);
      if (!deleted) return jsonResponse({ error: 'Expense not found' }, 404);
      return jsonResponse({ ok: true });
    }

    // GET /expenses — list expenses (with optional filters)
    if (method === 'GET' && url.pathname === '/expenses') {
      const filters = parseFilters(url);
      const expenses = await getExpenses(filters);
      return jsonResponse(expenses);
    }

    // GET /summary?month=YYYY-MM — monthly summary
    if (method === 'GET' && url.pathname === '/summary') {
      const month = url.searchParams.get('month') ?? currentMonth();
      const expenses = await getExpenses();
      const summary = computeMonthlySummary(expenses, month);
      return jsonResponse(summary);
    }

    // GET /export — CSV export (with optional filters)
    if (method === 'GET' && url.pathname === '/export') {
      const filters = parseFilters(url);
      const expenses = await getExpenses(filters);
      const csv = expensesToCsv(expenses);
      return new Response(csv, {
        headers: {
          'Content-Type': 'text/csv; charset=utf-8',
          'Content-Disposition': 'attachment; filename="expenses.csv"',
        },
      });
    }

    // GET / — render the full page
    if (method === 'GET' && url.pathname === '/') {
      const filters = parseFilters(url);
      const expenses = await getExpenses(filters);
      const month = url.searchParams.get('month') ?? currentMonth();
      const allExpenses = await getExpenses();
      const summary = computeMonthlySummary(allExpenses, month);
      const ssr = createSSR();
      const body = ssr(renderPage(expenses, summary, filters));
      return htmlResponse(body);
    }

    return jsonResponse({ error: 'Not found' }, 404);
  },
};

