export type Category = 'food' | 'transport' | 'housing' | 'entertainment' | 'utilities' | 'other';

export const CATEGORIES: Category[] = ['food', 'transport', 'housing', 'entertainment', 'utilities', 'other'];

export type Expense = {
  id: string;
  amount: number;
  category: Category;
  date: string; // ISO date string YYYY-MM-DD
  notes?: string;
  createdAt: string; // ISO datetime
};

export type ExpenseFilter = {
  startDate?: string;
  endDate?: string;
  category?: Category;
};

export type CategorySummary = {
  category: Category;
  total: number;
  count: number;
  percentage: number;
};

export type MonthlySummary = {
  month: string; // YYYY-MM
  total: number;
  categories: CategorySummary[];
};

export const CATEGORY_COLORS: Record<Category, string> = {
  food: '#ef4444',
  transport: '#3b82f6',
  housing: '#22c55e',
  entertainment: '#a855f7',
  utilities: '#f59e0b',
  other: '#6b7280',
};

export const CATEGORY_LABELS: Record<Category, string> = {
  food: 'Food',
  transport: 'Transport',
  housing: 'Housing',
  entertainment: 'Entertainment',
  utilities: 'Utilities',
  other: 'Other',
};

import type { Expense } from './types';

const DATA_PATH = new URL('./data/expenses.jsonl', import.meta.url).pathname;

export const loadExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];

  const text = await file.text();
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Expense);
};

export const saveExpense = async (expense: Expense): Promise<void> => {
  const file = Bun.file(DATA_PATH);
  const existing = (await file.exists()) ? await file.text() : '';
  await Bun.write(DATA_PATH, existing + JSON.stringify(expense) + '\n');
};

export const saveAllExpenses = async (expenses: Expense[]): Promise<void> => {
  const content = expenses.map((e) => JSON.stringify(e)).join('\n') + (expenses.length ? '\n' : '');
  await Bun.write(DATA_PATH, content);
};

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await loadExpenses();
  const filtered = expenses.filter((e) => e.id !== id);
  if (filtered.length === expenses.length) return false;
  await saveAllExpenses(filtered);
  return true;
};

import type { Expense, ExpenseFilter, Category } from './types';
import { loadExpenses, saveExpense } from './store';

export const generateId = (): string => crypto.randomUUID();

export const createExpense = async (params: {
  amount: number;
  category: Category;
  date?: string;
  notes?: string;
}): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(params.amount * 100) / 100,
    category: params.category,
    date: params.date ?? new Date().toISOString().slice(0, 10),
    notes: params.notes?.trim() || undefined,
    createdAt: new Date().toISOString(),
  };
  await saveExpense(expense);
  return expense;
};

export const listExpenses = async (filter?: ExpenseFilter): Promise<Expense[]> => {
  const all = await loadExpenses();
  return applyFilter(all, filter).sort((a, b) => b.date.localeCompare(a.date));
};

export const applyFilter = (expenses: Expense[], filter?: ExpenseFilter): Expense[] => {
  if (!filter) return expenses;

  return expenses.filter((e) => {
    if (filter.startDate && e.date < filter.startDate) return false;
    if (filter.endDate && e.date > filter.endDate) return false;
    if (filter.category && e.category !== filter.category) return false;
    return true;
  });
};

export const getExpensesByMonth = async (month: string): Promise<Expense[]> => {
  const all = await loadExpenses();
  return all.filter((e) => e.date.slice(0, 7) === month).sort((a, b) => b.date.localeCompare(a.date));
};

import type { Expense, Category, CategorySummary, MonthlySummary } from './types';
import { CATEGORIES } from './types';
import { loadExpenses } from './store';

export const computeCategorySummaries = (expenses: Expense[]): CategorySummary[] => {
  const total = expenses.reduce((sum, e) => sum + e.amount, 0);

  const byCategory = new Map<Category, { total: number; count: number }>();
  for (const cat of CATEGORIES) {
    byCategory.set(cat, { total: 0, count: 0 });
  }

  for (const e of expenses) {
    const entry = byCategory.get(e.category)!;
    entry.total += e.amount;
    entry.count += 1;
  }

  return CATEGORIES.map((category) => {
    const entry = byCategory.get(category)!;
    return {
      category,
      total: Math.round(entry.total * 100) / 100,
      count: entry.count,
      percentage: total > 0 ? Math.round((entry.total / total) * 10000) / 100 : 0,
    };
  }).filter((s) => s.count > 0);
};

export const getMonthlySummary = async (month: string): Promise<MonthlySummary> => {
  const all = await loadExpenses();
  const monthExpenses = all.filter((e) => e.date.slice(0, 7) === month);
  const total = Math.round(monthExpenses.reduce((sum, e) => sum + e.amount, 0) * 100) / 100;
  const categories = computeCategorySummaries(monthExpenses);

  return { month, total, categories };
};

export const getAvailableMonths = async (): Promise<string[]> => {
  const all = await loadExpenses();
  const months = new Set(all.map((e) => e.date.slice(0, 7)));
  return [...months].sort().reverse();
};

import { h } from 'plaited';
import type { CategorySummary } from './types';
import { CATEGORY_COLORS, CATEGORY_LABELS } from './types';

type PieSlice = {
  category: string;
  percentage: number;
  color: string;
  startAngle: number;
  endAngle: number;
};

const computeSlices = (categories: CategorySummary[]): PieSlice[] => {
  const slices: PieSlice[] = [];
  let currentAngle = -90; // start from top

  for (const cat of categories) {
    const sweep = (cat.percentage / 100) * 360;
    slices.push({
      category: CATEGORY_LABELS[cat.category],
      percentage: cat.percentage,
      color: CATEGORY_COLORS[cat.category],
      startAngle: currentAngle,
      endAngle: currentAngle + sweep,
    });
    currentAngle += sweep;
  }

  return slices;
};

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = (angleDeg * Math.PI) / 180;
  return { x: cx + r * Math.cos(rad), y: cy + r * Math.sin(rad) };
};

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle);
  const end = polarToCartesian(cx, cy, r, startAngle);
  const largeArcFlag = endAngle - startAngle > 180 ? 1 : 0;

  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArcFlag} 0 ${end.x} ${end.y} Z`;
};

export const renderPieChart = (categories: CategorySummary[]): ReturnType<typeof h> => {
  if (categories.length === 0) {
    return h('p', { style: { color: '#9ca3af', fontStyle: 'italic', textAlign: 'center' } }, 'No expenses to chart');
  }

  const cx = 100;
  const cy = 100;
  const r = 90;
  const slices = computeSlices(categories);

  // Handle single-category case (full circle)
  const paths =
    slices.length === 1
      ? [h('circle', { cx: String(cx), cy: String(cy), r: String(r), fill: slices[0].color })]
      : slices.map((slice) =>
          h('path', {
            d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
            fill: slice.color,
          }),
        );

  const legend = slices.map((slice) =>
    h(
      'div',
      {
        style: {
          display: 'flex',
          alignItems: 'center',
          gap: '8px',
          fontSize: '14px',
          marginBottom: '4px',
        },
      },
      h('span', {
        style: {
          width: '12px',
          height: '12px',
          borderRadius: '2px',
          backgroundColor: slice.color,
          display: 'inline-block',
          flexShrink: '0',
        },
      }),
      h('span', {}, `${slice.category}: ${slice.percentage}%`),
    ),
  );

  return h(
    'div',
    {
      style: {
        display: 'flex',
        flexWrap: 'wrap',
        gap: '24px',
        alignItems: 'center',
        justifyContent: 'center',
      },
    },
    h(
      'svg',
      {
        viewBox: '0 0 200 200',
        width: '200',
        height: '200',
        style: { maxWidth: '200px' },
      },
      ...paths,
    ),
    h('div', { style: { display: 'flex', flexDirection: 'column' } }, ...legend),
  );
};

import type { Expense, ExpenseFilter } from './types';
