const escapeCSV = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`;
  }
  return value;
};

export const exportToCSV = async (filter?: ExpenseFilter): Promise<string> => {
  const expenses = await listExpenses(filter);
  const header = 'Date,Category,Amount,Notes';
  const rows = expenses.map(
    (e) =>
      `${e.date},${escapeCSV(CATEGORY_LABELS[e.category])},${e.amount.toFixed(2)},${escapeCSV(e.notes ?? '')}`,
  );

  return [header, ...rows].join('\n');
};

export const saveCSVFile = async (filter?: ExpenseFilter): Promise<string> => {
  const csv = await exportToCSV(filter);
  const timestamp = new Date().toISOString().slice(0, 10);
  const filePath = new URL(`./data/expenses-export-${timestamp}.csv`, import.meta.url).pathname;
  await Bun.write(filePath, csv);
  return filePath;
};

