    return h('option', { value: m, ...(m === selectedMonth ? { selected: 'true' } : {}) }, label);
  });

  return h('div', { style: { marginBottom: '16px' } },
    h('label', { style: styles.label, for: 'monthSelect' }, 'Select Month'),
    h('select', {
      id: 'monthSelect',
      name: 'month',
      'p-trigger': 'change:selectMonth',
      style: styles.select,
    }, ...options),
  );
};

export const renderPage = (params: {
  expenses: Expense[];
  summary: MonthlySummary;
  months: string[];
  selectedMonth: string;
  filter?: ExpenseFilter;
}): ReturnType<typeof h> => {
  return h('div', { style: styles.container },
    h('h1', { style: styles.heading }, 'Expense Logger'),
    renderExpenseForm(),
    h('div', { style: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' } },
      h('div', {},
