import type { Category, ExpenseFilter } from './types';
import { CATEGORIES } from './types';
import { createExpense, listExpenses } from './expense';
import { getMonthlySummary, getAvailableMonths } from './summary';
import { deleteExpense } from './store';
import { exportToCSV, saveCSVFile } from './csv';
import { renderPage } from './ui';

const parseFilter = (params: URLSearchParams): ExpenseFilter | undefined => {
  const startDate = params.get('startDate') || undefined;
  const endDate = params.get('endDate') || undefined;
  const category = params.get('category') as Category | undefined;

  if (!startDate && !endDate && !category) return undefined;

  return {
    startDate,
    endDate,
    category: category && CATEGORIES.includes(category) ? category : undefined,
  };
};

const getCurrentMonth = (): string => new Date().toISOString().slice(0, 7);

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const path = url.pathname;

  // API: Add expense
  if (path === '/api/expenses' && req.method === 'POST') {
    const body = await req.json();
    const expense = await createExpense({
      amount: Number(body.amount),
      category: body.category as Category,
      date: body.date || undefined,
      notes: body.notes || undefined,
    });
    return Response.json(expense, { status: 201 });
  }

  // API: Delete expense
  if (path.startsWith('/api/expenses/') && req.method === 'DELETE') {
    const id = path.slice('/api/expenses/'.length);
    const deleted = await deleteExpense(id);
    if (!deleted) return Response.json({ error: 'Not found' }, { status: 404 });
    return Response.json({ success: true });
  }

  // API: List expenses (with optional filters)
  if (path === '/api/expenses' && req.method === 'GET') {
    const filter = parseFilter(url.searchParams);
    const expenses = await listExpenses(filter);
    return Response.json(expenses);
  }

  // API: Monthly summary
  if (path === '/api/summary' && req.method === 'GET') {
    const month = url.searchParams.get('month') || getCurrentMonth();
    const summary = await getMonthlySummary(month);
    return Response.json(summary);
  }

  // API: Export CSV
  if (path === '/api/export' && req.method === 'GET') {
    const filter = parseFilter(url.searchParams);
    const csv = await exportToCSV(filter);
    return new Response(csv, {
      headers: {
        'Content-Type': 'text/csv',
        'Content-Disposition': `attachment; filename="expenses-${new Date().toISOString().slice(0, 10)}.csv"`,
      },
    });
  }

  // API: Save CSV to file
  if (path === '/api/export/save' && req.method === 'POST') {
    const filter = parseFilter(url.searchParams);
    const filePath = await saveCSVFile(filter);
    return Response.json({ path: filePath });
  }

  // API: Available months
  if (path === '/api/months' && req.method === 'GET') {
    const months = await getAvailableMonths();
    return Response.json(months);
  }

  // UI: Main page
  if (path === '/' && req.method === 'GET') {
    const filter = parseFilter(url.searchParams);
    const selectedMonth = url.searchParams.get('month') || getCurrentMonth();
    const [expenses, summary, months] = await Promise.all([
      listExpenses(filter),
      getMonthlySummary(selectedMonth),
      getAvailableMonths(),
    ]);

    const availableMonths = months.length > 0 ? months : [getCurrentMonth()];
    const ssr = createSSR();
    const html = ssr(renderPage({
      expenses,
      summary,
      months: availableMonths,
      selectedMonth,
      filter,
    }));

    return new Response(
      `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Expense Logger</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background-color: #f9fafb; min-height: 100vh; }
  </style>
</head>
<body>${html}</body>
</html>`,
      { headers: { 'Content-Type': 'text/html; charset=utf-8' } },
    );
  }

  return Response.json({ error: 'Not found' }, { status: 404 });
};

