import { type Expense, type ExpenseInput, type ExpenseFilter } from './types'

const DATA_PATH = new URL('../data/expenses.jsonl', import.meta.url).pathname

const generateId = (): string => crypto.randomUUID()

export const loadExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []

  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Expense)
}

export const saveExpense = async (input: ExpenseInput): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(input.amount * 100) / 100,
    category: input.category,
    date: input.date,
    notes: input.notes ?? '',
    createdAt: new Date().toISOString(),
  }

  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  const existing = exists ? await file.text() : ''
  const newContent = existing + JSON.stringify(expense) + '\n'
  await Bun.write(DATA_PATH, newContent)

  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await loadExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false

  const content = filtered.map((e) => JSON.stringify(e)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

export const filterExpenses = (expenses: Expense[], filter: ExpenseFilter): Expense[] => {
  return expenses.filter((expense) => {
    if (filter.category && expense.category !== filter.category) return false

    if (filter.dateRange?.start && expense.date < filter.dateRange.start) return false
    if (filter.dateRange?.end && expense.date > filter.dateRange.end) return false

    return true
  })
}

export const getExpensesByMonth = (expenses: Expense[], month: string): Expense[] => {
  return expenses.filter((e) => e.date.startsWith(month))
}

import { CATEGORIES, type Expense, type CategorySummary, type MonthlySummary } from './types'

export const computeCategorySummaries = (expenses: Expense[]): CategorySummary[] => {
  const total = expenses.reduce((sum, e) => sum + e.amount, 0)
  if (total === 0) return []

  const grouped = new Map<string, { total: number; count: number }>()
  for (const cat of CATEGORIES) {
    grouped.set(cat, { total: 0, count: 0 })
  }

  for (const expense of expenses) {
    const entry = grouped.get(expense.category)!
    entry.total += expense.amount
    entry.count += 1
  }

  return CATEGORIES.map((category) => {
    const entry = grouped.get(category)!
    return {
      category,
      total: Math.round(entry.total * 100) / 100,
      percentage: total > 0 ? Math.round((entry.total / total) * 10000) / 100 : 0,
      count: entry.count,
    }
  }).filter((s) => s.count > 0)
}

export const computeMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month))
  const total = Math.round(monthExpenses.reduce((sum, e) => sum + e.amount, 0) * 100) / 100

  return {
    month,
    total,
    categories: computeCategorySummaries(monthExpenses),
    count: monthExpenses.length,
  }
}

export const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set<string>()
  for (const expense of expenses) {
    months.add(expense.date.slice(0, 7))
  }
  return [...months].sort().reverse()
}

import type { Expense } from './types'

const escapeField = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`
  }
  return value
}

export const expensesToCsv = (expenses: Expense[]): string => {
  const header = 'date,amount,category,notes'
  const rows = expenses
    .sort((a, b) => a.date.localeCompare(b.date))
    .map(
      (e) =>
        `${e.date},${e.amount.toFixed(2)},${e.category},${escapeField(e.notes)}`
    )

  return [header, ...rows].join('\n') + '\n'
}

import { h } from 'plaited'
import type { CategorySummary } from './types'

const COLORS: Record<string, string> = {
  food: '#4CAF50',
  transport: '#2196F3',
  housing: '#FF9800',
  entertainment: '#9C27B0',
  utilities: '#F44336',
  other: '#607D8B',
}

type PieSlice = {
  category: string
  percentage: number
  total: number
  color: string
  startAngle: number
  endAngle: number
}

const computeSlices = (categories: CategorySummary[]): PieSlice[] => {
  const slices: PieSlice[] = []
  let currentAngle = -90 // start from top

  for (const cat of categories) {
    const angle = (cat.percentage / 100) * 360
    slices.push({
      category: cat.category,
      percentage: cat.percentage,
      total: cat.total,
      color: COLORS[cat.category] ?? '#999',
      startAngle: currentAngle,
      endAngle: currentAngle + angle,
    })
    currentAngle += angle
  }

  return slices
}

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = (angleDeg * Math.PI) / 180
  return {
    x: cx + r * Math.cos(rad),
    y: cy + r * Math.sin(rad),
  }
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArcFlag = endAngle - startAngle > 180 ? 1 : 0

  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArcFlag} 0 ${end.x} ${end.y}`,
    'Z',
  ].join(' ')
}

export const renderPieChart = (categories: CategorySummary[]) => {
  if (categories.length === 0) {
    return h('p', { style: 'color:#888;text-align:center;padding:20px;' }, 'No expenses to chart')
  }

  const cx = 100
  const cy = 100
  const r = 90
  const slices = computeSlices(categories)

  // Handle single-category case (full circle)
  const paths =
    slices.length === 1
      ? [
          h('circle', {
            cx: String(cx),
            cy: String(cy),
            r: String(r),
            fill: slices[0].color,
          }),
        ]
      : slices.map((slice) =>
          h('path', {
            d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
            fill: slice.color,
          })
        )

  const svg = h(
    'svg',
    {
      viewBox: '0 0 200 200',
      width: '200',
      height: '200',
      style: 'display:block;margin:0 auto;',
    },
    ...paths
  )

  const legend = h(
    'div',
    { style: 'display:flex;flex-wrap:wrap;gap:8px 16px;justify-content:center;margin-top:12px;' },
    ...slices.map((slice) =>
      h(
        'div',
        { style: 'display:flex;align-items:center;gap:6px;font-size:13px;' },
        h('span', {
          style: `display:inline-block;width:12px;height:12px;border-radius:2px;background:${slice.color};`,
        }),
        h('span', {}, `${slice.category} $${slice.total.toFixed(2)} (${slice.percentage}%)`)
      )
    )
  )

  return h('div', {}, svg, legend)
}

