import { createSSR } from 'plaited'
import { CATEGORIES, type Category, type ExpenseFilter } from './types'
import { loadExpenses, saveExpense, deleteExpense, filterExpenses } from './store'
import { computeMonthlySummary, getAvailableMonths } from './summary'
import { expensesToCsv } from './csv'
import { renderPage } from './views'

const isValidCategory = (val: unknown): val is Category =>
  typeof val === 'string' && CATEGORIES.includes(val as Category)

const isValidDate = (val: unknown): val is string =>
  typeof val === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(val)

const todayStr = (): string => new Date().toISOString().slice(0, 10)
const currentMonth = (): string => todayStr().slice(0, 7)

const parseFilter = (url: URL): { filter: ExpenseFilter; month: string } => {
  const start = url.searchParams.get('start') || undefined
  const end = url.searchParams.get('end') || undefined
  const category = url.searchParams.get('category') || undefined
  const month = url.searchParams.get('month') || currentMonth()

  return {
    filter: {
      dateRange: start || end ? { start, end } : undefined,
      category: isValidCategory(category) ? category : undefined,
    },
    month,
  }
}

const ssr = createSSR()

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)

    // POST /expenses — add new expense
    if (req.method === 'POST' && url.pathname === '/expenses') {
      const formData = await req.formData()
      const amount = parseFloat(formData.get('amount') as string)
      const category = formData.get('category') as string
      const date = formData.get('date') as string
      const notes = (formData.get('notes') as string) ?? ''

      if (isNaN(amount) || amount <= 0) {
        return new Response('Invalid amount', { status: 400 })
      }
      if (!isValidCategory(category)) {
        return new Response('Invalid category', { status: 400 })
      }
      if (!isValidDate(date)) {
        return new Response('Invalid date', { status: 400 })
      }

      await saveExpense({ amount, category, date, notes })
      return Response.redirect(req.headers.get('referer') || '/', 303)
    }

    // POST /expenses/:id/delete — delete expense
    if (req.method === 'POST' && url.pathname.match(/^\/expenses\/[^/]+\/delete$/)) {
      const id = url.pathname.split('/')[2]
      await deleteExpense(id)
      return Response.redirect(req.headers.get('referer') || '/', 303)
    }

    // GET /export — download CSV
    if (req.method === 'GET' && url.pathname === '/export') {
      const { filter } = parseFilter(url)
      const allExpenses = await loadExpenses()
      const filtered = filter.dateRange || filter.category
        ? filterExpenses(allExpenses, filter)
        : allExpenses
      const csv = expensesToCsv(filtered)

      return new Response(csv, {
        headers: {
          'Content-Type': 'text/csv',
          'Content-Disposition': `attachment; filename="expenses-${todayStr()}.csv"`,
        },
      })
    }

    // GET / — main page
    if (req.method === 'GET' && url.pathname === '/') {
      const { filter, month } = parseFilter(url)
      const allExpenses = await loadExpenses()
      const months = getAvailableMonths(allExpenses)
      const filtered = filter.dateRange || filter.category
        ? filterExpenses(allExpenses, filter)
        : allExpenses
      const summary = computeMonthlySummary(allExpenses, month)
      const today = todayStr()

      const html = ssr(renderPage(filtered, summary, filter, months, today))

      return new Response(`<!DOCTYPE html>${html}`, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Expense Logger running at http://localhost:${server.port}`)

