const mapFeedPost = (item: FeedViewPost): PostView => {
  const { post } = item;
  return {
    uri: post.uri,
    cid: post.cid,
    author: {
      did: post.author.did,
      handle: post.author.handle,
      displayName: post.author.displayName ?? post.author.handle,
      avatar: post.author.avatar,
    },
    text: post.record?.text ?? "",
    createdAt: post.record?.createdAt ?? new Date().toISOString(),
    likeCount: post.likeCount ?? 0,
    repostCount: post.repostCount ?? 0,
    replyCount: post.replyCount ?? 0,
    isLiked: !!post.viewer?.like,
    likeUri: post.viewer?.like,
  };
};

export const getTimeline = async (
  agent: BskyAgent,
  options: TimelineOptions = {}
): Promise<TimelineResponse> => {
  const { limit = 25, cursor } = options;

  const response = await agent.getTimeline({ limit, cursor });

  const posts = (response.data.feed as unknown as FeedViewPost[]).map(
    mapFeedPost
  );

  return {
    posts,
    cursor: response.data.cursor,
  };
};

export const getAuthorFeed = async (
  agent: BskyAgent,
  actor: string,
  options: TimelineOptions = {}
): Promise<TimelineResponse> => {
  const { limit = 25, cursor } = options;

  const response = await agent.getAuthorFeed({ actor, limit, cursor });

  const posts = (response.data.feed as unknown as FeedViewPost[]).map(
    mapFeedPost
  );

  return {
    posts,
    cursor: response.data.cursor,
  };
};

import { RichText } from "@atproto/api";
import type { BskyAgent } from "@atproto/api";

export type CreatePostResult = {
  uri: string;
  cid: string;
};

export const createPost = async (
  agent: BskyAgent,
  text: string
): Promise<CreatePostResult> => {
  const richText = new RichText({ text });
  await richText.detectFacets(agent);

  const response = await agent.post({
    text: richText.text,
    facets: richText.facets,
    createdAt: new Date().toISOString(),
  });

  return {
    uri: response.uri,
    cid: response.cid,
  };
};

export const deletePost = async (
  agent: BskyAgent,
