  agent: BskyAgent,
  uri: string,
  cid: string
): Promise<string> => {
  const response = await agent.like(uri, cid);
  return response.uri;
};

export const unlikePost = async (
  agent: BskyAgent,
  likeUri: string
): Promise<void> => {
  await agent.deleteLike(likeUri);
};

