  const likeStyle = post.isLiked ? styles.actionBtnLiked : styles.actionBtn;
  const likeLabel = post.isLiked ? "Unlike" : "Like";

  return h("article", { style: styles.post, "data-post-uri": post.uri }, [
    h("div", { style: styles.postHeader }, [
      avatarEl,
      h("div", { style: styles.authorInfo }, [
        h("span", { style: styles.displayName }, [post.author.displayName]),
        h("span", { style: styles.handleTime }, [
          `@${post.author.handle} · ${formatTimestamp(post.createdAt)}`,
        ]),
