          "p-trigger": "toggle-like",
          "data-uri": post.uri,
          "data-cid": post.cid,
          "data-like-uri": post.likeUri ?? "",
        },
        [`${post.isLiked ? "\u2764\uFE0F" : "\u{1F90D}"} ${post.likeCount}`]
