export type BlueskyClient = {
  agent: BskyAgent;
  session: SessionData | null;
  login: (identifier: string, password: string) => Promise<SessionData>;
  resumeSession: () => Promise<SessionData | null>;
  logout: () => Promise<void>;
  getTimeline: (options?: TimelineOptions) => Promise<TimelineResponse>;
  getAuthorFeed: (
    actor: string,
    options?: TimelineOptions
  ) => Promise<TimelineResponse>;
  createPost: (text: string) => Promise<{ uri: string; cid: string }>;
  deletePost: (postUri: string) => Promise<void>;
  likePost: (uri: string, cid: string) => Promise<string>;
  unlikePost: (likeUri: string) => Promise<void>;
  getProfile: (actor: string) => Promise<ProfileView>;
  followUser: (did: string) => Promise<string>;
  unfollowUser: (followUri: string) => Promise<void>;
  searchUsers: (query: string, limit?: number) => Promise<ProfileView[]>;
  renderFeed: (timeline: TimelineResponse) => ReturnType<typeof renderFeed>;
  renderPost: (post: PostView) => ReturnType<typeof renderPost>;
  renderProfile: (profile: ProfileView) => ReturnType<typeof renderProfile>;
  renderComposer: () => ReturnType<typeof renderComposer>;
  renderLoginForm: () => ReturnType<typeof renderLoginForm>;
};

export const createClient = async (
  serviceUrl = "https://bsky.social"
): Promise<BlueskyClient> => {
  const agent = new BskyAgent({ service: serviceUrl });

  const client: BlueskyClient = {
    agent,
    session: null,

    login: async (identifier: string, password: string) => {
      const sess = await login(agent, identifier, password);
      client.session = sess;
      return sess;
    },

    resumeSession: async () => {
      const sess = await resumeSession(agent);
      client.session = sess;
      return sess;
    },

    logout: async () => {
      await clearSession();
      client.session = null;
    },

    getTimeline: (options?: TimelineOptions) => getTimeline(agent, options),

    getAuthorFeed: (actor: string, options?: TimelineOptions) =>
      getAuthorFeed(agent, actor, options),

    createPost: (text: string) => createPost(agent, text),

    deletePost: (postUri: string) => deletePost(agent, postUri),

    likePost: (uri: string, cid: string) => likePost(agent, uri, cid),

    unlikePost: (likeUri: string) => unlikePost(agent, likeUri),

    getProfile: (actor: string) => getProfile(agent, actor),

    followUser: (did: string) => followUser(agent, did),

    unfollowUser: (followUri: string) => unfollowUser(agent, followUri),

    searchUsers: (query: string, limit?: number) =>
      searchUsers(agent, query, limit),

    renderFeed,
    renderPost,
    renderProfile,
    renderComposer,
    renderLoginForm,
  };

  return client;
};

