import { BskyAgent, RichText } from '@atproto/api'
import type {
  Credentials,
  SessionData,
  PostRecord,
  TimelineOptions,
  TimelineResult,
  CreatePostOptions,
  CreatePostResult,
  LikePostOptions,
  UnlikePostOptions,
  ProfileResult,
  GetProfileOptions,
  FollowOptions,
  UnfollowOptions,
  FollowResult,
} from './types'

const SESSION_PATH = 'data/session.json'

const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2))
}

const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH)
  if (!(await file.exists())) return null
  try {
    return await file.json()
  } catch {
    return null
  }
}

const clearSession = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH)
  if (await file.exists()) {
    await Bun.write(SESSION_PATH, '{}')
  }
}

export type BlueskyClient = {
  agent: BskyAgent
  login: (credentials: Credentials) => Promise<SessionData>
  resumeSession: () => Promise<boolean>
  logout: () => Promise<void>
  getTimeline: (options?: TimelineOptions) => Promise<TimelineResult>
  createPost: (options: CreatePostOptions) => Promise<CreatePostResult>
  likePost: (options: LikePostOptions) => Promise<{ uri: string }>
  unlikePost: (options: UnlikePostOptions) => Promise<void>
  getProfile: (options: GetProfileOptions) => Promise<ProfileResult>
  follow: (options: FollowOptions) => Promise<FollowResult>
  unfollow: (options: UnfollowOptions) => Promise<void>
  getAuthorFeed: (options: GetProfileOptions & TimelineOptions) => Promise<TimelineResult>
}

export const createBlueskyClient = (): BlueskyClient => {
  const agent = new BskyAgent({ service: 'https://bsky.social' })

  const login = async (credentials: Credentials): Promise<SessionData> => {
    const response = await agent.login({
      identifier: credentials.identifier,
      password: credentials.password,
    })

    const session: SessionData = {
      did: response.data.did,
      handle: response.data.handle,
      accessJwt: response.data.accessJwt,
      refreshJwt: response.data.refreshJwt,
    }

    await saveSession(session)
    return session
  }

  const resumeSession = async (): Promise<boolean> => {
    const session = await loadSession()
    if (!session || !session.accessJwt) return false

    try {
      await agent.resumeSession({
        did: session.did,
        handle: session.handle,
        accessJwt: session.accessJwt,
        refreshJwt: session.refreshJwt,
        active: true,
      })
      return true
    } catch {
      await clearSession()
      return false
    }
  }

  const logout = async (): Promise<void> => {
    await clearSession()
  }

  const mapPost = (feedItem: { post: any }): PostRecord => {
    const { post } = feedItem
    const record = post.record as { text: string; createdAt: string }
    return {
      uri: post.uri,
      cid: post.cid,
      author: {
        did: post.author.did,
        handle: post.author.handle,
        displayName: post.author.displayName ?? post.author.handle,
        avatar: post.author.avatar,
      },
      text: record.text,
      createdAt: record.createdAt,
      likeCount: post.likeCount ?? 0,
      replyCount: post.replyCount ?? 0,
      repostCount: post.repostCount ?? 0,
      isLiked: !!post.viewer?.like,
      likeUri: post.viewer?.like,
    }
  }

  const getTimeline = async (options: TimelineOptions = {}): Promise<TimelineResult> => {
    const response = await agent.getTimeline({
      limit: options.limit ?? 25,
      cursor: options.cursor,
    })

    return {
      posts: response.data.feed.map(mapPost),
      cursor: response.data.cursor,
    }
  }

  const createPost = async (options: CreatePostOptions): Promise<CreatePostResult> => {
    const rt = new RichText({ text: options.text })
    await rt.detectFacets(agent)

    const response = await agent.post({
      text: rt.text,
      facets: rt.facets,
      createdAt: new Date().toISOString(),
    })

    return {
      uri: response.uri,
      cid: response.cid,
    }
  }

  const likePost = async (options: LikePostOptions): Promise<{ uri: string }> => {
    const response = await agent.like(options.uri, options.cid)
    return { uri: response.uri }
  }

  const unlikePost = async (options: UnlikePostOptions): Promise<void> => {
    await agent.deleteLike(options.likeUri)
  }

  const getProfile = async (options: GetProfileOptions): Promise<ProfileResult> => {
    const response = await agent.getProfile({ actor: options.actor })
    const profile = response.data

    return {
      did: profile.did,
      handle: profile.handle,
      displayName: profile.displayName ?? profile.handle,
      description: profile.description ?? '',
      avatar: profile.avatar,
      banner: profile.banner,
      followersCount: profile.followersCount ?? 0,
      followsCount: profile.followsCount ?? 0,
      postsCount: profile.postsCount ?? 0,
      isFollowing: !!profile.viewer?.following,
      followUri: profile.viewer?.following,
      isFollowedBy: !!profile.viewer?.followedBy,
    }
  }

  const follow = async (options: FollowOptions): Promise<FollowResult> => {
    const response = await agent.follow(options.did)
    return { uri: response.uri }
  }

  const unfollow = async (options: UnfollowOptions): Promise<void> => {
    await agent.deleteFollow(options.followUri)
  }

  const getAuthorFeed = async (
    options: GetProfileOptions & TimelineOptions
  ): Promise<TimelineResult> => {
    const response = await agent.getAuthorFeed({
      actor: options.actor,
      limit: options.limit ?? 25,
      cursor: options.cursor,
    })

    return {
      posts: response.data.feed.map(mapPost),
      cursor: response.data.cursor,
    }
  }

  return {
    agent,
    login,
    resumeSession,
    logout,
    getTimeline,
    createPost,
    likePost,
    unlikePost,
    getProfile,
    follow,
    unfollow,
    getAuthorFeed,
  }
}

