import { createBlueskyClient } from './client'
import type { BlueskyClient } from './client'
import {
  renderLoginForm,
  renderTimeline,
  renderProfile,
  renderError,
} from './views'
import type {
  Credentials,
  TimelineResult,
  ProfileResult,
} from './types'

export { createBlueskyClient } from './client'
export type { BlueskyClient } from './client'

type RouteHandler = (params: Record<string, string>) => Promise<string>

type AppState = {
  client: BlueskyClient
  handle: string
  isAuthenticated: boolean
}

const state: AppState = {
  client: createBlueskyClient(),
  handle: '',
  isAuthenticated: false,
}

const ensureAuth = async (): Promise<boolean> => {
  if (state.isAuthenticated) return true
  const resumed = await state.client.resumeSession()
  if (resumed && state.client.agent.session) {
    state.handle = state.client.agent.session.handle
    state.isAuthenticated = true
    return true
  }
  return false
}

const routes: Record<string, RouteHandler> = {
  login: async (params) => {
    const { identifier, password } = params
    if (!identifier || !password) {
      return renderLoginForm()
    }

    try {
      const credentials: Credentials = { identifier, password }
      const session = await state.client.login(credentials)
      state.handle = session.handle
      state.isAuthenticated = true
      const timeline = await state.client.getTimeline({ limit: 25 })
      return renderTimeline(timeline, state.handle)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Login failed'
      return renderLoginForm(message)
    }
  },

  logout: async () => {
    await state.client.logout()
    state.isAuthenticated = false
    state.handle = ''
    return renderLoginForm()
  },

  timeline: async (params) => {
    if (!(await ensureAuth())) return renderLoginForm()

    try {
      const timeline = await state.client.getTimeline({
        limit: Number(params.limit) || 25,
        cursor: params.cursor || undefined,
      })
      return renderTimeline(timeline, state.handle)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Failed to load timeline'
      return renderError(message)
    }
  },

  createPost: async (params) => {
    if (!(await ensureAuth())) return renderLoginForm()

    try {
      const { text } = params
      if (!text || text.trim().length === 0) {
        return renderError('Post text cannot be empty')
      }
      if (text.length > 300) {
        return renderError('Post exceeds 300 character limit')
      }

      await state.client.createPost({ text: text.trim() })
      const timeline = await state.client.getTimeline({ limit: 25 })
      return renderTimeline(timeline, state.handle)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Failed to create post'
      return renderError(message)
    }
  },

  like: async (params) => {
    if (!(await ensureAuth())) return renderLoginForm()

    try {
      const { uri, cid } = params
      await state.client.likePost({ uri, cid })
      return JSON.stringify({ success: true, action: 'liked' })
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Failed to like post'
      return JSON.stringify({ success: false, error: message })
    }
  },

  unlike: async (params) => {
    if (!(await ensureAuth())) return renderLoginForm()

    try {
      const { likeUri } = params
      await state.client.unlikePost({ likeUri })
      return JSON.stringify({ success: true, action: 'unliked' })
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Failed to unlike post'
      return JSON.stringify({ success: false, error: message })
    }
  },

  profile: async (params) => {
    if (!(await ensureAuth())) return renderLoginForm()

    try {
      const { actor } = params
      const [profile, authorFeed] = await Promise.all([
        state.client.getProfile({ actor }),
        state.client.getAuthorFeed({
          actor,
          limit: Number(params.limit) || 25,
          cursor: params.cursor || undefined,
        }),
      ])
      return renderProfile(profile, authorFeed, state.handle)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Failed to load profile'
      return renderError(message)
    }
  },

  follow: async (params) => {
    if (!(await ensureAuth())) return renderLoginForm()

    try {
      const { did } = params
      const result = await state.client.follow({ did })
      return JSON.stringify({ success: true, uri: result.uri })
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Failed to follow'
      return JSON.stringify({ success: false, error: message })
    }
  },

  unfollow: async (params) => {
    if (!(await ensureAuth())) return renderLoginForm()

    try {
      const { followUri } = params
      await state.client.unfollow({ followUri })
      return JSON.stringify({ success: true, action: 'unfollowed' })
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Failed to unfollow'
      return JSON.stringify({ success: false, error: message })
    }
  },
}

export const handleRoute = async (
  route: string,
  params: Record<string, string> = {}
): Promise<string> => {
  const handler = routes[route]
  if (!handler) {
    return renderError(`Unknown route: ${route}`)
  }
  return handler(params)
}

export const init = async (): Promise<string> => {
  const authenticated = await ensureAuth()
  if (authenticated) {
    const timeline = await state.client.getTimeline({ limit: 25 })
    return renderTimeline(timeline, state.handle)
  }
  return renderLoginForm()
}

{
  "name": "@node/bluesky-client",
  "version": "1.0.0",
  "description": "Bluesky social client for viewing feeds, posting, and managing follows",
  "main": "src/index.ts",
  "dependencies": {
    "@atproto/api": "^0.13.0"
  },
  "modnet": {
    "contentType": "social",
    "structure": "feed",
    "mechanics": ["post", "like", "follow"],
    "boundary": "none",
    "scale": 2
  }
}

export type SessionData = {
  did: string;
  handle: string;
  accessJwt: string;
  refreshJwt: string;
  service: string;
};

export type PostAuthor = {
  did: string;
  handle: string;
  displayName: string;
  avatar: string | undefined;
};

export type PostView = {
  uri: string;
  cid: string;
  author: PostAuthor;
  text: string;
  createdAt: string;
  likeCount: number;
  repostCount: number;
  replyCount: number;
  isLiked: boolean;
  likeUri: string | undefined;
};

export type ProfileView = {
  did: string;
  handle: string;
  displayName: string;
  description: string;
  avatar: string | undefined;
  banner: string | undefined;
  followersCount: number;
  followsCount: number;
  postsCount: number;
  isFollowing: boolean;
  followUri: string | undefined;
};

export type FeedPage = {
  posts: PostView[];
  cursor: string | undefined;
};

export type AuthCredentials = {
  identifier: string;
  password: string;
  service?: string;
};

import { BskyAgent } from '@atproto/api';
import type { AuthCredentials, SessionData } from './types';

const SESSION_PATH = 'data/session.json';
const DEFAULT_SERVICE = 'https://bsky.social';

let agent: BskyAgent | null = null;

const getAgent = (): BskyAgent => {
  if (!agent) {
    throw new Error('Not authenticated. Call login() first.');
  }
  return agent;
};

const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2));
};

const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH);
  if (!(await file.exists())) return null;
  try {
    return (await file.json()) as SessionData;
  } catch {
    return null;
  }
};

const clearSession = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH);
  if (await file.exists()) {
    await Bun.write(SESSION_PATH, '{}');
  }
};

const login = async (credentials: AuthCredentials): Promise<SessionData> => {
  const service = credentials.service ?? DEFAULT_SERVICE;
  agent = new BskyAgent({ service });

  const response = await agent.login({
    identifier: credentials.identifier,
    password: credentials.password,
  });

  const session: SessionData = {
    did: response.data.did,
    handle: response.data.handle,
    accessJwt: response.data.accessJwt,
    refreshJwt: response.data.refreshJwt,
    service,
  };

  await saveSession(session);
  return session;
};

const resumeSession = async (): Promise<SessionData | null> => {
  const saved = await loadSession();
  if (!saved || !saved.accessJwt) return null;

  agent = new BskyAgent({ service: saved.service });

  try {
    await agent.resumeSession({
      did: saved.did,
      handle: saved.handle,
      accessJwt: saved.accessJwt,
      refreshJwt: saved.refreshJwt,
      active: true,
    });
    return saved;
  } catch {
    agent = null;
    await clearSession();
    return null;
  }
};

const logout = async (): Promise<void> => {
  agent = null;
  await clearSession();
};

export { getAgent, login, resumeSession, logout };

import type { AppBskyFeedDefs } from '@atproto/api';
import { getAgent } from './auth';
import type { FeedPage, PostView } from './types';

const mapPost = (feedItem: AppBskyFeedDefs.FeedViewPost): PostView | null => {
  const post = feedItem.post;
  const record = post.record as { text?: string; createdAt?: string } | undefined;

  if (!record?.text) return null;

  const viewer = post.viewer ?? {};

  return {
    uri: post.uri,
    cid: post.cid,
    author: {
      did: post.author.did,
      handle: post.author.handle,
      displayName: post.author.displayName ?? post.author.handle,
      avatar: post.author.avatar,
    },
    text: record.text,
    createdAt: record.createdAt ?? new Date().toISOString(),
    likeCount: post.likeCount ?? 0,
    repostCount: post.repostCount ?? 0,
    replyCount: post.replyCount ?? 0,
    isLiked: !!viewer.like,
    likeUri: viewer.like,
  };
};

const getTimeline = async (cursor?: string, limit = 25): Promise<FeedPage> => {
  const agent = getAgent();
  const response = await agent.getTimeline({ cursor, limit });

  const posts = response.data.feed
    .map(mapPost)
    .filter((p): p is PostView => p !== null);

  return {
    posts,
    cursor: response.data.cursor,
  };
};

const getAuthorFeed = async (
  actor: string,
  cursor?: string,
  limit = 25
): Promise<FeedPage> => {
  const agent = getAgent();
  const response = await agent.getAuthorFeed({ actor, cursor, limit });

  const posts = response.data.feed
    .map(mapPost)
    .filter((p): p is PostView => p !== null);

  return {
    posts,
    cursor: response.data.cursor,
  };
};

export { getTimeline, getAuthorFeed };

import { RichText } from '@atproto/api';
import { getAgent } from './auth';

const MAX_POST_LENGTH = 300;

type CreatePostResult = {
  uri: string;
  cid: string;
};

const createPost = async (text: string): Promise<CreatePostResult> => {
  if (text.length === 0) {
    throw new Error('Post text cannot be empty.');
  }
  if (text.length > MAX_POST_LENGTH) {
    throw new Error(`Post text exceeds ${MAX_POST_LENGTH} characters.`);
  }

  const agent = getAgent();

  const richText = new RichText({ text });
  await richText.detectFacets(agent);

  const response = await agent.post({
    text: richText.text,
    facets: richText.facets,
    createdAt: new Date().toISOString(),
  });

  return { uri: response.uri, cid: response.cid };
};

const deletePost = async (uri: string): Promise<void> => {
  const agent = getAgent();
  await agent.deletePost(uri);
};

const likePost = async (uri: string, cid: string): Promise<string> => {
  const agent = getAgent();
  const response = await agent.like(uri, cid);
  return response.uri;
};

const unlikePost = async (likeUri: string): Promise<void> => {
  const agent = getAgent();
  await agent.deleteLike(likeUri);
};

export { createPost, deletePost, likePost, unlikePost, MAX_POST_LENGTH };

