import { login, resumeSession, logout, getAgent } from './auth';
import { getTimeline, getAuthorFeed } from './feed';
import { createPost, deletePost, likePost, unlikePost, MAX_POST_LENGTH } from './posts';
import { getProfile, followUser, unfollowUser } from './profile';
import { renderFeed, renderProfile, renderLoginForm, renderToString } from './ui';
import type { AuthCredentials, SessionData, PostView, ProfileView, FeedPage } from './types';

type AppState = {
  session: SessionData | null;
  currentView: 'login' | 'feed' | 'profile';
  feedPage: FeedPage | null;
  currentProfile: ProfileView | null;
  error: string | undefined;
};

const state: AppState = {
  session: null,
  currentView: 'login',
  feedPage: null,
  currentProfile: null,
  error: undefined,
};

const handleLogin = async (credentials: AuthCredentials): Promise<string> => {
  try {
    state.session = await login(credentials);
    state.currentView = 'feed';
    state.error = undefined;
    return renderTimeline();
  } catch (err) {
    state.error = err instanceof Error ? err.message : 'Login failed';
    return renderToString(renderLoginForm(state.error));
  }
};

const handleResume = async (): Promise<string> => {
  const session = await resumeSession();
  if (session) {
    state.session = session;
    state.currentView = 'feed';
    return renderTimeline();
  }
  return renderToString(renderLoginForm());
};

const handleLogout = async (): Promise<string> => {
  await logout();
  state.session = null;
  state.currentView = 'login';
  state.feedPage = null;
  state.currentProfile = null;
  return renderToString(renderLoginForm());
};

const renderTimeline = async (cursor?: string): Promise<string> => {
  const feedPage = await getTimeline(cursor);

  if (cursor && state.feedPage) {
    state.feedPage = {
      posts: [...state.feedPage.posts, ...feedPage.posts],
      cursor: feedPage.cursor,
    };
  } else {
    state.feedPage = feedPage;
  }

  state.currentView = 'feed';
  return renderToString(renderFeed(state.feedPage, state.session?.handle ?? ''));
};

const handleCreatePost = async (text: string): Promise<string> => {
  await createPost(text);
  return renderTimeline();
};

const handleToggleLike = async (
  uri: string,
  cid: string,
  isLiked: boolean,
  likeUri?: string
): Promise<{ isLiked: boolean; likeUri: string | undefined; likeCount: number }> => {
  if (isLiked && likeUri) {
    await unlikePost(likeUri);
    const post = state.feedPage?.posts.find((p) => p.uri === uri);
    if (post) {
      post.isLiked = false;
      post.likeUri = undefined;
      post.likeCount = Math.max(0, post.likeCount - 1);
    }
    return { isLiked: false, likeUri: undefined, likeCount: post?.likeCount ?? 0 };
  } else {
    const newLikeUri = await likePost(uri, cid);
    const post = state.feedPage?.posts.find((p) => p.uri === uri);
    if (post) {
      post.isLiked = true;
      post.likeUri = newLikeUri;
      post.likeCount += 1;
    }
    return { isLiked: true, likeUri: newLikeUri, likeCount: post?.likeCount ?? 0 };
  }
};

const handleViewProfile = async (actor: string): Promise<string> => {
  const profile = await getProfile(actor);
  state.currentProfile = profile;
  state.currentView = 'profile';
  return renderToString(renderProfile(profile));
};

const handleToggleFollow = async (
  did: string,
  isFollowing: boolean,
  followUri?: string
): Promise<{ isFollowing: boolean; followUri: string | undefined }> => {
  if (isFollowing && followUri) {
    await unfollowUser(followUri);
    if (state.currentProfile) {
      state.currentProfile.isFollowing = false;
      state.currentProfile.followUri = undefined;
      state.currentProfile.followersCount = Math.max(0, state.currentProfile.followersCount - 1);
    }
    return { isFollowing: false, followUri: undefined };
  } else {
    const newFollowUri = await followUser(did);
    if (state.currentProfile) {
      state.currentProfile.isFollowing = true;
      state.currentProfile.followUri = newFollowUri;
      state.currentProfile.followersCount += 1;
    }
    return { isFollowing: true, followUri: newFollowUri };
  }
};

const handleDeletePost = async (uri: string): Promise<string> => {
  await deletePost(uri);
  return renderTimeline();
};

const handleViewAuthorFeed = async (actor: string, cursor?: string): Promise<FeedPage> => {
  return getAuthorFeed(actor, cursor);
};

export {
  handleLogin,
  handleResume,
  handleLogout,
  renderTimeline,
  handleCreatePost,
  handleToggleLike,
  handleViewProfile,
  handleToggleFollow,
  handleDeletePost,
  handleViewAuthorFeed,
  MAX_POST_LENGTH,
};

export type { AuthCredentials, SessionData, PostView, ProfileView, FeedPage };

