  "name": "@node/inventory-manager",
  "version": "1.0.0",
  "description": "Inventory tracking with low-stock alerts, barcode input, bulk import, and search",
  "modnet": {
    "contentType": "logistics",
    "structure": "collection",
    "mechanics": ["sort", "filter", "track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

import type { InventoryItem, NewItemInput, UpdateItemInput, SearchParams } from './types'

const DATA_PATH = `${import.meta.dir}/data/inventory.json`

const generateId = (): string => crypto.randomUUID()

const readItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

const writeItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

export const getAllItems = async (params?: SearchParams): Promise<InventoryItem[]> => {
  let items = await readItems()

  if (params?.q) {
    const query = params.q.toLowerCase()
    items = items.filter(
      (item) =>
        item.name.toLowerCase().includes(query) ||
        item.sku.toLowerCase().includes(query)
    )
  }

  if (params?.category) {
    const cat = params.category.toLowerCase()
    items = items.filter((item) => item.category.toLowerCase() === cat)
  }

  const sortBy = params?.sortBy ?? 'name'
  const order = params?.order ?? 'asc'
  items.sort((a, b) => {
    const aVal = a[sortBy]
    const bVal = b[sortBy]
    if (typeof aVal === 'string' && typeof bVal === 'string') {
      return order === 'asc' ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal)
    }
    if (typeof aVal === 'number' && typeof bVal === 'number') {
      return order === 'asc' ? aVal - bVal : bVal - aVal
    }
    return 0
  })

  return items
}

export const getItemById = async (id: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.id === id)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.sku.toLowerCase() === sku.toLowerCase())
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const items = await readItems()
  return items
    .filter((item) => item.quantity <= item.reorderThreshold)
    .sort((a, b) => a.quantity - b.quantity)
}

export const addItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const items = await readItems()
  const existing = items.find((item) => item.sku.toLowerCase() === input.sku.toLowerCase())
  if (existing) throw new Error(`Item with SKU "${input.sku}" already exists`)

  const now = new Date().toISOString()
  const newItem: InventoryItem = {
    id: generateId(),
    ...input,
    createdAt: now,
    updatedAt: now,
  }

  items.push(newItem)
  await writeItems(items)
  return newItem
}

export const updateItem = async (id: string, input: UpdateItemInput): Promise<InventoryItem> => {
  const items = await readItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) throw new Error(`Item with id "${id}" not found`)

  const updated: InventoryItem = {
    ...items[index],
    ...input,
    updatedAt: new Date().toISOString(),
  }

  items[index] = updated
  await writeItems(items)
  return updated
}

export const deleteItem = async (id: string): Promise<void> => {
  const items = await readItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) throw new Error(`Item with id "${id}" not found`)

  items.splice(index, 1)
  await writeItems(items)
}

export const bulkImport = async (inputs: NewItemInput[]): Promise<{ added: number; skipped: string[] }> => {
  const items = await readItems()
  const existingSkus = new Set(items.map((item) => item.sku.toLowerCase()))
  const skipped: string[] = []
  const now = new Date().toISOString()

  for (const input of inputs) {
    if (existingSkus.has(input.sku.toLowerCase())) {
      skipped.push(input.sku)
      continue
    }
    items.push({
      id: generateId(),
      ...input,
      createdAt: now,
      updatedAt: now,
    })
    existingSkus.add(input.sku.toLowerCase())
  }

  await writeItems(items)
  return { added: inputs.length - skipped.length, skipped }
}

export const getCategories = async (): Promise<string[]> => {
  const items = await readItems()
  return [...new Set(items.map((item) => item.category))].sort()
}

