import {
  getAllItems,
  getItemById,
  getItemBySku,
  getLowStockItems,
  addItem,
  updateItem,
  deleteItem,
  bulkImport,
  getCategories,
} from './store'
import { renderDashboard, renderItemDetail } from './ui'
import type { NewItemInput } from './types'

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (content: unknown) =>
  new Response(String(content), {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // Dashboard
  if (path === '/' && method === 'GET') {
    const q = url.searchParams.get('q') ?? undefined
    const category = url.searchParams.get('category') ?? undefined
    const showAdd = url.searchParams.has('add')
    const showBulk = url.searchParams.has('bulk')
    const sortBy = (url.searchParams.get('sortBy') as 'name' | 'quantity' | 'sku') ?? undefined
    const order = (url.searchParams.get('order') as 'asc' | 'desc') ?? undefined

    const [items, lowStockItems, categories] = await Promise.all([
      getAllItems({ q, category, sortBy, order }),
      getLowStockItems(),
      getCategories(),
    ])

    const page = renderDashboard(items, lowStockItems, categories, q, category, showAdd, showBulk)
    return html(`<!DOCTYPE html>${page}`)
  }

  // List items (JSON API)
  if (path === '/items' && method === 'GET') {
    const q = url.searchParams.get('q') ?? undefined
    const category = url.searchParams.get('category') ?? undefined
    const items = await getAllItems({ q, category })
    return json(items)
  }

  // Low stock items
  if (path === '/items/low-stock' && method === 'GET') {
    const items = await getLowStockItems()
    return json(items)
  }

  // Barcode lookup
  const barcodeMatch = path.match(/^\/items\/barcode\/(.+)$/)
  if (barcodeMatch && method === 'GET') {
    const sku = decodeURIComponent(barcodeMatch[1])
    const item = await getItemBySku(sku)
    if (!item) return json({ error: `No item found with SKU "${sku}"` }, 404)
    return json(item)
  }

  // Bulk import
  if (path === '/items/bulk' && method === 'POST') {
    const contentType = req.headers.get('content-type') ?? ''
    let items: NewItemInput[]

    if (contentType.includes('application/json')) {
      const body = await req.json()
      items = Array.isArray(body) ? body : body.items
    } else {
      // Form submission - parse textarea content
      const formData = await req.formData()
      const rawItems = formData.get('items') as string
      items = JSON.parse(rawItems)
    }

    if (!Array.isArray(items)) {
      return json({ error: 'Expected an array of items' }, 400)
    }

    for (const item of items) {
      if (!item.name || !item.sku || item.quantity == null || !item.category || item.reorderThreshold == null) {
        return json({ error: 'Each item must have name, sku, quantity, category, and reorderThreshold' }, 400)
      }
    }

    const result = await bulkImport(items)

    if (contentType.includes('application/json')) {
      return json(result)
    }
    // Redirect back to dashboard for form submissions
    return Response.redirect(new URL('/', url.origin).toString(), 303)
  }

  // Add item
  if (path === '/items' && method === 'POST') {
    const contentType = req.headers.get('content-type') ?? ''
    let input: NewItemInput

    if (contentType.includes('application/json')) {
      input = await req.json()
    } else {
      const formData = await req.formData()
      input = {
        name: formData.get('name') as string,
        sku: formData.get('sku') as string,
        quantity: Number(formData.get('quantity')),
        category: formData.get('category') as string,
        reorderThreshold: Number(formData.get('reorderThreshold')),
      }
    }

    if (!input.name || !input.sku || input.quantity == null || !input.category || input.reorderThreshold == null) {
      return json({ error: 'Missing required fields: name, sku, quantity, category, reorderThreshold' }, 400)
    }

    try {
      const item = await addItem(input)
      if (contentType.includes('application/json')) {
        return json(item, 201)
      }
      return Response.redirect(new URL('/', url.origin).toString(), 303)
    } catch (err) {
      return json({ error: (err as Error).message }, 409)
    }
  }

  // Get single item
  const itemIdMatch = path.match(/^\/items\/([a-f0-9-]+)$/)
  if (itemIdMatch && method === 'GET') {
    const item = await getItemById(itemIdMatch[1])
    if (!item) return json({ error: 'Item not found' }, 404)

    const accept = req.headers.get('accept') ?? ''
    if (accept.includes('text/html')) {
      const page = renderItemDetail(item)
      return html(`<!DOCTYPE html>${page}`)
    }
    return json(item)
  }

  // Update item
  if (itemIdMatch && method === 'PUT') {
    try {
      const input = await req.json()
      const item = await updateItem(itemIdMatch[1], input)
      return json(item)
    } catch (err) {
      return json({ error: (err as Error).message }, 404)
    }
  }

  // Delete item
  if (itemIdMatch && method === 'DELETE') {
    try {
      await deleteItem(itemIdMatch[1])
      return json({ ok: true })
    } catch (err) {
      return json({ error: (err as Error).message }, 404)
    }
  }

  return json({ error: 'Not found' }, 404)
}

