import type { InventoryItem, NewItemInput, UpdateItemInput, BulkImportResult } from './types'

const DATA_PATH = `${import.meta.dir}/data/items.json`

const readItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

const generateId = (): string => crypto.randomUUID()

export const getAllItems = async (search?: string): Promise<InventoryItem[]> => {
  const items = await readItems()
  if (!search) return items
  const q = search.toLowerCase()
  return items.filter(
    (item) => item.name.toLowerCase().includes(q) || item.sku.toLowerCase().includes(q)
  )
}

export const getItemById = async (id: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.id === id)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.sku.toLowerCase() === sku.toLowerCase())
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const items = await readItems()
  return items.filter((item) => item.quantity <= item.reorderThreshold)
}

export const addItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const items = await readItems()
  const existing = items.find((item) => item.sku.toLowerCase() === input.sku.toLowerCase())
  if (existing) throw new Error(`Item with SKU "${input.sku}" already exists`)

  const now = new Date().toISOString()
  const newItem: InventoryItem = {
    id: generateId(),
    ...input,
    createdAt: now,
    updatedAt: now,
  }
  items.push(newItem)
  await writeItems(items)
  return newItem
}

export const updateItem = async (id: string, input: UpdateItemInput): Promise<InventoryItem> => {
  const items = await readItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) throw new Error(`Item with id "${id}" not found`)

  if (input.sku) {
    const duplicate = items.find(
      (item) => item.sku.toLowerCase() === input.sku!.toLowerCase() && item.id !== id
    )
    if (duplicate) throw new Error(`Another item with SKU "${input.sku}" already exists`)
  }

  items[index] = {
    ...items[index],
    ...input,
    updatedAt: new Date().toISOString(),
  }
  await writeItems(items)
  return items[index]
}

export const deleteItem = async (id: string): Promise<void> => {
  const items = await readItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) throw new Error(`Item with id "${id}" not found`)
  items.splice(index, 1)
  await writeItems(items)
}

export const bulkImport = async (data: unknown): Promise<BulkImportResult> => {
  if (!Array.isArray(data)) throw new Error('Import data must be a JSON array')

  const items = await readItems()
  const result: BulkImportResult = { imported: 0, skipped: 0, errors: [] }
  const requiredFields = ['name', 'sku', 'quantity', 'category', 'reorderThreshold'] as const

  for (let i = 0; i < data.length; i++) {
    const entry = data[i]
    const missing = requiredFields.filter((f) => entry[f] === undefined || entry[f] === null)

    if (missing.length > 0) {
      result.errors.push(`Row ${i + 1}: missing fields: ${missing.join(', ')}`)
      result.skipped++
      continue
    }

    if (typeof entry.quantity !== 'number' || typeof entry.reorderThreshold !== 'number') {
      result.errors.push(`Row ${i + 1}: quantity and reorderThreshold must be numbers`)
      result.skipped++
      continue
    }

    const duplicate = items.find(
      (item) => item.sku.toLowerCase() === String(entry.sku).toLowerCase()
    )
    if (duplicate) {
      result.errors.push(`Row ${i + 1}: SKU "${entry.sku}" already exists`)
      result.skipped++
      continue
    }

    const now = new Date().toISOString()
    items.push({
      id: generateId(),
      name: String(entry.name),
      sku: String(entry.sku),
      quantity: entry.quantity,
      category: String(entry.category),
      reorderThreshold: entry.reorderThreshold,
      createdAt: now,
      updatedAt: now,
    })
    result.imported++
  }

  await writeItems(items)
  return result
}

