import { getAllItems, getLowStockItems, addItem, updateItem, deleteItem, bulkImport, getItemBySku } from './store'
import { renderDashboard, renderMessage, renderBarcodeLookup } from './ui'
import type { NewItemInput } from './types'

const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  params.forEach((value, key) => {
    result[key] = value
  })
  return result
}

const html = (body: string, status = 200) =>
  new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data, null, 2), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const redirect = (path: string) =>
  new Response(null, { status: 303, headers: { Location: path } })

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // Dashboard
    if (pathname === '/' && method === 'GET') {
      const search = url.searchParams.get('search') ?? undefined
      const [items, lowStock] = await Promise.all([getAllItems(search), getLowStockItems()])
      return html(renderDashboard(items, lowStock, search))
    }

    // Barcode / SKU lookup
    if (pathname === '/barcode-lookup' && method === 'GET') {
      const sku = url.searchParams.get('sku') ?? ''
      if (!sku) return redirect('/')
      const item = await getItemBySku(sku)
      return html(renderBarcodeLookup(item, sku))
    }

    // API: list items as JSON
    if (pathname === '/api/items' && method === 'GET') {
      const search = url.searchParams.get('search') ?? undefined
      const items = await getAllItems(search)
      return json(items)
    }

    // API: barcode lookup JSON
    if (pathname.startsWith('/api/items/barcode/') && method === 'GET') {
      const sku = pathname.split('/api/items/barcode/')[1]
      const item = await getItemBySku(decodeURIComponent(sku))
      if (!item) return json({ error: 'Item not found' }, 404)
      return json(item)
    }

    // Add item (form POST)
    if (pathname === '/items' && method === 'POST') {
      const contentType = req.headers.get('content-type') ?? ''

      try {
        let input: NewItemInput

        if (contentType.includes('application/json')) {
          input = await req.json()
        } else {
          const body = await parseFormBody(req)
          input = {
            name: body.name,
            sku: body.sku,
            quantity: parseInt(body.quantity, 10),
            category: body.category,
            reorderThreshold: parseInt(body.reorderThreshold, 10),
          }
        }

        if (!input.name || !input.sku || isNaN(input.quantity) || !input.category || isNaN(input.reorderThreshold)) {
          if (contentType.includes('application/json')) {
            return json({ error: 'Missing required fields' }, 400)
          }
          return html(renderMessage('Error', 'All fields are required and quantity/threshold must be numbers.', true), 400)
        }

        const item = await addItem(input)

        if (contentType.includes('application/json')) {
          return json(item, 201)
        }
        return redirect('/')
      } catch (err) {
        const msg = err instanceof Error ? err.message : 'Unknown error'
        if (contentType.includes('application/json')) {
          return json({ error: msg }, 400)
        }
        return html(renderMessage('Error', msg, true), 400)
      }
    }

    // Update item (JSON API)
    if (pathname.startsWith('/items/') && method === 'PUT') {
      const id = pathname.split('/items/')[1]
      try {
        const body = await req.json()
        const updated = await updateItem(id, body)
        return json(updated)
      } catch (err) {
        const msg = err instanceof Error ? err.message : 'Unknown error'
        return json({ error: msg }, 400)
      }
    }

    // Delete item (form POST for HTML, DELETE for API)
    if (pathname.match(/^\/items\/[^/]+\/delete$/) && method === 'POST') {
      const id = pathname.split('/items/')[1].replace('/delete', '')
      try {
        await deleteItem(id)
        return redirect('/')
      } catch (err) {
        const msg = err instanceof Error ? err.message : 'Unknown error'
        return html(renderMessage('Error', msg, true), 400)
      }
    }

    if (pathname.startsWith('/items/') && method === 'DELETE') {
      const id = pathname.split('/items/')[1]
      try {
        await deleteItem(id)
        return json({ success: true })
      } catch (err) {
        const msg = err instanceof Error ? err.message : 'Unknown error'
        return json({ error: msg }, 400)
      }
    }

    // Bulk import
    if (pathname === '/items/bulk' && method === 'POST') {
      const contentType = req.headers.get('content-type') ?? ''

      try {
        let data: unknown

        if (contentType.includes('application/json')) {
          data = await req.json()
        } else {
          const body = await parseFormBody(req)
          data = JSON.parse(body.jsonData)
        }

        const result = await bulkImport(data)
        const message = [
          `Imported: ${result.imported}`,
          `Skipped: ${result.skipped}`,
          ...(result.errors.length > 0 ? ['', 'Errors:', ...result.errors] : []),
        ].join('\n')

        if (contentType.includes('application/json')) {
          return json(result)
        }
        return html(renderMessage('Import Complete', message, result.errors.length > 0))
      } catch (err) {
        const msg = err instanceof Error ? err.message : 'Invalid JSON'
        if (contentType.includes('application/json')) {
          return json({ error: msg }, 400)
        }
        return html(renderMessage('Import Error', msg, true), 400)
      }
    }

    // API: low stock items
    if (pathname === '/api/low-stock' && method === 'GET') {
      const items = await getLowStockItems()
      return json(items)
    }

    return html(renderMessage('Not Found', 'The page you requested does not exist.', true), 404)
  },
})

