export type InventoryItem = {
  sku: string;
  name: string;
  quantity: number;
  category: string;
  reorderThreshold: number;
  createdAt: string;
  updatedAt: string;
};

export type DashboardStats = {
  totalItems: number;
  totalQuantity: number;
  lowStockItems: InventoryItem[];
  categories: Record<string, number>;
};

export type ImportResult = {
  created: number;
  updated: number;
  errors: string[];
};

import type { InventoryItem } from "./types";

const DATA_PATH = "./data/inventory.jsonl";

const readAllItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  return text
    .split("\n")
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as InventoryItem);
};

const writeAllItems = async (items: InventoryItem[]): Promise<void> => {
  const content = items.map((item) => JSON.stringify(item)).join("\n") + "\n";
  await Bun.write(DATA_PATH, content);
};

export const getAll = async (): Promise<InventoryItem[]> => {
  return readAllItems();
};

export const getBySku = async (sku: string): Promise<InventoryItem | null> => {
  const items = await readAllItems();
  return items.find((item) => item.sku === sku) ?? null;
};

export const upsert = async (
  data: Omit<InventoryItem, "createdAt" | "updatedAt">
): Promise<{ created: boolean; item: InventoryItem }> => {
  const items = await readAllItems();
  const now = new Date().toISOString();
  const existingIndex = items.findIndex((item) => item.sku === data.sku);

  if (existingIndex >= 0) {
    const existing = items[existingIndex];
    const updated: InventoryItem = {
      ...existing,
      name: data.name,
      quantity: data.quantity,
      category: data.category,
      reorderThreshold: data.reorderThreshold,
      updatedAt: now,
    };
    items[existingIndex] = updated;
    await writeAllItems(items);
    return { created: false, item: updated };
  }

  const newItem: InventoryItem = {
    ...data,
    createdAt: now,
    updatedAt: now,
  };
  items.push(newItem);
  await writeAllItems(items);
  return { created: true, item: newItem };
};

export const remove = async (sku: string): Promise<boolean> => {
  const items = await readAllItems();
  const filtered = items.filter((item) => item.sku !== sku);
  if (filtered.length === items.length) return false;
  await writeAllItems(filtered);
  return true;
};

export const search = async (query: string): Promise<InventoryItem[]> => {
  const items = await readAllItems();
  const q = query.toLowerCase();
  return items.filter(
    (item) =>
      item.name.toLowerCase().includes(q) ||
      item.sku.toLowerCase() === q
  );
};

export const getLowStock = async (): Promise<InventoryItem[]> => {
  const items = await readAllItems();
  return items.filter((item) => item.quantity <= item.reorderThreshold);
};

export const getStats = async () => {
  const items = await readAllItems();
  const categories: Record<string, number> = {};
  let totalQuantity = 0;

  for (const item of items) {
    totalQuantity += item.quantity;
    categories[item.category] = (categories[item.category] ?? 0) + 1;
  }

  return {
    totalItems: items.length,
    totalQuantity,
    lowStockItems: items.filter((item) => item.quantity <= item.reorderThreshold),
    categories,
  };
};

import type { ImportResult } from "./types";
import { upsert } from "./store";

type RawImportItem = {
  sku?: string;
  name?: string;
  quantity?: number;
  category?: string;
  reorderThreshold?: number;
};

const validateItem = (raw: RawImportItem, index: number): string | null => {
  if (!raw.sku || typeof raw.sku !== "string") return `Item ${index}: missing or invalid sku`;
  if (!raw.name || typeof raw.name !== "string") return `Item ${index}: missing or invalid name`;
  if (typeof raw.quantity !== "number" || raw.quantity < 0) return `Item ${index}: missing or invalid quantity`;
  if (!raw.category || typeof raw.category !== "string") return `Item ${index}: missing or invalid category`;
  if (typeof raw.reorderThreshold !== "number" || raw.reorderThreshold < 0)
    return `Item ${index}: missing or invalid reorderThreshold`;
  return null;
};

export const bulkImport = async (data: unknown): Promise<ImportResult> => {
  if (!Array.isArray(data)) {
    return { created: 0, updated: 0, errors: ["Input must be a JSON array"] };
  }

  const result: ImportResult = { created: 0, updated: 0, errors: [] };

  for (let i = 0; i < data.length; i++) {
    const raw = data[i] as RawImportItem;
    const error = validateItem(raw, i);
    if (error) {
      result.errors.push(error);
      continue;
    }

    const { created } = await upsert({
      sku: raw.sku!,
      name: raw.name!,
      quantity: raw.quantity!,
      category: raw.category!,
      reorderThreshold: raw.reorderThreshold!,
    });

    if (created) result.created++;
    else result.updated++;
  }

  return result;
};

