  const isLow = item.quantity <= item.reorderThreshold;
  const badgeStyle = { ...styles.badge, ...(isLow ? styles.badgeDanger : styles.badgeSuccess) };
  return h("span", { style: badgeStyle }, isLow ? "LOW" : "OK");
};

const renderAlertBanner = (lowStockItems: InventoryItem[]) => {
  if (lowStockItems.length === 0) return h(Fragment, {}, "");

  return h(
    "div",
    { style: styles.alertBanner },
    h("div", { style: styles.alertTitle }, `⚠ ${lowStockItems.length} item${lowStockItems.length > 1 ? "s" : ""} below reorder threshold`),
    ...lowStockItems.map((item) =>
