import { createSSR } from "plaited";
import * as store from "./store";
import { bulkImport } from "./import";
import {
  renderDashboard,
  renderSearchResults,
  renderItemDetail,
  renderImportResult,
  renderAddItemForm,
  renderBulkImportForm,
} from "./dashboard";

const ssr = createSSR();

const html = (template: ReturnType<typeof renderDashboard>) => {
  const rendered = ssr(template);
  return new Response(rendered, {
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });
};

const json = (data: unknown, status = 200) => {
  return new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });
};

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const path = url.pathname;
  const method = req.method;

  // GET / — Dashboard
  if (path === "/" && method === "GET") {
    const stats = await store.getStats();
    const items = await store.getAll();
    return html(renderDashboard(stats, items));
  }

  // GET /search?q=... — Search
  if (path === "/search" && method === "GET") {
    const query = url.searchParams.get("q") ?? "";
    if (!query) {
      return Response.redirect("/", 302);
    }
    const results = await store.search(query);
    return html(renderSearchResults(query, results));
  }

  // GET /item/new — Add item form
  if (path === "/item/new" && method === "GET") {
    return html(renderAddItemForm());
  }

  // GET /item/:sku — Item detail
  if (path.startsWith("/item/") && method === "GET") {
    const sku = decodeURIComponent(path.slice(6));
    const item = await store.getBySku(sku);
    if (!item) return json({ error: "Item not found" }, 404);
    return html(renderItemDetail(item));
  }

  // POST /item — Create or update item
  if (path === "/item" && method === "POST") {
    const contentType = req.headers.get("content-type") ?? "";
    let data: Record<string, unknown>;

    if (contentType.includes("application/json")) {
      data = await req.json();
    } else {
      const form = await req.formData();
      data = {
        sku: form.get("sku") as string,
        name: form.get("name") as string,
        quantity: Number(form.get("quantity")),
        category: form.get("category") as string,
        reorderThreshold: Number(form.get("reorderThreshold")),
      };
    }

    const { sku, name, quantity, category, reorderThreshold } = data as {
      sku: string;
      name: string;
      quantity: number;
      category: string;
      reorderThreshold: number;
    };

    if (!sku || !name || quantity == null || !category || reorderThreshold == null) {
      return json({ error: "Missing required fields: sku, name, quantity, category, reorderThreshold" }, 400);
    }

    const result = await store.upsert({ sku, name, quantity, category, reorderThreshold });
    return json(result, result.created ? 201 : 200);
  }

  // DELETE /item/:sku — Delete item
  if (path.startsWith("/item/") && method === "DELETE") {
    const sku = decodeURIComponent(path.slice(6));
    const removed = await store.remove(sku);
    if (!removed) return json({ error: "Item not found" }, 404);
    return json({ ok: true });
  }

  // POST /barcode — Barcode lookup
  if (path === "/barcode" && method === "POST") {
    const contentType = req.headers.get("content-type") ?? "";
    let sku: string;

    if (contentType.includes("application/json")) {
      const body = await req.json();
      sku = body.sku;
    } else {
      const form = await req.formData();
      sku = form.get("sku") as string;
    }

    if (!sku) return json({ error: "No SKU provided" }, 400);

    const item = await store.getBySku(sku.trim());
    if (!item) return json({ error: `No item found with SKU: ${sku}` }, 404);
    return html(renderItemDetail(item));
  }

  // GET /import — Bulk import form
  if (path === "/import" && method === "GET") {
    return html(renderBulkImportForm());
  }

  // POST /import — Bulk import
  if (path === "/import" && method === "POST") {
    const contentType = req.headers.get("content-type") ?? "";
    let data: unknown;

    if (contentType.includes("application/json")) {
      data = await req.json();
    } else {
      const form = await req.formData();
      const jsonStr = form.get("jsonData") as string;
      try {
        data = JSON.parse(jsonStr);
      } catch {
        return json({ error: "Invalid JSON" }, 400);
      }
    }

    const result = await bulkImport(data);
    const isApi = contentType.includes("application/json");
    return isApi ? json(result) : html(renderImportResult(result));
  }

  // GET /api/items — JSON API: all items
  if (path === "/api/items" && method === "GET") {
    const items = await store.getAll();
    return json(items);
  }

  // GET /api/low-stock — JSON API: low stock items
  if (path === "/api/low-stock" && method === "GET") {
    const items = await store.getLowStock();
    return json(items);
  }

  // GET /api/stats — JSON API: dashboard stats
  if (path === "/api/stats" && method === "GET") {
    const stats = await store.getStats();
    return json(stats);
  }

  return json({ error: "Not found" }, 404);
};

export default {
  port: 3000,
  fetch: handleRequest,
};

