export type WeatherCondition = {
  id: number
  main: string
  description: string
  icon: string
}

export type CurrentWeather = {
  coord: { lon: number; lat: number }
  weather: WeatherCondition[]
  main: {
    temp: number
    feels_like: number
    temp_min: number
    temp_max: number
    pressure: number
    humidity: number
  }
  wind: { speed: number; deg: number }
  clouds: { all: number }
  dt: number
  sys: { country: string; sunrise: number; sunset: number }
  name: string
}

export type ForecastEntry = {
  dt: number
  main: {
    temp: number
    feels_like: number
    temp_min: number
    temp_max: number
    pressure: number
    humidity: number
  }
  weather: WeatherCondition[]
  wind: { speed: number; deg: number }
  dt_txt: string
}

export type ForecastResponse = {
  city: { name: string; country: string }
  list: ForecastEntry[]
}

export type DayForecast = {
  date: string
  dayName: string
  tempHigh: number
  tempLow: number
  condition: WeatherCondition
  humidity: number
  windSpeed: number
}

export type WeatherDashboardData = {
  current: CurrentWeather
  forecast: ForecastResponse
  dailyForecasts: DayForecast[]
}

export type TemperatureUnit = 'celsius' | 'fahrenheit'

export const celsiusToFahrenheit = (c: number): number =>
  Math.round((c * 9) / 5 + 32)

export const formatTemp = (tempC: number): string =>
  `${Math.round(tempC)}°C / ${celsiusToFahrenheit(tempC)}°F`

export const formatTempShort = (tempC: number, unit: 'C' | 'F'): string =>
  unit === 'C' ? `${Math.round(tempC)}°C` : `${celsiusToFahrenheit(tempC)}°F`

export const windDegToDirection = (deg: number): string => {
  const directions = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW']
  const index = Math.round(deg / 45) % 8
  return directions[index]
}

export const formatDate = (timestamp: number): string => {
  const date = new Date(timestamp * 1000)
  return date.toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
  })
}

export const getDayName = (timestamp: number): string => {
  const date = new Date(timestamp * 1000)
  return date.toLocaleDateString('en-US', { weekday: 'short' })
}

export const weatherIconUrl = (iconCode: string): string =>
  `https://openweathermap.org/img/wn/${iconCode}@2x.png`

import type { CurrentWeather, ForecastResponse, DayForecast, WeatherDashboardData } from './types'
import { getDayName, formatDate } from './utils'

const CITY_DATA: Record<string, { lat: number; lon: number; country: string }> = {
  'new york': { lat: 40.71, lon: -74.01, country: 'US' },
  london: { lat: 51.51, lon: -0.13, country: 'GB' },
  tokyo: { lat: 35.69, lon: 139.69, country: 'JP' },
  paris: { lat: 48.86, lon: 2.35, country: 'FR' },
  sydney: { lat: -33.87, lon: 151.21, country: 'AU' },
}

const CONDITIONS = [
  { id: 800, main: 'Clear', description: 'clear sky', icon: '01d' },
  { id: 801, main: 'Clouds', description: 'few clouds', icon: '02d' },
  { id: 802, main: 'Clouds', description: 'scattered clouds', icon: '03d' },
  { id: 500, main: 'Rain', description: 'light rain', icon: '10d' },
  { id: 501, main: 'Rain', description: 'moderate rain', icon: '10d' },
  { id: 600, main: 'Snow', description: 'light snow', icon: '13d' },
  { id: 200, main: 'Thunderstorm', description: 'thunderstorm', icon: '11d' },
]

const seededRandom = (seed: number): number => {
  const x = Math.sin(seed) * 10000
  return x - Math.floor(x)
}

const generateCurrentWeather = (city: string): CurrentWeather => {
  const cityKey = city.toLowerCase()
  const cityInfo = CITY_DATA[cityKey] ?? { lat: 0, lon: 0, country: 'XX' }
  const seed = cityKey.split('').reduce((acc, c) => acc + c.charCodeAt(0), 0)
  const temp = 10 + seededRandom(seed) * 25
  const conditionIndex = Math.floor(seededRandom(seed + 1) * CONDITIONS.length)
  const now = Math.floor(Date.now() / 1000)

  return {
    coord: { lon: cityInfo.lon, lat: cityInfo.lat },
    weather: [CONDITIONS[conditionIndex]],
    main: {
      temp: Math.round(temp * 10) / 10,
      feels_like: Math.round((temp - 2 + seededRandom(seed + 2) * 4) * 10) / 10,
      temp_min: Math.round((temp - 3) * 10) / 10,
      temp_max: Math.round((temp + 3) * 10) / 10,
      pressure: 1013 + Math.round(seededRandom(seed + 3) * 20 - 10),
      humidity: 40 + Math.round(seededRandom(seed + 4) * 50),
    },
    wind: {
      speed: Math.round(seededRandom(seed + 5) * 15 * 10) / 10,
      deg: Math.round(seededRandom(seed + 6) * 360),
    },
    clouds: { all: Math.round(seededRandom(seed + 7) * 100) },
    dt: now,
    sys: {
      country: cityInfo.country,
      sunrise: now - 21600,
      sunset: now + 21600,
    },
    name: city.split(' ').map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
  }
}

const generateForecast = (city: string): ForecastResponse => {
  const cityKey = city.toLowerCase()
  const cityInfo = CITY_DATA[cityKey] ?? { lat: 0, lon: 0, country: 'XX' }
  const seed = cityKey.split('').reduce((acc, c) => acc + c.charCodeAt(0), 0)
  const baseTemp = 10 + seededRandom(seed) * 25
  const now = Math.floor(Date.now() / 1000)
  const daySeconds = 86400

  const list = Array.from({ length: 40 }, (_, i) => {
    const dt = now + i * 10800
    const daySeed = seed + Math.floor(i / 8) * 100 + (i % 8)
    const hourOffset = (i % 8) * 3
    const diurnalVariation = Math.sin(((hourOffset - 6) / 24) * Math.PI * 2) * 5
    const dayVariation = seededRandom(daySeed) * 10 - 5
    const temp = baseTemp + diurnalVariation + dayVariation
    const conditionIndex = Math.floor(seededRandom(daySeed + 10) * CONDITIONS.length)
    const date = new Date(dt * 1000)
    const dtTxt = date.toISOString().replace('T', ' ').substring(0, 19)

    return {
      dt,
      main: {
        temp: Math.round(temp * 10) / 10,
        feels_like: Math.round((temp - 1) * 10) / 10,
        temp_min: Math.round((temp - 2) * 10) / 10,
        temp_max: Math.round((temp + 2) * 10) / 10,
        pressure: 1013 + Math.round(seededRandom(daySeed + 20) * 20 - 10),
        humidity: 40 + Math.round(seededRandom(daySeed + 30) * 50),
      },
      weather: [CONDITIONS[conditionIndex]],
      wind: {
        speed: Math.round(seededRandom(daySeed + 40) * 15 * 10) / 10,
        deg: Math.round(seededRandom(daySeed + 50) * 360),
      },
      dt_txt: dtTxt,
    }
  })

  return {
    city: {
      name: city.split(' ').map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
      country: cityInfo.country,
    },
    list,
  }
}

const aggregateDailyForecasts = (forecast: ForecastResponse): DayForecast[] => {
  const dayMap = new Map<string, { temps: number[]; entries: typeof forecast.list }>()

  for (const entry of forecast.list) {
    const dateKey = entry.dt_txt.substring(0, 10)
    const existing = dayMap.get(dateKey)
    if (existing) {
      existing.temps.push(entry.main.temp)
      existing.entries.push(entry)
    } else {
      dayMap.set(dateKey, { temps: [entry.main.temp], entries: [entry] })
    }
  }

  const days: DayForecast[] = []
  for (const [dateKey, { temps, entries }] of dayMap) {
    if (days.length >= 5) break
    const midEntry = entries[Math.floor(entries.length / 2)]
    days.push({
      date: formatDate(midEntry.dt),
      dayName: getDayName(midEntry.dt),
      tempHigh: Math.round(Math.max(...temps) * 10) / 10,
      tempLow: Math.round(Math.min(...temps) * 10) / 10,
      condition: midEntry.weather[0],
      humidity: midEntry.main.humidity,
      windSpeed: midEntry.wind.speed,
    })
  }

  return days
}

export const getWeatherData = (city: string): WeatherDashboardData => {
  const current = generateCurrentWeather(city)
  const forecast = generateForecast(city)
  const dailyForecasts = aggregateDailyForecasts(forecast)
  return { current, forecast, dailyForecasts }
}

export const getAvailableCities = (): string[] => Object.keys(CITY_DATA)

import { h } from 'plaited'
