const CHART_WIDTH = 500
const CHART_HEIGHT = 200
const PADDING = { top: 20, right: 30, bottom: 40, left: 45 }

const plotWidth = CHART_WIDTH - PADDING.left - PADDING.right
const plotHeight = CHART_HEIGHT - PADDING.top - PADDING.bottom

const buildPolylinePoints = (
  values: number[],
  minVal: number,
  maxVal: number,
): string => {
  const range = maxVal - minVal || 1
  return values
    .map((v, i) => {
      const x = PADDING.left + (i / (values.length - 1)) * plotWidth
      const y = PADDING.top + plotHeight - ((v - minVal) / range) * plotHeight
      return `${Math.round(x)},${Math.round(y)}`
    })
    .join(' ')
}

export const renderTempChart = (forecasts: DayForecast[]) => {
  const highs = forecasts.map((f) => f.tempHigh)
  const lows = forecasts.map((f) => f.tempLow)
  const allTemps = [...highs, ...lows]
  const minTemp = Math.floor(Math.min(...allTemps)) - 2
  const maxTemp = Math.ceil(Math.max(...allTemps)) + 2

  const highPoints = buildPolylinePoints(highs, minTemp, maxTemp)
  const lowPoints = buildPolylinePoints(lows, minTemp, maxTemp)

  const yTicks = 5
  const yLabels = Array.from({ length: yTicks }, (_, i) => {
    const val = minTemp + ((maxTemp - minTemp) * i) / (yTicks - 1)
    const y = PADDING.top + plotHeight - (i / (yTicks - 1)) * plotHeight
    return { val: Math.round(val), y }
  })

  return h(
    'div',
    { style: { marginTop: '24px' } },
    h('h3', { style: { margin: '0 0 12px', fontSize: '16px', color: '#374151' } }, 'Temperature Trend'),
    h(
      'svg',
      {
        viewBox: `0 0 ${CHART_WIDTH} ${CHART_HEIGHT}`,
        style: { width: '100%', maxWidth: `${CHART_WIDTH}px`, height: 'auto', background: '#f9fafb', borderRadius: '8px', border: '1px solid #e5e7eb' },
      },
      // Y-axis grid lines and labels
      ...yLabels.map(({ val, y }) =>
        h('g', {},
          h('line', { x1: String(PADDING.left), y1: String(Math.round(y)), x2: String(CHART_WIDTH - PADDING.right), y2: String(Math.round(y)), stroke: '#e5e7eb', 'stroke-width': '1' }),
          h('text', { x: String(PADDING.left - 8), y: String(Math.round(y) + 4), 'text-anchor': 'end', 'font-size': '11', fill: '#6b7280' }, `${val}°`),
        ),
      ),
      // X-axis labels
      ...forecasts.map((f, i) => {
        const x = PADDING.left + (i / (forecasts.length - 1)) * plotWidth
        return h('text', { x: String(Math.round(x)), y: String(CHART_HEIGHT - 8), 'text-anchor': 'middle', 'font-size': '11', fill: '#6b7280' }, f.dayName)
      }),
      // High temperature line
      h('polyline', { points: highPoints, fill: 'none', stroke: '#ef4444', 'stroke-width': '2.5', 'stroke-linejoin': 'round' }),
      // Low temperature line
      h('polyline', { points: lowPoints, fill: 'none', stroke: '#3b82f6', 'stroke-width': '2.5', 'stroke-linejoin': 'round' }),
      // High temp data points
      ...highs.map((v, i) => {
        const x = PADDING.left + (i / (highs.length - 1)) * plotWidth
        const y = PADDING.top + plotHeight - ((v - minTemp) / (maxTemp - minTemp || 1)) * plotHeight
        return h('circle', { cx: String(Math.round(x)), cy: String(Math.round(y)), r: '4', fill: '#ef4444', stroke: '#fff', 'stroke-width': '1.5' })
      }),
      // Low temp data points
      ...lows.map((v, i) => {
        const x = PADDING.left + (i / (lows.length - 1)) * plotWidth
        const y = PADDING.top + plotHeight - ((v - minTemp) / (maxTemp - minTemp || 1)) * plotHeight
        return h('circle', { cx: String(Math.round(x)), cy: String(Math.round(y)), r: '4', fill: '#3b82f6', stroke: '#fff', 'stroke-width': '1.5' })
      }),
      // Legend
      h('circle', { cx: String(CHART_WIDTH - PADDING.right - 90), cy: String(PADDING.top - 6), r: '4', fill: '#ef4444' }),
      h('text', { x: String(CHART_WIDTH - PADDING.right - 82), y: String(PADDING.top - 2), 'font-size': '11', fill: '#6b7280' }, 'High'),
      h('circle', { cx: String(CHART_WIDTH - PADDING.right - 40), cy: String(PADDING.top - 6), r: '4', fill: '#3b82f6' }),
      h('text', { x: String(CHART_WIDTH - PADDING.right - 32), y: String(PADDING.top - 2), 'font-size': '11', fill: '#6b7280' }, 'Low'),
    ),
  )
}

