import { createSSR } from 'plaited'
import { getWeatherData, getAvailableCities } from './data'
import { renderDashboard } from './ui'
import type { WeatherDashboardData } from './types'

const DATA_PATH = './data/last-search.json'

const saveLastSearch = async (city: string): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify({ city, timestamp: Date.now() }))
}

const loadLastSearch = async (): Promise<string> => {
  try {
    const file = Bun.file(DATA_PATH)
    if (await file.exists()) {
      const data = await file.json()
      return data.city ?? 'London'
    }
  } catch {
    // ignore read errors
  }
  return 'London'
}

export const getWeather = (city: string): WeatherDashboardData => {
  return getWeatherData(city)
}

export const renderWeatherPage = async (city?: string): Promise<string> => {
  const targetCity = city ?? (await loadLastSearch())
  const data = getWeatherData(targetCity)

  if (city) {
    await saveLastSearch(city)
  }

  const template = renderDashboard(data)
  const ssr = createSSR()
  return ssr(template)
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)

  if (url.pathname === '/api/weather') {
    const city = url.searchParams.get('city') ?? 'London'
    const data = getWeatherData(city)
    return new Response(JSON.stringify(data), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  if (url.pathname === '/api/cities') {
    return new Response(JSON.stringify(getAvailableCities()), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  const city = url.searchParams.get('city') ?? undefined
  const html = await renderWeatherPage(city)

  return new Response(
    `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f3f4f6; min-height: 100vh; }
  </style>
</head>
<body>${html}</body>
</html>`,
    { headers: { 'Content-Type': 'text/html' } },
  )
}

export default {
  getWeather,
  renderWeatherPage,
  handleRequest,
}

