import type { ForecastResponse, DayForecast } from './types'

export const celsiusToFahrenheit = (c: number): number =>
  Math.round((c * 9 / 5 + 32) * 10) / 10

export const formatTemp = (celsius: number): string =>
  `${Math.round(celsius)}°C / ${Math.round(celsiusToFahrenheit(celsius))}°F`

export const windDirection = (deg: number): string => {
  const dirs = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW']
  return dirs[Math.round(deg / 45) % 8]
}

export const weatherIconUrl = (icon: string): string =>
  `https://openweathermap.org/img/wn/${icon}@2x.png`

export const getDayName = (timestamp: number): string =>
  new Date(timestamp * 1000).toLocaleDateString('en-US', { weekday: 'short' })

export const getDateStr = (timestamp: number): string =>
  new Date(timestamp * 1000).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })

export const aggregateDailyForecasts = (forecast: ForecastResponse): DayForecast[] => {
  const dayMap = new Map<string, { temps: number[]; humidities: number[]; winds: number[]; entries: typeof forecast.list }>()

  for (const entry of forecast.list) {
    const dateKey = entry.dt_txt.split(' ')[0]
    const existing = dayMap.get(dateKey)
    if (existing) {
      existing.temps.push(entry.main.temp)
      existing.humidities.push(entry.main.humidity)
      existing.winds.push(entry.wind.speed)
      existing.entries.push(entry)
    } else {
      dayMap.set(dateKey, {
        temps: [entry.main.temp],
        humidities: [entry.main.humidity],
        winds: [entry.wind.speed],
        entries: [entry],
      })
    }
  }

  const days: DayForecast[] = []
  for (const [, data] of dayMap) {
    if (days.length >= 5) break
    const midEntry = data.entries[Math.floor(data.entries.length / 2)]
    days.push({
      date: getDateStr(midEntry.dt),
      dayName: getDayName(midEntry.dt),
      tempMin: Math.round(Math.min(...data.temps) * 10) / 10,
      tempMax: Math.round(Math.max(...data.temps) * 10) / 10,
      humidity: Math.round(data.humidities.reduce((a, b) => a + b, 0) / data.humidities.length),
      wind: Math.round(data.winds.reduce((a, b) => a + b, 0) / data.winds.length * 10) / 10,
      description: midEntry.weather[0].description,
      icon: midEntry.weather[0].icon,
    })
  }

  return days
}

import { h } from 'plaited'
import type { DayForecast } from './types'
import { celsiusToFahrenheit } from './utils'

const CHART_WIDTH = 600
const CHART_HEIGHT = 200
const PADDING = { top: 30, right: 40, bottom: 40, left: 50 }

const plotWidth = CHART_WIDTH - PADDING.left - PADDING.right
const plotHeight = CHART_HEIGHT - PADDING.top - PADDING.bottom

export const renderTempChart = (days: DayForecast[]) => {
  if (days.length === 0) return h('div', {}, 'No forecast data')

  const allTemps = days.flatMap((d) => [d.tempMin, d.tempMax])
  const minTemp = Math.floor(Math.min(...allTemps)) - 2
  const maxTemp = Math.ceil(Math.max(...allTemps)) + 2
  const tempRange = maxTemp - minTemp || 1

  const xStep = plotWidth / Math.max(days.length - 1, 1)

  const toY = (temp: number): number =>
    PADDING.top + plotHeight - ((temp - minTemp) / tempRange) * plotHeight

  const toX = (i: number): number => PADDING.left + i * xStep

  const highPoints = days.map((d, i) => `${toX(i)},${toY(d.tempMax)}`)
  const lowPoints = days.map((d, i) => `${toX(i)},${toY(d.tempMin)}`)

  const gridLines = []
  const gridSteps = 5
  for (let i = 0; i <= gridSteps; i++) {
    const temp = minTemp + (tempRange * i) / gridSteps
    const y = toY(temp)
    gridLines.push(
      h('line', { x1: String(PADDING.left), y1: String(y), x2: String(CHART_WIDTH - PADDING.right), y2: String(y), stroke: '#e0e0e0', 'stroke-width': '1' }),
      h('text', { x: String(PADDING.left - 8), y: String(y + 4), 'text-anchor': 'end', fill: '#888', 'font-size': '11' }, `${Math.round(temp)}°`)
    )
  }

  const xLabels = days.map((d, i) =>
    h('text', {
      x: String(toX(i)),
      y: String(CHART_HEIGHT - 8),
      'text-anchor': 'middle',
      fill: '#888',
      'font-size': '11',
    }, d.dayName)
  )

  const highDots = days.map((d, i) =>
    h('circle', { cx: String(toX(i)), cy: String(toY(d.tempMax)), r: '4', fill: '#e74c3c' })
  )

  const lowDots = days.map((d, i) =>
    h('circle', { cx: String(toX(i)), cy: String(toY(d.tempMin)), r: '4', fill: '#3498db' })
  )

  const highLabels = days.map((d, i) =>
    h('text', {
      x: String(toX(i)),
      y: String(toY(d.tempMax) - 10),
      'text-anchor': 'middle',
      fill: '#e74c3c',
      'font-size': '10',
      'font-weight': 'bold',
    }, `${Math.round(d.tempMax)}°`)
  )

  const lowLabels = days.map((d, i) =>
    h('text', {
      x: String(toX(i)),
      y: String(toY(d.tempMin) + 18),
      'text-anchor': 'middle',
      fill: '#3498db',
      'font-size': '10',
      'font-weight': 'bold',
    }, `${Math.round(d.tempMin)}°`)
  )

  return h('svg', {
    viewBox: `0 0 ${CHART_WIDTH} ${CHART_HEIGHT}`,
    style: 'width:100%;max-width:600px;height:auto;background:#fafafa;border-radius:8px;',
  },
    ...gridLines,
    h('polyline', { points: highPoints.join(' '), fill: 'none', stroke: '#e74c3c', 'stroke-width': '2.5', 'stroke-linejoin': 'round' }),
    h('polyline', { points: lowPoints.join(' '), fill: 'none', stroke: '#3498db', 'stroke-width': '2.5', 'stroke-linejoin': 'round' }),
    ...highDots,
    ...lowDots,
    ...highLabels,
    ...lowLabels,
    ...xLabels,
    h('text', { x: String(CHART_WIDTH - PADDING.right), y: '16', 'text-anchor': 'end', fill: '#e74c3c', 'font-size': '11' }, 'High'),
    h('text', { x: String(CHART_WIDTH - PADDING.right - 50), y: '16', 'text-anchor': 'end', fill: '#3498db', 'font-size': '11' }, 'Low'),
  )
}

