const HISTORY_PATH = './data/search-history.json'

type SearchHistory = {
  searches: { city: string; timestamp: string }[]
}

const loadHistory = async (): Promise<SearchHistory> => {
  try {
    const file = Bun.file(HISTORY_PATH)
    if (await file.exists()) {
      return await file.json()
    }
  } catch {
    // ignore read errors
  }
  return { searches: [] }
}

const saveSearch = async (city: string): Promise<void> => {
  const history = await loadHistory()
  history.searches.unshift({ city, timestamp: new Date().toISOString() })
  history.searches = history.searches.slice(0, 50)
  await Bun.write(HISTORY_PATH, JSON.stringify(history, null, 2))
}

export const handleRequest = async (city: string): Promise<string> => {
  const data = getWeatherData(city)
  const availableCities = getAvailableCities()

  if (data && city.trim()) {
    await saveSearch(city.trim())
  }

  const vdom = renderDashboard(data, city, availableCities)
  const ssr = createSSR()
  return ssr(vdom)
}

export const serve = () => {
  return Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' || url.pathname === '/weather') {
        const city = url.searchParams.get('city') ?? ''
        const html = await handleRequest(city)

        return new Response(
          `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f0f2f5; min-height: 100vh; padding: 20px; }
  </style>
</head>
<body>
  ${html}
</body>
</html>`,
          { headers: { 'Content-Type': 'text/html; charset=utf-8' } }
        )
      }

      if (url.pathname === '/api/weather') {
        const city = url.searchParams.get('city') ?? ''
        const data = getWeatherData(city)

        if (!data) {
          return Response.json({ error: 'City not found', available: getAvailableCities() }, { status: 404 })
        }

        return Response.json(data)
      }

      return new Response('Not Found', { status: 404 })
    },
  })
}

if (import.meta.main) {
  const server = serve()
  console.log(`Weather Dashboard running at http://localhost:${server.port}`)
}

