    name: city,
  }
}

const generateForecastEntries = (): ForecastEntry[] => {
  const now = Math.floor(Date.now() / 1000)
  const daySeconds = 86400
  const conditions: Array<{ main: string; description: string; icon: string; id: number }> = [
    { id: 800, main: 'Clear', description: 'clear sky', icon: '01d' },
    { id: 802, main: 'Clouds', description: 'scattered clouds', icon: '03d' },
    { id: 500, main: 'Rain', description: 'light rain', icon: '10d' },
    { id: 801, main: 'Clouds', description: 'few clouds', icon: '02d' },
    { id: 800, main: 'Clear', description: 'clear sky', icon: '01d' },
  ]
  const temps = [
    { temp: 20, min: 15, max: 22, humidity: 55 },
    { temp: 17, min: 13, max: 19, humidity: 68 },
    { temp: 14, min: 11, max: 16, humidity: 78 },
    { temp: 19, min: 14, max: 21, humidity: 52 },
    { temp: 22, min: 17, max: 24, humidity: 45 },
  ]

  const entries: ForecastEntry[] = []
  for (let day = 0; day < 5; day++) {
    for (const hour of [6, 9, 12, 15, 18, 21]) {
      const dt = now + (day + 1) * daySeconds + hour * 3600
      const date = new Date(dt * 1000)
      const variation = (hour - 12) * 0.5
      entries.push({
        dt,
        main: {
          temp: temps[day].temp + variation,
          feels_like: temps[day].temp + variation - 1.5,
          temp_min: temps[day].min,
          temp_max: temps[day].max,
          pressure: 1012 + day,
          humidity: temps[day].humidity,
        },
        weather: [conditions[day]],
        wind: { speed: 3.0 + day * 0.5, deg: 180 + day * 30 },
        dt_txt: date.toISOString().replace('T', ' ').slice(0, 19),
      })
    }
  }
  return entries
}

const aggregateDailyForecasts = (entries: ForecastEntry[]): DayForecast[] => {
  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']
  const grouped = new Map<string, ForecastEntry[]>()

  for (const entry of entries) {
    const dateKey = entry.dt_txt.slice(0, 10)
    const existing = grouped.get(dateKey) ?? []
    existing.push(entry)
    grouped.set(dateKey, existing)
  }

  const dailies: DayForecast[] = []
  for (const [dateKey, dayEntries] of grouped) {
    const date = new Date(dateKey + 'T12:00:00')
    const temps = dayEntries.map((e) => e.main.temp)
    const midday = dayEntries.find((e) => e.dt_txt.includes('12:')) ?? dayEntries[0]
    dailies.push({
      date: dateKey,
      dayName: dayNames[date.getDay()],
      tempMin: Math.round(Math.min(...temps)),
      tempMax: Math.round(Math.max(...temps)),
      humidity: midday.main.humidity,
      wind: midday.wind.speed,
      description: midday.weather[0].description,
      icon: midday.weather[0].icon,
    })
  }
  return dailies.slice(0, 5)
}

export const getWeatherData = (city: string): WeatherDashboardData => {
  const current = generateCurrentWeather(city)
  const forecastEntries = generateForecastEntries()
  const forecast: ForecastResponse = {
    list: forecastEntries,
    city: { name: city, country: 'GB', coord: current.coord },
  }
  const dailyForecasts = aggregateDailyForecasts(forecastEntries)
  return { current, forecast, dailyForecasts }
}

