const renderChart = (dailyForecasts: DayForecast[]) => {
  const width = 700
  const height = 180
  const padding = { top: 20, right: 40, bottom: 40, left: 40 }
  const chartW = width - padding.left - padding.right
  const chartH = height - padding.top - padding.bottom

  const maxTemps = dailyForecasts.map((d) => d.tempMax)
  const minTemps = dailyForecasts.map((d) => d.tempMin)
  const allTemps = [...maxTemps, ...minTemps]
  const tempMin = Math.min(...allTemps) - 2
  const tempMax = Math.max(...allTemps) + 2

  const xStep = chartW / (dailyForecasts.length - 1)
  const scaleY = (temp: number) =>
    padding.top + chartH - ((temp - tempMin) / (tempMax - tempMin)) * chartH

  const maxPoints = maxTemps.map((t, i) => `${padding.left + i * xStep},${scaleY(t)}`).join(' ')
  const minPoints = minTemps.map((t, i) => `${padding.left + i * xStep},${scaleY(t)}`).join(' ')

  const gridLines: number[] = []
  const gridStep = Math.ceil((tempMax - tempMin) / 4)
  for (let t = Math.ceil(tempMin); t <= Math.floor(tempMax); t += gridStep) {
    gridLines.push(t)
  }

  return h(
    'svg',
    { viewBox: `0 0 ${width} ${height}`, style: styles.chartSvg },
    ...gridLines.map((t) =>
      h(Fragment, {},
        h('line', {
          x1: String(padding.left),
          y1: String(scaleY(t)),
          x2: String(width - padding.right),
          y2: String(scaleY(t)),
          stroke: '#334155',
          'stroke-dasharray': '4',
        }),
        h('text', {
          x: String(padding.left - 8),
          y: String(scaleY(t) + 4),
          fill: '#64748b',
          'font-size': '11',
          'text-anchor': 'end',
        }, `${t}°`),
      ),
    ),
    h('polyline', {
      points: maxPoints,
      fill: 'none',
      stroke: '#f59e0b',
      'stroke-width': '2.5',
      'stroke-linejoin': 'round',
    }),
    h('polyline', {
      points: minPoints,
      fill: 'none',
      stroke: '#38bdf8',
      'stroke-width': '2.5',
      'stroke-linejoin': 'round',
    }),
    ...maxTemps.map((t, i) =>
      h('circle', {
        cx: String(padding.left + i * xStep),
        cy: String(scaleY(t)),
        r: '4',
        fill: '#f59e0b',
      }),
    ),
    ...minTemps.map((t, i) =>
      h('circle', {
        cx: String(padding.left + i * xStep),
        cy: String(scaleY(t)),
        r: '4',
        fill: '#38bdf8',
      }),
    ),
    ...dailyForecasts.map((d, i) =>
      h('text', {
        x: String(padding.left + i * xStep),
        y: String(height - 8),
        fill: '#94a3b8',
        'font-size': '12',
        'text-anchor': 'middle',
      }, d.dayName),
    ),
    h('circle', { cx: String(width - padding.right - 80), cy: '12', r: '4', fill: '#f59e0b' }),
    h('text', {
      x: String(width - padding.right - 72),
      y: '16',
      fill: '#94a3b8',
      'font-size': '11',
    }, 'High'),
    h('circle', { cx: String(width - padding.right - 30), cy: '12', r: '4', fill: '#38bdf8' }),
    h('text', {
      x: String(width - padding.right - 22),
      y: '16',
      fill: '#94a3b8',
      'font-size': '11',
    }, 'Low'),
  )
}

