import { getWeatherData, saveLastSearch, loadLastSearch } from './weather-data'
import { renderDashboard } from './weather-ui'
import type { WeatherDashboardData } from './types'

const DEFAULT_CITY = 'London'

export const getWeather = async (city?: string): Promise<WeatherDashboardData> => {
  const targetCity = city ?? (await loadLastSearch()) ?? DEFAULT_CITY
  const data = getWeatherData(targetCity)
  await saveLastSearch(targetCity)
  return data
}

export const renderWeather = async (city?: string): Promise<string> => {
  const data = await getWeather(city)
  return renderDashboard(data)
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)

  if (url.pathname === '/api/weather') {
    const city = url.searchParams.get('city') ?? DEFAULT_CITY
    const data = await getWeather(city)
    return new Response(JSON.stringify(data), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  if (url.pathname === '/' || url.pathname === '/dashboard') {
    const city = url.searchParams.get('city') ?? undefined
    const html = await renderWeather(city)
    return new Response(
      `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Weather Dashboard</title><style>body{margin:0;background:#0a0f1e;min-height:100vh;padding:20px;box-sizing:border-box}</style></head><body>${html}</body></html>`,
      { headers: { 'Content-Type': 'text/html' } },
    )
  }

  return new Response('Not Found', { status: 404 })
}

