import type { ForumData } from "./types";

const DATA_PATH = `${import.meta.dir}/data/forum.json`;

const defaultData: ForumData = { threads: [] };

export const loadData = async (): Promise<ForumData> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) {
    await Bun.write(DATA_PATH, JSON.stringify(defaultData, null, 2));
    return structuredClone(defaultData);
  }
  const text = await file.text();
  return JSON.parse(text) as ForumData;
};

export const saveData = async (data: ForumData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2));
};

import { loadData, saveData } from "./store";
import type {
  Thread,
  Reply,
  SortMode,
  VoteDirection,
  CreateThreadInput,
  CreateReplyInput,
} from "./types";

const generateId = (): string => crypto.randomUUID();

export const getThreads = async (
  sort: SortMode = "newest",
  query?: string
): Promise<Thread[]> => {
  const data = await loadData();
  let threads = data.threads;

  if (query) {
    const lower = query.toLowerCase();
    threads = threads.filter((t) => t.title.toLowerCase().includes(lower));
  }

  const sorted = [...threads];
  switch (sort) {
    case "newest":
      sorted.sort(
        (a, b) =>
          new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      );
      break;
    case "votes":
      sorted.sort((a, b) => b.votes - a.votes);
      break;
    case "active": {
      const lastActivity = (t: Thread): number => {
        if (t.replies.length === 0) return new Date(t.createdAt).getTime();
        const latest = t.replies.reduce((max, r) => {
          const time = new Date(r.createdAt).getTime();
          return time > max ? time : max;
        }, 0);
        return latest;
      };
      sorted.sort((a, b) => lastActivity(b) - lastActivity(a));
      break;
    }
  }

  return sorted;
};

export const getThread = async (id: string): Promise<Thread | null> => {
  const data = await loadData();
  return data.threads.find((t) => t.id === id) ?? null;
};

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const data = await loadData();
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    createdAt: new Date().toISOString(),
    votes: 0,
    replies: [],
  };
  data.threads.push(thread);
  await saveData(data);
  return thread;
};

export const createReply = async (
  threadId: string,
  input: CreateReplyInput
): Promise<Reply | null> => {
  const data = await loadData();
  const thread = data.threads.find((t) => t.id === threadId);
  if (!thread) return null;

  if (input.parentReplyId) {
    const parentExists = thread.replies.some(
      (r) => r.id === input.parentReplyId && r.parentReplyId === null
    );
    if (!parentExists) return null;
  }

  const reply: Reply = {
    id: generateId(),
    threadId,
    parentReplyId: input.parentReplyId ?? null,
    body: input.body,
    author: input.author,
    createdAt: new Date().toISOString(),
    votes: 0,
  };
  thread.replies.push(reply);
  await saveData(data);
  return reply;
};

export const voteThread = async (
  threadId: string,
  direction: VoteDirection
): Promise<Thread | null> => {
  const data = await loadData();
  const thread = data.threads.find((t) => t.id === threadId);
  if (!thread) return null;
  thread.votes += direction === "up" ? 1 : -1;
  await saveData(data);
  return thread;
};

export const voteReply = async (
  threadId: string,
  replyId: string,
  direction: VoteDirection
): Promise<Reply | null> => {
  const data = await loadData();
  const thread = data.threads.find((t) => t.id === threadId);
  if (!thread) return null;
  const reply = thread.replies.find((r) => r.id === replyId);
  if (!reply) return null;
  reply.votes += direction === "up" ? 1 : -1;
  await saveData(data);
  return reply;
};

