const styleStr = (obj: Record<string, string>): string =>
  Object.entries(obj)
    .map(
      ([key, value]) =>
        `${key.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${value}`
    )
    .join(";");

