  getThreads,
  getThread,
  createThread,
  createReply,
  voteThread,
  voteReply,
} from "./forum";
import {
  renderThreadList,
  renderThread,
  renderNewThreadForm,
} from "./views";
import type { SortMode, VoteDirection } from "./types";

const parseFormBody = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text();
  const params = new URLSearchParams(text);
  const result: Record<string, string> = {};
  for (const [key, value] of params.entries()) {
    result[key] = value;
  }
  return result;
};

const html = (body: string, status = 200): Response =>
  new Response(body, {
    status,
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });

const redirect = (url: string): Response =>
  new Response(null, {
    status: 303,
    headers: { Location: url },
  });

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const { pathname } = url;
  const method = req.method;

  // GET / — Thread list
  if (pathname === "/" && method === "GET") {
    const sort = (url.searchParams.get("sort") as SortMode) || "newest";
    const query = url.searchParams.get("q") || "";
    const threads = await getThreads(sort, query || undefined);
    return html(renderThreadList(threads, sort, query));
  }

  // GET /new — New thread form
  if (pathname === "/new" && method === "GET") {
    return html(renderNewThreadForm());
  }

  // POST /thread — Create thread
  if (pathname === "/thread" && method === "POST") {
    const body = await parseFormBody(req);
    if (!body.title || !body.body || !body.author) {
      return html("<p>Missing required fields.</p>", 400);
    }
    const thread = await createThread({
      title: body.title,
      body: body.body,
      author: body.author,
    });
    return redirect(`/thread/${thread.id}`);
  }

  // GET /thread/:id — View thread
  const threadMatch = pathname.match(/^\/thread\/([^/]+)$/);
  if (threadMatch && method === "GET") {
    const thread = await getThread(threadMatch[1]);
    if (!thread) return html("<p>Thread not found.</p>", 404);
    return html(renderThread(thread));
  }

  // POST /thread/:id/reply — Create reply
  const replyMatch = pathname.match(/^\/thread\/([^/]+)\/reply$/);
  if (replyMatch && method === "POST") {
    const body = await parseFormBody(req);
    if (!body.body || !body.author) {
      return html("<p>Missing required fields.</p>", 400);
    }
    await createReply(replyMatch[1], {
      body: body.body,
      author: body.author,
      parentReplyId: body.parentReplyId || null,
    });
    return redirect(`/thread/${replyMatch[1]}`);
  }

  // POST /thread/:id/vote — Vote on thread
  const threadVoteMatch = pathname.match(/^\/thread\/([^/]+)\/vote$/);
  if (threadVoteMatch && method === "POST") {
    const body = await parseFormBody(req);
    const direction = body.direction as VoteDirection;
    if (direction !== "up" && direction !== "down") {
      return html("<p>Invalid vote direction.</p>", 400);
    }
    await voteThread(threadVoteMatch[1], direction);
    const referer = req.headers.get("referer") || "/";
    return redirect(referer);
  }

  // POST /thread/:id/reply/:replyId/vote — Vote on reply
  const replyVoteMatch = pathname.match(
    /^\/thread\/([^/]+)\/reply\/([^/]+)\/vote$/
  );
  if (replyVoteMatch && method === "POST") {
    const body = await parseFormBody(req);
    const direction = body.direction as VoteDirection;
    if (direction !== "up" && direction !== "down") {
      return html("<p>Invalid vote direction.</p>", 400);
    }
    await voteReply(replyVoteMatch[1], replyVoteMatch[2], direction);
    const referer = req.headers.get("referer") || `/thread/${replyVoteMatch[1]}`;
    return redirect(referer);
  }

  return html("<p>Not found.</p>", 404);
};

