import type { Thread, Reply, CreateThreadInput, CreateReplyInput, SortMode } from "./types";

const DATA_PATH = new URL("./data/threads.json", import.meta.url).pathname;

const generateId = (): string => crypto.randomUUID();

const readThreads = async (): Promise<Thread[]> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) return [];
  const text = await file.text();
  return JSON.parse(text) as Thread[];
};

const writeThreads = async (threads: Thread[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(threads, null, 2));
};

export const getAllThreads = async (
  sort: SortMode = "newest",
  search?: string
): Promise<Thread[]> => {
  let threads = await readThreads();

  if (search) {
    const query = search.toLowerCase();
    threads = threads.filter((t) => t.title.toLowerCase().includes(query));
  }

  const sorters: Record<SortMode, (a: Thread, b: Thread) => number> = {
    newest: (a, b) =>
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
    top: (a, b) => b.votes - a.votes,
    active: (a, b) => {
      const lastReplyA =
        a.replies.length > 0
          ? new Date(a.replies[a.replies.length - 1].createdAt).getTime()
          : new Date(a.createdAt).getTime();
      const lastReplyB =
        b.replies.length > 0
          ? new Date(b.replies[b.replies.length - 1].createdAt).getTime()
          : new Date(b.createdAt).getTime();
      return lastReplyB - lastReplyA;
    },
  };

  threads.sort(sorters[sort]);
  return threads;
};

export const getThread = async (id: string): Promise<Thread | undefined> => {
  const threads = await readThreads();
  return threads.find((t) => t.id === id);
};

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const threads = await readThreads();
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    createdAt: new Date().toISOString(),
    votes: 0,
    replies: [],
  };
  threads.push(thread);
  await writeThreads(threads);
  return thread;
};

export const addReply = async (
  threadId: string,
  input: CreateReplyInput
): Promise<Reply | null> => {
  const threads = await readThreads();
  const thread = threads.find((t) => t.id === threadId);
  if (!thread) return null;

  const reply: Reply = {
    id: generateId(),
    threadId,
    body: input.body,
    author: input.author,
    createdAt: new Date().toISOString(),
    votes: 0,
  };
  thread.replies.push(reply);
  await writeThreads(threads);
  return reply;
};

export const voteThread = async (
  threadId: string,
  direction: "up" | "down"
): Promise<Thread | null> => {
  const threads = await readThreads();
  const thread = threads.find((t) => t.id === threadId);
  if (!thread) return null;

  thread.votes += direction === "up" ? 1 : -1;
  await writeThreads(threads);
  return thread;
};

export const voteReply = async (
  threadId: string,
  replyId: string,
  direction: "up" | "down"
): Promise<Reply | null> => {
  const threads = await readThreads();
  const thread = threads.find((t) => t.id === threadId);
  if (!thread) return null;

  const reply = thread.replies.find((r) => r.id === replyId);
  if (!reply) return null;

  reply.votes += direction === "up" ? 1 : -1;
  await writeThreads(threads);
  return reply;
};

