import type { SortMode, VoteInput } from "./types";
import {
  getAllThreads,
  getThread,
  createThread,
  addReply,
  voteThread,
  voteReply,
} from "./store";
import { renderThreadList, renderNewThreadForm, renderThreadDetail } from "./ui";

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });

const htmlResponse = (html: string, status = 200): Response =>
  new Response(html, {
    status,
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });

const redirect = (path: string): Response =>
  new Response(null, { status: 303, headers: { Location: path } });

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text();
  const params = new URLSearchParams(text);
  const result: Record<string, string> = {};
  for (const [key, value] of params.entries()) {
    result[key] = value;
  }
  return result;
};

const isJsonRequest = (req: Request): boolean => {
  const accept = req.headers.get("accept") ?? "";
  const contentType = req.headers.get("content-type") ?? "";
  return accept.includes("application/json") || contentType.includes("application/json");
};

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const { pathname } = url;
  const method = req.method;

  // GET / — thread list page
  if (method === "GET" && pathname === "/") {
    const sort = (url.searchParams.get("sort") as SortMode) || "newest";
    const search = url.searchParams.get("search") ?? "";
    const threads = await getAllThreads(sort, search || undefined);

    if (isJsonRequest(req)) {
      return jsonResponse(threads);
    }
    return htmlResponse(renderThreadList(threads, sort, search));
  }

  // GET /new — new thread form
  if (method === "GET" && pathname === "/new") {
    return htmlResponse(renderNewThreadForm());
  }

  // GET /threads — JSON API for thread list
  if (method === "GET" && pathname === "/threads") {
    const sort = (url.searchParams.get("sort") as SortMode) || "newest";
    const search = url.searchParams.get("search") ?? undefined;
    const threads = await getAllThreads(sort, search);
    return jsonResponse(threads);
  }

  // POST /threads — create thread
  if (method === "POST" && pathname === "/threads") {
    if (isJsonRequest(req)) {
      const body = await req.json();
      const thread = await createThread(body);
      return jsonResponse(thread, 201);
    }
    const form = await parseFormData(req);
    await createThread({
      title: form.title ?? "",
      body: form.body ?? "",
      author: form.author ?? "Anonymous",
    });
    return redirect("/");
  }

  // Match /threads/:id patterns
  const threadMatch = pathname.match(/^\/threads\/([^/]+)$/);
  if (threadMatch) {
    const threadId = threadMatch[1];

    // GET /threads/:id — thread detail
    if (method === "GET") {
      const thread = await getThread(threadId);
      if (!thread) return jsonResponse({ error: "Thread not found" }, 404);

      if (isJsonRequest(req)) {
        return jsonResponse(thread);
      }
      return htmlResponse(renderThreadDetail(thread));
    }
  }

  // POST /threads/:id/vote
  const voteMatch = pathname.match(/^\/threads\/([^/]+)\/vote$/);
  if (method === "POST" && voteMatch) {
    const threadId = voteMatch[1];
    let direction: "up" | "down";

    if (isJsonRequest(req)) {
      const body = (await req.json()) as VoteInput;
      direction = body.direction;
    } else {
      const form = await parseFormData(req);
      direction = form.direction as "up" | "down";
    }

    const thread = await voteThread(threadId, direction);
    if (!thread) return jsonResponse({ error: "Thread not found" }, 404);

    if (isJsonRequest(req)) {
      return jsonResponse(thread);
    }
    return redirect(req.headers.get("referer") ?? "/");
  }

  // POST /threads/:id/replies
  const replyMatch = pathname.match(/^\/threads\/([^/]+)\/replies$/);
  if (method === "POST" && replyMatch) {
    const threadId = replyMatch[1];

    if (isJsonRequest(req)) {
      const body = await req.json();
      const reply = await addReply(threadId, body);
      if (!reply) return jsonResponse({ error: "Thread not found" }, 404);
      return jsonResponse(reply, 201);
    }

    const form = await parseFormData(req);
    const reply = await addReply(threadId, {
      body: form.body ?? "",
      author: form.author ?? "Anonymous",
    });
    if (!reply) return jsonResponse({ error: "Thread not found" }, 404);
    return redirect(`/threads/${threadId}`);
  }

  // POST /threads/:id/replies/:replyId/vote
  const replyVoteMatch = pathname.match(
    /^\/threads\/([^/]+)\/replies\/([^/]+)\/vote$/
  );
  if (method === "POST" && replyVoteMatch) {
    const threadId = replyVoteMatch[1];
    const replyId = replyVoteMatch[2];
    let direction: "up" | "down";

    if (isJsonRequest(req)) {
      const body = (await req.json()) as VoteInput;
      direction = body.direction;
    } else {
      const form = await parseFormData(req);
      direction = form.direction as "up" | "down";
    }

    const reply = await voteReply(threadId, replyId, direction);
    if (!reply) return jsonResponse({ error: "Reply not found" }, 404);

    if (isJsonRequest(req)) {
      return jsonResponse(reply);
    }
    return redirect(req.headers.get("referer") ?? `/threads/${threadId}`);
  }

  return jsonResponse({ error: "Not found" }, 404);
};

import { handleRequest } from "./routes";

const PORT = Number(process.env.PORT) || 3000;

const server = Bun.serve({
  port: PORT,
  fetch: handleRequest,
});

console.log(`Discussion Forum running at http://localhost:${server.port}`);

