# Discussion Forum

A full-featured discussion forum module supporting threaded conversations with nested replies, community voting, and flexible sorting.

## Features

- **Create threads** with a title and body text, attributed to an author
- **Reply to threads** with one level of nested replies (replies to replies appear under the parent reply)
- **Vote** on threads and replies (upvote/downvote) to surface the best content
- **Sort threads** by newest, most upvoted, or most active (most recent reply)
- **Search** threads by title using a search bar
- **Thread list view** showing title, author, reply count, and vote score

## Data Model

- Threads: `{ id, title, body, author, votes, createdAt, updatedAt }`
- Replies: `{ id, threadId, parentReplyId?, body, author, votes, createdAt }`

## Usage

```ts
import { createThread, replyToThread, vote, listThreads } from "./forum";

// Create a thread
const thread = await createThread({ title: "Hello", body: "World", author: "alice" });

// Reply to a thread
const reply = await replyToThread({ threadId: thread.id, body: "Great post!", author: "bob" });

// Nested reply
const nested = await replyToThread({ threadId: thread.id, parentReplyId: reply.id, body: "Thanks!", author: "alice" });

// Vote
await vote({ targetId: thread.id, targetType: "thread", direction: "up" });

// List threads sorted by newest
const threads = await listThreads({ sort: "newest" });

// Search threads
const results = await listThreads({ sort: "newest", search: "Hello" });
```

export type Thread = {
  id: string;
  title: string;
  body: string;
  author: string;
  upvotes: number;
  downvotes: number;
  createdAt: string;
  updatedAt: string;
};

export type Reply = {
  id: string;
  threadId: string;
  parentReplyId: string | null;
  body: string;
  author: string;
  upvotes: number;
  downvotes: number;
  createdAt: string;
};

export type SortMode = "newest" | "most-upvoted" | "most-active";

export type VoteDirection = "up" | "down";

export type VoteTarget = "thread" | "reply";

export type CreateThreadInput = {
  title: string;
  body: string;
  author: string;
};

export type CreateReplyInput = {
  threadId: string;
  parentReplyId?: string | null;
  body: string;
  author: string;
};

export type VoteInput = {
  targetId: string;
  targetType: VoteTarget;
  direction: VoteDirection;
};

export type ListThreadsInput = {
  sort: SortMode;
  search?: string;
};

export type ThreadSummary = {
  id: string;
  title: string;
  author: string;
  replyCount: number;
  score: number;
  createdAt: string;
  updatedAt: string;
};

import type { Thread, Reply } from "./types";

const THREADS_PATH = "./data/threads.json";
const REPLIES_PATH = "./data/replies.json";

const readJson = async <T>(path: string, fallback: T): Promise<T> => {
  const file = Bun.file(path);
  if (!(await file.exists())) {
    await Bun.write(path, JSON.stringify(fallback, null, 2));
    return fallback;
  }
  return file.json() as Promise<T>;
};

const writeJson = async <T>(path: string, data: T): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2));
};

export const loadThreads = (): Promise<Thread[]> => readJson(THREADS_PATH, []);

export const saveThreads = (threads: Thread[]): Promise<void> =>
  writeJson(THREADS_PATH, threads);

export const loadReplies = (): Promise<Reply[]> => readJson(REPLIES_PATH, []);

export const saveReplies = (replies: Reply[]): Promise<void> =>
  writeJson(REPLIES_PATH, replies);

import type {
  Thread,
  Reply,
  CreateThreadInput,
  CreateReplyInput,
  VoteInput,
  ListThreadsInput,
  ThreadSummary,
  SortMode,
} from "./types";
import { loadThreads, saveThreads, loadReplies, saveReplies } from "./store";

const generateId = (): string => crypto.randomUUID();

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const threads = await loadThreads();
  const now = new Date().toISOString();
  const thread: Thread = {
    id: generateId(),
    title: input.title.trim(),
    body: input.body.trim(),
    author: input.author.trim(),
    upvotes: 0,
    downvotes: 0,
    createdAt: now,
    updatedAt: now,
  };
  threads.push(thread);
  await saveThreads(threads);
  return thread;
};

export const getThread = async (threadId: string): Promise<Thread | null> => {
  const threads = await loadThreads();
  return threads.find((t) => t.id === threadId) ?? null;
};

export const replyToThread = async (input: CreateReplyInput): Promise<Reply> => {
  const threads = await loadThreads();
  const thread = threads.find((t) => t.id === input.threadId);
  if (!thread) {
    throw new Error(`Thread not found: ${input.threadId}`);
  }

  if (input.parentReplyId) {
    const replies = await loadReplies();
    const parent = replies.find((r) => r.id === input.parentReplyId);
    if (!parent) {
      throw new Error(`Parent reply not found: ${input.parentReplyId}`);
    }
    if (parent.parentReplyId !== null) {
      throw new Error("Nesting limited to one level deep");
    }
  }

  const reply: Reply = {
    id: generateId(),
    threadId: input.threadId,
    parentReplyId: input.parentReplyId ?? null,
    body: input.body.trim(),
    author: input.author.trim(),
    upvotes: 0,
    downvotes: 0,
    createdAt: new Date().toISOString(),
  };

  const replies = await loadReplies();
  replies.push(reply);
  await saveReplies(replies);

  thread.updatedAt = reply.createdAt;
  await saveThreads(threads);

  return reply;
};

export const vote = async (input: VoteInput): Promise<void> => {
  if (input.targetType === "thread") {
    const threads = await loadThreads();
    const thread = threads.find((t) => t.id === input.targetId);
    if (!thread) throw new Error(`Thread not found: ${input.targetId}`);
    if (input.direction === "up") thread.upvotes += 1;
    else thread.downvotes += 1;
    await saveThreads(threads);
  } else {
    const replies = await loadReplies();
    const reply = replies.find((r) => r.id === input.targetId);
    if (!reply) throw new Error(`Reply not found: ${input.targetId}`);
    if (input.direction === "up") reply.upvotes += 1;
    else reply.downvotes += 1;
    await saveReplies(replies);
  }
};

const getScore = (item: { upvotes: number; downvotes: number }): number =>
  item.upvotes - item.downvotes;

const getLatestReplyTime = (threadId: string, replies: Reply[]): string => {
  const threadReplies = replies.filter((r) => r.threadId === threadId);
  if (threadReplies.length === 0) return "";
  return threadReplies.reduce((latest, r) =>
    r.createdAt > latest.createdAt ? r : latest
  ).createdAt;
};

const sortThreads = (threads: Thread[], replies: Reply[], mode: SortMode): Thread[] => {
  const sorted = [...threads];
  switch (mode) {
    case "newest":
      return sorted.sort((a, b) => b.createdAt.localeCompare(a.createdAt));
    case "most-upvoted":
      return sorted.sort((a, b) => getScore(b) - getScore(a));
    case "most-active": {
      return sorted.sort((a, b) => {
        const aLatest = getLatestReplyTime(a.id, replies) || a.createdAt;
        const bLatest = getLatestReplyTime(b.id, replies) || b.createdAt;
        return bLatest.localeCompare(aLatest);
      });
    }
  }
};

export const listThreads = async (
  input: ListThreadsInput
): Promise<ThreadSummary[]> => {
  const [threads, replies] = await Promise.all([loadThreads(), loadReplies()]);

  let filtered = threads;
  if (input.search) {
    const query = input.search.toLowerCase();
    filtered = threads.filter((t) => t.title.toLowerCase().includes(query));
  }

  const sorted = sortThreads(filtered, replies, input.sort);

  return sorted.map((t) => ({
    id: t.id,
    title: t.title,
    author: t.author,
    replyCount: replies.filter((r) => r.threadId === t.id).length,
    score: getScore(t),
    createdAt: t.createdAt,
    updatedAt: t.updatedAt,
  }));
};

export const getThreadReplies = async (
  threadId: string
): Promise<Reply[]> => {
  const replies = await loadReplies();
  return replies
    .filter((r) => r.threadId === threadId)
    .sort((a, b) => a.createdAt.localeCompare(b.createdAt));
};

import type { SortMode, VoteDirection, VoteTarget } from "./types";
import {
  createThread,
  getThread,
  replyToThread,
  vote,
  listThreads,
  getThreadReplies,
} from "./forum";
import {
  renderThreadList,
  renderNewThreadForm,
  renderThreadDetail,
} from "./views";

const html = (body: string): Response =>
  new Response(
    `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Discussion Forum</title></head><body style="margin:0;background:#f3f4f6">${body}</body></html>`,
    { headers: { "Content-Type": "text/html; charset=utf-8" } }
  );

const redirect = (url: string): Response =>
  new Response(null, { status: 302, headers: { Location: url } });

const parseForm = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text();
  const params = new URLSearchParams(text);
  const result: Record<string, string> = {};
  params.forEach((value, key) => {
    result[key] = value;
  });
  return result;
};

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const { pathname } = url;
  const method = req.method;

  // GET / — thread list
  if (pathname === "/" && method === "GET") {
    const sort = (url.searchParams.get("sort") as SortMode) || "newest";
    const search = url.searchParams.get("search") || "";
    const threads = await listThreads({ sort, search });
    return html(renderThreadList(threads, sort, search));
  }

  // GET /new — new thread form
  if (pathname === "/new" && method === "GET") {
    return html(renderNewThreadForm());
  }

  // POST /thread — create thread
  if (pathname === "/thread" && method === "POST") {
    const form = await parseForm(req);
    await createThread({
      title: form.title || "Untitled",
      body: form.body || "",
      author: form.author || "Anonymous",
    });
    return redirect("/");
  }

  // GET /thread/:id — thread detail
  const threadMatch = pathname.match(/^\/thread\/([a-f0-9-]+)$/);
  if (threadMatch && method === "GET") {
    const thread = await getThread(threadMatch[1]);
    if (!thread) return new Response("Thread not found", { status: 404 });
    const replies = await getThreadReplies(thread.id);
    return html(renderThreadDetail(thread, replies));
  }

  // POST /thread/:id/reply — add reply
  const replyMatch = pathname.match(/^\/thread\/([a-f0-9-]+)\/reply$/);
  if (replyMatch && method === "POST") {
    const form = await parseForm(req);
    await replyToThread({
      threadId: replyMatch[1],
      parentReplyId: form.parentReplyId || null,
      body: form.body || "",
      author: form.author || "Anonymous",
    });
    return redirect(`/thread/${replyMatch[1]}`);
  }

  // POST /vote — vote on thread or reply
  if (pathname === "/vote" && method === "POST") {
    const form = await parseForm(req);
    await vote({
      targetId: form.targetId,
      targetType: (form.targetType as VoteTarget) || "thread",
      direction: (form.direction as VoteDirection) || "up",
    });
    return redirect(form.returnTo || "/");
  }

  return new Response("Not found", { status: 404 });
};

