export type Category = 'length' | 'weight' | 'temperature' | 'volume' | 'time'

export type UnitDef = {
  symbol: string
  name: string
  toBase: (v: number) => number
  fromBase: (v: number) => number
  formulaToBase: string
  formulaFromBase: string
}

export type CategoryDef = {
  label: string
  baseUnit: string
  units: UnitDef[]
}

const linearUnit = (symbol: string, name: string, factor: number): UnitDef => ({
  symbol,
  name,
  toBase: (v) => v * factor,
  fromBase: (v) => v / factor,
  formulaToBase: factor === 1 ? `{v}` : `{v} * ${factor}`,
  formulaFromBase: factor === 1 ? `{v}` : `{v} / ${factor}`,
})

export const categories: Record<Category, CategoryDef> = {
