export type ConversionResult = {
  fromValue: number
  fromUnit: string
  toValue: number
  toUnit: string
  formula: string
  category: Category
}

const buildFormula = (
  fromUnit: UnitDef,
  toUnit: UnitDef,
  value: number,
  baseUnit: string,
): string => {
  if (fromUnit.symbol === toUnit.symbol) {
    return `${value} ${fromUnit.symbol} = ${value} ${toUnit.symbol} (same unit)`
  }

  const toBaseFormula = fromUnit.formulaToBase.replace(/\{v\}/g, String(value))
  const baseValue = fromUnit.toBase(value)
  const fromBaseFormula = toUnit.formulaFromBase.replace(/\{v\}/g, String(roundSmart(baseValue)))

  return `${value} ${fromUnit.symbol} → ${roundSmart(baseValue)} ${baseUnit} → ${roundSmart(toUnit.fromBase(baseValue))} ${toUnit.symbol}  [${toBaseFormula} = ${roundSmart(baseValue)} ${baseUnit}, then ${fromBaseFormula}]`
}

const roundSmart = (v: number): number => {
  if (Number.isInteger(v)) return v
  return Math.round(v * 1e8) / 1e8
}

export const convert = (
  category: Category,
  value: number,
  fromSymbol: string,
  toSymbol: string,
): ConversionResult => {
  const cat = categories[category]
  if (!cat) throw new Error(`Unknown category: ${category}`)

  const fromUnit = cat.units.find((u) => u.symbol === fromSymbol)
  const toUnit = cat.units.find((u) => u.symbol === toSymbol)
  if (!fromUnit) throw new Error(`Unknown unit: ${fromSymbol}`)
  if (!toUnit) throw new Error(`Unknown unit: ${toSymbol}`)

  const baseValue = fromUnit.toBase(value)
  const toValue = roundSmart(toUnit.fromBase(baseValue))

  return {
    fromValue: value,
    fromUnit: fromSymbol,
    toValue,
    toUnit: toSymbol,
    formula: buildFormula(fromUnit, toUnit, value, cat.baseUnit),
    category,
  }
}

import { convert, categories, type Category } from './conversions'
import { renderPage } from './ui'

const validCategories = Object.keys(categories) as Category[]

const isCategory = (v: string): v is Category => validCategories.includes(v as Category)

const parseQuery = (url: URL) => {
  const category = url.searchParams.get('category') ?? 'length'
  const value = url.searchParams.get('value')
  const from = url.searchParams.get('from')
  const to = url.searchParams.get('to')
  return { category, value, from, to }
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: (req) => {
    const url = new URL(req.url)
    const path = url.pathname

    if (path === '/convert') {
      const { category, value, from, to } = parseQuery(url)

      if (!isCategory(category)) {
        return new Response('Invalid category', { status: 400 })
      }

      const numValue = Number(value ?? '1')
      if (Number.isNaN(numValue)) {
        return new Response('Invalid value', { status: 400 })
      }

      const cat = categories[category]
      const fromUnit = from ?? cat.units[0].symbol
      const toUnit = to ?? cat.units[1]?.symbol ?? cat.units[0].symbol

      const acceptsJson = req.headers.get('accept')?.includes('application/json')

      try {
        const result = convert(category, numValue, fromUnit, toUnit)

        if (acceptsJson) {
          return Response.json(result)
        }

        const html = renderPage(category, result, fromUnit, toUnit, String(numValue))
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      } catch (err) {
        const msg = err instanceof Error ? err.message : 'Conversion error'
        return new Response(msg, { status: 400 })
      }
    }

    // Default: render the form
    const { category } = parseQuery(url)
    const activeCategory: Category = isCategory(category) ? category : 'length'
    const html = renderPage(activeCategory)
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  },
})

console.log(`Unit Converter running at http://localhost:${server.port}`)

