export const categoryKeys: Category[] = ["length", "weight", "temperature", "volume", "time"];

import { categories, type Category, type UnitDef } from "./units";

export type ConversionResult = {
  inputValue: number;
  outputValue: number;
  fromUnit: UnitDef;
  toUnit: UnitDef;
  formula: string;
};

const findUnit = (category: Category, symbol: string): UnitDef | undefined =>
  categories[category].units.find((u) => u.symbol === symbol);

const formatNumber = (n: number): string => {
  if (Number.isInteger(n)) return n.toString();
  const abs = Math.abs(n);
  if (abs >= 1) return parseFloat(n.toFixed(6)).toString();
  if (abs >= 0.0001) return parseFloat(n.toFixed(8)).toString();
  return n.toExponential(6);
};

const buildFormula = (
  fromUnit: UnitDef,
  toUnit: UnitDef,
  baseUnitSymbol: string,
): string => {
  if (fromUnit.symbol === toUnit.symbol) return `1 ${fromUnit.symbol} = 1 ${toUnit.symbol}`;

  const fromIsBase = fromUnit.formulaToBase === "v";
  const toIsBase = toUnit.formulaToBase === "v";

  if (fromIsBase) {
    return `${toUnit.symbol} = ${toUnit.formulaFromBase.replace(/v/g, fromUnit.symbol)}`;
  }
  if (toIsBase) {
    return `${baseUnitSymbol} = ${fromUnit.formulaToBase.replace(/v/g, fromUnit.symbol)}`;
  }

  return `${fromUnit.symbol} → ${baseUnitSymbol}: ${fromUnit.formulaToBase.replace(/v/g, fromUnit.symbol)}, then ${baseUnitSymbol} → ${toUnit.symbol}: ${toUnit.formulaFromBase.replace(/v/g, baseUnitSymbol)}`;
};

export const convert = (
  category: Category,
  fromSymbol: string,
  toSymbol: string,
  value: number,
): ConversionResult | null => {
  const fromUnit = findUnit(category, fromSymbol);
  const toUnit = findUnit(category, toSymbol);
  if (!fromUnit || !toUnit) return null;

  const baseValue = fromUnit.toBase(value);
  const outputValue = toUnit.fromBase(baseValue);
  const baseUnitSymbol = categories[category].baseUnit;

  return {
    inputValue: value,
    outputValue,
    fromUnit,
    toUnit,
    formula: buildFormula(fromUnit, toUnit, baseUnitSymbol),
  };
};

export const formatResult = (result: ConversionResult): string =>
  `${formatNumber(result.inputValue)} ${result.fromUnit.symbol} = ${formatNumber(result.outputValue)} ${result.toUnit.symbol}`;

