  const from = fromSymbol ?? cat.units[0].symbol;
  const to = toSymbol ?? (cat.units.length > 1 ? cat.units[1].symbol : cat.units[0].symbol);
  const numValue = parseFloat(value) || 0;
  const result = convert(activeCategory, from, to, numValue);

  return h("div", { style: styles.container },
    h("h1", { style: styles.title }, "Unit Converter"),
    renderTabs(activeCategory),
    renderForm(activeCategory, from, to, value),
