// Base-unit conversion factors: each unit maps to its equivalent in the base unit
// Length base: meters
const lengthFactors: Record<string, number> = {
  mm: 0.001,
  cm: 0.01,
  m: 1,
  km: 1000,
  in: 0.0254,
  ft: 0.3048,
  yd: 0.9144,
  mi: 1609.344,
}

// Weight base: grams
const weightFactors: Record<string, number> = {
  mg: 0.001,
  g: 1,
  kg: 1000,
  lb: 453.592,
  oz: 28.3495,
}

// Volume base: milliliters
const volumeFactors: Record<string, number> = {
  ml: 1,
  l: 1000,
  gal: 3785.41,
  qt: 946.353,
  pt: 473.176,
  cup: 236.588,
  tbsp: 14.7868,
  tsp: 4.92892,
}

// Time base: seconds
const timeFactors: Record<string, number> = {
  ms: 0.001,
  s: 1,
  min: 60,
  hr: 3600,
  day: 86400,
  week: 604800,
}

const factorTables: Record<Exclude<Category, 'temperature'>, Record<string, number>> = {
  length: lengthFactors,
  weight: weightFactors,
  volume: volumeFactors,
  time: timeFactors,
}

