const convertTemperature = (value: number, from: string, to: string): { result: number; formula: string } => {
  if (from === to) return { result: value, formula: `${from} = ${to}` }

  const conversions: Record<string, { result: number; formula: string }> = {
    'C-F': { result: (value * 9) / 5 + 32, formula: '°F = (°C × 9/5) + 32' },
    'C-K': { result: value + 273.15, formula: 'K = °C + 273.15' },
    'F-C': { result: ((value - 32) * 5) / 9, formula: '°C = (°F − 32) × 5/9' },
    'F-K': { result: ((value - 32) * 5) / 9 + 273.15, formula: 'K = (°F − 32) × 5/9 + 273.15' },
    'K-C': { result: value - 273.15, formula: '°C = K − 273.15' },
    'K-F': { result: ((value - 273.15) * 9) / 5 + 32, formula: '°F = (K − 273.15) × 9/5 + 32' },
  }

  const key = `${from}-${to}`
  return conversions[key] ?? { result: value, formula: 'unknown' }
}

const formatNumber = (n: number): string => {
  if (Number.isInteger(n)) return n.toString()
  const fixed = n.toPrecision(10)
  return parseFloat(fixed).toString()
}

const buildFactorFormula = (from: string, to: string, factor: number): string => {
  if (factor === 1) return `${from} = ${to}`
  if (factor >= 1) return `1 ${from} = ${formatNumber(factor)} ${to}`
  return `1 ${from} = ${formatNumber(factor)} ${to}`
}

export const convert = (value: number, from: string, to: string, category: Category): ConversionResult => {
  if (from === to) {
    return {
      fromValue: value,
      toValue: value,
      fromUnit: from,
      toUnit: to,
      formula: `${from} = ${to} (same unit)`,
    }
  }

  if (category === 'temperature') {
    const { result, formula } = convertTemperature(value, from, to)
    return {
      fromValue: value,
      toValue: result,
      fromUnit: from,
      toUnit: to,
      formula,
    }
  }

  const table = factorTables[category]
  const fromFactor = table[from]
  const toFactor = table[to]
  const baseValue = value * fromFactor
  const toValue = baseValue / toFactor
  const combinedFactor = fromFactor / toFactor

  return {
    fromValue: value,
    toValue,
    fromUnit: from,
    toUnit: to,
    formula: buildFactorFormula(from, to, combinedFactor),
  }
}

