const styleToStr = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}: ${v}`
    })
    .join('; ')

const formatResult = (n: number): string => {
  if (Number.isNaN(n) || !Number.isFinite(n)) return '—'
  if (Number.isInteger(n)) return n.toLocaleString()
  if (Math.abs(n) < 0.0001 || Math.abs(n) > 1e12) return n.toExponential(4)
  return parseFloat(n.toPrecision(8)).toLocaleString(undefined, { maximumFractionDigits: 8 })
}

