import { type Category, categories, units, convert } from './converter.js'
import { type ConverterState, getDefaultState, renderConverter } from './ui.js'

export { convert, units, categories }
export type { Category, ConverterState }

export const createConverter = () => {
  let state: ConverterState = getDefaultState('length')

  const setCategory = (category: Category) => {
    state = getDefaultState(category)
  }

  const setValue = (value: string) => {
    state = { ...state, value }
  }

  const setFromUnit = (unit: string) => {
    state = { ...state, fromUnit: unit }
  }

  const setToUnit = (unit: string) => {
    state = { ...state, toUnit: unit }
  }

  const swapUnits = () => {
    state = { ...state, fromUnit: state.toUnit, toUnit: state.fromUnit }
  }

  const getResult = () => {
    const numValue = parseFloat(state.value)
    if (Number.isNaN(numValue)) return null
    return convert(numValue, state.fromUnit, state.toUnit, state.category)
  }

  const render = (): string => renderConverter(state)

  const getState = (): ConverterState => ({ ...state })

  const handleEvent = (trigger: string, payload?: string) => {
    if (trigger.startsWith('category-')) {
      const cat = trigger.replace('category-', '') as Category
      if (categories.some((c) => c.key === cat)) {
        setCategory(cat)
      }
    } else if (trigger === 'value-change') {
      setValue(payload ?? '')
    } else if (trigger === 'from-change') {
      setFromUnit(payload ?? state.fromUnit)
    } else if (trigger === 'to-change') {
      setToUnit(payload ?? state.toUnit)
    } else if (trigger === 'swap-units') {
      swapUnits()
    }
  }

  return {
    setCategory,
    setValue,
    setFromUnit,
    setToUnit,
    swapUnits,
    getResult,
    getState,
    render,
    handleEvent,
  }
}

