  { id: 'transport', name: 'Transport', color: '#607D8B' },
]

export const getCategoryColor = (categories: MarkerCategory[], categoryId: string): string => {
  const cat = categories.find((c) => c.id === categoryId)
  return cat?.color ?? '#2196F3'
}

import type { MapMarker, MapCircle, MapState } from './types'
import { DEFAULT_CATEGORIES } from './categories'

const MARKERS_PATH = './data/markers.json'
const CIRCLES_PATH = './data/circles.json'

const readJson = async <T>(path: string, fallback: T): Promise<T> => {
  try {
    const file = Bun.file(path)
    if (await file.exists()) {
      return (await file.json()) as T
    }
  } catch {
    // fall through
  }
  return fallback
}

const writeJson = async <T>(path: string, data: T): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2))
}

export const loadState = async (): Promise<MapState> => {
  const [markers, circles] = await Promise.all([
    readJson<MapMarker[]>(MARKERS_PATH, []),
    readJson<MapCircle[]>(CIRCLES_PATH, []),
  ])
  return { markers, circles, categories: DEFAULT_CATEGORIES }
}

export const saveMarkers = async (markers: MapMarker[]): Promise<void> => {
  await writeJson(MARKERS_PATH, markers)
}

export const saveCircles = async (circles: MapCircle[]): Promise<void> => {
  await writeJson(CIRCLES_PATH, circles)
}

