            ),
            h('div', { style: styleToString(styles.modalActions as Record<string, string>) },
              h('button', { style: styleToString(styles.btnSecondary), id: 'circle-cancel' }, 'Cancel'),
              h('button', { style: styleToString(styles.btnPrimary), id: 'circle-save' }, 'Save'),
            ),
          ),
        ),
        // Client script
        h('script', {}, `
          (function() {
            const categories = ${categoriesJson};
            let markers = ${markersJson};
            let circles = ${circlesJson};
            let leafletMarkers = {};
            let leafletCircles = {};
            let activeFilters = new Set(categories.map(c => c.id));
            let addMode = null; // null | 'marker' | 'circle'
            let pendingLatLng = null;

            // Init map
            const map = L.map('map').setView([51.505, -0.09], 13);
            L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
              attribution: '&copy; OpenStreetMap contributors',
              maxZoom: 19,
            }).addTo(map);

            // Colored marker icon factory
            const createIcon = (color) => {
              const svg = \`<svg xmlns="http://www.w3.org/2000/svg" width="25" height="41" viewBox="0 0 25 41">
                <path d="M12.5 0C5.6 0 0 5.6 0 12.5C0 21.9 12.5 41 12.5 41S25 21.9 25 12.5C25 5.6 19.4 0 12.5 0Z" fill="\${color}"/>
                <circle cx="12.5" cy="12.5" r="6" fill="white" opacity="0.9"/>
              </svg>\`;
              return L.divIcon({
                html: svg,
                iconSize: [25, 41],
                iconAnchor: [12, 41],
                popupAnchor: [0, -35],
                className: '',
              });
            };

            const getCategoryColor = (catId) => {
              const cat = categories.find(c => c.id === catId);
              return cat ? cat.color : '#2196F3';
            };

            const getCategoryName = (catId) => {
              const cat = categories.find(c => c.id === catId);
              return cat ? cat.name : 'General';
            };

            // Render category filters
            const renderFilters = () => {
              const container = document.getElementById('category-filters');
              container.innerHTML = '';
              categories.forEach(cat => {
                const item = document.createElement('label');
                item.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:4px;font-size:13px;cursor:pointer;';
                const cb = document.createElement('input');
                cb.type = 'checkbox';
                cb.checked = activeFilters.has(cat.id);
                cb.addEventListener('change', () => {
                  if (cb.checked) activeFilters.add(cat.id);
                  else activeFilters.delete(cat.id);
                  updateVisibility();
                });
                const dot = document.createElement('span');
                dot.style.cssText = 'width:10px;height:10px;border-radius:50%;display:inline-block;flex-shrink:0;background-color:' + cat.color;
                item.appendChild(cb);
                item.appendChild(dot);
                item.appendChild(document.createTextNode(' ' + cat.name));
                container.appendChild(item);
              });
            };

            // Add marker to map
            const addMarkerToMap = (m) => {
              const color = getCategoryColor(m.categoryId);
              const icon = createIcon(color);
              const lm = L.marker([m.lat, m.lng], { icon }).addTo(map);
              lm.bindPopup(
                '<div class="popup-title">' + escapeHtml(m.title) + '</div>' +
                '<div class="popup-desc">' + escapeHtml(m.description) + '</div>' +
                '<div class="popup-category">' + escapeHtml(getCategoryName(m.categoryId)) + '</div>'
              );
              leafletMarkers[m.id] = lm;
            };

            // Add circle to map
            const addCircleToMap = (c) => {
              const lc = L.circle([c.lat, c.lng], {
                radius: c.radius,
                color: c.color,
                fillColor: c.color,
                fillOpacity: 0.15,
                weight: 2,
              }).addTo(map);
              if (c.label) lc.bindPopup('<b>' + escapeHtml(c.label) + '</b>');
              leafletCircles[c.id] = lc;
            };

            // Render sidebar marker list
            const renderMarkerList = () => {
              const container = document.getElementById('marker-list');
              container.innerHTML = '';
              const visible = markers.filter(m => activeFilters.has(m.categoryId));
              if (visible.length === 0) {
                container.innerHTML = '<div style="padding:16px;color:#999;font-size:13px;">No markers yet. Click "+ Marker" to add one.</div>';
                return;
              }
              // Group by category
              const grouped = {};
              visible.forEach(m => {
                if (!grouped[m.categoryId]) grouped[m.categoryId] = [];
                grouped[m.categoryId].push(m);
              });
              Object.keys(grouped).forEach(catId => {
                const catName = getCategoryName(catId);
                const catColor = getCategoryColor(catId);
                const header = document.createElement('div');
                header.style.cssText = 'padding:8px 16px;font-size:11px;font-weight:600;text-transform:uppercase;color:#6c757d;display:flex;align-items:center;gap:6px;';
                const hdot = document.createElement('span');
                hdot.style.cssText = 'width:8px;height:8px;border-radius:50%;background:' + catColor;
                header.appendChild(hdot);
                header.appendChild(document.createTextNode(catName));
                container.appendChild(header);

                grouped[catId].forEach(m => {
                  const item = document.createElement('div');
                  item.className = 'marker-item';
                  item.style.cssText = 'padding:10px 16px;cursor:pointer;display:flex;align-items:flex-start;gap:10px;border-bottom:1px solid #e9ecef;';
                  item.addEventListener('click', () => {
                    map.setView([m.lat, m.lng], 16, { animate: true });
                    const lm = leafletMarkers[m.id];
                    if (lm) lm.openPopup();
                  });
                  const dot = document.createElement('span');
                  dot.style.cssText = 'width:10px;height:10px;border-radius:50%;margin-top:4px;flex-shrink:0;background:' + catColor;
                  const info = document.createElement('div');
                  info.innerHTML = '<div style="font-size:14px;font-weight:500;margin-bottom:2px;">' + escapeHtml(m.title) + '</div>' +
                    '<p style="font-size:12px;color:#6c757d;margin:0;">' + escapeHtml(m.description) + '</p>';
                  item.appendChild(dot);
                  item.appendChild(info);
                  container.appendChild(item);
                });
              });
            };

            const updateVisibility = () => {
              markers.forEach(m => {
                const lm = leafletMarkers[m.id];
                if (!lm) return;
                if (activeFilters.has(m.categoryId)) {
                  if (!map.hasLayer(lm)) map.addLayer(lm);
                } else {
                  if (map.hasLayer(lm)) map.removeLayer(lm);
                }
              });
              renderMarkerList();
            };

            const escapeHtml = (str) => {
              const div = document.createElement('div');
              div.textContent = str || '';
              return div.innerHTML;
            };

            const generateId = () => Date.now().toString(36) + Math.random().toString(36).slice(2, 7);

            // API helpers
            const apiPost = async (url, body) => {
              const res = await fetch(url, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(body),
              });
              return res.json();
            };

            // Search
            document.getElementById('search-input').addEventListener('keydown', async (e) => {
              if (e.key !== 'Enter') return;
              const q = e.target.value.trim();
              if (!q) return;
              try {
                const res = await fetch('/api/search?q=' + encodeURIComponent(q));
                const results = await res.json();
                if (results.length > 0) {
                  const r = results[0];
                  map.flyTo([r.lat, r.lng], 15, { animate: true });
                  L.popup()
                    .setLatLng([r.lat, r.lng])
                    .setContent('<b>' + escapeHtml(r.displayName) + '</b>')
                    .openOn(map);
                }
              } catch (err) {
                console.error('Search failed:', err);
              }
            });

            // Add marker mode
            const btnAddMarker = document.getElementById('btn-add-marker');
            btnAddMarker.addEventListener('click', () => {
              if (addMode === 'marker') {
                addMode = null;
                btnAddMarker.style.cssText = '${styleToString(styles.btn)}';
              } else {
                addMode = 'marker';
                btnAddMarker.style.cssText = '${styleToString(styles.btnActive)}';
                document.getElementById('btn-add-circle').style.cssText = '${styleToString(styles.btn)}';
              }
            });

            // Add circle mode
            const btnAddCircle = document.getElementById('btn-add-circle');
            btnAddCircle.addEventListener('click', () => {
              if (addMode === 'circle') {
                addMode = null;
                btnAddCircle.style.cssText = '${styleToString(styles.btn)}';
              } else {
                addMode = 'circle';
                btnAddCircle.style.cssText = '${styleToString(styles.btnActive)}';
                btnAddMarker.style.cssText = '${styleToString(styles.btn)}';
              }
            });

            // Map click handler
            map.on('click', (e) => {
              if (!addMode) return;
              pendingLatLng = e.latlng;
              if (addMode === 'marker') {
                // Populate category select
                const sel = document.getElementById('marker-category');
                sel.innerHTML = '';
                categories.forEach(cat => {
                  const opt = document.createElement('option');
                  opt.value = cat.id;
                  opt.textContent = cat.name;
                  sel.appendChild(opt);
                });
                document.getElementById('marker-title').value = '';
                document.getElementById('marker-desc').value = '';
                document.getElementById('marker-modal').style.display = 'flex';
              } else if (addMode === 'circle') {
                document.getElementById('circle-label').value = '';
                document.getElementById('circle-radius').value = '500';
                document.getElementById('circle-color').value = '#0d6efd';
                document.getElementById('circle-modal').style.display = 'flex';
              }
            });

            // Marker modal
            document.getElementById('modal-cancel').addEventListener('click', () => {
              document.getElementById('marker-modal').style.display = 'none';
            });
            document.getElementById('modal-save').addEventListener('click', async () => {
              const title = document.getElementById('marker-title').value.trim();
              const desc = document.getElementById('marker-desc').value.trim();
              const catId = document.getElementById('marker-category').value;
              if (!title) return;
              const marker = {
                id: generateId(),
                lat: pendingLatLng.lat,
                lng: pendingLatLng.lng,
                title,
                description: desc,
                categoryId: catId,
              };
              markers.push(marker);
              addMarkerToMap(marker);
              renderMarkerList();
              document.getElementById('marker-modal').style.display = 'none';
              addMode = null;
              btnAddMarker.style.cssText = '${styleToString(styles.btn)}';
              await apiPost('/api/markers', marker);
            });

            // Circle modal
            document.getElementById('circle-cancel').addEventListener('click', () => {
              document.getElementById('circle-modal').style.display = 'none';
            });
            document.getElementById('circle-save').addEventListener('click', async () => {
              const label = document.getElementById('circle-label').value.trim();
              const radius = parseInt(document.getElementById('circle-radius').value, 10) || 500;
              const color = document.getElementById('circle-color').value;
              const circle = {
                id: generateId(),
                lat: pendingLatLng.lat,
                lng: pendingLatLng.lng,
                radius,
                color,
                label,
              };
              circles.push(circle);
              addCircleToMap(circle);
              document.getElementById('circle-modal').style.display = 'none';
              addMode = null;
              btnAddCircle.style.cssText = '${styleToString(styles.btn)}';
              await apiPost('/api/circles', circle);
            });

            // Init
            renderFilters();
            markers.forEach(addMarkerToMap);
            circles.forEach(addCircleToMap);
            renderMarkerList();

            // Fit bounds if we have markers
            if (markers.length > 0) {
              const group = L.featureGroup(Object.values(leafletMarkers));
              map.fitBounds(group.getBounds().pad(0.2));
            }
          })();
        `),
      ),
    )
  )

  return '<!DOCTYPE html>' + html
}

import { loadState, saveMarkers, saveCircles } from './store'
import { renderPage } from './render'
import type { MapMarker, MapCircle, SearchResult } from './types'

const PORT = Number(process.env.PORT) || 3000

const searchLocation = async (query: string): Promise<SearchResult[]> => {
  const url = `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(query)}&limit=5`
  const res = await fetch(url, {
    headers: { 'User-Agent': 'interactive-map-module/1.0' },
  })
  const data = (await res.json()) as Array<{ lat: string; lon: string; display_name: string }>
  return data.map((r) => ({
    lat: parseFloat(r.lat),
    lng: parseFloat(r.lon),
    displayName: r.display_name,
  }))
}

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const state = await loadState()

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url

    // Serve main page
    if (pathname === '/' && req.method === 'GET') {
      const html = renderPage(state)
      return htmlResponse(html)
    }

    // Search API
    if (pathname === '/api/search' && req.method === 'GET') {
      const q = url.searchParams.get('q') ?? ''
      if (!q) return jsonResponse([])
      const results = await searchLocation(q)
      return jsonResponse(results)
    }

    // Add marker
    if (pathname === '/api/markers' && req.method === 'POST') {
      const marker = (await req.json()) as MapMarker
      if (!marker.id || !marker.title || marker.lat == null || marker.lng == null) {
        return jsonResponse({ error: 'Invalid marker data' }, 400)
      }
      state.markers.push(marker)
      await saveMarkers(state.markers)
      return jsonResponse({ ok: true })
    }

    // Delete marker
    if (pathname.startsWith('/api/markers/') && req.method === 'DELETE') {
      const id = pathname.split('/').pop()
      state.markers = state.markers.filter((m) => m.id !== id)
      await saveMarkers(state.markers)
      return jsonResponse({ ok: true })
    }

    // Get all markers
    if (pathname === '/api/markers' && req.method === 'GET') {
      return jsonResponse(state.markers)
    }

    // Add circle
    if (pathname === '/api/circles' && req.method === 'POST') {
      const circle = (await req.json()) as MapCircle
      if (!circle.id || circle.lat == null || circle.lng == null) {
        return jsonResponse({ error: 'Invalid circle data' }, 400)
      }
      state.circles.push(circle)
      await saveCircles(state.circles)
      return jsonResponse({ ok: true })
    }

    // Delete circle
    if (pathname.startsWith('/api/circles/') && req.method === 'DELETE') {
      const id = pathname.split('/').pop()
      state.circles = state.circles.filter((c) => c.id !== id)
      await saveCircles(state.circles)
      return jsonResponse({ ok: true })
    }

    // Get all circles
    if (pathname === '/api/circles' && req.method === 'GET') {
      return jsonResponse(state.circles)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

