const categoryLabel = (cat: MarkerCategory): string => {
  const labels: Record<MarkerCategory, string> = {
    default: 'Default',
    food: 'Food & Drink',
    lodging: 'Lodging',
    shopping: 'Shopping',
    nature: 'Nature',
    transport: 'Transport',
    culture: 'Culture',
    danger: 'Danger',
  };
  return labels[cat];
};

const groupByCategory = (markers: MapMarker[]): Record<string, MapMarker[]> => {
  const groups: Record<string, MapMarker[]> = {};
  for (const m of markers) {
    const cat = m.category || 'default';
    if (!groups[cat]) groups[cat] = [];
    groups[cat].push(m);
  }
  return groups;
};

