const clientScript = (markers: MapMarker[]): string => `
(function() {
  const CATEGORY_COLORS = ${JSON.stringify(CATEGORY_COLORS)};
  const API = {
    getMarkers: () => fetch('/api/markers').then(r => r.json()),
    addMarker: (m) => fetch('/api/markers', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify(m) }).then(r => r.json()),
    deleteMarker: (id) => fetch('/api/markers/' + id, { method: 'DELETE' }).then(r => r.json()),
    getCircles: () => fetch('/api/circles').then(r => r.json()),
    addCircle: (c) => fetch('/api/circles', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify(c) }).then(r => r.json()),
    deleteCircle: (id) => fetch('/api/circles/' + id, { method: 'DELETE' }).then(r => r.json()),
    search: (q) => fetch('/api/search?q=' + encodeURIComponent(q)).then(r => r.json()),
  };

  let mode = 'marker';
  let pendingLatLng = null;
  const leafletMarkers = {};
  const leafletCircles = {};

  const map = L.map('map').setView([40.7128, -74.006], 12);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
    maxZoom: 19,
  }).addTo(map);

  const createIcon = (color) => L.divIcon({
    className: 'custom-marker',
    html: '<div style="width:24px;height:24px;border-radius:50% 50% 50% 0;background:' + color + ';transform:rotate(-45deg);border:2px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,0.3);"></div>',
    iconSize: [24, 24],
    iconAnchor: [12, 24],
    popupAnchor: [0, -24],
  });

  const addMarkerToMap = (m) => {
    const color = CATEGORY_COLORS[m.category] || CATEGORY_COLORS.default;
    const marker = L.marker([m.lat, m.lng], { icon: createIcon(color) })
      .bindPopup('<strong>' + escapeHtml(m.title) + '</strong><br>' + escapeHtml(m.description || ''))
      .addTo(map);
    leafletMarkers[m.id] = marker;
  };

  const addCircleToMap = (c) => {
    const circle = L.circle([c.lat, c.lng], {
      radius: c.radius,
      color: c.color,
      fillColor: c.color,
      fillOpacity: 0.15,
      weight: 2,
    }).addTo(map);
    if (c.label) circle.bindPopup(escapeHtml(c.label));
    leafletCircles[c.id] = circle;
  };

  const escapeHtml = (s) => {
    const d = document.createElement('div');
    d.textContent = s;
    return d.innerHTML;
  };

  // Load initial data
  const initialMarkers = ${JSON.stringify(markers)};
  initialMarkers.forEach(addMarkerToMap);

  API.getCircles().then(circles => circles.forEach(addCircleToMap));

  // Map click handler
  map.on('click', (e) => {
    pendingLatLng = e.latlng;
    if (mode === 'marker') {
      document.getElementById('marker-form').style.display = 'block';
      document.getElementById('circle-form').style.display = 'none';
      document.getElementById('form-title').value = '';
      document.getElementById('form-desc').value = '';
      document.getElementById('form-title').focus();
    } else {
      document.getElementById('circle-form').style.display = 'block';
      document.getElementById('marker-form').style.display = 'none';
      document.getElementById('circle-label').value = '';
      document.getElementById('circle-label').focus();
    }
  });

  // Mode buttons
  document.getElementById('mode-marker').addEventListener('click', () => {
    mode = 'marker';
    document.getElementById('mode-marker').classList.add('active');
    document.getElementById('mode-circle').classList.remove('active');
  });

  document.getElementById('mode-circle').addEventListener('click', () => {
    mode = 'circle';
    document.getElementById('mode-circle').classList.add('active');
    document.getElementById('mode-marker').classList.remove('active');
  });

  // Save marker
  document.getElementById('form-save').addEventListener('click', async () => {
    const title = document.getElementById('form-title').value.trim();
    if (!title || !pendingLatLng) return;
    const category = document.getElementById('category-select').value;
    const desc = document.getElementById('form-desc').value.trim();
    const marker = await API.addMarker({
      lat: pendingLatLng.lat,
      lng: pendingLatLng.lng,
      title,
      description: desc,
      category,
    });
    addMarkerToMap(marker);
    refreshSidebar();
    document.getElementById('marker-form').style.display = 'none';
    pendingLatLng = null;
  });

  document.getElementById('form-cancel').addEventListener('click', () => {
    document.getElementById('marker-form').style.display = 'none';
    pendingLatLng = null;
  });

  // Save circle
  document.getElementById('circle-save').addEventListener('click', async () => {
    if (!pendingLatLng) return;
    const label = document.getElementById('circle-label').value.trim();
    const radius = parseInt(document.getElementById('circle-radius').value, 10) || 500;
    const color = document.getElementById('circle-color').value;
    const circle = await API.addCircle({
      lat: pendingLatLng.lat,
      lng: pendingLatLng.lng,
      radius,
      color,
      label,
    });
    addCircleToMap(circle);
    document.getElementById('circle-form').style.display = 'none';
    pendingLatLng = null;
  });

  document.getElementById('circle-cancel').addEventListener('click', () => {
    document.getElementById('circle-form').style.display = 'none';
    pendingLatLng = null;
  });

  // Search
  const searchInput = document.getElementById('search-input');
  const searchResults = document.getElementById('search-results');

  document.getElementById('search-btn').addEventListener('click', async () => {
    const q = searchInput.value.trim();
    if (!q) return;
    const results = await API.search(q);
    searchResults.innerHTML = '';
    results.forEach(r => {
      const li = document.createElement('li');
      li.textContent = r.displayName;
      li.addEventListener('click', () => {
        map.setView([r.lat, r.lng], 14);
        searchResults.innerHTML = '';
        searchInput.value = r.displayName;
      });
      searchResults.appendChild(li);
    });
  });

  searchInput.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') document.getElementById('search-btn').click();
  });

  document.addEventListener('click', (e) => {
    if (!e.target.closest('.search-bar')) searchResults.innerHTML = '';
  });

  // Sidebar interactions
  const refreshSidebar = async () => {
    const markers = await API.getMarkers();
    const sidebar = document.getElementById('sidebar');
    const grouped = {};
    markers.forEach(m => {
      const cat = m.category || 'default';
      if (!grouped[cat]) grouped[cat] = [];
      grouped[cat].push(m);
    });

    const catLabels = {
      default:'Default', food:'Food & Drink', lodging:'Lodging', shopping:'Shopping',
      nature:'Nature', transport:'Transport', culture:'Culture', danger:'Danger'
    };

    let html = '<h2 class="sidebar-title">Markers</h2>';
    if (markers.length === 0) {
      html += '<p class="empty-msg">No markers yet. Click the map to add one.</p>';
    } else {
      Object.entries(grouped).sort(([a],[b]) => a.localeCompare(b)).forEach(([cat, ms]) => {
        const color = CATEGORY_COLORS[cat] || CATEGORY_COLORS.default;
        html += '<div class="category-group">';
        html += '<h3 class="category-heading"><span class="category-dot" style="background:' + color + '"></span>' + catLabels[cat] + '<span class="category-count">(' + ms.length + ')</span></h3>';
        html += '<ul class="marker-list">';
        ms.forEach(m => {
          html += '<li class="marker-item" data-id="' + m.id + '" data-lat="' + m.lat + '" data-lng="' + m.lng + '">';
          html += '<span class="marker-dot" style="background:' + color + '"></span>';
          html += '<span class="marker-title">' + escapeHtml(m.title) + '</span>';
          html += '<button class="delete-btn" data-id="' + m.id + '" title="Delete marker">&times;</button>';
          html += '</li>';
        });
        html += '</ul></div>';
      });
    }
    sidebar.innerHTML = html;
    bindSidebarEvents();
  };

  const bindSidebarEvents = () => {
    document.querySelectorAll('.marker-item').forEach(item => {
      item.addEventListener('click', (e) => {
        if (e.target.closest('.delete-btn')) return;
        const lat = parseFloat(item.dataset.lat);
        const lng = parseFloat(item.dataset.lng);
        const id = item.dataset.id;
        map.setView([lat, lng], 16);
        if (leafletMarkers[id]) leafletMarkers[id].openPopup();
      });
    });

    document.querySelectorAll('.delete-btn').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        e.stopPropagation();
        const id = btn.dataset.id;
        await API.deleteMarker(id);
        if (leafletMarkers[id]) {
          map.removeLayer(leafletMarkers[id]);
          delete leafletMarkers[id];
        }
        refreshSidebar();
      });
    });
  };

  bindSidebarEvents();
})();
`;

import { getMarkers, addMarker, deleteMarker, updateMarker, getCircles, addCircle, deleteCircle } from './store';
import { searchLocation } from './search';
import { renderPage } from './view';
import type { MapMarker, MapCircle, MarkerCategory } from './types';

const generateId = (): string => crypto.randomUUID();

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url);
    const path = url.pathname;
    const method = req.method;

    // Serve main page
    if (path === '/' && method === 'GET') {
      const markers = await getMarkers();
      return htmlResponse(renderPage(markers));
    }

    // Marker API
    if (path === '/api/markers' && method === 'GET') {
      return jsonResponse(await getMarkers());
    }

    if (path === '/api/markers' && method === 'POST') {
      const body = (await req.json()) as {
        lat: number;
        lng: number;
        title: string;
        description?: string;
        category?: MarkerCategory;
      };

      const marker: MapMarker = {
        id: generateId(),
        lat: body.lat,
        lng: body.lng,
        title: body.title,
        description: body.description || '',
        category: body.category || 'default',
        createdAt: new Date().toISOString(),
      };

      const saved = await addMarker(marker);
      return jsonResponse(saved, 201);
    }

    const markerMatch = path.match(/^\/api\/markers\/([^/]+)$/);
    if (markerMatch) {
      const id = markerMatch[1];

      if (method === 'DELETE') {
        const deleted = await deleteMarker(id);
        return deleted
          ? jsonResponse({ ok: true })
          : jsonResponse({ error: 'Not found' }, 404);
      }

      if (method === 'PATCH') {
        const body = (await req.json()) as Partial<MapMarker>;
        const updated = await updateMarker(id, body);
        return updated
          ? jsonResponse(updated)
          : jsonResponse({ error: 'Not found' }, 404);
      }
    }

    // Circle API
    if (path === '/api/circles' && method === 'GET') {
      return jsonResponse(await getCircles());
    }

    if (path === '/api/circles' && method === 'POST') {
      const body = (await req.json()) as {
        lat: number;
        lng: number;
        radius: number;
        color?: string;
        label?: string;
      };

      const circle: MapCircle = {
        id: generateId(),
        lat: body.lat,
        lng: body.lng,
        radius: body.radius || 500,
        color: body.color || '#2196F3',
        label: body.label || '',
        createdAt: new Date().toISOString(),
      };

      const saved = await addCircle(circle);
      return jsonResponse(saved, 201);
    }

    const circleMatch = path.match(/^\/api\/circles\/([^/]+)$/);
    if (circleMatch && method === 'DELETE') {
      const deleted = await deleteCircle(circleMatch[1]);
      return deleted
        ? jsonResponse({ ok: true })
        : jsonResponse({ error: 'Not found' }, 404);
    }

    // Search API
    if (path === '/api/search' && method === 'GET') {
      const query = url.searchParams.get('q') || '';
      if (!query) return jsonResponse([]);
      try {
        const results = await searchLocation(query);
        return jsonResponse(results);
      } catch (err) {
        return jsonResponse({ error: 'Search failed' }, 502);
      }
    }

    return jsonResponse({ error: 'Not found' }, 404);
  },
});

