const styleToString = (style: Record<string, string>): string =>
  Object.entries(style)
    .map(([key, value]) => {
      const cssKey = key.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
      return `${cssKey}: ${value}`;
    })
    .join('; ');

const renderMarkersByCategory = (state: MapState, filter: MarkerCategory | 'all') => {
  const filtered = filter === 'all'
    ? state.markers
    : state.markers.filter((m) => m.category === filter);

  if (filtered.length === 0) {
    return h('div', { style: styleToString(styles.emptyState as Record<string, string>) },
      h('p', {}, 'No markers yet'),
      h('p', { style: 'font-size: 12px' }, 'Click "Add Marker" to place one on the map'),
    );
  }

  const grouped = new Map<MarkerCategory, typeof filtered>();
  for (const marker of filtered) {
    const group = grouped.get(marker.category) ?? [];
    group.push(marker);
    grouped.set(marker.category, group);
  }

  return h(Fragment, {},
    ...Array.from(grouped.entries()).map(([category, markers]) =>
      h('div', { style: styleToString(styles.categoryGroup as Record<string, string>) },
        h('div', { style: styleToString(styles.categoryHeader as Record<string, string>) },
          h('span', {
            style: `${styleToString(styles.categoryDot as Record<string, string>)}; background-color: ${getCategoryColor(category)}`,
          }),
          getCategoryLabel(category),
          ` (${markers.length})`,
        ),
        ...markers.map((marker) =>
          h('div', {
            style: styleToString(styles.markerItem as Record<string, string>),
            'p-trigger': 'click:centerOnMarker',
            'data-marker-id': marker.id,
            'data-lat': String(marker.lat),
            'data-lng': String(marker.lng),
          },
            h('button', {
              style: styleToString(styles.deleteBtn as Record<string, string>),
              'p-trigger': 'click:deleteMarker',
              'data-marker-id': marker.id,
            }, '\u00D7'),
            h('p', { style: styleToString(styles.markerTitle as Record<string, string>) }, marker.title),
            marker.description
              ? h('p', { style: styleToString(styles.markerDesc as Record<string, string>) }, marker.description)
              : null,
            h('p', { style: styleToString(styles.markerCoords as Record<string, string>) },
              `${marker.lat.toFixed(5)}, ${marker.lng.toFixed(5)}`),
          ),
        ),
      ),
    ),
  );
};

