          // Load existing markers and circles
          var initialMarkers = ${JSON.stringify(state.markers)};
          var initialCircles = ${JSON.stringify(state.circles)};
          initialMarkers.forEach(addMarkerToMap);
          initialCircles.forEach(addCircleToMap);

          // Map click handler
