          document.getElementById('btn-add-marker').addEventListener('click', function() {
            mode = 'marker';
            pendingLat = null;
            pendingLng = null;
            document.getElementById('marker-title').value = '';
            document.getElementById('marker-desc').value = '';
            document.getElementById('marker-category').value = 'default';
            document.getElementById('marker-coords').textContent = 'Click on map to set position';
