            .then(function(marker) {
              addMarkerToMap(marker);
              refreshSidebar();
              mode = null;
              document.getElementById('marker-modal').style.display = 'none';
            });
          });

          // Add Circle button
          document.getElementById('btn-add-circle').addEventListener('click', function() {
            mode = 'circle';
            pendingLat = null;
            pendingLng = null;
            document.getElementById('circle-label').value = '';
            document.getElementById('circle-radius').value = '500';
            document.getElementById('circle-color').value = '#0d6efd';
            document.getElementById('circle-coords').textContent = 'Click on map to set center';
            document.getElementById('circle-modal').style.display = 'flex';
          });

          document.getElementById('circle-cancel').addEventListener('click', function() {
            mode = null;
            document.getElementById('circle-modal').style.display = 'none';
          });

          document.getElementById('circle-submit').addEventListener('click', function() {
            var label = document.getElementById('circle-label').value.trim();
            if (!label) { alert('Label is required'); return; }
            if (pendingLat === null) { alert('Click on the map to set a center point'); return; }

            var data = {
              label: label,
              radius: parseInt(document.getElementById('circle-radius').value, 10),
              color: document.getElementById('circle-color').value,
              lat: pendingLat,
              lng: pendingLng,
            };

            fetch('/api/circles', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify(data),
            })
            .then(function(r) { return r.json(); })
            .then(function(circle) {
              addCircleToMap(circle);
              refreshSidebar();
              mode = null;
              document.getElementById('circle-modal').style.display = 'none';
            });
          });

          // Search
          document.getElementById('search-form').addEventListener('submit', function(e) {
            e.preventDefault();
            var query = document.getElementById('search-input').value.trim();
            if (!query) return;

            fetch('/api/search?q=' + encodeURIComponent(query))
              .then(function(r) { return r.json(); })
