          // Sidebar click delegation
          document.getElementById('marker-list').addEventListener('click', function(e) {
            var deleteBtn = e.target.closest('[p-trigger="click:deleteMarker"]');
            if (deleteBtn) {
              e.stopPropagation();
              var id = deleteBtn.getAttribute('data-marker-id');
              fetch('/api/markers/' + id, { method: 'DELETE' })
                .then(function() {
                  if (markers[id]) {
                    map.removeLayer(markers[id]);
                    delete markers[id];
                  }
                  refreshSidebar();
                });
              return;
            }

            var markerItem = e.target.closest('[p-trigger="click:centerOnMarker"]');
            if (markerItem) {
              var lat = parseFloat(markerItem.getAttribute('data-lat'));
              var lng = parseFloat(markerItem.getAttribute('data-lng'));
              var markerId = markerItem.getAttribute('data-marker-id');
              map.flyTo([lat, lng], 17);
              if (markers[markerId]) {
                markers[markerId].openPopup();
              }
            }
          });

          function refreshSidebar() {
            var filter = document.getElementById('category-filter').value;
            fetch('/api/state')
              .then(function(r) { return r.json(); })
              .then(function(state) {
                var list = document.getElementById('marker-list');
                var filtered = filter === 'all'
                  ? state.markers
                  : state.markers.filter(function(m) { return m.category === filter; });

                if (filtered.length === 0) {
                  list.innerHTML = '<div style="text-align: center; padding: 32px 16px; color: #adb5bd;">' +
                    '<p>No markers yet</p><p style="font-size: 12px">Click "+ Marker" to place one on the map</p></div>';
                  return;
                }

                var grouped = {};
                filtered.forEach(function(m) {
                  if (!grouped[m.category]) grouped[m.category] = [];
                  grouped[m.category].push(m);
                });

                var html = '';
                Object.keys(grouped).forEach(function(cat) {
                  var color = categoryColors[cat] || categoryColors['default'];
                  var catLabel = cat.charAt(0).toUpperCase() + cat.slice(1);
                  html += '<div style="margin-bottom: 12px;">';
                  html += '<div style="display: flex; align-items: center; gap: 6px; padding: 6px 8px; font-size: 12px; font-weight: 600; text-transform: uppercase; color: #6c757d; letter-spacing: 0.5px;">';
                  html += '<span style="width: 10px; height: 10px; border-radius: 50%; display: inline-block; background-color: ' + color + ';"></span>';
                  html += catLabel + ' (' + grouped[cat].length + ')';
                  html += '</div>';

                  grouped[cat].forEach(function(marker) {
                    html += '<div class="marker-item" style="padding: 10px 12px; background-color: white; border-radius: 6px; margin-bottom: 4px; cursor: pointer; border: 1px solid #e9ecef;" p-trigger="click:centerOnMarker" data-marker-id="' + marker.id + '" data-lat="' + marker.lat + '" data-lng="' + marker.lng + '">';
                    html += '<button style="float: right; background: none; border: none; color: #dc3545; cursor: pointer; font-size: 14px; padding: 0 4px;" p-trigger="click:deleteMarker" data-marker-id="' + marker.id + '">&times;</button>';
                    html += '<p style="font-size: 14px; font-weight: 500; margin: 0 0 2px 0;">' + escapeHtml(marker.title) + '</p>';
                    if (marker.description) {
                      html += '<p style="font-size: 12px; color: #6c757d; margin: 0;">' + escapeHtml(marker.description) + '</p>';
                    }
                    html += '<p style="font-size: 11px; color: #adb5bd; margin: 2px 0 0 0;">' + marker.lat.toFixed(5) + ', ' + marker.lng.toFixed(5) + '</p>';
                    html += '</div>';
                  });

                  html += '</div>';
                });

                list.innerHTML = html;
              });
          }

          // Save map state on move
          map.on('moveend', function() {
            var center = map.getCenter();
            fetch('/api/center', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ lat: center.lat, lng: center.lng, zoom: map.getZoom() }),
            });
          });
        })();
      `),
    ),
  );

  return html;
};

import { loadState, addMarker, removeMarker, addCircle, removeCircle, updateCenter } from './store';
import { searchLocation } from './search';
import { renderPage } from './render';
import { createSSR } from '@plaited/template/ssr';
import type { MarkerCategory } from './types';

const PORT = 3000;

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;

    // API: Get full state
    if (pathname === '/api/state' && req.method === 'GET') {
      const state = await loadState();
      return Response.json(state);
    }

    // API: Add marker
    if (pathname === '/api/markers' && req.method === 'POST') {
      const body = await req.json() as {
        title: string;
        description: string;
        category: MarkerCategory;
        lat: number;
        lng: number;
      };
      const marker = await addMarker({
        title: body.title,
        description: body.description,
        category: body.category,
        lat: body.lat,
        lng: body.lng,
      });
      return Response.json(marker);
    }

    // API: Delete marker
    if (pathname.startsWith('/api/markers/') && req.method === 'DELETE') {
      const id = pathname.split('/api/markers/')[1];
      const removed = await removeMarker(id);
      return removed
        ? Response.json({ ok: true })
        : new Response('Not found', { status: 404 });
    }

    // API: Add circle
    if (pathname === '/api/circles' && req.method === 'POST') {
      const body = await req.json() as {
        label: string;
        radius: number;
        color: string;
        lat: number;
        lng: number;
      };
      const circle = await addCircle({
        lat: body.lat,
        lng: body.lng,
        radius: body.radius,
        label: body.label,
        color: body.color,
      });
      return Response.json(circle);
    }

    // API: Delete circle
    if (pathname.startsWith('/api/circles/') && req.method === 'DELETE') {
      const id = pathname.split('/api/circles/')[1];
      const removed = await removeCircle(id);
      return removed
        ? Response.json({ ok: true })
        : new Response('Not found', { status: 404 });
    }

    // API: Search location
    if (pathname === '/api/search' && req.method === 'GET') {
      const query = url.searchParams.get('q') ?? '';
      if (!query) {
        return Response.json([]);
      }
      const results = await searchLocation(query);
      return Response.json(results);
    }

    // API: Update center
    if (pathname === '/api/center' && req.method === 'POST') {
      const body = await req.json() as { lat: number; lng: number; zoom: number };
      await updateCenter(body.lat, body.lng, body.zoom);
      return Response.json({ ok: true });
    }

    // Main page
    if (pathname === '/' || pathname === '/index.html') {
      const state = await loadState();
      const template = renderPage(state);
      const html = createSSR(template);
      return new Response(`<!DOCTYPE html>${html}`, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    }

    return new Response('Not found', { status: 404 });
  },
});

