import type { CalendarEvent } from './types';

const DATA_PATH = `${import.meta.dir}/data/events.json`;

const generateId = (): string =>
  `evt_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

const readEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  if (!text.trim()) return [];
  return JSON.parse(text) as CalendarEvent[];
};

const writeEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2));
};

export const getAllEvents = async (): Promise<CalendarEvent[]> => {
  return readEvents();
};

export const getEventsForDate = async (date: string): Promise<CalendarEvent[]> => {
  const events = await readEvents();
  return events
    .filter((e) => e.date === date)
    .sort((a, b) => a.startTime.localeCompare(b.startTime));
};

export const getEventsForMonth = async (
  year: number,
  month: number,
): Promise<Map<string, CalendarEvent[]>> => {
  const events = await readEvents();
  const map = new Map<string, CalendarEvent[]>();

  const startDate = new Date(year, month, 1);
  const endDate = new Date(year, month + 1, 0);
  const startStr = formatDate(startDate);
  const endStr = formatDate(endDate);

  for (const event of events) {
    if (event.date >= startStr && event.date <= endStr) {
      const existing = map.get(event.date) ?? [];
      existing.push(event);
      map.set(event.date, existing);
    }
  }

  return map;
};

export const createEvent = async (
  data: Omit<CalendarEvent, 'id'>,
): Promise<CalendarEvent> => {
  const events = await readEvents();
  const event: CalendarEvent = { ...data, id: generateId() };
  events.push(event);

  if (data.recurrence !== 'none') {
    const occurrences = expandRecurrence(event);
    events.push(...occurrences);
  }

  await writeEvents(events);
  return event;
};

export const updateEvent = async (
  id: string,
  data: Partial<Omit<CalendarEvent, 'id'>>,
): Promise<CalendarEvent | null> => {
  const events = await readEvents();
  const idx = events.findIndex((e) => e.id === id);
  if (idx === -1) return null;

  const updated = { ...events[idx], ...data };
  events[idx] = updated;

  // If recurrence changed, remove old occurrences and regenerate
  if (data.recurrence !== undefined || data.date !== undefined) {
    const parentId = updated.parentId ?? updated.id;
    const filtered = events.filter(
      (e, i) => i === idx || (e.parentId !== parentId && e.id !== parentId),
    );
    if (updated.recurrence !== 'none') {
      const base = { ...updated, parentId: undefined };
      const occurrences = expandRecurrence(base);
      filtered.push(...occurrences);
    }
    await writeEvents(filtered);
    return updated;
  }

  await writeEvents(events);
  return updated;
};

export const deleteEvent = async (
  id: string,
  deleteSeries: boolean = false,
): Promise<boolean> => {
  const events = await readEvents();
  const event = events.find((e) => e.id === id);
  if (!event) return false;

  let filtered: CalendarEvent[];
  if (deleteSeries) {
    const parentId = event.parentId ?? event.id;
    filtered = events.filter((e) => e.id !== parentId && e.parentId !== parentId);
  } else {
    filtered = events.filter((e) => e.id !== id);
  }

  await writeEvents(filtered);
  return true;
};

const formatDate = (d: Date): string => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

const expandRecurrence = (event: CalendarEvent, count: number = 12): CalendarEvent[] => {
  const occurrences: CalendarEvent[] = [];
  const baseDate = new Date(event.date + 'T00:00:00');

  for (let i = 1; i <= count; i++) {
    const next = new Date(baseDate);

    if (event.recurrence === 'daily') {
      next.setDate(next.getDate() + i);
    } else if (event.recurrence === 'weekly') {
      next.setDate(next.getDate() + i * 7);
    } else if (event.recurrence === 'monthly') {
      next.setMonth(next.getMonth() + i);
    } else {
      break;
    }

    occurrences.push({
      ...event,
      id: generateId() + `_r${i}`,
      date: formatDate(next),
      parentId: event.id,
    });
  }

  return occurrences;
};

import type { DayCell, MonthGrid, CalendarEvent } from './types';

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
];

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

const formatDate = (d: Date): string => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

const todayStr = (): string => formatDate(new Date());

export const buildMonthGrid = (
  year: number,
  month: number,
  eventMap: Map<string, CalendarEvent[]>,
): MonthGrid => {
  const firstDay = new Date(year, month, 1);
  const lastDay = new Date(year, month + 1, 0);
  const today = todayStr();

  const startOffset = firstDay.getDay(); // 0=Sun
  const totalDays = lastDay.getDate();

  const weeks: DayCell[][] = [];
  let currentWeek: DayCell[] = [];

  // Fill leading days from previous month
  const prevMonthLast = new Date(year, month, 0);
  for (let i = startOffset - 1; i >= 0; i--) {
    const d = new Date(prevMonthLast);
    d.setDate(prevMonthLast.getDate() - i);
    const dateStr = formatDate(d);
    currentWeek.push({
      date: dateStr,
      day: d.getDate(),
      isCurrentMonth: false,
      isToday: dateStr === today,
      events: eventMap.get(dateStr) ?? [],
    });
  }

  // Fill current month days
  for (let day = 1; day <= totalDays; day++) {
    const dateStr = formatDate(new Date(year, month, day));
    currentWeek.push({
      date: dateStr,
      day,
      isCurrentMonth: true,
      isToday: dateStr === today,
      events: eventMap.get(dateStr) ?? [],
    });

    if (currentWeek.length === 7) {
      weeks.push(currentWeek);
      currentWeek = [];
    }
  }

  // Fill trailing days from next month
  if (currentWeek.length > 0) {
    let nextDay = 1;
    while (currentWeek.length < 7) {
      const d = new Date(year, month + 1, nextDay);
      const dateStr = formatDate(d);
      currentWeek.push({
        date: dateStr,
        day: nextDay,
        isCurrentMonth: false,
        isToday: dateStr === today,
        events: eventMap.get(dateStr) ?? [],
      });
      nextDay++;
    }
    weeks.push(currentWeek);
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month]} ${year}`,
    weeks,
  };
};

export const navigateMonth = (
  year: number,
  month: number,
  direction: 1 | -1,
): { year: number; month: number } => {
  const d = new Date(year, month + direction, 1);
  return { year: d.getFullYear(), month: d.getMonth() };
};

export const formatTime = (time: string): string => {
  const [h, m] = time.split(':').map(Number);
  const ampm = h >= 12 ? 'PM' : 'AM';
  const hour = h % 12 || 12;
  return `${hour}:${String(m).padStart(2, '0')} ${ampm}`;
};

export const getDayName = (dateStr: string): string => {
  const d = new Date(dateStr + 'T00:00:00');
  return DAY_NAMES[d.getDay()];
};

export const getFullDayName = (dateStr: string): string => {
  const fullNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  const d = new Date(dateStr + 'T00:00:00');
  return fullNames[d.getDay()];
};

