const renderDayCell = (cell: DayCell): ReturnType<typeof h> => {
  const cellStyle = {
    ...styles.dayCell,
    ...(cell.isCurrentMonth ? {} : styles.dayCellOutside),
    ...(cell.isToday ? styles.dayCellToday : {}),
  };

  const dayLabel = cell.isToday
    ? h('span', { style: styles.todayBadge }, String(cell.day))
    : h('span', { style: styles.dayNumber }, String(cell.day));

  const dots = cell.events.length > 0
    ? h('div', { style: styles.eventDots },
        ...cell.events.slice(0, 5).map((evt) =>
          h('span', {
            style: {
              ...styles.eventDot,
              backgroundColor: CATEGORY_COLORS[evt.category],
            },
          }),
        ),
        ...(cell.events.length > 5
          ? [h('span', { style: { fontSize: '9px', color: '#9ca3af' } }, `+${cell.events.length - 5}`)]
          : []),
      )
    : null;

  return h('div', {
    style: cellStyle,
    'p-trigger': 'click:selectDate',
    'data-date': cell.date,
  },
    dayLabel,
    ...(dots ? [dots] : []),
  );
};

