import type { CalendarEvent, Category, Recurrence, ViewState } from './types';
import { buildMonthGrid, navigateMonth } from './calendar';
import { renderMonthView, renderDayView, renderEventForm } from './views';
import {
  getAllEvents,
  getEventsForDate,
  getEventsForMonth,
  createEvent,
  updateEvent,
  deleteEvent,
} from './store';

// --- State ---

const now = new Date();

let state: ViewState = {
  view: 'month',
  year: now.getFullYear(),
  month: now.getMonth(),
};

// --- Actions ---

export const showMonth = async (year?: number, month?: number): Promise<string> => {
  if (year !== undefined) state.year = year;
  if (month !== undefined) state.month = month;
  state.view = 'month';

  const eventMap = await getEventsForMonth(state.year, state.month);
  const grid = buildMonthGrid(state.year, state.month, eventMap);
  return renderMonthView(grid);
};

export const showPrevMonth = async (): Promise<string> => {
  const { year, month } = navigateMonth(state.year, state.month, -1);
  return showMonth(year, month);
};

export const showNextMonth = async (): Promise<string> => {
  const { year, month } = navigateMonth(state.year, state.month, 1);
  return showMonth(year, month);
};

export const showDay = async (date: string): Promise<string> => {
  state.view = 'day';
  state.selectedDate = date;

  const events = await getEventsForDate(date);
  return renderDayView(date, events);
};

export const showEventForm = async (eventId?: string, prefillDate?: string): Promise<string> => {
  state.view = 'form';

  if (eventId) {
    state.editingEventId = eventId;
    const events = await getAllEvents();
    const event = events.find((e) => e.id === eventId);
    return renderEventForm(event ?? undefined);
  }

  state.editingEventId = undefined;
  return renderEventForm(undefined, prefillDate ?? state.selectedDate);
};

export const handleCreateEvent = async (data: {
  title: string;
  date: string;
  startTime: string;
  endTime: string;
  description: string;
  category: Category;
  recurrence: Recurrence;
}): Promise<string> => {
  await createEvent(data);
  return showDay(data.date);
};

export const handleUpdateEvent = async (
  id: string,
  data: Partial<Omit<CalendarEvent, 'id'>>,
): Promise<string> => {
  const updated = await updateEvent(id, data);
  const date = updated?.date ?? state.selectedDate ?? formatToday();
  return showDay(date);
};

export const handleDeleteEvent = async (
  id: string,
  deleteSeries: boolean = false,
): Promise<string> => {
  await deleteEvent(id, deleteSeries);
  const date = state.selectedDate ?? formatToday();
  return showDay(date);
};

export const getCurrentState = (): ViewState => ({ ...state });

// --- Dispatch ---

export const dispatch = async (
  action: string,
  payload?: Record<string, unknown>,
): Promise<string> => {
  switch (action) {
    case 'prevMonth':
      return showPrevMonth();
    case 'nextMonth':
      return showNextMonth();
    case 'selectDate':
      return showDay(payload?.date as string);
    case 'backToMonth':
      return showMonth(state.year, state.month);
    case 'newEvent':
      return showEventForm();
    case 'newEventForDate':
      return showEventForm(undefined, payload?.date as string);
    case 'editEvent':
      return showEventForm(payload?.eventId as string);
    case 'deleteEvent':
      return handleDeleteEvent(
        payload?.eventId as string,
        (payload?.deleteSeries as boolean) ?? false,
      );
    case 'cancelForm':
      if (state.selectedDate) return showDay(state.selectedDate);
      return showMonth(state.year, state.month);
    case 'submitEvent': {
      const eventId = payload?.eventId as string | undefined;
      const eventData = {
        title: payload?.title as string,
        date: payload?.date as string,
        startTime: payload?.startTime as string,
        endTime: payload?.endTime as string,
        description: (payload?.description as string) ?? '',
        category: (payload?.category as Category) ?? 'personal',
        recurrence: (payload?.recurrence as Recurrence) ?? 'none',
      };
      if (eventId) {
        return handleUpdateEvent(eventId, eventData);
      }
      return handleCreateEvent(eventData);
    }
    default:
      return showMonth();
  }
};

const formatToday = (): string => {
  const d = new Date();
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

