export type EventCategory = 'work' | 'personal' | 'health' | 'social';

export type RecurrenceRule = 'daily' | 'weekly' | 'monthly';

export type CalendarEvent = {
  id: string;
  title: string;
  date: string;           // YYYY-MM-DD
  startTime: string;      // HH:MM (24h)
  endTime: string;        // HH:MM (24h)
  description: string;
  category: EventCategory;
  recurrence?: RecurrenceRule;
  recurrenceEnd?: string;  // YYYY-MM-DD — when recurrence stops
};

export type DayCell = {
  date: string;           // YYYY-MM-DD
  dayNumber: number;
  isCurrentMonth: boolean;
  isToday: boolean;
  categories: EventCategory[];  // categories present on this day
};

export type MonthGrid = {
  year: number;
  month: number;          // 0-indexed
  label: string;          // e.g. "March 2026"
  weeks: DayCell[][];     // 6 rows x 7 cols
};

export type CreateEventInput = {
  title: string;
  date: string;
  startTime: string;
  endTime: string;
  description?: string;
  category?: EventCategory;
  recurrence?: RecurrenceRule;
  recurrenceEnd?: string;
};

export type UpdateEventInput = Partial<CreateEventInput> & { id: string };

export type CategoryColors = Record<EventCategory, { bg: string; fg: string; dot: string }>;

import type { CalendarEvent, CreateEventInput, UpdateEventInput } from './types';

const DATA_PATH = `${import.meta.dir}/data/events.json`;

const generateId = (): string => crypto.randomUUID();

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  return text.trim() ? JSON.parse(text) : [];
};

const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2));
};

export const createEvent = async (input: CreateEventInput): Promise<CalendarEvent> => {
  const events = await loadEvents();
  const event: CalendarEvent = {
    id: generateId(),
    title: input.title,
    date: input.date,
    startTime: input.startTime,
    endTime: input.endTime,
    description: input.description ?? '',
    category: input.category ?? 'personal',
    recurrence: input.recurrence,
    recurrenceEnd: input.recurrenceEnd,
  };
  events.push(event);
  await saveEvents(events);
  return event;
};

export const updateEvent = async (input: UpdateEventInput): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  const idx = events.findIndex((e) => e.id === input.id);
  if (idx === -1) return null;
  const existing = events[idx];
  const updated: CalendarEvent = {
    ...existing,
    title: input.title ?? existing.title,
    date: input.date ?? existing.date,
    startTime: input.startTime ?? existing.startTime,
    endTime: input.endTime ?? existing.endTime,
    description: input.description ?? existing.description,
    category: input.category ?? existing.category,
    recurrence: input.recurrence !== undefined ? input.recurrence : existing.recurrence,
    recurrenceEnd: input.recurrenceEnd !== undefined ? input.recurrenceEnd : existing.recurrenceEnd,
  };
  events[idx] = updated;
  await saveEvents(events);
  return updated;
};

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents();
  const filtered = events.filter((e) => e.id !== id);
  if (filtered.length === events.length) return false;
  await saveEvents(filtered);
  return true;
};

export const getEvent = async (id: string): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  return events.find((e) => e.id === id) ?? null;
};

