import { loadEvents } from './store';

const DAYS_OF_WEEK = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
];

const toDateStr = (d: Date): string => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

const parseDate = (s: string): Date => {
  const [y, m, d] = s.split('-').map(Number);
  return new Date(y, m - 1, d);
};

const addDays = (d: Date, n: number): Date => {
  const r = new Date(d);
  r.setDate(r.getDate() + n);
  return r;
};

const addMonths = (d: Date, n: number): Date => {
  const r = new Date(d);
  r.setMonth(r.getMonth() + n);
  return r;
};

/** Expand a single event into all dates it occupies within a date range */
const expandRecurrence = (
  event: CalendarEvent,
  rangeStart: string,
  rangeEnd: string,
): string[] => {
  const dates: string[] = [];
  const base = parseDate(event.date);
  const rEnd = event.recurrenceEnd ? parseDate(event.recurrenceEnd) : parseDate(rangeEnd);
  const end = rEnd < parseDate(rangeEnd) ? rEnd : parseDate(rangeEnd);
  const start = parseDate(rangeStart);

  if (!event.recurrence) {
    const ds = event.date;
    if (ds >= rangeStart && ds <= rangeEnd) dates.push(ds);
    return dates;
  }

  let current = new Date(base);
  // Cap iterations to prevent infinite loops
  let iterations = 0;
  const maxIterations = 400;

  while (current <= end && iterations < maxIterations) {
    iterations++;
    const ds = toDateStr(current);
    if (current >= start && current <= end) {
      dates.push(ds);
    }
    switch (event.recurrence) {
      case 'daily':
        current = addDays(current, 1);
        break;
      case 'weekly':
        current = addDays(current, 7);
        break;
      case 'monthly':
        current = addMonths(current, 1);
        break;
    }
  }

  return dates;
};

/** Get all events (with recurrence expanded) that fall on a given date */
export const getEventsForDate = async (dateStr: string): Promise<CalendarEvent[]> => {
  const events = await loadEvents();
  const result: CalendarEvent[] = [];

  for (const event of events) {
    const occurrences = expandRecurrence(event, dateStr, dateStr);
    if (occurrences.length > 0) {
      result.push({ ...event, date: dateStr });
    }
  }

  result.sort((a, b) => a.startTime.localeCompare(b.startTime));
  return result;
};

/** Build the month grid with event category indicators */
export const buildMonthGrid = async (year: number, month: number): Promise<MonthGrid> => {
  const firstDay = new Date(year, month, 1);
  const startOffset = firstDay.getDay(); // 0=Sun
  const gridStart = addDays(firstDay, -startOffset);

  // Always show 6 weeks
  const gridEnd = addDays(gridStart, 41);
  const rangeStart = toDateStr(gridStart);
  const rangeEnd = toDateStr(gridEnd);

  const events = await loadEvents();

  // Build a map of date -> categories present
  const dateCategoryMap = new Map<string, Set<EventCategory>>();
  for (const event of events) {
    const occurrences = expandRecurrence(event, rangeStart, rangeEnd);
    for (const ds of occurrences) {
      if (!dateCategoryMap.has(ds)) dateCategoryMap.set(ds, new Set());
      dateCategoryMap.get(ds)!.add(event.category);
    }
  }

  const todayStr = toDateStr(new Date());
  const weeks: DayCell[][] = [];

  for (let w = 0; w < 6; w++) {
    const week: DayCell[] = [];
    for (let d = 0; d < 7; d++) {
      const cellDate = addDays(gridStart, w * 7 + d);
      const ds = toDateStr(cellDate);
      week.push({
        date: ds,
        dayNumber: cellDate.getDate(),
        isCurrentMonth: cellDate.getMonth() === month,
        isToday: ds === todayStr,
        categories: Array.from(dateCategoryMap.get(ds) ?? []),
      });
    }
    weeks.push(week);
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month]} ${year}`,
    weeks,
  };
};

