  return String(template);
};

const formatTime = (time: string): string => {
  const [hStr, mStr] = time.split(':');
  const hour = parseInt(hStr, 10);
  const min = mStr;
  const ampm = hour >= 12 ? 'PM' : 'AM';
  const h12 = hour === 0 ? 12 : hour > 12 ? hour - 12 : hour;
  return `${h12}:${min} ${ampm}`;
};

import { buildMonthGrid, getEventsForDate, toDateStr } from './calendar';
import { createEvent, deleteEvent, getEvent, updateEvent } from './store';
import { renderDayView, renderEventForm, renderMonthView } from './render';
import type { CreateEventInput, EventCategory, RecurrenceRule } from './types';

export type Route =
  | { view: 'month'; year: number; month: number }
  | { view: 'day'; date: string }
  | { view: 'form'; date: string; eventId?: string }; // eventId present = edit

/** Default route: current month */
const defaultRoute = (): Route => {
  const now = new Date();
  return { view: 'month', year: now.getFullYear(), month: now.getMonth() };
};

/** Navigate to previous month */
export const prevMonth = (current: Route & { view: 'month' }): Route => {
  let { year, month } = current;
  month -= 1;
  if (month < 0) {
    month = 11;
    year -= 1;
  }
  return { view: 'month', year, month };
};

/** Navigate to next month */
export const nextMonth = (current: Route & { view: 'month' }): Route => {
  let { year, month } = current;
  month += 1;
  if (month > 11) {
    month = 0;
    year += 1;
  }
  return { view: 'month', year, month };
};

/** Render the appropriate view for a given route */
export const renderRoute = async (route: Route = defaultRoute()): Promise<string> => {
  switch (route.view) {
    case 'month': {
      const grid = await buildMonthGrid(route.year, route.month);
      return renderMonthView(grid);
    }
    case 'day': {
      const events = await getEventsForDate(route.date);
      return renderDayView(route.date, events);
    }
    case 'form': {
      const existing = route.eventId ? await getEvent(route.eventId) : undefined;
      return renderEventForm(route.date, existing ?? undefined);
    }
  }
};

/** Handle event creation from form submission */
export const handleCreateEvent = async (formData: {
  title: string;
  date: string;
  startTime: string;
  endTime: string;
  description?: string;
  category?: string;
  recurrence?: string;
  recurrenceEnd?: string;
}) => {
  const input: CreateEventInput = {
    title: formData.title,
    date: formData.date,
    startTime: formData.startTime,
    endTime: formData.endTime,
    description: formData.description,
    category: (formData.category as EventCategory) || 'personal',
    recurrence: formData.recurrence ? (formData.recurrence as RecurrenceRule) : undefined,
    recurrenceEnd: formData.recurrenceEnd || undefined,
  };
  return createEvent(input);
};

/** Handle event update from form submission */
export const handleUpdateEvent = async (
  id: string,
  formData: {
    title?: string;
    date?: string;
    startTime?: string;
    endTime?: string;
    description?: string;
    category?: string;
    recurrence?: string;
    recurrenceEnd?: string;
  },
) => {
  return updateEvent({
    id,
    title: formData.title,
    date: formData.date,
    startTime: formData.startTime,
    endTime: formData.endTime,
    description: formData.description,
    category: formData.category ? (formData.category as EventCategory) : undefined,
    recurrence: formData.recurrence ? (formData.recurrence as RecurrenceRule) : undefined,
    recurrenceEnd: formData.recurrenceEnd || undefined,
  });
};

/** Handle event deletion */
export const handleDeleteEvent = async (id: string) => {
  return deleteEvent(id);
};

/** HTTP request handler for serving the calendar */
export const serve = Bun.serve({
  port: 3100,
  fetch: async (req) => {
    const url = new URL(req.url);
    const path = url.pathname;

    // API routes
    if (path === '/api/events' && req.method === 'POST') {
      const body = await req.json();
      const event = await handleCreateEvent(body);
      return Response.json(event, { status: 201 });
    }

    if (path.startsWith('/api/events/') && req.method === 'PUT') {
      const id = path.split('/').pop()!;
      const body = await req.json();
      const event = await handleUpdateEvent(id, body);
      if (!event) return Response.json({ error: 'Not found' }, { status: 404 });
      return Response.json(event);
    }

    if (path.startsWith('/api/events/') && req.method === 'DELETE') {
      const id = path.split('/').pop()!;
      const ok = await handleDeleteEvent(id);
      if (!ok) return Response.json({ error: 'Not found' }, { status: 404 });
      return Response.json({ deleted: true });
    }

    if (path === '/api/day' && req.method === 'GET') {
      const date = url.searchParams.get('date') ?? toDateStr(new Date());
      const events = await getEventsForDate(date);
      return Response.json(events);
    }

    // View routes — return HTML
    const yearParam = url.searchParams.get('year');
    const monthParam = url.searchParams.get('month');
    const dateParam = url.searchParams.get('date');
    const viewParam = url.searchParams.get('view') ?? 'month';
    const eventIdParam = url.searchParams.get('eventId');

    let route: Route;
    if (viewParam === 'day' && dateParam) {
      route = { view: 'day', date: dateParam };
    } else if (viewParam === 'form' && dateParam) {
      route = { view: 'form', date: dateParam, eventId: eventIdParam ?? undefined };
    } else {
      const now = new Date();
      route = {
        view: 'month',
        year: yearParam ? parseInt(yearParam, 10) : now.getFullYear(),
        month: monthParam ? parseInt(monthParam, 10) : now.getMonth(),
      };
    }

    const content = await renderRoute(route);
    const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Calendar</title>
  <style>* { margin: 0; padding: 0; box-sizing: border-box; }</style>
</head>
<body>${content}</body>
</html>`;
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    });
  },
});

