import type { CalendarEvent } from './types';

const DATA_PATH = `${import.meta.dir}/data/events.jsonl`;

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as CalendarEvent);
};

export const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  const content = events.map((e) => JSON.stringify(e)).join('\n') + '\n';
  await Bun.write(DATA_PATH, content);
};

export const generateId = (): string =>
  `evt_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;

export const addEvent = async (event: CalendarEvent): Promise<CalendarEvent> => {
  const events = await loadEvents();
  events.push(event);
  await saveEvents(events);
  return event;
};

export const updateEvent = async (
  id: string,
  updates: Partial<Omit<CalendarEvent, 'id'>>
): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  const idx = events.findIndex((e) => e.id === id);
  if (idx === -1) return null;
  events[idx] = { ...events[idx], ...updates };
  await saveEvents(events);
  return events[idx];
};

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents();
  const filtered = events.filter((e) => e.id !== id);
  if (filtered.length === events.length) return false;
  await saveEvents(filtered);
  return true;
};

export const getEventsForDate = async (dateStr: string): Promise<CalendarEvent[]> => {
  const events = await loadEvents();
  return expandRecurring(events, dateStr)
    .sort((a, b) => a.startTime.localeCompare(b.startTime));
};

const expandRecurring = (events: CalendarEvent[], targetDate: string): CalendarEvent[] => {
  const target = new Date(targetDate + 'T00:00:00');
  const result: CalendarEvent[] = [];

  for (const event of events) {
    const eventDate = new Date(event.date + 'T00:00:00');

    if (target < eventDate) continue;

    if (event.recurrence === 'none') {
      if (event.date === targetDate) result.push(event);
      continue;
    }

    if (event.recurrence === 'daily') {
      result.push({ ...event, date: targetDate });
      continue;
    }

    if (event.recurrence === 'weekly') {
      if (target.getDay() === eventDate.getDay()) {
        result.push({ ...event, date: targetDate });
      }
      continue;
    }

    if (event.recurrence === 'monthly') {
      if (target.getDate() === eventDate.getDate()) {
        result.push({ ...event, date: targetDate });
      }
      continue;
    }
  }

  return result;
};

export const getEventsInMonth = async (
  year: number,
  month: number
): Promise<Map<string, CalendarEvent[]>> => {
  const events = await loadEvents();
  const map = new Map<string, CalendarEvent[]>();
  const daysInMonth = new Date(year, month, 0).getDate();

  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    const dayEvents = expandRecurring(events, dateStr);
    if (dayEvents.length > 0) {
      map.set(dateStr, dayEvents);
    }
  }

  return map;
};

import type { DayCell, MonthGrid, CalendarEvent, Category } from './types';
import { getEventsInMonth } from './store';

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
];

const todayStr = (): string => {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
};

export const buildMonthGrid = async (year: number, month: number): Promise<MonthGrid> => {
  const eventMap = await getEventsInMonth(year, month);
  const today = todayStr();

  const firstDay = new Date(year, month - 1, 1);
  const startDow = firstDay.getDay(); // 0=Sun
  const daysInMonth = new Date(year, month, 0).getDate();
  const daysInPrevMonth = new Date(year, month - 1, 0).getDate();

  const cells: DayCell[] = [];

  // Previous month padding
  for (let i = startDow - 1; i >= 0; i--) {
    const day = daysInPrevMonth - i;
    const prevMonth = month === 1 ? 12 : month - 1;
    const prevYear = month === 1 ? year - 1 : year;
    const dateStr = `${prevYear}-${String(prevMonth).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    cells.push({ date: dateStr, day, isCurrentMonth: false, isToday: dateStr === today, categories: [] });
  }

  // Current month
  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    const dayEvents = eventMap.get(dateStr) ?? [];
    const categories = [...new Set(dayEvents.map((e) => e.category))] as Category[];
    cells.push({ date: dateStr, day, isCurrentMonth: true, isToday: dateStr === today, categories });
  }

  // Next month padding to fill last week
  const remaining = 7 - (cells.length % 7);
  if (remaining < 7) {
    const nextMonth = month === 12 ? 1 : month + 1;
    const nextYear = month === 12 ? year + 1 : year;
    for (let day = 1; day <= remaining; day++) {
      const dateStr = `${nextYear}-${String(nextMonth).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
      cells.push({ date: dateStr, day, isCurrentMonth: false, isToday: dateStr === today, categories: [] });
    }
  }

  // Split into weeks
  const weeks: DayCell[][] = [];
  for (let i = 0; i < cells.length; i += 7) {
    weeks.push(cells.slice(i, i + 7));
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month - 1]} ${year}`,
    weeks,
  };
};

export const formatTime = (time24: string): string => {
  const [h, m] = time24.split(':').map(Number);
  const period = h >= 12 ? 'PM' : 'AM';
  const hour12 = h === 0 ? 12 : h > 12 ? h - 12 : h;
  return `${hour12}:${String(m).padStart(2, '0')} ${period}`;
};

export const currentMonth = (): { year: number; month: number } => {
  const d = new Date();
  return { year: d.getFullYear(), month: d.getMonth() + 1 };
};

export const navigateMonth = (year: number, month: number, delta: number): { year: number; month: number } => {
  let m = month + delta;
  let y = year;
  while (m > 12) { m -= 12; y++; }
  while (m < 1) { m += 12; y--; }
  return { year: y, month: m };
};

