import type { CalendarEvent, Category, Recurrence } from './types';
import { buildMonthGrid, currentMonth, navigateMonth, formatTime } from './calendar';
import { loadEvents, addEvent, updateEvent, deleteEvent, getEventsForDate, generateId } from './store';
import { renderMonthView, renderDayView, renderEventForm } from './render';

// --- Action handlers ---

export type Action =
  | { type: 'view-month'; year?: number; month?: number }
  | { type: 'prev-month'; year: number; month: number }
  | { type: 'next-month'; year: number; month: number }
  | { type: 'select-date'; date: string }
  | { type: 'show-create-form'; date?: string }
  | { type: 'show-edit-form'; eventId: string }
  | { type: 'create-event'; data: EventFormData }
  | { type: 'update-event'; eventId: string; data: EventFormData }
  | { type: 'delete-event'; eventId: string }
  | { type: 'list-events'; date: string }
  | { type: 'back-to-month'; year: number; month: number };

export type EventFormData = {
  title: string;
  date: string;
  startTime: string;
  endTime: string;
  description?: string;
  category: Category;
  recurrence: Recurrence;
};

export type ActionResult = {
  html?: string;
  data?: unknown;
  message?: string;
};

export const handleAction = async (action: Action): Promise<ActionResult> => {
  switch (action.type) {
    case 'view-month': {
      const { year, month } = action.year && action.month
        ? { year: action.year, month: action.month }
        : currentMonth();
      const grid = await buildMonthGrid(year, month);
      return { html: renderMonthView(grid), data: { year, month } };
    }

    case 'prev-month': {
      const { year, month } = navigateMonth(action.year, action.month, -1);
      const grid = await buildMonthGrid(year, month);
      return { html: renderMonthView(grid), data: { year, month } };
    }

    case 'next-month': {
      const { year, month } = navigateMonth(action.year, action.month, 1);
      const grid = await buildMonthGrid(year, month);
      return { html: renderMonthView(grid), data: { year, month } };
    }

    case 'select-date': {
      const events = await getEventsForDate(action.date);
      return { html: renderDayView(action.date, events), data: { date: action.date, eventCount: events.length } };
    }

    case 'show-create-form': {
      const date = action.date ?? new Date().toISOString().slice(0, 10);
      return { html: renderEventForm(date) };
    }

    case 'show-edit-form': {
      const events = await loadEvents();
      const event = events.find((e) => e.id === action.eventId);
      if (!event) return { message: `Event ${action.eventId} not found.` };
      return { html: renderEventForm(event.date, event) };
    }

    case 'create-event': {
      const event: CalendarEvent = {
        id: generateId(),
        title: action.data.title,
        date: action.data.date,
        startTime: action.data.startTime,
        endTime: action.data.endTime,
        description: action.data.description ?? '',
        category: action.data.category,
        recurrence: action.data.recurrence,
      };
      const created = await addEvent(event);
      const events = await getEventsForDate(created.date);
      return {
        html: renderDayView(created.date, events),
        data: created,
        message: `Event "${created.title}" created.`,
      };
    }

    case 'update-event': {
      const updated = await updateEvent(action.eventId, {
        title: action.data.title,
        date: action.data.date,
        startTime: action.data.startTime,
        endTime: action.data.endTime,
        description: action.data.description ?? '',
        category: action.data.category,
        recurrence: action.data.recurrence,
      });
      if (!updated) return { message: `Event ${action.eventId} not found.` };
      const events = await getEventsForDate(updated.date);
      return {
        html: renderDayView(updated.date, events),
        data: updated,
        message: `Event "${updated.title}" updated.`,
      };
    }

    case 'delete-event': {
      const allEvents = await loadEvents();
      const target = allEvents.find((e) => e.id === action.eventId);
      const deleted = await deleteEvent(action.eventId);
      if (!deleted) return { message: `Event ${action.eventId} not found.` };
      if (target) {
        const events = await getEventsForDate(target.date);
        return {
          html: renderDayView(target.date, events),
          message: `Event "${target.title}" deleted.`,
        };
      }
      return { message: 'Event deleted.' };
    }

    case 'list-events': {
      const events = await getEventsForDate(action.date);
      return {
        data: events.map((e) => ({
          id: e.id,
          title: e.title,
          time: `${formatTime(e.startTime)} - ${formatTime(e.endTime)}`,
          category: e.category,
          recurrence: e.recurrence,
          description: e.description,
        })),
        message: events.length === 0
          ? `No events on ${action.date}.`
          : `${events.length} event(s) on ${action.date}.`,
      };
    }

    case 'back-to-month': {
      const grid = await buildMonthGrid(action.year, action.month);
      return { html: renderMonthView(grid), data: { year: action.year, month: action.month } };
    }
  }
};

