export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }

export const hexToRgb = (hex: string): RGB => {
  const clean = hex.replace(/^#/, '')
  const full =
    clean.length === 3
      ? clean
          .split('')
          .map((c) => c + c)
          .join('')
      : clean
  const num = parseInt(full, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

export const rgbToHex = ({ r, g, b }: RGB): string => {
  const toHex = (n: number) =>
    Math.round(Math.max(0, Math.min(255, n)))
      .toString(16)
      .padStart(2, '0')
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`
}

export const rgbToHsl = ({ r, g, b }: RGB): HSL => {
  const rn = r / 255
  const gn = g / 255
  const bn = b / 255
  const max = Math.max(rn, gn, bn)
  const min = Math.min(rn, gn, bn)
  const l = (max + min) / 2
  if (max === min) return { h: 0, s: 0, l: Math.round(l * 100) }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === rn) h = ((gn - bn) / d + (gn < bn ? 6 : 0)) / 6
  else if (max === gn) h = ((bn - rn) / d + 2) / 6
  else h = ((rn - gn) / d + 4) / 6
  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100),
  }
}

export const hslToRgb = ({ h, s, l }: HSL): RGB => {
  const sn = s / 100
  const ln = l / 100
  if (sn === 0) {
    const v = Math.round(ln * 255)
    return { r: v, g: v, b: v }
  }
  const hue2rgb = (p: number, q: number, t: number): number => {
    const tt = t < 0 ? t + 1 : t > 1 ? t - 1 : t
    if (tt < 1 / 6) return p + (q - p) * 6 * tt
    if (tt < 1 / 2) return q
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6
    return p
  }
  const q = ln < 0.5 ? ln * (1 + sn) : ln + sn - ln * sn
  const p = 2 * ln - q
  const hn = h / 360
  return {
    r: Math.round(hue2rgb(p, q, hn + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, hn) * 255),
    b: Math.round(hue2rgb(p, q, hn - 1 / 3) * 255),
  }
}

export const isValidHex = (hex: string): boolean =>
  /^#?([0-9A-Fa-f]{3}|[0-9A-Fa-f]{6})$/.test(hex)

export const normalizeHex = (hex: string): string => {
  const clean = hex.replace(/^#/, '')
  const full =
    clean.length === 3
      ? clean
          .split('')
          .map((c) => c + c)
          .join('')
      : clean
  return `#${full.toLowerCase()}`
}

export const formatRgb = ({ r, g, b }: RGB): string => `rgb(${r}, ${g}, ${b})`

export const formatHsl = ({ h, s, l }: HSL): string => `hsl(${h}, ${s}%, ${l}%)`

import { type HSL, hexToRgb, rgbToHsl, hslToRgb, rgbToHex, normalizeHex } from './color'

export type HarmonyType =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

export type PaletteColor = {
  hex: string
  label: string
}

const rotateHue = (h: number, degrees: number): number => (h + degrees + 360) % 360

const hslToHex = (hsl: HSL): string => rgbToHex(hslToRgb(hsl))

const baseHsl = (hex: string): HSL => rgbToHsl(hexToRgb(hex))

export const generatePalette = (baseHex: string, harmony: HarmonyType): PaletteColor[] => {
  const hex = normalizeHex(baseHex)
  const { h, s, l } = baseHsl(hex)

  const make = (label: string, hue: number): PaletteColor => ({
    hex: hslToHex({ h: rotateHue(h, hue), s, l }),
    label,
  })

  const base: PaletteColor = { hex, label: 'Base' }

  switch (harmony) {
    case 'complementary':
      return [base, make('Complement', 180)]

    case 'analogous':
      return [make('Analogous -30', -30), base, make('Analogous +30', 30)]

    case 'triadic':
      return [base, make('Triadic +120', 120), make('Triadic +240', 240)]

    case 'split-complementary':
      return [base, make('Split +150', 150), make('Split +210', 210)]

    case 'tetradic':
      return [base, make('Tetradic +90', 90), make('Tetradic +180', 180), make('Tetradic +270', 270)]
  }
}

export const harmonyTypes: { value: HarmonyType; label: string; description: string }[] = [
  { value: 'complementary', label: 'Complementary', description: 'Base + opposite (180°)' },
  { value: 'analogous', label: 'Analogous', description: 'Adjacent colors (±30°)' },
  { value: 'triadic', label: 'Triadic', description: 'Three equidistant (120°)' },
  { value: 'split-complementary', label: 'Split-Complementary', description: 'Base + split opposite (±150°)' },
  { value: 'tetradic', label: 'Tetradic', description: 'Four equidistant (90°)' },
]

import { type RGB, hexToRgb } from './color'

export type WcagLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  ratioText: string
  normalText: WcagLevel
  largeText: WcagLevel
}

const relativeLuminance = ({ r, g, b }: RGB): number => {
  const linearize = (c: number): number => {
    const srgb = c / 255
    return srgb <= 0.03928 ? srgb / 12.92 : Math.pow((srgb + 0.055) / 1.055, 2.4)
  }
  return 0.2126 * linearize(r) + 0.7152 * linearize(g) + 0.0722 * linearize(b)
}

export const contrastRatio = (hex1: string, hex2: string): number => {
  const l1 = relativeLuminance(hexToRgb(hex1))
  const l2 = relativeLuminance(hexToRgb(hex2))
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

const levelForNormalText = (ratio: number): WcagLevel => {
  if (ratio >= 7) return 'AAA'
  if (ratio >= 4.5) return 'AA'
  return 'Fail'
}

const levelForLargeText = (ratio: number): WcagLevel => {
  if (ratio >= 4.5) return 'AAA'
  if (ratio >= 3) return 'AA'
  return 'Fail'
}

export const checkContrast = (hex1: string, hex2: string): ContrastResult => {
  const ratio = contrastRatio(hex1, hex2)
  return {
    ratio,
    ratioText: `${ratio.toFixed(2)}:1`,
    normalText: levelForNormalText(ratio),
    largeText: levelForLargeText(ratio),
  }
}

