const renderSwatchCard = (color: PaletteColor, index: number) => {
  const rgb = hexToRgb(color.hex)
  const hsl = rgbToHsl(rgb)
  const hexVal = color.hex.toUpperCase()
  const rgbVal = formatRgb(rgb)
  const hslVal = formatHsl(hsl)

  return h('div', { style: styles.swatchCard, 'p-target': `swatch-${index}` },
    h('div', {
      style: { ...styles.swatchColor, backgroundColor: color.hex },
      'p-trigger': `select-contrast:click`,
