const renderContrastChecker = (result: ContrastResult | null, hex1?: string, hex2?: string) => {
  if (!result || !hex1 || !hex2) {
    return h('div', { style: styles.contrastSection },
      h('h3', { style: styles.sectionTitle }, 'Contrast Checker'),
      h('p', { style: styles.selectHint }, 'Click two swatches above to compare their contrast ratio')
