export type RenderOptions = {
  baseHex: string
  harmony: HarmonyType
  contrastHex1?: string
  contrastHex2?: string
}

export const renderPalette = (options: RenderOptions): string => {
  const { baseHex, harmony, contrastHex1, contrastHex2 } = options
  const colors = generatePalette(baseHex, harmony)
  const contrastResult =
    contrastHex1 && contrastHex2 ? checkContrast(contrastHex1, contrastHex2) : null

  const template = h('div', { style: styles.container },
    h('h1', { style: styles.heading }, 'Color Palette Generator'),

    h('div', { style: styles.section },
      h('div', { style: styles.inputRow },
        h('input', {
          type: 'color',
          value: baseHex,
          style: styles.colorPicker,
          'p-trigger': 'color-pick:input',
          'p-target': 'color-picker',
        }),
        h('input', {
          type: 'text',
          value: baseHex.toUpperCase(),
          placeholder: '#3B82F6',
          style: styles.hexInput,
          maxlength: '7',
          'p-trigger': 'hex-input:input',
          'p-target': 'hex-input',
        })
      )
    ),

    h('div', { style: styles.section },
      h('h3', { style: styles.sectionTitle }, 'Harmony'),
      h('div', { style: styles.harmonyGrid },
        ...harmonyTypes.map((ht) =>
          h('button', {
            style: ht.value === harmony ? styles.harmonyBtnActive : styles.harmonyBtn,
            'p-trigger': 'set-harmony:click',
            'data-harmony': ht.value,
            title: ht.description,
          }, ht.label)
        )
      )
    ),

    h('div', { style: styles.section },
      h('h3', { style: styles.sectionTitle }, 'Palette'),
      h('div', { style: styles.paletteRow },
        ...colors.map((c, i) => renderSwatchCard(c, i))
      )
    ),

    renderContrastChecker(contrastResult, contrastHex1, contrastHex2)
  )

  const ssr = createSSR()
  return ssr(template)
}

import { isValidHex, normalizeHex, hexToRgb, rgbToHsl, formatRgb, formatHsl } from './color'
import { type HarmonyType, generatePalette, harmonyTypes } from './palette'
import { checkContrast, type ContrastResult } from './contrast'
import { renderPalette, type RenderOptions } from './render'

export type PaletteState = {
  baseHex: string
  harmony: HarmonyType
  contrastHex1: string | null
  contrastHex2: string | null
}

const DEFAULT_STATE: PaletteState = {
  baseHex: '#3b82f6',
  harmony: 'complementary',
  contrastHex1: null,
  contrastHex2: null,
}

const STATE_PATH = './data/state.json'

const loadState = async (): Promise<PaletteState> => {
  const file = Bun.file(STATE_PATH)
  if (await file.exists()) {
    return { ...DEFAULT_STATE, ...(await file.json()) }
  }
  return { ...DEFAULT_STATE }
}

const saveState = async (state: PaletteState): Promise<void> => {
  await Bun.write(STATE_PATH, JSON.stringify(state, null, 2))
}

export const setBaseColor = async (hex: string): Promise<PaletteState> => {
  if (!isValidHex(hex)) throw new Error(`Invalid hex color: ${hex}`)
  const state = await loadState()
  state.baseHex = normalizeHex(hex)
  state.contrastHex1 = null
  state.contrastHex2 = null
  await saveState(state)
  return state
}

export const setHarmony = async (harmony: HarmonyType): Promise<PaletteState> => {
  const valid = harmonyTypes.map((h) => h.value)
  if (!valid.includes(harmony)) throw new Error(`Invalid harmony: ${harmony}`)
  const state = await loadState()
  state.harmony = harmony
  state.contrastHex1 = null
  state.contrastHex2 = null
  await saveState(state)
  return state
}

export const selectContrastColor = async (hex: string): Promise<PaletteState> => {
  if (!isValidHex(hex)) throw new Error(`Invalid hex color: ${hex}`)
  const state = await loadState()
  const normalized = normalizeHex(hex)
  if (!state.contrastHex1) {
    state.contrastHex1 = normalized
  } else if (!state.contrastHex2) {
    state.contrastHex2 = normalized
  } else {
    state.contrastHex1 = normalized
    state.contrastHex2 = null
  }
  await saveState(state)
  return state
}

export const getContrastReport = async (hex1: string, hex2: string): Promise<ContrastResult> => {
  if (!isValidHex(hex1)) throw new Error(`Invalid hex color: ${hex1}`)
  if (!isValidHex(hex2)) throw new Error(`Invalid hex color: ${hex2}`)
  return checkContrast(normalizeHex(hex1), normalizeHex(hex2))
}

export const getPaletteColors = async (hex: string, harmony: HarmonyType) => {
  if (!isValidHex(hex)) throw new Error(`Invalid hex color: ${hex}`)
  const colors = generatePalette(normalizeHex(hex), harmony)
  return colors.map((c) => {
    const rgb = hexToRgb(c.hex)
    const hsl = rgbToHsl(rgb)
    return {
      ...c,
      rgb: formatRgb(rgb),
      hsl: formatHsl(hsl),
    }
  })
}

export const render = async (): Promise<string> => {
  const state = await loadState()
  const options: RenderOptions = {
    baseHex: state.baseHex,
    harmony: state.harmony,
    contrastHex1: state.contrastHex1 ?? undefined,
    contrastHex2: state.contrastHex2 ?? undefined,
  }
  return renderPalette(options)
}

export const handleAction = async (action: string, payload: Record<string, string>): Promise<string> => {
  switch (action) {
    case 'color-pick':
    case 'hex-input': {
      const hex = payload.value ?? ''
      if (isValidHex(hex)) await setBaseColor(hex)
      break
    }
    case 'set-harmony': {
      const harmony = payload.harmony as HarmonyType
      await setHarmony(harmony)
      break
    }
    case 'select-contrast': {
      const hex = payload.hex ?? ''
      if (isValidHex(hex)) await selectContrastColor(hex)
      break
    }
    case 'copy-value': {
      return JSON.stringify({ copied: payload.value })
    }
  }
  return render()
}

