export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }

export const hexToRgb = (hex: string): RGB => {
  const clean = hex.replace(/^#/, '')
  const full = clean.length === 3
    ? clean.split('').map(c => c + c).join('')
    : clean
  const num = parseInt(full, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

export const rgbToHex = ({ r, g, b }: RGB): string => {
  const toHex = (n: number) => n.toString(16).padStart(2, '0')
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`
}

export const rgbToHsl = ({ r, g, b }: RGB): HSL => {
  const rn = r / 255
  const gn = g / 255
  const bn = b / 255
  const max = Math.max(rn, gn, bn)
  const min = Math.min(rn, gn, bn)
  const l = (max + min) / 2
  if (max === min) return { h: 0, s: 0, l }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === rn) h = ((gn - bn) / d + (gn < bn ? 6 : 0)) / 6
  else if (max === gn) h = ((bn - rn) / d + 2) / 6
  else h = ((rn - gn) / d + 4) / 6
  return { h: h * 360, s, l }
}

export const hslToRgb = ({ h, s, l }: HSL): RGB => {
  const hue = ((h % 360) + 360) % 360
  if (s === 0) {
    const v = Math.round(l * 255)
    return { r: v, g: v, b: v }
  }
  const hueToRgb = (p: number, q: number, t: number): number => {
    const tt = t < 0 ? t + 1 : t > 1 ? t - 1 : t
    if (tt < 1 / 6) return p + (q - p) * 6 * tt
    if (tt < 1 / 2) return q
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6
    return p
  }
  const q = l < 0.5 ? l * (1 + s) : l + s - l * s
  const p = 2 * l - q
  const hn = hue / 360
  return {
    r: Math.round(hueToRgb(p, q, hn + 1 / 3) * 255),
    g: Math.round(hueToRgb(p, q, hn) * 255),
    b: Math.round(hueToRgb(p, q, hn - 1 / 3) * 255),
  }
}

export const hexToHsl = (hex: string): HSL => rgbToHsl(hexToRgb(hex))
export const hslToHex = (hsl: HSL): string => rgbToHex(hslToRgb(hsl))

export const formatRgb = ({ r, g, b }: RGB): string => `rgb(${r}, ${g}, ${b})`
export const formatHsl = ({ h, s, l }: HSL): string =>
  `hsl(${Math.round(h)}, ${Math.round(s * 100)}%, ${Math.round(l * 100)}%)`

export const isValidHex = (hex: string): boolean =>
  /^#?([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(hex)

export const normalizeHex = (hex: string): string => {
  const clean = hex.replace(/^#/, '')
  const full = clean.length === 3
    ? clean.split('').map(c => c + c).join('')
    : clean
  return `#${full.toLowerCase()}`
}

import { hexToHsl, hslToHex, normalizeHex } from './color'

export type HarmonyMode =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

export type PaletteColor = {
  hex: string
  label: string
}

const shiftHue = (h: number, degrees: number): number =>
  ((h + degrees) % 360 + 360) % 360

const fromBase = (baseHex: string, offsets: number[], labels: string[]): PaletteColor[] => {
  const { h, s, l } = hexToHsl(baseHex)
  return [
    { hex: normalizeHex(baseHex), label: 'Base' },
    ...offsets.map((offset, i) => ({
      hex: hslToHex({ h: shiftHue(h, offset), s, l }),
      label: labels[i],
    })),
  ]
}

export const generatePalette = (baseHex: string, mode: HarmonyMode): PaletteColor[] => {
  switch (mode) {
    case 'complementary':
      return fromBase(baseHex, [180], ['Complement'])

    case 'analogous':
      return fromBase(
        baseHex,
        [-60, -30, 30, 60],
        ['Analogous -60°', 'Analogous -30°', 'Analogous +30°', 'Analogous +60°']
      )

    case 'triadic':
      return fromBase(baseHex, [120, 240], ['Triad 120°', 'Triad 240°'])

    case 'split-complementary':
      return fromBase(baseHex, [150, 210], ['Split 150°', 'Split 210°'])

    case 'tetradic':
      return fromBase(baseHex, [90, 180, 270], ['Tetrad 90°', 'Tetrad 180°', 'Tetrad 270°'])
  }
}

export const HARMONY_MODES: { value: HarmonyMode; label: string; description: string }[] = [
  { value: 'complementary', label: 'Complementary', description: 'Opposite on the color wheel' },
  { value: 'analogous', label: 'Analogous', description: 'Neighboring hues' },
  { value: 'triadic', label: 'Triadic', description: 'Three evenly spaced colors' },
  { value: 'split-complementary', label: 'Split-Complementary', description: 'Adjacent to the complement' },
  { value: 'tetradic', label: 'Tetradic', description: 'Four-color rectangle' },
]

import type { RGB } from './color'
import { hexToRgb } from './color'

export type WCAGLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  ratioDisplay: string
  normalText: WCAGLevel
  largeText: WCAGLevel
}

const relativeLuminance = ({ r, g, b }: RGB): number => {
  const linearize = (c: number): number => {
    const s = c / 255
    return s <= 0.04045 ? s / 12.92 : Math.pow((s + 0.055) / 1.055, 2.4)
  }
  return 0.2126 * linearize(r) + 0.7152 * linearize(g) + 0.0722 * linearize(b)
}

export const contrastRatio = (hex1: string, hex2: string): number => {
  const l1 = relativeLuminance(hexToRgb(hex1))
  const l2 = relativeLuminance(hexToRgb(hex2))
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

const classifyLevel = (ratio: number, thresholdAA: number, thresholdAAA: number): WCAGLevel => {
  if (ratio >= thresholdAAA) return 'AAA'
  if (ratio >= thresholdAA) return 'AA'
  return 'Fail'
}

export const checkContrast = (hex1: string, hex2: string): ContrastResult => {
  const ratio = contrastRatio(hex1, hex2)
  return {
    ratio,
    ratioDisplay: `${ratio.toFixed(2)}:1`,
    normalText: classifyLevel(ratio, 4.5, 7),
    largeText: classifyLevel(ratio, 3, 4.5),
  }
}

