export type UIState = {
  baseHex: string
  mode: HarmonyMode
  selectedColors: [string, string] | [string] | []
}

export const renderApp = (state: UIState) => {
  const palette = generatePalette(state.baseHex, state.mode)
  const contrast = state.selectedColors.length === 2
    ? checkContrast(state.selectedColors[0], state.selectedColors[1])
    : null

  return h('div', { style: styles.container },
    h('h1', { style: styles.heading }, 'Color Palette Generator'),

    h('div', { style: styles.inputRow },
      h('div', {},
        h('label', { style: styles.label }, 'Base Color'),
        h('div', { style: { display: 'flex', gap: '8px', alignItems: 'center' } },
          h('input', {
            type: 'color',
            value: state.baseHex,
            style: styles.colorPicker,
            'p-trigger': 'input',
            'p-target': 'color-picker',
          }),
          h('input', {
            type: 'text',
            value: state.baseHex,
            placeholder: '#3498db',
            style: styles.hexInput,
            'p-trigger': 'change',
            'p-target': 'hex-input',
          }),
        ),
      ),
    ),

    h('div', { style: styles.modeSelector },
      ...HARMONY_MODES.map(m =>
        h('button', {
          style: styles.modeButton(m.value === state.mode),
          'p-trigger': 'click',
          'data-mode': m.value,
          title: m.description,
        }, m.label)
      ),
    ),

    h('div', { style: styles.palette },
      ...palette.map(color =>
        renderSwatch(color, state.selectedColors.includes(color.hex))
      ),
    ),

    h('div', { style: styles.contrastSection },
      h('h2', { style: styles.contrastHeading }, 'Contrast Checker'),
      state.selectedColors.length > 0
        ? h('div', { style: styles.selectedColors },
            ...state.selectedColors.map(hex =>
              h('span', { style: styles.selectedChip(hex) },
                h('span', { style: styles.selectedChipDot(hex) }),
                hex,
              )
            ),
          )
        : null,
      state.selectedColors.length < 2
        ? h('p', { style: styles.contrastInstruction },
            state.selectedColors.length === 0
              ? 'Click any two swatches to check their contrast ratio.'
              : 'Click one more swatch to compare.'
          )
        : null,
      contrast
        ? renderContrastResult(contrast, state.selectedColors[0], state.selectedColors[1])
        : null,
    ),
  )
}

export const renderToHTML = (state: UIState): string => {
  const ssr = createSSR()
  const template = renderApp(state)
  return ssr(template)
}

import { isValidHex, normalizeHex } from './color'
import { generatePalette, HARMONY_MODES, type HarmonyMode } from './harmony'
import { checkContrast, type ContrastResult } from './contrast'
import { renderToHTML, type UIState } from './ui'
import { hexToRgb, hexToHsl, formatRgb, formatHsl } from './color'

const DEFAULT_STATE: UIState = {
  baseHex: '#3498db',
  mode: 'complementary',
  selectedColors: [],
}

const dataDir = `${import.meta.dir}/data`

const loadState = async (): Promise<UIState> => {
  const file = Bun.file(`${dataDir}/state.json`)
  if (await file.exists()) {
    return await file.json()
  }
  return DEFAULT_STATE
}

const saveState = async (state: UIState): Promise<void> => {
  await Bun.write(`${dataDir}/state.json`, JSON.stringify(state, null, 2))
}

export const setBaseColor = async (hex: string): Promise<UIState> => {
  if (!isValidHex(hex)) throw new Error(`Invalid hex color: ${hex}`)
  const state = await loadState()
  const updated: UIState = {
    ...state,
    baseHex: normalizeHex(hex),
    selectedColors: [],
  }
  await saveState(updated)
  return updated
}

export const setHarmonyMode = async (mode: HarmonyMode): Promise<UIState> => {
  const valid = HARMONY_MODES.some(m => m.value === mode)
  if (!valid) throw new Error(`Invalid harmony mode: ${mode}`)
  const state = await loadState()
  const updated: UIState = {
    ...state,
    mode,
    selectedColors: [],
  }
  await saveState(updated)
  return updated
}

export const selectColorForContrast = async (hex: string): Promise<UIState> => {
  const state = await loadState()
  const normalized = normalizeHex(hex)
  let selected: UIState['selectedColors']

  if (state.selectedColors.length < 2) {
    if (state.selectedColors.includes(normalized)) {
      selected = state.selectedColors.filter(c => c !== normalized) as UIState['selectedColors']
    } else {
      selected = [...state.selectedColors, normalized] as UIState['selectedColors']
    }
  } else {
    selected = [normalized]
  }

  const updated: UIState = { ...state, selectedColors: selected }
  await saveState(updated)
  return updated
}

export const getPalette = async () => {
  const state = await loadState()
  const colors = generatePalette(state.baseHex, state.mode)
  return colors.map(c => {
    const rgb = hexToRgb(c.hex)
    const hsl = hexToHsl(c.hex)
    return {
      ...c,
      rgb: formatRgb(rgb),
      hsl: formatHsl(hsl),
    }
  })
}

export const getContrastCheck = async (): Promise<ContrastResult | null> => {
  const state = await loadState()
  if (state.selectedColors.length !== 2) return null
  return checkContrast(state.selectedColors[0], state.selectedColors[1])
}

export const render = async (): Promise<string> => {
  const state = await loadState()
  return renderToHTML(state)
}

export const getState = loadState

