// ── Color type definitions ──────────────────────────────────────────

export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }

export type ColorValue = {
  hex: string
  rgb: RGB
  hsl: HSL
}

export type HarmonyMode =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

// ── Conversion utilities ────────────────────────────────────────────

const clamp = (v: number, min: number, max: number): number =>
  Math.max(min, Math.min(max, v))

const round = (v: number, decimals = 1): number =>
  Math.round(v * 10 ** decimals) / 10 ** decimals

export const hexToRgb = (hex: string): RGB => {
  const clean = hex.replace(/^#/, '')
  const full =
    clean.length === 3
      ? clean
          .split('')
          .map((c) => c + c)
          .join('')
      : clean
  const n = parseInt(full, 16)
  return {
    r: (n >> 16) & 0xff,
    g: (n >> 8) & 0xff,
    b: n & 0xff,
  }
}

export const rgbToHex = ({ r, g, b }: RGB): string => {
  const toHex = (v: number) =>
    clamp(Math.round(v), 0, 255).toString(16).padStart(2, '0')
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`
}

export const rgbToHsl = ({ r, g, b }: RGB): HSL => {
  const rn = r / 255
  const gn = g / 255
  const bn = b / 255
  const max = Math.max(rn, gn, bn)
  const min = Math.min(rn, gn, bn)
  const d = max - min
  const l = (max + min) / 2

  if (d === 0) return { h: 0, s: 0, l: round(l * 100) }

  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)

  let h = 0
  if (max === rn) h = ((gn - bn) / d + (gn < bn ? 6 : 0)) / 6
  else if (max === gn) h = ((bn - rn) / d + 2) / 6
  else h = ((rn - gn) / d + 4) / 6

  return {
    h: round(h * 360),
    s: round(s * 100),
    l: round(l * 100),
  }
}

export const hslToRgb = ({ h, s, l }: HSL): RGB => {
  const sn = s / 100
  const ln = l / 100
  const c = (1 - Math.abs(2 * ln - 1)) * sn
  const x = c * (1 - Math.abs(((h / 60) % 2) - 1))
  const m = ln - c / 2

  let rn = 0,
    gn = 0,
    bn = 0
  if (h < 60) [rn, gn, bn] = [c, x, 0]
  else if (h < 120) [rn, gn, bn] = [x, c, 0]
  else if (h < 180) [rn, gn, bn] = [0, c, x]
  else if (h < 240) [rn, gn, bn] = [0, x, c]
  else if (h < 300) [rn, gn, bn] = [x, 0, c]
  else [rn, gn, bn] = [c, 0, x]

  return {
    r: Math.round((rn + m) * 255),
    g: Math.round((gn + m) * 255),
    b: Math.round((bn + m) * 255),
  }
}

export const toColorValue = (hex: string): ColorValue => {
  const rgb = hexToRgb(hex)
  const hsl = rgbToHsl(rgb)
  return { hex: rgbToHex(rgb), rgb, hsl }
}

export const hslToColorValue = (hsl: HSL): ColorValue => {
  const normalized: HSL = {
    h: ((hsl.h % 360) + 360) % 360,
    s: clamp(hsl.s, 0, 100),
    l: clamp(hsl.l, 0, 100),
  }
  const rgb = hslToRgb(normalized)
  return { hex: rgbToHex(rgb), rgb, hsl: normalized }
}

// ── Validation ──────────────────────────────────────────────────────

export const isValidHex = (value: string): boolean =>
  /^#?([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(value.trim())

// ── Format helpers ──────────────────────────────────────────────────

export const formatRgb = ({ r, g, b }: RGB): string => `rgb(${r}, ${g}, ${b})`

export const formatHsl = ({ h, s, l }: HSL): string =>
  `hsl(${h}°, ${s}%, ${l}%)`

import { type ColorValue, type HSL, type HarmonyMode, hslToColorValue, toColorValue } from './color'

// ── Palette type ────────────────────────────────────────────────────

export type Palette = {
  mode: HarmonyMode
  base: ColorValue
  colors: ColorValue[]
}

// ── Hue rotation helper ─────────────────────────────────────────────

const rotateHue = (hsl: HSL, degrees: number): HSL => ({
  ...hsl,
  h: ((hsl.h + degrees) % 360 + 360) % 360,
})

// ── Harmony generators ──────────────────────────────────────────────

const complementary = (base: ColorValue): ColorValue[] => [
  base,
  hslToColorValue(rotateHue(base.hsl, 180)),
]

const analogous = (base: ColorValue): ColorValue[] => [
  hslToColorValue(rotateHue(base.hsl, -30)),
  base,
  hslToColorValue(rotateHue(base.hsl, 30)),
]

const triadic = (base: ColorValue): ColorValue[] => [
  base,
  hslToColorValue(rotateHue(base.hsl, 120)),
  hslToColorValue(rotateHue(base.hsl, 240)),
]

const splitComplementary = (base: ColorValue): ColorValue[] => [
  base,
  hslToColorValue(rotateHue(base.hsl, 150)),
  hslToColorValue(rotateHue(base.hsl, 210)),
]

const tetradic = (base: ColorValue): ColorValue[] => [
  base,
  hslToColorValue(rotateHue(base.hsl, 90)),
  hslToColorValue(rotateHue(base.hsl, 180)),
  hslToColorValue(rotateHue(base.hsl, 270)),
]

// ── Generator map ───────────────────────────────────────────────────

const generators: Record<HarmonyMode, (base: ColorValue) => ColorValue[]> = {
  complementary,
  analogous,
  triadic,
  'split-complementary': splitComplementary,
  tetradic,
}

// ── Public API ──────────────────────────────────────────────────────

export const generatePalette = (hex: string, mode: HarmonyMode): Palette => {
  const base = toColorValue(hex)
  const gen = generators[mode]
  return {
    mode,
    base,
    colors: gen(base),
  }
}

export const HARMONY_MODES: HarmonyMode[] = [
  'complementary',
  'analogous',
  'triadic',
  'split-complementary',
  'tetradic',
]

import type { RGB, ColorValue } from './color'

// ── WCAG contrast utilities ─────────────────────────────────────────

export type WcagLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  ratioLabel: string
  normalText: WcagLevel
  largeText: WcagLevel
  uiComponents: WcagLevel
}

// Relative luminance per WCAG 2.1
const linearize = (channel: number): number => {
  const srgb = channel / 255
  return srgb <= 0.04045 ? srgb / 12.92 : ((srgb + 0.055) / 1.055) ** 2.4
}

export const relativeLuminance = ({ r, g, b }: RGB): number =>
  0.2126 * linearize(r) + 0.7152 * linearize(g) + 0.0722 * linearize(b)

export const contrastRatio = (c1: RGB, c2: RGB): number => {
  const l1 = relativeLuminance(c1)
  const l2 = relativeLuminance(c2)
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

const gradeNormalText = (ratio: number): WcagLevel => {
  if (ratio >= 7) return 'AAA'
  if (ratio >= 4.5) return 'AA'
  return 'Fail'
}

const gradeLargeText = (ratio: number): WcagLevel => {
  if (ratio >= 4.5) return 'AAA'
  if (ratio >= 3) return 'AA'
  return 'Fail'
}

const gradeUiComponents = (ratio: number): WcagLevel => {
  if (ratio >= 4.5) return 'AAA'
  if (ratio >= 3) return 'AA'
  return 'Fail'
}

export const checkContrast = (a: ColorValue, b: ColorValue): ContrastResult => {
  const ratio = contrastRatio(a.rgb, b.rgb)
  const rounded = Math.round(ratio * 100) / 100
  return {
    ratio: rounded,
    ratioLabel: `${rounded.toFixed(2)}:1`,
    normalText: gradeNormalText(rounded),
    largeText: gradeLargeText(rounded),
    uiComponents: gradeUiComponents(rounded),
  }
}

