import { isValidHex, toColorValue, type HarmonyMode } from './color'
import { generatePalette, HARMONY_MODES, type Palette } from './harmony'
import { checkContrast, type ContrastResult } from './contrast'
import { renderToHtml, type RenderState } from './render'

// ── State management ────────────────────────────────────────────────

type AppState = {
  baseHex: string
  mode: HarmonyMode
  palette: Palette | null
  contrastFg: number
  contrastBg: number
}

const DEFAULT_STATE: AppState = {
  baseHex: '#3a86ff',
  mode: 'complementary',
  palette: null,
  contrastFg: 0,
  contrastBg: 1,
}

let state: AppState = { ...DEFAULT_STATE }

// ── Data persistence ────────────────────────────────────────────────

const DATA_PATH = `${import.meta.dir}/data/palettes.jsonl`

type SavedPalette = {
  timestamp: string
  baseHex: string
  mode: HarmonyMode
  colors: string[]
}

const savePalette = async (palette: Palette): Promise<void> => {
  const entry: SavedPalette = {
    timestamp: new Date().toISOString(),
    baseHex: palette.base.hex,
    mode: palette.mode,
    colors: palette.colors.map((c) => c.hex),
  }
  const line = JSON.stringify(entry) + '\n'
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(DATA_PATH, existing + line)
}

const loadHistory = async (): Promise<SavedPalette[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as SavedPalette)
}

// ── Core API ────────────────────────────────────────────────────────

export const generate = async (
  hex: string,
  mode: HarmonyMode = 'complementary',
): Promise<Palette> => {
  const normalizedHex = hex.startsWith('#') ? hex : `#${hex}`
  if (!isValidHex(normalizedHex)) {
    throw new Error(`Invalid hex color: ${hex}`)
  }

  state.baseHex = normalizedHex
  state.mode = mode
  state.palette = generatePalette(normalizedHex, mode)
  state.contrastFg = 0
  state.contrastBg = Math.min(1, state.palette.colors.length - 1)

  await savePalette(state.palette)
  return state.palette
}

export const getContrastCheck = (
  fgIndex: number,
  bgIndex: number,
): ContrastResult => {
  if (!state.palette) {
    throw new Error('Generate a palette first')
  }
  const { colors } = state.palette
  if (fgIndex < 0 || fgIndex >= colors.length || bgIndex < 0 || bgIndex >= colors.length) {
    throw new Error(`Color index out of range (0-${colors.length - 1})`)
  }
  state.contrastFg = fgIndex
  state.contrastBg = bgIndex
  return checkContrast(colors[fgIndex], colors[bgIndex])
}

export const checkHexContrast = (
  hex1: string,
  hex2: string,
): ContrastResult => {
  const c1 = toColorValue(hex1.startsWith('#') ? hex1 : `#${hex1}`)
  const c2 = toColorValue(hex2.startsWith('#') ? hex2 : `#${hex2}`)
  return checkContrast(c1, c2)
}

export const copyColorValue = (
  colorIndex: number,
  format: 'hex' | 'rgb' | 'hsl' = 'hex',
): string => {
  if (!state.palette) {
    throw new Error('Generate a palette first')
  }
  const { colors } = state.palette
  if (colorIndex < 0 || colorIndex >= colors.length) {
    throw new Error(`Color index out of range (0-${colors.length - 1})`)
  }
  const color = colors[colorIndex]
  const { formatRgb, formatHsl } = require('./color')
  switch (format) {
    case 'hex':
      return color.hex.toUpperCase()
    case 'rgb':
      return formatRgb(color.rgb)
    case 'hsl':
      return formatHsl(color.hsl)
  }
}

// ── Render ───────────────────────────────────────────────────────────

export const render = (): string => {
  const contrastResult =
    state.palette
      ? checkContrast(
          state.palette.colors[state.contrastFg],
          state.palette.colors[state.contrastBg],
        )
      : null

  const renderState: RenderState = {
    baseHex: state.baseHex,
    mode: state.mode,
    palette: state.palette,
    contrastFg: state.contrastFg,
    contrastBg: state.contrastBg,
    contrastResult,
  }

  return renderToHtml(renderState)
}

// ── History ──────────────────────────────────────────────────────────

export const getHistory = async (): Promise<SavedPalette[]> => loadHistory()

// ── CLI entry point ──────────────────────────────────────────────────

const main = async () => {
  const args = process.argv.slice(2)
  const hex = args[0] ?? '#3a86ff'
  const mode = (args[1] as HarmonyMode) ?? 'complementary'

  if (!HARMONY_MODES.includes(mode)) {
    console.error(`Invalid mode. Choose from: ${HARMONY_MODES.join(', ')}`)
    process.exit(1)
  }

  const palette = await generate(hex, mode)

  console.log(`\n  Color Palette — ${mode}`)
  console.log(`  Base: ${palette.base.hex.toUpperCase()}\n`)

  for (const [i, color] of palette.colors.entries()) {
    const { formatRgb, formatHsl } = await import('./color')
    console.log(`  [${i + 1}] ${color.hex.toUpperCase()}`)
    console.log(`      ${formatRgb(color.rgb)}`)
    console.log(`      ${formatHsl(color.hsl)}`)
    console.log()
  }

  // Show contrast between first two colors
  if (palette.colors.length >= 2) {
    const result = getContrastCheck(0, 1)
    console.log(`  Contrast (1 vs 2): ${result.ratioLabel}`)
    console.log(`    Normal text: ${result.normalText}`)
    console.log(`    Large text:  ${result.largeText}`)
    console.log(`    UI:          ${result.uiComponents}\n`)
  }
}

main().catch(console.error)

