export type ToolbarAction =
  | 'h1' | 'h2' | 'h3'
  | 'bold' | 'italic' | 'strikethrough'
  | 'link' | 'image'
  | 'code' | 'codeblock'
  | 'ul' | 'ol'
  | 'blockquote' | 'hr' | 'table'

const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const parseInline = (text: string): string => {
  let result = text
  // Images (before links so ![alt](url) isn't caught by link regex)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" style="max-width:100%;" />')
  // Links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // Bold + italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  // Strikethrough
  result = result.replace(/~~(.+?)~~/g, '<del>$1</del>')
  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>')
  return result
}

const parseTable = (lines: string[]): { html: string; consumed: number } => {
  if (lines.length < 2) return { html: '', consumed: 0 }

  const headerLine = lines[0]
  const separatorLine = lines[1]

  if (!separatorLine.match(/^\|?[\s-:|]+\|?$/)) return { html: '', consumed: 0 }

  const parseRow = (line: string): string[] =>
    line
      .replace(/^\|/, '')
      .replace(/\|$/, '')
      .split('|')
      .map((cell) => cell.trim())

  const alignments: string[] = parseRow(separatorLine).map((cell) => {
    const left = cell.startsWith(':')
    const right = cell.endsWith(':')
    if (left && right) return 'center'
    if (right) return 'right'
    return 'left'
  })

  const headers = parseRow(headerLine)
  let html = '<table><thead><tr>'
  headers.forEach((header, i) => {
    const align = alignments[i] || 'left'
    html += `<th style="text-align:${align};">${parseInline(escapeHtml(header))}</th>`
  })
  html += '</tr></thead><tbody>'

  let consumed = 2
  for (let i = 2; i < lines.length; i++) {
    const line = lines[i]
    if (!line.includes('|')) break
    const cells = parseRow(line)
    html += '<tr>'
    cells.forEach((cell, j) => {
      const align = alignments[j] || 'left'
      html += `<td style="text-align:${align};">${parseInline(escapeHtml(cell))}</td>`
    })
    html += '</tr>'
    consumed++
  }

  html += '</tbody></table>'
  return { html, consumed }
}

export const renderMarkdown = (markdown: string): string => {
  const lines = markdown.split('\n')
  const output: string[] = []
  let i = 0
  let inCodeBlock = false
  let codeBlockContent: string[] = []
  let codeBlockLang = ''

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code blocks
    if (line.startsWith('```')) {
      if (!inCodeBlock) {
        inCodeBlock = true
        codeBlockLang = line.slice(3).trim()
        codeBlockContent = []
        i++
        continue
      } else {
        inCodeBlock = false
        const langAttr = codeBlockLang ? ` class="language-${escapeHtml(codeBlockLang)}"` : ''
        output.push(
          `<pre><code${langAttr}>${escapeHtml(codeBlockContent.join('\n'))}</code></pre>`
        )
        i++
        continue
      }
    }

    if (inCodeBlock) {
      codeBlockContent.push(line)
      i++
      continue
    }

    // Blank line
    if (line.trim() === '') {
      i++
      continue
    }

    // Horizontal rule
    if (/^(---|\*\*\*|___)$/.test(line.trim())) {
      output.push('<hr />')
      i++
      continue
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      const level = headingMatch[1].length
      output.push(`<h${level}>${parseInline(escapeHtml(headingMatch[2]))}</h${level}>`)
      i++
      continue
    }

    // Table detection
    if (line.includes('|') && i + 1 < lines.length && lines[i + 1].match(/^\|?[\s-:|]+\|?$/)) {
      const tableResult = parseTable(lines.slice(i))
      if (tableResult.html) {
        output.push(tableResult.html)
        i += tableResult.consumed
        continue
      }
    }

    // Blockquote
    if (line.startsWith('>')) {
      const quoteLines: string[] = []
      while (i < lines.length && lines[i].startsWith('>')) {
        quoteLines.push(lines[i].replace(/^>\s?/, ''))
        i++
      }
      output.push(`<blockquote>${renderMarkdown(quoteLines.join('\n'))}</blockquote>`)
      continue
    }

    // Unordered list
    if (/^[\s]*[-*+]\s/.test(line)) {
      const listItems: string[] = []
      while (i < lines.length && /^[\s]*[-*+]\s/.test(lines[i])) {
        listItems.push(lines[i].replace(/^[\s]*[-*+]\s/, ''))
        i++
      }
      output.push(
        '<ul>' + listItems.map((item) => `<li>${parseInline(escapeHtml(item))}</li>`).join('') + '</ul>'
      )
      continue
    }

    // Ordered list
    if (/^[\s]*\d+\.\s/.test(line)) {
      const listItems: string[] = []
      while (i < lines.length && /^[\s]*\d+\.\s/.test(lines[i])) {
        listItems.push(lines[i].replace(/^[\s]*\d+\.\s/, ''))
        i++
      }
      output.push(
        '<ol>' + listItems.map((item) => `<li>${parseInline(escapeHtml(item))}</li>`).join('') + '</ol>'
      )
      continue
    }

    // Paragraph
    const paraLines: string[] = []
    while (i < lines.length && lines[i].trim() !== '' && !lines[i].startsWith('#') && !lines[i].startsWith('```') && !lines[i].startsWith('>') && !/^[\s]*[-*+]\s/.test(lines[i]) && !/^[\s]*\d+\.\s/.test(lines[i]) && !/^(---|\*\*\*|___)$/.test(lines[i].trim())) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      output.push(`<p>${parseInline(escapeHtml(paraLines.join('\n')))}</p>`)
    }
  }

  // Close unclosed code block
  if (inCodeBlock) {
    output.push(`<pre><code>${escapeHtml(codeBlockContent.join('\n'))}</code></pre>`)
  }

  return output.join('\n')
}

import type { Document, DocumentListItem, SaveDocumentRequest } from './types'

const DATA_PATH = `${import.meta.dir}/data/documents.json`

const readDocuments = async (): Promise<Document[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Document[]
}

const writeDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

const generateId = (): string =>
  `doc_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`

export const listDocuments = async (): Promise<DocumentListItem[]> => {
  const docs = await readDocuments()
  return docs
    .map(({ id, title, updatedAt }) => ({ id, title, updatedAt }))
    .sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
}

export const getDocument = async (id: string): Promise<Document | null> => {
  const docs = await readDocuments()
  return docs.find((d) => d.id === id) ?? null
}

export const saveDocument = async (req: SaveDocumentRequest): Promise<Document> => {
  const docs = await readDocuments()
  const now = new Date().toISOString()
  const doc: Document = {
    id: generateId(),
    title: req.title,
    content: req.content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await writeDocuments(docs)
  return doc
}

export const updateDocument = async (
  id: string,
  req: SaveDocumentRequest
): Promise<Document | null> => {
  const docs = await readDocuments()
  const index = docs.findIndex((d) => d.id === id)
  if (index === -1) return null
  docs[index] = {
    ...docs[index],
    title: req.title,
    content: req.content,
    updatedAt: new Date().toISOString(),
  }
  await writeDocuments(docs)
  return docs[index]
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments()
  const filtered = docs.filter((d) => d.id !== id)
  if (filtered.length === docs.length) return false
  await writeDocuments(filtered)
  return true
}

