      return `<button
        style="${styleToString(styles.toolbarBtn as unknown as Record<string, string>)}"
        title="${btn.title}"
        data-action="${btn.action}"
        data-before="${encodeURIComponent(insert.before)}"
        data-after="${encodeURIComponent(insert.after)}"
        data-placeholder="${encodeURIComponent(insert.placeholder)}"
        p-trigger="click:toolbar-action"
