  </div>

  <!-- Toolbar -->
  <div style="${styleToString(styles.toolbar as unknown as Record<string, string>)}" p-target="toolbar">
    ${toolbarHtml}
  </div>

  <!-- Main content -->
  <div style="${styleToString(styles.splitPane as unknown as Record<string, string>)}">
    <!-- Sidebar (hidden by default) -->
    <div id="sidebar" style="${styleToString(styles.sidebar as unknown as Record<string, string>)}; display: none;">
      <div style="${styleToString(styles.sidebarHeader as unknown as Record<string, string>)}">
        <span>Saved Documents</span>
      </div>
      <div style="${styleToString(styles.docList as unknown as Record<string, string>)}" id="doc-list" p-target="doc-list">
        ${docListHtml}
      </div>
    </div>

    <!-- Editor pane -->
    <div style="${styleToString(styles.editorPane as unknown as Record<string, string>)}">
      <div style="${styleToString(styles.paneLabel as unknown as Record<string, string>)}">Editor</div>
      <textarea
        id="editor"
        style="${styleToString(styles.textarea as unknown as Record<string, string>)}"
        p-trigger="input:editor-input"
        spellcheck="false"
      >${content}</textarea>
    </div>

    <!-- Preview pane -->
    <div style="${styleToString(styles.previewPane as unknown as Record<string, string>)}">
      <div style="${styleToString(styles.paneLabel as unknown as Record<string, string>)}">Preview</div>
      <div class="preview" id="preview" style="${styleToString(styles.preview as unknown as Record<string, string>)}" p-target="preview">
        ${preview}
      </div>
    </div>
  </div>

  <script>
    const editor = document.getElementById('editor');
    const preview = document.getElementById('preview');
    const titleInput = document.getElementById('doc-title');
    const sidebar = document.getElementById('sidebar');
    let currentDocId = null;

    // Live preview
    editor.addEventListener('input', () => {
      fetch('/render', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ markdown: editor.value }),
      })
        .then((r) => r.json())
        .then((data) => { preview.innerHTML = data.html; });
    });

    // Toolbar actions
    document.querySelectorAll('[data-action]').forEach((btn) => {
      btn.addEventListener('click', () => {
        const before = decodeURIComponent(btn.dataset.before);
        const after = decodeURIComponent(btn.dataset.after);
        const placeholder = decodeURIComponent(btn.dataset.placeholder);
        const start = editor.selectionStart;
        const end = editor.selectionEnd;
        const selected = editor.value.substring(start, end);
        const insert = selected || placeholder;
        editor.value =
          editor.value.substring(0, start) + before + insert + after + editor.value.substring(end);
        editor.focus();
        const newCursorPos = start + before.length + insert.length;
        editor.setSelectionRange(
          start + before.length,
          newCursorPos
        );
        editor.dispatchEvent(new Event('input'));
      });
    });

    // Save document
    document.getElementById('save-btn').addEventListener('click', () => {
      const title = titleInput.value.trim() || 'Untitled';
      const content = editor.value;
      const method = currentDocId ? 'PUT' : 'POST';
      const url = currentDocId ? '/documents/' + currentDocId : '/documents';
      fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title, content }),
      })
        .then((r) => r.json())
        .then((doc) => {
          currentDocId = doc.id;
          refreshDocList();
        });
    });

    // New document
    document.getElementById('new-btn').addEventListener('click', () => {
      currentDocId = null;
      titleInput.value = '';
      editor.value = '';
      editor.dispatchEvent(new Event('input'));
    });

    // Toggle sidebar
    document.getElementById('toggle-sidebar').addEventListener('click', () => {
      sidebar.style.display = sidebar.style.display === 'none' ? 'flex' : 'none';
    });

    // Load document
    const attachDocListeners = () => {
      document.querySelectorAll('[data-id]').forEach((el) => {
        el.addEventListener('click', () => {
          fetch('/documents/' + el.dataset.id)
            .then((r) => r.json())
            .then((doc) => {
              currentDocId = doc.id;
              titleInput.value = doc.title;
              editor.value = doc.content;
              editor.dispatchEvent(new Event('input'));
            });
        });
      });
    };
    attachDocListeners();

    // Refresh document list
    const refreshDocList = () => {
      fetch('/documents')
        .then((r) => r.json())
        .then((docs) => {
          const list = document.getElementById('doc-list');
          if (docs.length === 0) {
            list.innerHTML = '<div style="padding: 12px; color: #888; font-size: 13px;">No saved documents</div>';
            return;
          }
          list.innerHTML = docs
            .map((doc) =>
              '<div style="padding: 8px 12px; cursor: pointer; border-bottom: 1px solid #f0f0f0; font-size: 13px;" data-id="' + doc.id + '">' +
              '<div style="font-weight: 500; margin-bottom: 2px;">' + doc.title + '</div>' +
              '<div style="font-size: 11px; color: #888;">' + new Date(doc.updatedAt).toLocaleDateString() + '</div>' +
              '</div>'
            )
            .join('');
          attachDocListeners();
        });
    };

    // Tab key support in editor
    editor.addEventListener('keydown', (e) => {
      if (e.key === 'Tab') {
        e.preventDefault();
        const start = editor.selectionStart;
        const end = editor.selectionEnd;
        editor.value = editor.value.substring(0, start) + '  ' + editor.value.substring(end);
        editor.selectionStart = editor.selectionEnd = start + 2;
      }
    });
  </script>
</body>
</html>`
}

import { renderEditor } from './editor'
import { renderMarkdown } from './markdown'
import {
  listDocuments,
  getDocument,
  saveDocument,
  updateDocument,
  deleteDocument,
} from './documents'
import type { SaveDocumentRequest } from './types'

const parseJsonBody = async (req: Request): Promise<unknown> => {
  const text = await req.text()
  return JSON.parse(text)
}

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string, status = 200): Response =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // Serve editor UI
    if (pathname === '/' && method === 'GET') {
      const docs = await listDocuments()
      const html = renderEditor(docs)
      return htmlResponse(html)
    }

    // Render markdown to HTML
    if (pathname === '/render' && method === 'POST') {
      const body = (await parseJsonBody(req)) as { markdown: string }
      const html = renderMarkdown(body.markdown)
      return jsonResponse({ html })
    }

    // List documents
    if (pathname === '/documents' && method === 'GET') {
      const docs = await listDocuments()
      return jsonResponse(docs)
    }

    // Get document by ID
    const docMatch = pathname.match(/^\/documents\/(.+)$/)
    if (docMatch && method === 'GET') {
      const doc = await getDocument(docMatch[1])
      if (!doc) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(doc)
    }

    // Save new document
    if (pathname === '/documents' && method === 'POST') {
      const body = (await parseJsonBody(req)) as SaveDocumentRequest
      if (!body.title || body.content === undefined) {
        return jsonResponse({ error: 'title and content required' }, 400)
      }
      const doc = await saveDocument(body)
      return jsonResponse(doc, 201)
    }

    // Update document
    if (docMatch && method === 'PUT') {
      const body = (await parseJsonBody(req)) as SaveDocumentRequest
      const doc = await updateDocument(docMatch[1], body)
      if (!doc) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(doc)
    }

    // Delete document
    if (docMatch && method === 'DELETE') {
      const deleted = await deleteDocument(docMatch[1])
      if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ ok: true })
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

