// Markdown-to-HTML renderer supporting standard syntax

type Rule = {
  pattern: RegExp
  replace: string | ((...args: string[]) => string)
}

const escapeHtml = (str: string): string =>
  str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const renderTable = (block: string): string => {
  const rows = block.trim().split('\n')
  if (rows.length < 2) return `<p>${escapeHtml(block)}</p>`

  const parseRow = (row: string): string[] =>
    row
      .replace(/^\|/, '')
      .replace(/\|$/, '')
      .split('|')
      .map((cell) => cell.trim())

  const headerCells = parseRow(rows[0])
  const separatorCells = parseRow(rows[1])

  const isSeparator = separatorCells.every((cell) => /^:?-{3,}:?$/.test(cell))
  if (!isSeparator) return `<p>${escapeHtml(block)}</p>`

  const alignments = separatorCells.map((cell) => {
    if (cell.startsWith(':') && cell.endsWith(':')) return 'center'
    if (cell.endsWith(':')) return 'right'
    return 'left'
  })

  const renderCell = (tag: string, cells: string[], aligns: string[]): string =>
    '<tr>' +
    cells
      .map(
        (cell, i) =>
          `<${tag} style="text-align:${aligns[i] || 'left'}">${applyInlineRules(cell)}</${tag}>`,
      )
      .join('') +
    '</tr>'

  const headHtml = renderCell('th', headerCells, alignments)
  const bodyRows = rows
    .slice(2)
    .map((row) => renderCell('td', parseRow(row), alignments))
    .join('\n')

  return `<table>\n<thead>\n${headHtml}\n</thead>\n<tbody>\n${bodyRows}\n</tbody>\n</table>`
}

const inlineRules: Rule[] = [
  { pattern: /!\[([^\]]*)\]\(([^)]+)\)/g, replace: '<img src="$2" alt="$1" />' },
  { pattern: /\[([^\]]+)\]\(([^)]+)\)/g, replace: '<a href="$2">$1</a>' },
  { pattern: /`([^`]+)`/g, replace: '<code>$1</code>' },
  { pattern: /\*\*(.+?)\*\*/g, replace: '<strong>$1</strong>' },
  { pattern: /__(.+?)__/g, replace: '<strong>$1</strong>' },
  { pattern: /\*(.+?)\*/g, replace: '<em>$1</em>' },
  { pattern: /_(.+?)_/g, replace: '<em>$1</em>' },
  { pattern: /~~(.+?)~~/g, replace: '<del>$1</del>' },
]

const applyInlineRules = (text: string): string => {
  let result = escapeHtml(text)
  // Restore markdown syntax that was escaped
  result = result
    .replace(/\*\*/g, '**')
    .replace(/__/g, '__')
    .replace(/~~/g, '~~')
    .replace(/`/g, '`')

  // Decode just enough for inline rules to work on the original tokens
  result = text
  for (const rule of inlineRules) {
    result = result.replace(rule.pattern, rule.replace as string)
  }
  // Escape any remaining bare HTML in text segments (but not in our generated tags)
  return result
}

const renderCodeBlock = (lang: string, code: string): string => {
  const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : ''
  return `<pre><code${langAttr}>${escapeHtml(code)}</code></pre>`
}

const renderList = (lines: string[], ordered: boolean): string => {
  const tag = ordered ? 'ol' : 'ul'
  const items = lines.map((line) => {
    const content = line.replace(/^(\d+\.\s|[-*+]\s)/, '')
    return `<li>${applyInlineRules(content)}</li>`
  })
  return `<${tag}>\n${items.join('\n')}\n</${tag}>`
}

const renderBlockquote = (lines: string[]): string => {
  const inner = lines.map((l) => l.replace(/^>\s?/, '')).join('\n')
  return `<blockquote>${render(inner)}</blockquote>`
}

export const render = (markdown: string): string => {
  const lines = markdown.replace(/\r\n/g, '\n').split('\n')
  const blocks: string[] = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code block
    const fenceMatch = line.match(/^```(\w*)/)
    if (fenceMatch) {
      const lang = fenceMatch[1]
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(lines[i])
        i++
      }
      i++ // skip closing ```
      blocks.push(renderCodeBlock(lang, codeLines.join('\n')))
      continue
    }

    // Horizontal rule
    if (/^([-*_])\s*(\1\s*){2,}$/.test(line.trim())) {
      blocks.push('<hr />')
      i++
      continue
    }

    // Heading
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      const level = headingMatch[1].length
      blocks.push(`<h${level}>${applyInlineRules(headingMatch[2])}</h${level}>`)
      i++
      continue
    }

    // Table (peek ahead for separator row)
    if (line.includes('|') && i + 1 < lines.length && /^\|?\s*:?-{3,}:?\s*\|/.test(lines[i + 1])) {
      const tableLines: string[] = [line]
      i++
      while (i < lines.length && lines[i].includes('|')) {
        tableLines.push(lines[i])
        i++
      }
      blocks.push(renderTable(tableLines.join('\n')))
      continue
    }

    // Blockquote
    if (line.startsWith('>')) {
      const bqLines: string[] = []
      while (i < lines.length && (lines[i].startsWith('>') || (lines[i].trim() !== '' && bqLines.length > 0 && !lines[i].startsWith('#')))) {
        if (!lines[i].startsWith('>') && lines[i].trim() === '') break
        bqLines.push(lines[i])
        i++
      }
      blocks.push(renderBlockquote(bqLines))
      continue
    }

    // Unordered list
    if (/^[-*+]\s/.test(line)) {
      const listLines: string[] = []
      while (i < lines.length && /^[-*+]\s/.test(lines[i])) {
        listLines.push(lines[i])
        i++
      }
      blocks.push(renderList(listLines, false))
      continue
    }

    // Ordered list
    if (/^\d+\.\s/.test(line)) {
      const listLines: string[] = []
      while (i < lines.length && /^\d+\.\s/.test(lines[i])) {
        listLines.push(lines[i])
        i++
      }
      blocks.push(renderList(listLines, true))
      continue
    }

    // Blank line
    if (line.trim() === '') {
      i++
      continue
    }

    // Paragraph — collect contiguous non-empty lines
    const paraLines: string[] = []
    while (i < lines.length && lines[i].trim() !== '' && !lines[i].startsWith('#') && !lines[i].startsWith('>') && !lines[i].startsWith('```') && !/^[-*+]\s/.test(lines[i]) && !/^\d+\.\s/.test(lines[i]) && !/^([-*_])\s*(\1\s*){2,}$/.test(lines[i].trim())) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      blocks.push(`<p>${applyInlineRules(paraLines.join(' '))}</p>`)
    }
  }

  return blocks.join('\n')
}

// Document persistence layer using Bun file APIs

const DATA_PATH = new URL('./data/documents.json', import.meta.url).pathname

export type Document = {
  id: string
  title: string
  content: string
  createdAt: string
  updatedAt: string
}

const generateId = (): string =>
  `doc_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`

const readAll = async (): Promise<Document[]> => {
  try {
    const file = Bun.file(DATA_PATH)
    const text = await file.text()
    return JSON.parse(text) as Document[]
  } catch {
    return []
  }
}

const writeAll = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

export const listDocuments = async (): Promise<Document[]> => {
  const docs = await readAll()
  return docs.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
}

export const getDocument = async (id: string): Promise<Document | undefined> => {
  const docs = await readAll()
  return docs.find((d) => d.id === id)
}

export const createDocument = async (title: string, content: string): Promise<Document> => {
  const docs = await readAll()
  const now = new Date().toISOString()
  const doc: Document = {
    id: generateId(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await writeAll(docs)
  return doc
}

export const updateDocument = async (
  id: string,
  updates: { title?: string; content?: string },
): Promise<Document | undefined> => {
  const docs = await readAll()
  const idx = docs.findIndex((d) => d.id === id)
  if (idx === -1) return undefined
  const doc = docs[idx]
  if (updates.title !== undefined) doc.title = updates.title
  if (updates.content !== undefined) doc.content = updates.content
  doc.updatedAt = new Date().toISOString()
  await writeAll(docs)
  return doc
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readAll()
  const idx = docs.findIndex((d) => d.id === id)
  if (idx === -1) return false
  docs.splice(idx, 1)
  await writeAll(docs)
  return true
}

