const clientScript = `
const editor = document.getElementById('editor');
const preview = document.getElementById('preview');
const titleInput = document.getElementById('doc-title');
let currentDocId = null;
let debounceTimer = null;

const updatePreview = async () => {
  const res = await fetch('/api/render', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ markdown: editor.value }),
  });
  const data = await res.json();
  preview.innerHTML = data.html;
};

editor.addEventListener('input', () => {
  clearTimeout(debounceTimer);
  debounceTimer = setTimeout(updatePreview, 150);
});

// Toolbar actions
const insertions = {
  h1: { before: '# ', after: '' },
  h2: { before: '## ', after: '' },
  h3: { before: '### ', after: '' },
  bold: { before: '**', after: '**' },
  italic: { before: '*', after: '*' },
  strikethrough: { before: '~~', after: '~~' },
  link: { before: '[', after: '](url)' },
  image: { before: '![alt](', after: ')' },
  code: { before: '\`', after: '\`' },
  codeblock: { before: '\`\`\`\\n', after: '\\n\`\`\`' },
  ul: { before: '- ', after: '' },
  ol: { before: '1. ', after: '' },
  blockquote: { before: '> ', after: '' },
  hr: { before: '\\n---\\n', after: '' },
  table: { before: '| Header | Header |\\n| --- | --- |\\n| Cell | Cell |', after: '' },
};

document.querySelectorAll('[data-action]').forEach((btn) => {
  btn.addEventListener('click', () => {
    const action = btn.dataset.action;
    const ins = insertions[action];
    if (!ins) return;
    const start = editor.selectionStart;
    const end = editor.selectionEnd;
    const selected = editor.value.substring(start, end);
    const before = ins.before.replace(/\\\\n/g, '\\n');
    const after = ins.after.replace(/\\\\n/g, '\\n');
    const replacement = before + (selected || 'text') + after;
    editor.setRangeText(replacement, start, end, 'end');
    editor.focus();
    updatePreview();
  });
});

// Save
document.getElementById('save-btn').addEventListener('click', async () => {
  const title = titleInput.value.trim() || 'Untitled';
  const content = editor.value;
  if (currentDocId) {
    await fetch('/api/documents/' + currentDocId, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title, content }),
    });
  } else {
    const res = await fetch('/api/documents', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title, content }),
    });
    const doc = await res.json();
    currentDocId = doc.id;
  }
  loadDocList();
});

// New document
document.getElementById('new-btn').addEventListener('click', () => {
  currentDocId = null;
  titleInput.value = '';
  editor.value = '';
  preview.innerHTML = '';
});

// Load document list
const loadDocList = async () => {
  const res = await fetch('/api/documents');
  const docs = await res.json();
  const list = document.getElementById('doc-list');
  list.innerHTML = docs.map((d) =>
    '<div class="doc-item" data-id="' + d.id + '" style="padding:8px 12px;cursor:pointer;font-size:13px;border-bottom:1px solid #313244;color:#bac2de;">' +
      '<div>' + d.title + '</div>' +
      '<div style="font-size:11px;color:#6c7086;margin-top:2px;">' + new Date(d.updatedAt).toLocaleDateString() + '</div>' +
    '</div>'
  ).join('');
  list.querySelectorAll('.doc-item').forEach((el) => {
    el.addEventListener('click', () => loadDoc(el.dataset.id));
  });
};

const loadDoc = async (id) => {
  const res = await fetch('/api/documents/' + id);
  const doc = await res.json();
  currentDocId = doc.id;
  titleInput.value = doc.title;
  editor.value = doc.content;
  updatePreview();
};

// Delete current document
document.getElementById('delete-btn').addEventListener('click', async () => {
  if (!currentDocId) return;
  if (!confirm('Delete this document?')) return;
  await fetch('/api/documents/' + currentDocId, { method: 'DELETE' });
  currentDocId = null;
  titleInput.value = '';
  editor.value = '';
  preview.innerHTML = '';
  loadDocList();
});

// Initial load
loadDocList();
updatePreview();
`

