const parseJsonBody = async (req: Request): Promise<Record<string, unknown>> => {
  try {
    return (await req.json()) as Record<string, unknown>
  } catch {
    return {}
  }
}

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const extractId = (pathname: string): string => {
  const parts = pathname.split('/')
  return parts[parts.length - 1]
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // Serve editor page
    if (pathname === '/' && method === 'GET') {
      const docs = await listDocuments()
      const html = renderPage(docs, defaultContent)
      return htmlResponse(html)
    }

    // Render markdown
    if (pathname === '/api/render' && method === 'POST') {
      const body = await parseJsonBody(req)
      const markdown = (body.markdown as string) || ''
      const html = render(markdown)
      return jsonResponse({ html })
    }

    // List documents
    if (pathname === '/api/documents' && method === 'GET') {
      const docs = await listDocuments()
      return jsonResponse(docs)
    }

    // Create document
    if (pathname === '/api/documents' && method === 'POST') {
      const body = await parseJsonBody(req)
      const title = (body.title as string) || 'Untitled'
      const content = (body.content as string) || ''
      const doc = await createDocument(title, content)
      return jsonResponse(doc, 201)
    }

    // Single document operations
    if (pathname.startsWith('/api/documents/') && pathname.split('/').length === 4) {
      const id = extractId(pathname)

      if (method === 'GET') {
        const doc = await getDocument(id)
        if (!doc) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse(doc)
      }

      if (method === 'PUT') {
        const body = await parseJsonBody(req)
        const doc = await updateDocument(id, {
          title: body.title as string | undefined,
          content: body.content as string | undefined,
        })
        if (!doc) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse(doc)
      }

      if (method === 'DELETE') {
        const deleted = await deleteDocument(id)
        if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse({ ok: true })
      }
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

