export const buildEditorPage = (): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Markdown Editor</title>
  <style>${globalStyles}</style>
</head>
<body>
  <div class="header">
    <h1>MD Editor</h1>
    <input type="text" id="doc-title" placeholder="Document title..." value="Untitled" />
    <button class="btn-save" onclick="saveDocument()">Save</button>
    <button class="btn-load" onclick="openLoadModal()">Load</button>
    <button class="btn-new" onclick="newDocument()">New</button>
  </div>

  <div class="toolbar">
    <button onclick="insertFormat('h1')" title="Heading 1">H1</button>
    <button onclick="insertFormat('h2')" title="Heading 2">H2</button>
    <button onclick="insertFormat('h3')" title="Heading 3">H3</button>
    <div class="sep"></div>
    <button onclick="insertFormat('bold')" title="Bold"><b>B</b></button>
    <button onclick="insertFormat('italic')" title="Italic"><i>I</i></button>
    <div class="sep"></div>
    <button onclick="insertFormat('link')" title="Link">Link</button>
    <button onclick="insertFormat('image')" title="Image">Img</button>
    <div class="sep"></div>
    <button onclick="insertFormat('code')" title="Inline Code">&lt;/&gt;</button>
    <button onclick="insertFormat('codeblock')" title="Code Block">Block</button>
    <div class="sep"></div>
    <button onclick="insertFormat('ul')" title="Unordered List">&#8226; List</button>
    <button onclick="insertFormat('ol')" title="Ordered List">1. List</button>
    <div class="sep"></div>
    <button onclick="insertFormat('blockquote')" title="Blockquote">&gt; Quote</button>
    <button onclick="insertFormat('hr')" title="Horizontal Rule">&#8212; HR</button>
    <button onclick="insertFormat('table')" title="Table">Table</button>
  </div>

  <div class="editor-container">
    <div class="pane pane-editor">
      <textarea id="editor" spellcheck="false">${DEFAULT_CONTENT}</textarea>
    </div>
    <div class="pane pane-preview" id="preview"></div>
  </div>

  <div class="modal-overlay" id="modal-overlay">
    <div class="modal">
      <h2>Saved Documents</h2>
      <div id="doc-list"></div>
      <button class="close-btn" onclick="closeLoadModal()">Close</button>
    </div>
  </div>

  <script>
    let currentDocId = null;
    const editor = document.getElementById('editor');
    const preview = document.getElementById('preview');
    const titleInput = document.getElementById('doc-title');

    // Live preview
    const updatePreview = async () => {
      const res = await fetch('/api/render', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ content: editor.value })
      });
      const data = await res.json();
      preview.innerHTML = data.html;
    };

    let debounceTimer;
    editor.addEventListener('input', () => {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(updatePreview, 150);
    });

    // Initial render
    updatePreview();

    // Toolbar formatting
    const insertFormat = (type) => {
      const start = editor.selectionStart;
      const end = editor.selectionEnd;
      const selected = editor.value.substring(start, end);
      let before = '';
      let after = '';
      let insert = '';

      const formats = {
        h1: { before: '# ', after: '', placeholder: 'Heading 1' },
        h2: { before: '## ', after: '', placeholder: 'Heading 2' },
        h3: { before: '### ', after: '', placeholder: 'Heading 3' },
        bold: { before: '**', after: '**', placeholder: 'bold text' },
        italic: { before: '*', after: '*', placeholder: 'italic text' },
        link: { before: '[', after: '](url)', placeholder: 'link text' },
        image: { before: '![', after: '](url)', placeholder: 'alt text' },
        code: { before: '\`', after: '\`', placeholder: 'code' },
        codeblock: { before: '\`\`\`\\n', after: '\\n\`\`\`', placeholder: 'code here' },
        ul: { before: '- ', after: '', placeholder: 'list item' },
        ol: { before: '1. ', after: '', placeholder: 'list item' },
        blockquote: { before: '> ', after: '', placeholder: 'quote' },
        hr: { before: '', after: '', placeholder: '---' },
        table: { before: '', after: '', placeholder: '| Header 1 | Header 2 |\\n|----------|----------|\\n| Cell 1   | Cell 2   |' },
      };

      const fmt = formats[type];
      if (!fmt) return;

      if (type === 'hr' || type === 'table') {
        insert = '\\n' + fmt.placeholder + '\\n';
      } else if (selected) {
        insert = fmt.before + selected + fmt.after;
      } else {
        insert = fmt.before + fmt.placeholder + fmt.after;
      }

      editor.setRangeText(insert, start, end, 'end');
      editor.focus();
      updatePreview();
    };

    // Save
    const saveDocument = async () => {
      const title = titleInput.value.trim() || 'Untitled';
      const content = editor.value;
      const method = currentDocId ? 'PUT' : 'POST';
      const url = currentDocId ? '/api/documents/' + currentDocId : '/api/documents';

      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title, content })
      });
      const doc = await res.json();
      currentDocId = doc.id;
      titleInput.value = doc.title;
    };

    // Load modal
    const openLoadModal = async () => {
      const res = await fetch('/api/documents');
      const docs = await res.json();
      const list = document.getElementById('doc-list');

      if (docs.length === 0) {
        list.innerHTML = '<div class="empty">No saved documents</div>';
      } else {
        list.innerHTML = docs.map(d =>
          '<div class="doc-item" onclick="loadDocument(\\'' + d.id + '\\')">' +
            '<div>' +
              '<div class="doc-title">' + escapeHtmlStr(d.title) + '</div>' +
              '<div class="doc-date">' + new Date(d.updatedAt).toLocaleString() + '</div>' +
            '</div>' +
            '<button class="btn-delete" onclick="event.stopPropagation(); deleteDoc(\\'' + d.id + '\\')">&times;</button>' +
          '</div>'
        ).join('');
      }
      document.getElementById('modal-overlay').classList.add('active');
    };

    const closeLoadModal = () => {
      document.getElementById('modal-overlay').classList.remove('active');
    };

    const loadDocument = async (id) => {
      const res = await fetch('/api/documents/' + id);
      const doc = await res.json();
      currentDocId = doc.id;
      titleInput.value = doc.title;
      editor.value = doc.content;
      closeLoadModal();
      updatePreview();
    };

    const deleteDoc = async (id) => {
      await fetch('/api/documents/' + id, { method: 'DELETE' });
      if (currentDocId === id) {
        currentDocId = null;
        titleInput.value = 'Untitled';
      }
      openLoadModal();
    };

    const newDocument = () => {
      currentDocId = null;
      titleInput.value = 'Untitled';
      editor.value = '';
      updatePreview();
      editor.focus();
    };

    const escapeHtmlStr = (s) => {
      const div = document.createElement('div');
      div.textContent = s;
      return div.innerHTML;
    };

    // Tab key support in editor
    editor.addEventListener('keydown', (e) => {
      if (e.key === 'Tab') {
        e.preventDefault();
        const start = editor.selectionStart;
        editor.setRangeText('  ', start, start, 'end');
      }
    });
  </script>
</body>
</html>`

import { buildEditorPage } from './editor'
import { renderMarkdown } from './markdown'
import {
  listDocuments,
  getDocument,
  createDocument,
  updateDocument,
  deleteDocument,
} from './documents'

const PORT = Number(process.env.PORT) || 3000

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const extractId = (pathname: string): string =>
  pathname.split('/').pop() ?? ''

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url
  const method = req.method

  // Serve editor UI
  if (pathname === '/' && method === 'GET') {
    return htmlResponse(buildEditorPage())
  }

  // Render markdown to HTML
  if (pathname === '/api/render' && method === 'POST') {
    const body = (await req.json()) as { content: string }
    const html = renderMarkdown(body.content ?? '')
    return jsonResponse({ html })
  }

  // List documents
  if (pathname === '/api/documents' && method === 'GET') {
    return jsonResponse(await listDocuments())
  }

  // Create document
  if (pathname === '/api/documents' && method === 'POST') {
    const body = (await req.json()) as { title: string; content: string }
    const doc = await createDocument(body.title, body.content)
    return jsonResponse(doc, 201)
  }

  // Single document routes
  if (pathname.startsWith('/api/documents/') && pathname.split('/').length === 4) {
    const id = extractId(pathname)

    if (method === 'GET') {
      const doc = await getDocument(id)
      if (!doc) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(doc)
    }

    if (method === 'PUT') {
      const body = (await req.json()) as { title: string; content: string }
      const doc = await updateDocument(id, body.title, body.content)
      if (!doc) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(doc)
    }

    if (method === 'DELETE') {
      const deleted = await deleteDocument(id)
      if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ ok: true })
    }
  }

  return jsonResponse({ error: 'Not found' }, 404)
}

