import type { Project } from './types'

const DATA_PATH = './data/projects.json'

export const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Project[]
}

export const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

export const addProject = async (project: Project): Promise<void> => {
  const projects = await loadProjects()
  projects.push(project)
  await saveProjects(projects)
}

export const removeProject = async (id: string): Promise<void> => {
  const projects = await loadProjects()
  const filtered = projects.filter((p) => p.id !== id)
  await saveProjects(filtered)
}

export const updateProject = async (id: string, updates: Partial<Project>): Promise<void> => {
  const projects = await loadProjects()
  const index = projects.findIndex((p) => p.id === id)
  if (index === -1) return
  projects[index] = { ...projects[index], ...updates }
  await saveProjects(projects)
}

export const extractAllTags = (projects: Project[]): string[] => {
  const tagSet = new Set<string>()
  for (const project of projects) {
    for (const tag of project.tags) {
      tagSet.add(tag)
    }
  }
  return [...tagSet].sort()
}

import type { Project, SortMode } from './types'

export const filterByTag = (projects: Project[], tag: string | null): Project[] => {
  if (!tag) return projects
  return projects.filter((p) => p.tags.includes(tag))
}

export const searchByTitle = (projects: Project[], query: string): Project[] => {
  if (!query.trim()) return projects
  const lower = query.toLowerCase()
  return projects.filter((p) => p.title.toLowerCase().includes(lower))
}

export const sortProjects = (projects: Project[], mode: SortMode): Project[] => {
  const sorted = [...projects]
  switch (mode) {
    case 'date-desc':
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
    case 'date-asc':
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime())
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
  }
}

export const applyFilters = (
  projects: Project[],
  searchQuery: string,
  activeTag: string | null,
  sortMode: SortMode,
): Project[] => {
  let result = searchByTitle(projects, searchQuery)
  result = filterByTag(result, activeTag)
  result = sortProjects(result, sortMode)
  return result
}

import { h } from 'plaited'
import { createSSR } from 'plaited'
import type { SortMode } from './types'
import { loadProjects } from './data-store'
import { extractAllTags } from './data-store'
import { applyFilters } from './gallery-logic'
import { renderControls, renderTagBar, renderGrid, renderDetailView, renderLightbox } from './render'
import { styles } from './styles'

const styleStr = (obj: Record<string, string>): string =>
  Object.entries(obj)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${v}`)
    .join(';')

const ssr = createSSR()

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const searchQuery = url.searchParams.get('q') ?? ''
  const activeTag = url.searchParams.get('tag') ?? null
  const sortMode = (url.searchParams.get('sort') as SortMode) ?? 'date-desc'
  const selectedId = url.searchParams.get('project') ?? null
  const lightboxIdx = url.searchParams.get('lightbox')

  const projects = await loadProjects()
  const allTags = extractAllTags(projects)
  const filteredProjects = applyFilters(projects, searchQuery, activeTag, sortMode)
  const selectedProject = selectedId ? projects.find((p) => p.id === selectedId) ?? null : null

  const page = h(
    'html',
    { lang: 'en' },
    h(
      'head',
      null,
      h('meta', { charset: 'utf-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1' }),
      h('title', null, 'Portfolio Gallery'),
      h(
        'style',
        null,
        `
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { background: #f8f9fb; min-height: 100vh; }
        article:hover { box-shadow: 0 8px 24px rgba(0,0,0,0.12); transform: translateY(-2px); }
        img { transition: opacity 0.2s; }
        img:hover { opacity: 0.9; }
        button:hover { opacity: 0.85; }
        input:focus { border-color: #6366f1; box-shadow: 0 0 0 3px rgba(99,102,241,0.15); }
        a:hover { opacity: 0.85; }
        @media (max-width: 640px) {
          .grid { grid-template-columns: 1fr !important; }
        }
      `,
      ),
    ),
    h(
      'body',
      null,
      h(
        'div',
        { style: styleStr(styles.container) },
        h(
          'header',
          { style: styleStr(styles.header) },
          h('h1', { style: styleStr(styles.title) }, 'Portfolio'),
          h('p', { style: styleStr(styles.subtitle) }, `${projects.length} projects`),
        ),
        renderControls(searchQuery, sortMode),
        renderTagBar(allTags, activeTag),
        h(
          'div',
          { 'p-target': 'gallery-grid' },
          renderGrid(filteredProjects),
        ),
      ),
      selectedProject ? renderDetailView(selectedProject) : null,
      selectedProject && lightboxIdx !== null
        ? renderLightbox(selectedProject.images, parseInt(lightboxIdx, 10))
        : null,
    ),
  )

  const html = ssr(page)

  return new Response(`<!DOCTYPE html>${html}`, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const server = Bun.serve({
  port: 3000,
  fetch: handleRequest,
})

