        h('input', {
          class: 'search-input',
          type: 'text',
          placeholder: 'Search projects by title...',
          value: searchQuery ?? '',
          id: 'search-input',
        }),
        h('select', { class: 'sort-select', id: 'sort-select' },
          h('option', { value: 'date-desc', ...(sort === 'date-desc' ? { selected: '' } : {}) }, 'Newest First'),
          h('option', { value: 'date-asc', ...(sort === 'date-asc' ? { selected: '' } : {}) }, 'Oldest First'),
          h('option', { value: 'alpha-asc', ...(sort === 'alpha-asc' ? { selected: '' } : {}) }, 'A \u2192 Z'),
          h('option', { value: 'alpha-desc', ...(sort === 'alpha-desc' ? { selected: '' } : {}) }, 'Z \u2192 A'),
        ),
      ),
      h('div', { class: 'tag-bar' },
        h('button', {
          class: `tag-pill${!activeTag ? ' active' : ''}`,
          'p-trigger': 'tagClick',
          'data-tag': '',
        }, 'All'),
        ...allTags.map((tag) => renderTag(tag, activeTag)),
      ),
      h('div', { class: 'project-grid', id: 'project-grid', 'p-target': 'grid' },
        ...(projects.length > 0
          ? projects.map(renderCard)
          : [h('div', { class: 'empty-state' }, 'No projects found matching your criteria.')]),
      ),
      h('div', { id: 'detail-container', 'p-target': 'detail' }),
      h('script', {}, clientScript()),
    ),
  )
  return `<!DOCTYPE html>${page}`
}

