const clientScript = (): string => `
  (function() {
    const searchInput = document.getElementById('search-input');
    const sortSelect = document.getElementById('sort-select');
    let debounceTimer;

    const updateGallery = () => {
      const params = new URLSearchParams(window.location.search);
      const q = searchInput.value.trim();
      const sort = sortSelect.value;
      if (q) params.set('q', q); else params.delete('q');
      params.set('sort', sort);
      const url = '/?' + params.toString();
      window.history.replaceState(null, '', url);
      fetch('/api/projects?' + params.toString())
        .then(r => r.json())
        .then(projects => {
          const grid = document.getElementById('project-grid');
          if (projects.length === 0) {
            grid.innerHTML = '<div class="empty-state">No projects found matching your criteria.</div>';
            return;
          }
          grid.innerHTML = projects.map(p => \`
            <article class="project-card" data-id="\${p.id}" onclick="openDetail('\${p.id}')">
              <img class="card-thumbnail" src="\${p.thumbnail}" alt="\${p.title} thumbnail" loading="lazy">
              <div class="card-body">
                <h3 class="card-title">\${p.title}</h3>
                <p class="card-desc">\${p.description}</p>
                <div class="card-tags">\${p.tags.map(t => '<span class="card-tag">' + t + '</span>').join('')}</div>
                <div class="card-links">
                  \${p.demoUrl ? '<a class="card-link" href="' + p.demoUrl + '" target="_blank" rel="noopener noreferrer" onclick="event.stopPropagation()">\u{1F517} Demo</a>' : ''}
                  \${p.sourceUrl ? '<a class="card-link" href="' + p.sourceUrl + '" target="_blank" rel="noopener noreferrer" onclick="event.stopPropagation()">\u{1F4C1} Source</a>' : ''}
                </div>
              </div>
            </article>
          \`).join('');
        });
    };

    searchInput.addEventListener('input', () => {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(updateGallery, 300);
    });

    sortSelect.addEventListener('change', updateGallery);

    document.querySelector('.tag-bar').addEventListener('click', (e) => {
      const btn = e.target.closest('.tag-pill');
      if (!btn) return;
      const tag = btn.dataset.tag;
      const params = new URLSearchParams(window.location.search);
      if (tag) params.set('tag', tag); else params.delete('tag');
      window.history.replaceState(null, '', '/?' + params.toString());
      document.querySelectorAll('.tag-pill').forEach(p => p.classList.remove('active'));
      btn.classList.add('active');
      updateGallery();
    });

    document.getElementById('project-grid').addEventListener('click', (e) => {
      const card = e.target.closest('.project-card');
      if (!card || e.target.closest('a')) return;
      openDetail(card.dataset.id);
    });

    window.openDetail = (id) => {
      fetch('/api/projects/' + id)
        .then(r => r.json())
        .then(project => {
          const container = document.getElementById('detail-container');
          const dateStr = new Date(project.dateAdded).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
          container.innerHTML = \`
            <div class="detail-overlay" id="detail-overlay">
              <div class="detail-panel" onclick="event.stopPropagation()">
                <button class="detail-close" id="detail-close">\u00D7</button>
                <div class="carousel" id="carousel">
                  \${project.images.map((img, i) => '<img class="carousel-img' + (i === 0 ? ' active' : '') + '" src="' + img + '" alt="' + project.title + ' image ' + (i+1) + '" data-index="' + i + '">').join('')}
                  \${project.images.length > 1 ? \`
                    <button class="carousel-btn carousel-prev" id="carousel-prev">\u2039</button>
                    <button class="carousel-btn carousel-next" id="carousel-next">\u203A</button>
                    <div class="carousel-dots">
                      \${project.images.map((_, i) => '<button class="carousel-dot' + (i === 0 ? ' active' : '') + '" data-index="' + i + '"></button>').join('')}
                    </div>
                  \` : ''}
                </div>
                <div class="detail-body">
                  <h2 class="detail-title">\${project.title}</h2>
                  <p class="detail-date">Added \${dateStr}</p>
                  <p class="detail-desc">\${project.fullDescription}</p>
                  <div class="detail-tags">\${project.tags.map(t => '<span class="detail-tag">' + t + '</span>').join('')}</div>
                  <div class="detail-links">
                    \${project.demoUrl ? '<a class="detail-link-btn btn-demo" href="' + project.demoUrl + '" target="_blank" rel="noopener noreferrer">\u25B6 Live Demo</a>' : ''}
                    \${project.sourceUrl ? '<a class="detail-link-btn btn-source" href="' + project.sourceUrl + '" target="_blank" rel="noopener noreferrer">\u{1F4BB} Source Code</a>' : ''}
                  </div>
                </div>
              </div>
            </div>
          \`;
          document.body.style.overflow = 'hidden';
          initCarousel();
          initDetailClose();
        });
    };

    let currentSlide = 0;

    const initCarousel = () => {
      const imgs = document.querySelectorAll('#carousel .carousel-img');
      const dots = document.querySelectorAll('.carousel-dot');
      const total = imgs.length;
      if (total <= 1) return;
      currentSlide = 0;

      const goTo = (index) => {
        currentSlide = (index + total) % total;
        imgs.forEach((img, i) => {
          img.classList.toggle('active', i === currentSlide);
        });
        dots.forEach((dot, i) => {
          dot.classList.toggle('active', i === currentSlide);
        });
      };

      document.getElementById('carousel-prev')?.addEventListener('click', () => goTo(currentSlide - 1));
      document.getElementById('carousel-next')?.addEventListener('click', () => goTo(currentSlide + 1));
      dots.forEach(dot => {
        dot.addEventListener('click', () => goTo(parseInt(dot.dataset.index)));
      });
    };

    const initDetailClose = () => {
      const closeDetail = () => {
        document.getElementById('detail-container').innerHTML = '';
        document.body.style.overflow = '';
      };
      document.getElementById('detail-close')?.addEventListener('click', closeDetail);
      document.getElementById('detail-overlay')?.addEventListener('click', (e) => {
        if (e.target === e.currentTarget) closeDetail();
      });
      document.addEventListener('keydown', function handler(e) {
        if (e.key === 'Escape') {
          closeDetail();
          document.removeEventListener('keydown', handler);
        }
      });
    };
  })();
`

import { getProjects, getProjectById, getAllTags, addProject, updateProject, deleteProject } from './store'
import { renderGalleryPage } from './render'
import type { ProjectQuery, SortOption, Project } from './types'

const parseQuery = (url: URL): ProjectQuery => ({
  tag: url.searchParams.get('tag') ?? undefined,
  q: url.searchParams.get('q') ?? undefined,
  sort: (url.searchParams.get('sort') as SortOption) ?? 'date-desc',
})

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (body: string, status = 200) =>
  new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const PORT = Number(process.env.PORT) || 3000

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // Gallery page
    if (pathname === '/' && method === 'GET') {
      const query = parseQuery(url)
      const [projects, allTags] = await Promise.all([getProjects(query), getAllTags()])
      const page = renderGalleryPage(projects, allTags, query.tag, query.q, query.sort)
      return html(page)
    }

    // API: list projects
    if (pathname === '/api/projects' && method === 'GET') {
      const query = parseQuery(url)
      const projects = await getProjects(query)
      return json(projects)
    }

    // API: get single project
    const projectMatch = pathname.match(/^\/api\/projects\/([^/]+)$/)
    if (projectMatch && method === 'GET') {
      const project = await getProjectById(projectMatch[1])
      if (!project) return json({ error: 'Project not found' }, 404)
      return json(project)
    }

    // API: create project
    if (pathname === '/api/projects' && method === 'POST') {
      const body = (await req.json()) as Project
      if (!body.id || !body.title) {
        return json({ error: 'id and title are required' }, 400)
      }
      const existing = await getProjectById(body.id)
      if (existing) {
        return json({ error: 'Project with this id already exists' }, 409)
      }
      await addProject(body)
      return json(body, 201)
    }

    // API: update project
    if (projectMatch && method === 'PATCH') {
      const updates = (await req.json()) as Partial<Project>
      const updated = await updateProject(projectMatch[1], updates)
      if (!updated) return json({ error: 'Project not found' }, 404)
      return json(updated)
    }

    // API: delete project
    if (projectMatch && method === 'DELETE') {
      const deleted = await deleteProject(projectMatch[1])
      if (!deleted) return json({ error: 'Project not found' }, 404)
      return json({ success: true })
    }

    // API: get all tags
    if (pathname === '/api/tags' && method === 'GET') {
      const tags = await getAllTags()
      return json(tags)
    }

    return json({ error: 'Not found' }, 404)
  },
})

