export type Project = {
  id: string;
  title: string;
  description: string;
  fullDescription: string;
  thumbnail: string;
  images: string[];
  tags: string[];
  demoUrl: string;
  sourceUrl: string;
  dateAdded: string;
};

export type SortOption = "date-desc" | "date-asc" | "alpha-asc" | "alpha-desc";

export type FilterParams = {
  tag?: string;
  search?: string;
  sort?: SortOption;
};

import type { Project, FilterParams, SortOption } from "./types";

const DATA_PATH = `${import.meta.dir}/data/projects.json`;

const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) return [];
  return file.json();
};

const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2));
};

const sortProjects = (projects: Project[], sort: SortOption): Project[] => {
  const sorted = [...projects];
  switch (sort) {
    case "date-desc":
      return sorted.sort(
        (a, b) =>
          new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime()
      );
    case "date-asc":
      return sorted.sort(
        (a, b) =>
          new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime()
      );
    case "alpha-asc":
      return sorted.sort((a, b) =>
        a.title.localeCompare(b.title, undefined, { sensitivity: "base" })
      );
    case "alpha-desc":
      return sorted.sort((a, b) =>
        b.title.localeCompare(a.title, undefined, { sensitivity: "base" })
      );
    default:
      return sorted;
  }
};

export const getProjects = async (
  params: FilterParams = {}
): Promise<Project[]> => {
  let projects = await loadProjects();

  if (params.tag) {
    const tag = params.tag.toLowerCase();
    projects = projects.filter((p) =>
      p.tags.some((t) => t.toLowerCase() === tag)
    );
  }

  if (params.search) {
    const query = params.search.toLowerCase();
    projects = projects.filter((p) =>
      p.title.toLowerCase().includes(query)
    );
  }

  const sort = params.sort ?? "date-desc";
  projects = sortProjects(projects, sort);

  return projects;
};

export const getProjectById = async (
  id: string
): Promise<Project | undefined> => {
  const projects = await loadProjects();
  return projects.find((p) => p.id === id);
};

export const getAllTags = async (): Promise<string[]> => {
  const projects = await loadProjects();
  const tagSet = new Set<string>();
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t);
    }
  }
  return [...tagSet].sort((a, b) =>
    a.localeCompare(b, undefined, { sensitivity: "base" })
  );
};

export const addProject = async (project: Project): Promise<Project> => {
  const projects = await loadProjects();
  projects.push(project);
  await saveProjects(projects);
  return project;
};

export const updateProject = async (
  id: string,
  updates: Partial<Omit<Project, "id">>
): Promise<Project | undefined> => {
  const projects = await loadProjects();
  const idx = projects.findIndex((p) => p.id === id);
  if (idx === -1) return undefined;
  projects[idx] = { ...projects[idx], ...updates };
  await saveProjects(projects);
  return projects[idx];
};

export const deleteProject = async (id: string): Promise<boolean> => {
  const projects = await loadProjects();
  const idx = projects.findIndex((p) => p.id === id);
  if (idx === -1) return false;
  projects.splice(idx, 1);
  await saveProjects(projects);
  return true;
};

