              class: "lightbox-btn",
            }),
            h("img", {
              id: "lightbox-img",
              style: inlineStyle(styles.lightboxImage),
              src: "",
              alt: "Lightbox image",
            }),
            h(
              "button",
              {
                style: inlineStyle({
                  ...styles.lightboxButton,
                  right: "1rem",
                }),
                "p-trigger": "click:nextImage",
                class: "lightbox-btn",
              },
              "\u203A"
            ),
            h(
              "button",
              {
                style: inlineStyle(styles.lightboxClose),
                "p-trigger": "click:closeLightbox",
                class: "lightbox-btn",
              },
              "\u2715"
            ),
            h("span", {
              id: "lightbox-counter",
              style: inlineStyle(styles.lightboxCounter),
            })
          ),
          h(
            "script",
            {},
            `
            (()=>{
              const images = ${JSON.stringify(project.images)};
              let current = 0;
              const overlay = document.getElementById('lightbox');
              const img = document.getElementById('lightbox-img');
              const counter = document.getElementById('lightbox-counter');

              const show = (idx) => {
                current = idx;
                img.src = images[idx];
                counter.textContent = (idx + 1) + ' / ' + images.length;
                overlay.style.display = 'flex';
              };

              document.querySelectorAll('[data-index]').forEach(el => {
                el.addEventListener('click', () => show(parseInt(el.dataset.index)));
              });

              overlay.addEventListener('click', (e) => {
                if (e.target === overlay) overlay.style.display = 'none';
              });

              document.querySelectorAll('.lightbox-btn').forEach(btn => {
                const s = btn.style;
                if (s.right) {
                  btn.textContent = '\\u203A';
                  btn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    show((current + 1) % images.length);
                  });
                } else if (s.left) {
                  btn.textContent = '\\u2039';
                  btn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    show((current - 1 + images.length) % images.length);
                  });
                } else if (s.top === '1rem') {
                  btn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    overlay.style.display = 'none';
                  });
                }
              });

              document.addEventListener('keydown', (e) => {
                if (overlay.style.display === 'none') return;
                if (e.key === 'Escape') overlay.style.display = 'none';
                if (e.key === 'ArrowRight') show((current + 1) % images.length);
                if (e.key === 'ArrowLeft') show((current - 1 + images.length) % images.length);
              });
            })();
            `
          )
        )
      )
    )
  );
};

