import type { SortOption, Project } from "./types";
import {
  getProjects,
  getProjectById,
  getAllTags,
  addProject,
  updateProject,
  deleteProject,
} from "./store";
import { renderGalleryPage, renderDetailPage, renderNotFound } from "./render";

const isValidSort = (v: string | null): v is SortOption =>
  v !== null &&
  ["date-desc", "date-asc", "alpha-asc", "alpha-desc"].includes(v);

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });

const htmlResponse = (html: string, status = 200) =>
  new Response(html, {
    status,
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });

const server = Bun.serve({
  port: Number(process.env.PORT ?? 3000),

  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;

    // --- HTML Routes ---

    if (pathname === "/" && req.method === "GET") {
      const tag = url.searchParams.get("tag") ?? undefined;
      const search = url.searchParams.get("search") ?? undefined;
      const sortParam = url.searchParams.get("sort");
      const sort: SortOption = isValidSort(sortParam) ? sortParam : "date-desc";

      const [projects, allTags] = await Promise.all([
        getProjects({ tag, search, sort }),
        getAllTags(),
      ]);

      const html = renderGalleryPage(projects, allTags, { tag, search, sort });
      return htmlResponse(html);
    }

    const detailMatch = pathname.match(/^\/project\/([a-zA-Z0-9_-]+)$/);
    if (detailMatch && req.method === "GET") {
      const project = await getProjectById(detailMatch[1]);
      if (!project) return htmlResponse(renderNotFound(), 404);
      return htmlResponse(renderDetailPage(project));
    }

    // --- JSON API Routes ---

    if (pathname === "/api/projects" && req.method === "GET") {
      const tag = url.searchParams.get("tag") ?? undefined;
      const search = url.searchParams.get("search") ?? undefined;
      const sortParam = url.searchParams.get("sort");
      const sort: SortOption = isValidSort(sortParam) ? sortParam : "date-desc";

      const projects = await getProjects({ tag, search, sort });
      return jsonResponse(projects);
    }

    if (pathname === "/api/projects" && req.method === "POST") {
      const body = (await req.json()) as Partial<Project>;
      if (!body.id || !body.title) {
        return jsonResponse({ error: "id and title are required" }, 400);
      }
      const existing = await getProjectById(body.id);
      if (existing) {
        return jsonResponse({ error: "Project with this id already exists" }, 409);
      }
      const project: Project = {
        id: body.id,
        title: body.title,
        description: body.description ?? "",
        fullDescription: body.fullDescription ?? "",
        thumbnail: body.thumbnail ?? "",
        images: body.images ?? [],
        tags: body.tags ?? [],
        demoUrl: body.demoUrl ?? "",
        sourceUrl: body.sourceUrl ?? "",
        dateAdded: body.dateAdded ?? new Date().toISOString(),
      };
      const created = await addProject(project);
      return jsonResponse(created, 201);
    }

    const apiDetailMatch = pathname.match(
      /^\/api\/projects\/([a-zA-Z0-9_-]+)$/
    );

    if (apiDetailMatch && req.method === "GET") {
      const project = await getProjectById(apiDetailMatch[1]);
      if (!project) return jsonResponse({ error: "Not found" }, 404);
      return jsonResponse(project);
    }

    if (apiDetailMatch && req.method === "PUT") {
      const body = (await req.json()) as Partial<Omit<Project, "id">>;
      const updated = await updateProject(apiDetailMatch[1], body);
      if (!updated) return jsonResponse({ error: "Not found" }, 404);
      return jsonResponse(updated);
    }

    if (apiDetailMatch && req.method === "DELETE") {
      const deleted = await deleteProject(apiDetailMatch[1]);
      if (!deleted) return jsonResponse({ error: "Not found" }, 404);
      return jsonResponse({ success: true });
    }

    if (pathname === "/api/tags" && req.method === "GET") {
      const tags = await getAllTags();
      return jsonResponse(tags);
    }

    return jsonResponse({ error: "Not found" }, 404);
  },
});

