export type ChartType = 'bar' | 'line' | 'pie';

export type FieldType = 'numeric' | 'categorical';

export type FieldInfo = {
  name: string;
  type: FieldType;
};

export type ChartConfig = {
  type: ChartType;
  title: string;
  xLabel: string;
  yLabel: string;
  colors: string[];
  width: number;
  height: number;
  labelField: string;
  valueFields: string[];
};

export type DataRow = Record<string, string | number>;

export type ParsedData = {
  rows: DataRow[];
  fields: FieldInfo[];
  categoricalFields: string[];
  numericFields: string[];
};

export type ChartPadding = {
  top: number;
  right: number;
  bottom: number;
  left: number;
};

import type { DataRow, FieldInfo, FieldType, ParsedData } from './types';

const detectFieldType = (rows: DataRow[], fieldName: string): FieldType => {
  const values = rows.map((r) => r[fieldName]).filter((v) => v !== undefined && v !== null);
  if (values.length === 0) return 'categorical';

  const numericCount = values.filter((v) => {
    if (typeof v === 'number') return true;
    if (typeof v === 'string') {
      const trimmed = v.trim();
      return trimmed !== '' && !isNaN(Number(trimmed));
    }
    return false;
  }).length;

  return numericCount / values.length >= 0.8 ? 'numeric' : 'categorical';
};

export const parseData = (rows: DataRow[]): ParsedData => {
  if (rows.length === 0) {
    return { rows: [], fields: [], categoricalFields: [], numericFields: [] };
  }

  const fieldNames = Object.keys(rows[0]);

  const fields: FieldInfo[] = fieldNames.map((name) => ({
    name,
    type: detectFieldType(rows, name),
  }));

  const categoricalFields = fields.filter((f) => f.type === 'categorical').map((f) => f.name);
  const numericFields = fields.filter((f) => f.type === 'numeric').map((f) => f.name);

  const normalizedRows: DataRow[] = rows.map((row) => {
    const normalized: DataRow = {};
    for (const field of fields) {
      const value = row[field.name];
      if (field.type === 'numeric') {
        normalized[field.name] = typeof value === 'number' ? value : Number(value) || 0;
      } else {
        normalized[field.name] = String(value ?? '');
      }
    }
    return normalized;
  });

  return { rows: normalizedRows, fields, categoricalFields, numericFields };
};

export const pickDefaults = (
  parsed: ParsedData,
): { labelField: string; valueFields: string[] } => {
  const labelField = parsed.categoricalFields[0] ?? parsed.numericFields[0] ?? '';
  const valueFields =
    parsed.numericFields.length > 0
      ? parsed.numericFields
      : parsed.categoricalFields.slice(1);

  return { labelField, valueFields };
};

import { h } from 'plaited';
import type { ChartConfig, ChartPadding, DataRow } from './types';

const DEFAULT_COLORS = [
  '#4e79a7', '#f28e2b', '#e15759', '#76b7b2',
  '#59a14f', '#edc948', '#b07aa1', '#ff9da7',
  '#9c755f', '#bab0ac',
];

const pad: ChartPadding = { top: 50, right: 30, bottom: 60, left: 70 };

const resolveColors = (config: ChartConfig): string[] =>
  config.colors.length > 0 ? config.colors : DEFAULT_COLORS;

// ── helpers ──────────────────────────────────────────────────────────

const lerp = (a: number, b: number, t: number) => a + (b - a) * t;

const maxOfFields = (rows: DataRow[], fields: string[]): number => {
  let max = 0;
  for (const row of rows) {
    for (const f of fields) {
      const v = Number(row[f]);
      if (v > max) max = v;
    }
  }
  return max || 1;
};

const niceMax = (v: number): number => {
  if (v <= 0) return 1;
  const magnitude = Math.pow(10, Math.floor(Math.log10(v)));
  const normalized = v / magnitude;
  const nice = normalized <= 1 ? 1 : normalized <= 2 ? 2 : normalized <= 5 ? 5 : 10;
  return nice * magnitude;
};

const tickValues = (maxVal: number, count = 5): number[] => {
  const nice = niceMax(maxVal);
  const step = nice / count;
  return Array.from({ length: count + 1 }, (_, i) => Math.round(i * step * 100) / 100);
};

// ── title & labels ───────────────────────────────────────────────────

const renderTitle = (config: ChartConfig) =>
  config.title
    ? h('text', {
        x: String(config.width / 2),
        y: '28',
        'text-anchor': 'middle',
        'font-size': '16',
        'font-weight': 'bold',
        'font-family': 'system-ui, sans-serif',
        fill: '#333',
      }, config.title)
    : null;

const renderXLabel = (config: ChartConfig) =>
  config.xLabel
    ? h('text', {
        x: String(config.width / 2),
        y: String(config.height - 8),
        'text-anchor': 'middle',
        'font-size': '12',
        'font-family': 'system-ui, sans-serif',
        fill: '#666',
      }, config.xLabel)
    : null;

const renderYLabel = (config: ChartConfig) =>
  config.yLabel
    ? h('text', {
        x: '14',
        y: String(config.height / 2),
        'text-anchor': 'middle',
        'font-size': '12',
        'font-family': 'system-ui, sans-serif',
        fill: '#666',
        transform: `rotate(-90, 14, ${config.height / 2})`,
      }, config.yLabel)
    : null;

// ── axis grid ────────────────────────────────────────────────────────

const renderYAxis = (config: ChartConfig, maxVal: number) => {
  const ticks = tickValues(maxVal);
  const plotH = config.height - pad.top - pad.bottom;

  return ticks.map((tick) => {
    const y = pad.top + plotH - (tick / niceMax(maxVal)) * plotH;
    return h('g', { key: String(tick) },
      h('line', {
        x1: String(pad.left),
        y1: String(y),
        x2: String(config.width - pad.right),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(pad.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '10',
        'font-family': 'system-ui, sans-serif',
        fill: '#888',
      }, String(tick)),
    );
  });
};

// ── bar chart ────────────────────────────────────────────────────────

const renderBarChart = (rows: DataRow[], config: ChartConfig) => {
  const colors = resolveColors(config);
  const plotW = config.width - pad.left - pad.right;
  const plotH = config.height - pad.top - pad.bottom;
  const maxVal = maxOfFields(rows, config.valueFields);
  const nice = niceMax(maxVal);

  const groupCount = rows.length;
  const barCount = config.valueFields.length;
  const groupWidth = plotW / groupCount;
  const barGap = 2;
  const barWidth = Math.max(1, (groupWidth - barGap * (barCount + 1)) / barCount);

  const bars = rows.flatMap((row, gi) =>
    config.valueFields.map((field, bi) => {
      const val = Number(row[field]);
      const barH = (val / nice) * plotH;
      const x = pad.left + gi * groupWidth + barGap + bi * (barWidth + barGap);
      const y = pad.top + plotH - barH;
      return h('rect', {
        key: `${gi}-${bi}`,
        x: String(x),
        y: String(y),
        width: String(barWidth),
        height: String(barH),
        fill: colors[bi % colors.length],
        rx: '2',
      },
        h('title', {}, `${field}: ${val}`),
      );
    }),
  );

  const labels = rows.map((row, gi) => {
    const x = pad.left + gi * groupWidth + groupWidth / 2;
    const label = String(row[config.labelField] ?? gi);
    return h('text', {
      key: `label-${gi}`,
      x: String(x),
      y: String(config.height - pad.bottom + 16),
      'text-anchor': 'middle',
      'font-size': '10',
      'font-family': 'system-ui, sans-serif',
      fill: '#555',
    }, label.length > 12 ? `${label.slice(0, 11)}...` : label);
  });

  return [...renderYAxis(config, maxVal), ...bars, ...labels];
};

// ── line chart ───────────────────────────────────────────────────────

const renderLineChart = (rows: DataRow[], config: ChartConfig) => {
  const colors = resolveColors(config);
  const plotW = config.width - pad.left - pad.right;
  const plotH = config.height - pad.top - pad.bottom;
  const maxVal = maxOfFields(rows, config.valueFields);
  const nice = niceMax(maxVal);

  const stepX = rows.length > 1 ? plotW / (rows.length - 1) : plotW / 2;

  const lines = config.valueFields.map((field, fi) => {
    const points = rows.map((row, i) => {
      const x = pad.left + i * stepX;
      const val = Number(row[field]);
      const y = pad.top + plotH - (val / nice) * plotH;
      return `${x},${y}`;
    });

    const dots = rows.map((row, i) => {
      const x = pad.left + i * stepX;
      const val = Number(row[field]);
      const y = pad.top + plotH - (val / nice) * plotH;
      return h('circle', {
        key: `dot-${fi}-${i}`,
        cx: String(x),
        cy: String(y),
        r: '4',
        fill: colors[fi % colors.length],
      },
        h('title', {}, `${field}: ${val}`),
      );
    });

    return [
      h('polyline', {
        key: `line-${fi}`,
        points: points.join(' '),
        fill: 'none',
        stroke: colors[fi % colors.length],
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
      }),
      ...dots,
    ];
  });

  const labels = rows.map((row, i) => {
    const x = pad.left + i * stepX;
    const label = String(row[config.labelField] ?? i);
    return h('text', {
      key: `label-${i}`,
      x: String(x),
      y: String(config.height - pad.bottom + 16),
      'text-anchor': 'middle',
      'font-size': '10',
      'font-family': 'system-ui, sans-serif',
      fill: '#555',
    }, label.length > 12 ? `${label.slice(0, 11)}...` : label);
  });

  return [...renderYAxis(config, maxVal), ...lines.flat(), ...labels];
};

// ── pie chart ────────────────────────────────────────────────────────

const describeArc = (
  cx: number,
  cy: number,
  r: number,
  startAngle: number,
  endAngle: number,
): string => {
  const start = {
    x: cx + r * Math.cos(startAngle),
    y: cy + r * Math.sin(startAngle),
  };
  const end = {
    x: cx + r * Math.cos(endAngle),
    y: cy + r * Math.sin(endAngle),
  };
  const largeArc = endAngle - startAngle > Math.PI ? 1 : 0;

  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y}`,
    'Z',
  ].join(' ');
};

const renderPieChart = (rows: DataRow[], config: ChartConfig) => {
  const colors = resolveColors(config);
  const valueField = config.valueFields[0];
  if (!valueField) return [];

  const cx = config.width / 2;
  const cy = (config.height - pad.bottom + pad.top) / 2;
  const radius = Math.min(config.width - pad.left - pad.right, config.height - pad.top - pad.bottom) / 2 - 10;

  const total = rows.reduce((s, r) => s + Math.max(0, Number(r[valueField])), 0);
  if (total === 0) return [];

  let currentAngle = -Math.PI / 2;

  const slices = rows.map((row, i) => {
    const val = Math.max(0, Number(row[valueField]));
    const sliceAngle = (val / total) * 2 * Math.PI;
    const startAngle = currentAngle;
    const endAngle = currentAngle + sliceAngle;
    currentAngle = endAngle;

    const midAngle = (startAngle + endAngle) / 2;
    const labelR = radius + 18;
    const lx = cx + labelR * Math.cos(midAngle);
    const ly = cy + labelR * Math.sin(midAngle);
    const label = String(row[config.labelField] ?? i);
    const pct = ((val / total) * 100).toFixed(1);

    return h('g', { key: `slice-${i}` },
      h('path', {
        d: describeArc(cx, cy, radius, startAngle, endAngle),
        fill: colors[i % colors.length],
        stroke: '#fff',
        'stroke-width': '2',
      },
        h('title', {}, `${label}: ${val} (${pct}%)`),
      ),
      sliceAngle > 0.2
        ? h('text', {
            x: String(lx),
            y: String(ly),
            'text-anchor': 'middle',
            'font-size': '10',
            'font-family': 'system-ui, sans-serif',
            fill: '#333',
          }, `${label.slice(0, 10)} ${pct}%`)
        : null,
    );
  });

  return slices;
};

// ── legend ───────────────────────────────────────────────────────────

const renderLegend = (config: ChartConfig, rows: DataRow[]) => {
  const colors = resolveColors(config);

  const items = config.type === 'pie'
    ? rows.map((row, i) => ({
        label: String(row[config.labelField] ?? i),
        color: colors[i % colors.length],
      }))
    : config.valueFields.map((f, i) => ({
        label: f,
        color: colors[i % colors.length],
      }));

  if (items.length <= 1 && config.type !== 'pie') return [];

  const startX = pad.left;
  const y = config.height - 10;

  return items.map((item, i) =>
    h('g', { key: `legend-${i}` },
      h('rect', {
        x: String(startX + i * 100),
        y: String(y - 8),
        width: '10',
        height: '10',
        rx: '2',
        fill: item.color,
      }),
      h('text', {
        x: String(startX + i * 100 + 14),
        y: String(y),
        'font-size': '10',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
      }, item.label.length > 12 ? `${item.label.slice(0, 11)}...` : item.label),
    ),
  );
};

// ── public API ───────────────────────────────────────────────────────

export const renderChart = (rows: DataRow[], config: ChartConfig): ReturnType<typeof h> => {
  const chartBody = (() => {
    switch (config.type) {
      case 'bar':
        return renderBarChart(rows, config);
      case 'line':
        return renderLineChart(rows, config);
      case 'pie':
        return renderPieChart(rows, config);
    }
  })();

  return h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    width: String(config.width),
    height: String(config.height),
    viewBox: `0 0 ${config.width} ${config.height}`,
    style: 'background:#fff;border-radius:8px',
  },
    h('rect', { width: String(config.width), height: String(config.height), fill: '#fff', rx: '8' }),
    renderTitle(config),
    renderXLabel(config),
    renderYLabel(config),
    ...chartBody,
    ...renderLegend(config, rows),
  );
};

export const chartToSvgString = (rows: DataRow[], config: ChartConfig): string => {
  const tree = renderChart(rows, config);
  const serialize = (node: ReturnType<typeof h>): string => {
    if (node === null || node === undefined) return '';
    if (typeof node === 'string') return node;
    if (typeof node === 'number') return String(node);
    if (Array.isArray(node)) return node.map(serialize).join('');
    if (typeof node === 'object' && 'tag' in node) {
      const n = node as { tag: string; attrs?: Record<string, string>; children?: unknown[] };
      const attrs = n.attrs
        ? Object.entries(n.attrs)
            .filter(([, v]) => v !== undefined && v !== null)
            .map(([k, v]) => ` ${k}="${String(v).replace(/"/g, '&quot;')}"`)
            .join('')
        : '';
      const children = n.children ? n.children.map((c: unknown) => serialize(c as ReturnType<typeof h>)).join('') : '';
      if (!children && ['rect', 'line', 'circle', 'polyline'].includes(n.tag)) {
        return `<${n.tag}${attrs}/>`;
      }
      return `<${n.tag}${attrs}>${children}</${n.tag}>`;
    }
    return String(node);
  };

  return `<?xml version="1.0" encoding="UTF-8"?>\n${serialize(tree)}`;
};

import { h } from 'plaited';

type TokenType = 'key' | 'string' | 'number' | 'boolean' | 'null' | 'brace' | 'plain';

type Token = {
  type: TokenType;
  value: string;
};

const tokenize = (json: string): Token[] => {
  const tokens: Token[] = [];
  const re =
    /("(?:\\.|[^"\\])*")\s*(:)|("(?:\\.|[^"\\])*")|([-+]?\d+\.?\d*(?:[eE][+-]?\d+)?)|(\btrue\b|\bfalse\b)|(\bnull\b)|([[\]{},:])|([ \t\n\r]+)|(.)/g;

  let match: RegExpExecArray | null;
  while ((match = re.exec(json)) !== null) {
    if (match[1]) {
      tokens.push({ type: 'key', value: match[1] });
      tokens.push({ type: 'plain', value: ':' });
    } else if (match[3]) {
      tokens.push({ type: 'string', value: match[3] });
    } else if (match[4]) {
      tokens.push({ type: 'number', value: match[4] });
    } else if (match[5]) {
      tokens.push({ type: 'boolean', value: match[5] });
    } else if (match[6]) {
      tokens.push({ type: 'null', value: match[6] });
    } else if (match[7]) {
      tokens.push({ type: 'brace', value: match[7] });
    } else if (match[8]) {
      tokens.push({ type: 'plain', value: match[8] });
    } else if (match[9]) {
      tokens.push({ type: 'plain', value: match[9] });
    }
  }
  return tokens;
};

const colorMap: Record<TokenType, string> = {
  key: '#9876aa',
  string: '#6a8759',
  number: '#6897bb',
  boolean: '#cc7832',
  null: '#cc7832',
  brace: '#a9b7c6',
  plain: '#a9b7c6',
};

export const highlightJson = (json: string) => {
  const tokens = tokenize(json);
  return tokens.map((token, i) =>
    h('span', {
      key: String(i),
      style: `color:${colorMap[token.type]}`,
    }, token.value),
  );
};

