export const validateJson = (input: string): { valid: true; data: unknown[] } | { valid: false; error: string } => {
  const trimmed = input.trim();
  if (!trimmed) return { valid: false, error: 'Input is empty' };
  try {
    const parsed = JSON.parse(trimmed);
    if (!Array.isArray(parsed)) return { valid: false, error: 'Data must be a JSON array' };
    if (parsed.length === 0) return { valid: false, error: 'Array must not be empty' };
    if (typeof parsed[0] !== 'object' || parsed[0] === null) {
      return { valid: false, error: 'Array items must be objects' };
    }
    return { valid: true, data: parsed };
  } catch (e) {
    return { valid: false, error: `Invalid JSON: ${(e as Error).message}` };
  }
};

