export const handleGenerateChart = (body: {
  data: DataRow[];
  config?: Partial<ChartConfig>;
}): { svg: string; config: ChartConfig } => {
  const parsed = parseData(body.data);
  const defaults = pickDefaults(parsed);

  const config: ChartConfig = {
    ...DEFAULT_CONFIG,
    ...body.config,
    labelField: body.config?.labelField || defaults.labelField,
    valueFields:
      body.config?.valueFields && body.config.valueFields.length > 0
        ? body.config.valueFields
        : defaults.valueFields,
  };

  const svg = chartToSvgString(body.data, config);
  return { svg, config };
};

export const handleDetectFields = (data: DataRow[]) => {
  const parsed = parseData(data);
  const defaults = pickDefaults(parsed);
  return { fields: parsed.fields, defaults };
};

