const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url);

    // ── UI ──────────────────────────────────────────────
    if (req.method === 'GET' && url.pathname === '/') {
      const jsonInput = await loadSavedData();
      const ssr = createSSR();
      const rendered = ssr(renderApp(jsonInput, DEFAULT_CONFIG));
      return htmlResponse(rendered);
    }

    // ── API: generate chart ─────────────────────────────
    if (req.method === 'POST' && url.pathname === '/api/chart') {
      try {
        const body = (await req.json()) as { data: DataRow[]; config?: Partial<ChartConfig> };
        if (!Array.isArray(body.data)) {
          return jsonResponse({ error: 'body.data must be an array' }, 400);
        }
        const result = handleGenerateChart(body);
        return jsonResponse(result);
      } catch (e) {
        return jsonResponse({ error: (e as Error).message }, 400);
      }
    }

    // ── API: get SVG directly ───────────────────────────
    if (req.method === 'POST' && url.pathname === '/api/chart/svg') {
      try {
        const body = (await req.json()) as { data: DataRow[]; config?: Partial<ChartConfig> };
        if (!Array.isArray(body.data)) {
          return jsonResponse({ error: 'body.data must be an array' }, 400);
        }
        const result = handleGenerateChart(body);
        return new Response(result.svg, {
          headers: {
            'Content-Type': 'image/svg+xml',
            'Content-Disposition': 'attachment; filename="chart.svg"',
          },
        });
      } catch (e) {
        return jsonResponse({ error: (e as Error).message }, 400);
      }
    }

    // ── API: detect fields ──────────────────────────────
    if (req.method === 'POST' && url.pathname === '/api/detect') {
      try {
        const body = (await req.json()) as { data: DataRow[] };
        if (!Array.isArray(body.data)) {
          return jsonResponse({ error: 'body.data must be an array' }, 400);
        }
        const result = handleDetectFields(body.data);
        return jsonResponse(result);
      } catch (e) {
        return jsonResponse({ error: (e as Error).message }, 400);
      }
    }

    // ── API: save data ──────────────────────────────────
    if (req.method === 'POST' && url.pathname === '/api/save') {
      try {
        const body = (await req.json()) as { json: string };
        await saveData(body.json);
        return jsonResponse({ ok: true });
      } catch (e) {
        return jsonResponse({ error: (e as Error).message }, 400);
      }
    }

    return new Response('Not Found', { status: 404 });
  },
});

