import type { DataRow, FieldInfo, FieldType, AnalyzedData } from './types';

const isNumeric = (value: unknown): boolean => {
  if (typeof value === 'number') return true;
  if (typeof value === 'string') {
    const trimmed = value.trim();
    return trimmed !== '' && !isNaN(Number(trimmed));
  }
  return false;
};

const detectFieldType = (values: unknown[]): FieldType => {
  const nonNull = values.filter((v) => v !== null && v !== undefined && v !== '');
  if (nonNull.length === 0) return 'categorical';
  const numericCount = nonNull.filter(isNumeric).length;
  return numericCount / nonNull.length >= 0.8 ? 'numeric' : 'categorical';
};

export const analyzeData = (rows: DataRow[]): AnalyzedData => {
  if (rows.length === 0) {
    return { fields: [], rows: [], numericFields: [], categoricalFields: [] };
  }

  const fieldNames = Object.keys(rows[0]);
  const fields: FieldInfo[] = fieldNames.map((name) => {
    const values = rows.map((row) => row[name]);
    const type = detectFieldType(values);

    if (type === 'numeric') {
      const nums = values.map(Number).filter((n) => !isNaN(n));
      return {
        name,
        type,
        min: Math.min(...nums),
        max: Math.max(...nums),
      };
    }

    const uniqueValues = [...new Set(values.map(String))];
    return { name, type, uniqueValues };
  });

  return {
    fields,
    rows,
    numericFields: fields.filter((f) => f.type === 'numeric').map((f) => f.name),
    categoricalFields: fields.filter((f) => f.type === 'categorical').map((f) => f.name),
  };
};

export const coerceNumeric = (value: unknown): number => {
  const n = Number(value);
  return isNaN(n) ? 0 : n;
};

