const MARGINS: ChartMargins = { top: 50, right: 30, bottom: 60, left: 70 };

const escapeText = (text: string): string =>
  text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const niceScale = (min: number, max: number, ticks: number = 5): number[] => {
  const range = max - min || 1;
  const roughStep = range / ticks;
  const magnitude = Math.pow(10, Math.floor(Math.log10(roughStep)));
  const normalized = roughStep / magnitude;
  const niceStep =
    normalized <= 1.5 ? 1 * magnitude :
    normalized <= 3 ? 2 * magnitude :
    normalized <= 7 ? 5 * magnitude :
    10 * magnitude;

  const niceMin = Math.floor(min / niceStep) * niceStep;
  const niceMax = Math.ceil(max / niceStep) * niceStep;

  const result: number[] = [];
  for (let v = niceMin; v <= niceMax + niceStep * 0.5; v += niceStep) {
    result.push(Math.round(v * 1e10) / 1e10);
  }
  return result;
};

const formatNumber = (n: number): string => {
  if (Math.abs(n) >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (Math.abs(n) >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
  return n % 1 === 0 ? String(n) : n.toFixed(1);
};

