import { h } from 'plaited';
import type { ChartType, DataRow } from './types';
import { renderApp } from './app';
import { renderBarChart, renderLineChart, renderPieChart } from './chart-engine';
import { analyzeData } from './field-detector';
import { validateJson } from './json-editor';
import { PALETTES, DEFAULT_PALETTE } from './colors';

type ChartRequest = {
  data: DataRow[];
  type?: ChartType;
  title?: string;
  xLabel?: string;
  yLabel?: string;
  xField?: string;
  yFields?: string[];
  palette?: string;
  width?: number;
  height?: number;
};

const generateSvg = (req: ChartRequest): string => {
  const analysis = analyzeData(req.data);
  const xField = req.xField ?? analysis.categoricalFields[0] ?? analysis.numericFields[0] ?? '';
  const yFields = req.yFields ?? analysis.numericFields;
  const colors = PALETTES[req.palette ?? 'default'] ?? DEFAULT_PALETTE;
  const chartType = req.type ?? 'bar';

  const config = {
    type: chartType,
    title: req.title ?? 'Chart',
    xLabel: req.xLabel ?? xField,
    yLabel: req.yLabel ?? (yFields.length === 1 ? yFields[0] : 'Value'),
    xField,
    yFields,
    colors,
    width: req.width ?? 700,
    height: req.height ?? 420,
  };

  switch (chartType) {
    case 'bar':
      return renderBarChart(req.data, config);
    case 'line':
      return renderLineChart(req.data, config);
    case 'pie':
      return renderPieChart(req.data, config);
    default:
      return '';
  }
};

const handleApiChart = async (req: Request): Promise<Response> => {
  try {
    const body = (await req.json()) as ChartRequest;
    if (!body.data || !Array.isArray(body.data) || body.data.length === 0) {
      return new Response(JSON.stringify({ error: 'data must be a non-empty array of objects' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' },
      });
    }
    const svg = generateSvg(body);
    return new Response(svg, {
      headers: { 'Content-Type': 'image/svg+xml' },
    });
  } catch (e) {
    return new Response(JSON.stringify({ error: (e as Error).message }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' },
    });
  }
};

const handlePage = (_req: Request): Response => {
  const appHtml = renderApp();
  const page = h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, 'Chart Generator'),
      h('style', {},
        `* { margin: 0; padding: 0; box-sizing: border-box; }
         body { background: #f5f5f7; min-height: 100vh; }
         textarea:focus, input:focus, select:focus { outline: 2px solid #4e79a7; outline-offset: -1px; }
         button:hover { opacity: 0.9; }
         button:active { transform: scale(0.98); }`,
      ),
    ),
    h('body', {}, appHtml),
  );
  return new Response(`<!DOCTYPE html>${page}`, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });
};

const handleSaveData = async (req: Request): Promise<Response> => {
  try {
    const body = await req.json();
    const validation = validateJson(JSON.stringify(body));
    if (!validation.valid) {
      return new Response(JSON.stringify({ error: validation.error }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' },
      });
    }
    await Bun.write('data/saved.json', JSON.stringify(body, null, 2));
    return new Response(JSON.stringify({ ok: true }), {
      headers: { 'Content-Type': 'application/json' },
    });
  } catch (e) {
    return new Response(JSON.stringify({ error: (e as Error).message }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' },
    });
  }
};

const server = Bun.serve({
  port: 3000,
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url);

    if (url.pathname === '/api/chart' && req.method === 'POST') {
      return handleApiChart(req);
    }

    if (url.pathname === '/api/save' && req.method === 'POST') {
      return handleSaveData(req);
    }

    if (url.pathname === '/api/sample') {
      const sampleFile = Bun.file('data/sample.json');
      const exists = await sampleFile.exists();
      if (!exists) {
        return new Response('[]', { headers: { 'Content-Type': 'application/json' } });
      }
      return new Response(sampleFile, {
        headers: { 'Content-Type': 'application/json' },
      });
    }

    return handlePage(req);
  },
});

console.log(`Chart Generator running at http://localhost:${server.port}`);

