export type ToolType = 'pen' | 'rectangle' | 'circle' | 'line' | 'eraser';

export type Point = {
  x: number;
  y: number;
};

export type Stroke = {
  id: string;
  tool: ToolType;
  points: Point[];
  color: string;
  size: number;
  layerId: string;
};

export type ShapeStroke = Stroke & {
  tool: 'rectangle' | 'circle' | 'line';
  startPoint: Point;
  endPoint: Point;
};

export type Layer = {
  id: string;
  name: string;
