  opacity: number;
  strokes: Stroke[];
};

export type CanvasState = {
  layers: Layer[];
  activeLayerId: string;
  width: number;
  height: number;
};

export type HistoryEntry = {
  type: 'stroke-add' | 'stroke-remove' | 'layer-add' | 'layer-remove' | 'layer-toggle' | 'clear';
  layerId: string;
  stroke?: Stroke;
  layer?: Layer;
  previousStrokes?: Stroke[];
};

export type DrawingMetadata = {
  id: string;
  name: string;
