import type { HistoryEntry, CanvasState, Stroke } from './types';

export type HistoryManager = {
  push: (entry: HistoryEntry) => void;
  undo: (state: CanvasState) => CanvasState | null;
  redo: (state: CanvasState) => CanvasState | null;
  canUndo: () => boolean;
  canRedo: () => boolean;
  clear: () => void;
};

export const createHistoryManager = (): HistoryManager => {
  const undoStack: HistoryEntry[] = [];
  const redoStack: HistoryEntry[] = [];

  const applyEntry = (state: CanvasState, entry: HistoryEntry): CanvasState => {
    const layers = state.layers.map((l) => ({ ...l, strokes: [...l.strokes] }));

    switch (entry.type) {
      case 'stroke-add': {
        const layer = layers.find((l) => l.id === entry.layerId);
        if (layer && entry.stroke) {
          layer.strokes.push(entry.stroke);
        }
        break;
      }
      case 'stroke-remove': {
        const layer = layers.find((l) => l.id === entry.layerId);
        if (layer && entry.stroke) {
          layer.strokes = layer.strokes.filter((s) => s.id !== entry.stroke!.id);
        }
        break;
      }
      case 'layer-add': {
        if (entry.layer) {
          layers.push({ ...entry.layer, strokes: [...entry.layer.strokes] });
        }
        break;
      }
      case 'layer-remove': {
        const idx = layers.findIndex((l) => l.id === entry.layerId);
        if (idx !== -1) layers.splice(idx, 1);
        break;
      }
      case 'layer-toggle': {
        const layer = layers.find((l) => l.id === entry.layerId);
        if (layer) layer.visible = !layer.visible;
        break;
      }
      case 'clear': {
        const layer = layers.find((l) => l.id === entry.layerId);
        if (layer) layer.strokes = [];
        break;
      }
    }

    return { ...state, layers };
  };

  const invertEntry = (entry: HistoryEntry): HistoryEntry => {
    switch (entry.type) {
      case 'stroke-add':
        return { ...entry, type: 'stroke-remove' };
      case 'stroke-remove':
        return { ...entry, type: 'stroke-add' };
      case 'layer-add':
        return { ...entry, type: 'layer-remove' };
      case 'layer-remove':
        return { ...entry, type: 'layer-add' };
      case 'layer-toggle':
        return { ...entry };
      case 'clear':
        return {
          type: 'clear',
          layerId: entry.layerId,
          previousStrokes: entry.previousStrokes,
        };
    }
  };

  return {
    push: (entry: HistoryEntry) => {
      undoStack.push(entry);
      redoStack.length = 0;
    },

    undo: (state: CanvasState): CanvasState | null => {
      const entry = undoStack.pop();
      if (!entry) return null;

      if (entry.type === 'clear' && entry.previousStrokes) {
        const layers = state.layers.map((l) => {
          if (l.id === entry.layerId) {
            return { ...l, strokes: [...entry.previousStrokes!] };
          }
          return { ...l, strokes: [...l.strokes] };
        });
        redoStack.push(entry);
        return { ...state, layers };
      }

      const inverted = invertEntry(entry);
      redoStack.push(entry);
      return applyEntry(state, inverted);
    },

    redo: (state: CanvasState): CanvasState | null => {
      const entry = redoStack.pop();
      if (!entry) return null;
      undoStack.push(entry);
      return applyEntry(state, entry);
    },

    canUndo: () => undoStack.length > 0,
    canRedo: () => redoStack.length > 0,
    clear: () => {
      undoStack.length = 0;
      redoStack.length = 0;
    },
  };
};

import type { Layer, CanvasState } from './types';

let layerCounter = 0;

export const createLayer = (name?: string): Layer => {
  layerCounter += 1;
  return {
    id: `layer-${Date.now()}-${layerCounter}`,
    name: name ?? `Layer ${layerCounter}`,
    visible: true,
    opacity: 1,
    strokes: [],
  };
};

export const createInitialState = (width = 800, height = 600): CanvasState => {
  const baseLayer = createLayer('Background');
  return {
    layers: [baseLayer],
    activeLayerId: baseLayer.id,
    width,
    height,
  };
};

export const addLayer = (state: CanvasState, name?: string): { state: CanvasState; layer: Layer } => {
  const layer = createLayer(name);
  return {
    state: {
      ...state,
      layers: [...state.layers, layer],
      activeLayerId: layer.id,
    },
    layer,
  };
};

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state;
  const filtered = state.layers.filter((l) => l.id !== layerId);
  const activeLayerId = state.activeLayerId === layerId
    ? filtered[filtered.length - 1].id
    : state.activeLayerId;
  return { ...state, layers: filtered, activeLayerId };
};

export const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) =>
    l.id === layerId ? { ...l, visible: !l.visible } : l
  ),
});

export const setActiveLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  activeLayerId: layerId,
});

export const reorderLayers = (state: CanvasState, fromIndex: number, toIndex: number): CanvasState => {
  const layers = [...state.layers];
  const [moved] = layers.splice(fromIndex, 1);
  layers.splice(toIndex, 0, moved);
  return { ...state, layers };
};

export const getActiveLayer = (state: CanvasState): Layer | undefined =>
  state.layers.find((l) => l.id === state.activeLayerId);

import type { Point, Stroke, ShapeStroke, ToolType } from './types';

let strokeCounter = 0;

const generateStrokeId = (): string => {
  strokeCounter += 1;
  return `stroke-${Date.now()}-${strokeCounter}`;
};

export const createStroke = (
  tool: ToolType,
  startPoint: Point,
  color: string,
  size: number,
  layerId: string,
): Stroke => ({
  id: generateStrokeId(),
  tool,
  points: [startPoint],
  color: tool === 'eraser' ? 'eraser' : color,
  size,
  layerId,
});

export const addPointToStroke = (stroke: Stroke, point: Point): Stroke => ({
  ...stroke,
  points: [...stroke.points, point],
});

export const finalizeShapeStroke = (
  stroke: Stroke,
  endPoint: Point,
): ShapeStroke => ({
  ...stroke,
  tool: stroke.tool as 'rectangle' | 'circle' | 'line',
  startPoint: stroke.points[0],
  endPoint,
});

export const isShapeTool = (tool: ToolType): boolean =>
  tool === 'rectangle' || tool === 'circle' || tool === 'line';

export const renderStrokeToContext = (
  ctx: CanvasRenderingContext2D,
  stroke: Stroke,
): void => {
  ctx.save();

  if (stroke.color === 'eraser') {
    ctx.globalCompositeOperation = 'destination-out';
    ctx.strokeStyle = 'rgba(0,0,0,1)';
  } else {
    ctx.globalCompositeOperation = 'source-over';
    ctx.strokeStyle = stroke.color;
  }

  ctx.lineWidth = stroke.size;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';

  const { tool, points } = stroke;

  if (tool === 'pen' || tool === 'eraser') {
    if (points.length < 2) {
      ctx.beginPath();
      ctx.arc(points[0].x, points[0].y, stroke.size / 2, 0, Math.PI * 2);
      ctx.fillStyle = stroke.color === 'eraser' ? 'rgba(0,0,0,1)' : stroke.color;
      ctx.fill();
    } else {
      ctx.beginPath();
      ctx.moveTo(points[0].x, points[0].y);
      for (let i = 1; i < points.length; i++) {
        const midX = (points[i - 1].x + points[i].x) / 2;
        const midY = (points[i - 1].y + points[i].y) / 2;
        ctx.quadraticCurveTo(points[i - 1].x, points[i - 1].y, midX, midY);
      }
      ctx.stroke();
    }
  } else if (tool === 'line') {
    const shape = stroke as ShapeStroke;
    if (shape.startPoint && shape.endPoint) {
      ctx.beginPath();
      ctx.moveTo(shape.startPoint.x, shape.startPoint.y);
      ctx.lineTo(shape.endPoint.x, shape.endPoint.y);
      ctx.stroke();
    }
  } else if (tool === 'rectangle') {
    const shape = stroke as ShapeStroke;
    if (shape.startPoint && shape.endPoint) {
      const x = Math.min(shape.startPoint.x, shape.endPoint.x);
      const y = Math.min(shape.startPoint.y, shape.endPoint.y);
      const w = Math.abs(shape.endPoint.x - shape.startPoint.x);
      const h = Math.abs(shape.endPoint.y - shape.startPoint.y);
      ctx.strokeRect(x, y, w, h);
    }
  } else if (tool === 'circle') {
    const shape = stroke as ShapeStroke;
    if (shape.startPoint && shape.endPoint) {
      const cx = (shape.startPoint.x + shape.endPoint.x) / 2;
      const cy = (shape.startPoint.y + shape.endPoint.y) / 2;
      const rx = Math.abs(shape.endPoint.x - shape.startPoint.x) / 2;
      const ry = Math.abs(shape.endPoint.y - shape.startPoint.y) / 2;
      ctx.beginPath();
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
      ctx.stroke();
    }
  }

  ctx.restore();
};

export const renderLayerToContext = (
  ctx: CanvasRenderingContext2D,
  strokes: Stroke[],
): void => {
  for (const stroke of strokes) {
    renderStrokeToContext(ctx, stroke);
  }
};

import type { DrawingMetadata, CanvasState } from './types';
import { renderLayerToContext } from './tools';

const DATA_DIR = './data';
const METADATA_FILE = `${DATA_DIR}/drawings.json`;

export const loadDrawingsMetadata = async (): Promise<DrawingMetadata[]> => {
  const file = Bun.file(METADATA_FILE);
  const exists = await file.exists();
  if (!exists) return [];
  const text = await file.text();
  return JSON.parse(text) as DrawingMetadata[];
};

export const saveDrawingsMetadata = async (drawings: DrawingMetadata[]): Promise<void> => {
  await Bun.write(METADATA_FILE, JSON.stringify(drawings, null, 2));
};

export const exportCanvasAsPng = (
  state: CanvasState,
  canvas: HTMLCanvasElement,
): string => {
  const exportCanvas = document.createElement('canvas');
  exportCanvas.width = state.width;
  exportCanvas.height = state.height;
  const ctx = exportCanvas.getContext('2d')!;

  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, state.width, state.height);

  for (const layer of state.layers) {
    if (!layer.visible) continue;

    const layerCanvas = document.createElement('canvas');
    layerCanvas.width = state.width;
    layerCanvas.height = state.height;
    const layerCtx = layerCanvas.getContext('2d')!;

    renderLayerToContext(layerCtx, layer.strokes);

    ctx.globalAlpha = layer.opacity;
    ctx.drawImage(layerCanvas, 0, 0);
    ctx.globalAlpha = 1;
  }

  return exportCanvas.toDataURL('image/png');
};

export const downloadPng = (dataUrl: string, filename: string): void => {
  const link = document.createElement('a');
  link.download = filename;
  link.href = dataUrl;
  link.click();
};

export const saveDrawing = async (
  state: CanvasState,
  canvas: HTMLCanvasElement,
  name: string,
): Promise<DrawingMetadata> => {
  const dataUrl = exportCanvasAsPng(state, canvas);
  const id = `drawing-${Date.now()}`;
  const filename = `${id}.png`;

  const base64 = dataUrl.split(',')[1];
  const buffer = Uint8Array.from(atob(base64), (c) => c.charCodeAt(0));
  await Bun.write(`${DATA_DIR}/${filename}`, buffer);

  const metadata: DrawingMetadata = {
    id,
    name,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    width: state.width,
    height: state.height,
    filename,
  };

  const drawings = await loadDrawingsMetadata();
  drawings.push(metadata);
  await saveDrawingsMetadata(drawings);

  return metadata;
};

export const loadDrawingAsDataUrl = async (filename: string): Promise<string> => {
  const file = Bun.file(`${DATA_DIR}/${filename}`);
  const buffer = await file.arrayBuffer();
  const base64 = btoa(String.fromCharCode(...new Uint8Array(buffer)));
  return `data:image/png;base64,${base64}`;
};

export const deleteDrawing = async (id: string): Promise<void> => {
  const drawings = await loadDrawingsMetadata();
  const drawing = drawings.find((d) => d.id === id);
  if (!drawing) return;

  const file = Bun.file(`${DATA_DIR}/${drawing.filename}`);
  const exists = await file.exists();
  if (exists) {
    await Bun.write(`${DATA_DIR}/${drawing.filename}`, '');
  }

  const filtered = drawings.filter((d) => d.id !== id);
  await saveDrawingsMetadata(filtered);
};

