import type { CanvasState, ToolbarState, Point, Stroke, ToolType } from './types';
import { createStroke, addPointToStroke, finalizeShapeStroke, isShapeTool, renderLayerToContext, renderStrokeToContext } from './tools';
import { createHistoryManager } from './history';
import { createInitialState, addLayer, removeLayer, toggleLayerVisibility, setActiveLayer, getActiveLayer } from './layers';
import { exportCanvasAsPng, downloadPng } from './storage';
import type { HistoryManager } from './history';

export type CanvasController = {
  getState: () => CanvasState;
  getToolbar: () => ToolbarState;
  setTool: (tool: ToolType) => void;
  setColor: (color: string) => void;
  setBrushSize: (size: number) => void;
  onPointerDown: (point: Point) => void;
  onPointerMove: (point: Point) => void;
  onPointerUp: (point: Point) => void;
  undo: () => void;
  redo: () => void;
  clearActiveLayer: () => void;
  addNewLayer: (name?: string) => void;
  removeLayerById: (id: string) => void;
  toggleLayer: (id: string) => void;
  selectLayer: (id: string) => void;
  savePng: () => void;
  loadPng: () => void;
  redraw: () => void;
  setCanvas: (canvas: HTMLCanvasElement) => void;
  updateThumbnails: () => void;
};

export const createCanvasController = (
  width?: number,
  height?: number,
): CanvasController => {
  let state = createInitialState(width, height);
  let toolbar: ToolbarState = {
    activeTool: 'pen',
    color: '#000000',
    brushSize: 3,
  };

  let canvas: HTMLCanvasElement | null = null;
  let ctx: CanvasRenderingContext2D | null = null;
  let currentStroke: Stroke | null = null;
  let isDrawing = false;
  const history: HistoryManager = createHistoryManager();

  const redraw = (): void => {
    if (!ctx || !canvas) return;
    ctx.clearRect(0, 0, state.width, state.height);
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, state.width, state.height);

    for (const layer of state.layers) {
      if (!layer.visible) continue;

      const offscreen = document.createElement('canvas');
      offscreen.width = state.width;
      offscreen.height = state.height;
      const offCtx = offscreen.getContext('2d')!;

      renderLayerToContext(offCtx, layer.strokes);

      ctx.globalAlpha = layer.opacity;
      ctx.drawImage(offscreen, 0, 0);
      ctx.globalAlpha = 1;
    }

    if (currentStroke && isDrawing) {
      renderStrokeToContext(ctx, currentStroke);
    }
  };

  const updateThumbnails = (): void => {
    for (const layer of state.layers) {
      const thumb = document.querySelector(`[p-target="thumb-${layer.id}"]`) as HTMLCanvasElement | null;
      if (!thumb) continue;
      const thumbCtx = thumb.getContext('2d');
      if (!thumbCtx) continue;

      thumbCtx.clearRect(0, 0, thumb.width, thumb.height);
      thumbCtx.fillStyle = '#ffffff';
      thumbCtx.fillRect(0, 0, thumb.width, thumb.height);

      const scaleX = thumb.width / state.width;
      const scaleY = thumb.height / state.height;
      thumbCtx.save();
      thumbCtx.scale(scaleX, scaleY);
      renderLayerToContext(thumbCtx, layer.strokes);
      thumbCtx.restore();
    }
  };

  return {
    getState: () => state,
    getToolbar: () => toolbar,

    setTool: (tool: ToolType) => {
      toolbar = { ...toolbar, activeTool: tool };
    },

    setColor: (color: string) => {
      toolbar = { ...toolbar, color };
    },

    setBrushSize: (size: number) => {
      toolbar = { ...toolbar, brushSize: Math.max(1, Math.min(50, size)) };
    },

    onPointerDown: (point: Point) => {
      const activeLayer = getActiveLayer(state);
      if (!activeLayer || !activeLayer.visible) return;

      isDrawing = true;
      currentStroke = createStroke(
        toolbar.activeTool,
        point,
        toolbar.color,
        toolbar.brushSize,
        activeLayer.id,
      );

      if (isShapeTool(toolbar.activeTool)) {
        currentStroke = { ...currentStroke, points: [point] };
      }
    },

    onPointerMove: (point: Point) => {
      if (!isDrawing || !currentStroke) return;

      if (isShapeTool(toolbar.activeTool)) {
        const shapePreview = finalizeShapeStroke(currentStroke, point);
        currentStroke = shapePreview;
      } else {
        currentStroke = addPointToStroke(currentStroke, point);
      }

      redraw();
    },

    onPointerUp: (point: Point) => {
      if (!isDrawing || !currentStroke) return;
      isDrawing = false;

      let finalStroke: Stroke;
      if (isShapeTool(toolbar.activeTool)) {
        finalStroke = finalizeShapeStroke(currentStroke, point);
      } else {
        finalStroke = currentStroke;
      }

      const layerIdx = state.layers.findIndex((l) => l.id === finalStroke.layerId);
      if (layerIdx !== -1) {
        const updatedLayers = state.layers.map((l, i) => {
          if (i === layerIdx) {
            return { ...l, strokes: [...l.strokes, finalStroke] };
          }
          return l;
        });
        state = { ...state, layers: updatedLayers };

        history.push({
          type: 'stroke-add',
          layerId: finalStroke.layerId,
          stroke: finalStroke,
        });
      }

      currentStroke = null;
      redraw();
      updateThumbnails();
    },

    undo: () => {
      const newState = history.undo(state);
      if (newState) {
        state = newState;
        redraw();
        updateThumbnails();
      }
    },

    redo: () => {
      const newState = history.redo(state);
      if (newState) {
        state = newState;
        redraw();
        updateThumbnails();
      }
    },

    clearActiveLayer: () => {
      const activeLayer = getActiveLayer(state);
      if (!activeLayer) return;

      history.push({
        type: 'clear',
        layerId: activeLayer.id,
        previousStrokes: [...activeLayer.strokes],
      });

      state = {
        ...state,
        layers: state.layers.map((l) =>
          l.id === activeLayer.id ? { ...l, strokes: [] } : l
        ),
      };
      redraw();
      updateThumbnails();
    },

    addNewLayer: (name?: string) => {
      const result = addLayer(state, name);
      state = result.state;
      history.push({
        type: 'layer-add',
        layerId: result.layer.id,
        layer: result.layer,
      });
    },

    removeLayerById: (id: string) => {
      const layer = state.layers.find((l) => l.id === id);
      if (!layer || state.layers.length <= 1) return;

      history.push({
        type: 'layer-remove',
        layerId: id,
        layer: { ...layer, strokes: [...layer.strokes] },
      });
      state = removeLayer(state, id);
      redraw();
      updateThumbnails();
    },

    toggleLayer: (id: string) => {
      state = toggleLayerVisibility(state, id);
      history.push({ type: 'layer-toggle', layerId: id });
      redraw();
    },

    selectLayer: (id: string) => {
      state = setActiveLayer(state, id);
    },

    savePng: () => {
      if (!canvas) return;
      const dataUrl = exportCanvasAsPng(state, canvas);
      downloadPng(dataUrl, `drawing-${Date.now()}.png`);
    },

    loadPng: () => {
      const input = document.createElement('input');
      input.type = 'file';
      input.accept = 'image/png';
      input.onchange = () => {
        const file = input.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = () => {
          const img = new Image();
          img.onload = () => {
            const activeLayer = getActiveLayer(state);
            if (!activeLayer || !ctx) return;

            const offscreen = document.createElement('canvas');
            offscreen.width = state.width;
            offscreen.height = state.height;
            const offCtx = offscreen.getContext('2d')!;
            offCtx.drawImage(img, 0, 0, state.width, state.height);

            redraw();
            ctx.drawImage(offscreen, 0, 0);
          };
          img.src = reader.result as string;
        };
        reader.readAsDataURL(file);
      };
      input.click();
    },

    redraw,

    setCanvas: (c: HTMLCanvasElement) => {
      canvas = c;
      ctx = c.getContext('2d');
      redraw();
    },

    updateThumbnails,
  };
};

import { h, createSSR } from 'plaited';
import type { ToolType } from './types';
import { renderCanvas, renderStyles } from './renderer';
import { createCanvasController } from './canvas-controller';

export type { CanvasState, ToolbarState, Layer, Stroke, Point, ToolType } from './types';
export { createCanvasController } from './canvas-controller';
export { createInitialState, addLayer, removeLayer } from './layers';
export { createHistoryManager } from './history';
export { exportCanvasAsPng, saveDrawing, loadDrawingsMetadata } from './storage';

const getPointerPosition = (e: PointerEvent, canvas: HTMLCanvasElement): { x: number; y: number } => {
  const rect = canvas.getBoundingClientRect();
  return {
    x: e.clientX - rect.left,
    y: e.clientY - rect.top,
  };
};

export const mount = (root: HTMLElement, width = 800, height = 600): void => {
  const controller = createCanvasController(width, height);

  const render = (): void => {
    const state = controller.getState();
    const toolbar = controller.getToolbar();
    root.innerHTML = renderStyles() + renderCanvas(state, toolbar);

    const canvas = root.querySelector('[p-target="main-canvas"]') as HTMLCanvasElement;
    if (canvas) {
      controller.setCanvas(canvas);
      bindCanvasEvents(canvas);
    }

    requestAnimationFrame(() => {
      controller.updateThumbnails();
    });

    bindUIEvents(root);
  };

  const bindCanvasEvents = (canvas: HTMLCanvasElement): void => {
    canvas.addEventListener('pointerdown', (e: PointerEvent) => {
      canvas.setPointerCapture(e.pointerId);
      controller.onPointerDown(getPointerPosition(e, canvas));
    });

    canvas.addEventListener('pointermove', (e: PointerEvent) => {
      controller.onPointerMove(getPointerPosition(e, canvas));
    });

    canvas.addEventListener('pointerup', (e: PointerEvent) => {
      controller.onPointerUp(getPointerPosition(e, canvas));
      requestAnimationFrame(() => controller.updateThumbnails());
    });
  };

  const bindUIEvents = (container: HTMLElement): void => {
    container.addEventListener('click', (e: Event) => {
      const target = e.target as HTMLElement;
      const trigger = target.getAttribute('p-trigger');
      if (!trigger) return;

      if (trigger.startsWith('tool-select:')) {
        const tool = trigger.split(':')[1] as ToolType;
        controller.setTool(tool);
        render();
        return;
      }

      if (trigger.startsWith('color-select:')) {
        const color = trigger.split(':')[1];
        controller.setColor(color);
        render();
        return;
      }

      if (trigger.startsWith('layer-select:')) {
        const id = trigger.split(':')[1];
        controller.selectLayer(id);
        render();
        return;
      }

      if (trigger.startsWith('layer-toggle:')) {
        const id = trigger.split(':')[1];
        e.stopPropagation();
        controller.toggleLayer(id);
        render();
        return;
      }

      if (trigger.startsWith('layer-delete:')) {
        const id = trigger.split(':')[1];
        e.stopPropagation();
        controller.removeLayerById(id);
        render();
        return;
      }

      switch (trigger) {
        case 'undo':
          controller.undo();
          render();
          break;
        case 'redo':
          controller.redo();
          render();
          break;
        case 'clear':
          controller.clearActiveLayer();
          render();
          break;
        case 'layer-add':
          controller.addNewLayer();
          render();
          break;
        case 'save-png':
          controller.savePng();
          break;
        case 'load-png':
          controller.loadPng();
          break;
      }
    });

    container.addEventListener('input', (e: Event) => {
      const target = e.target as HTMLInputElement;
      const trigger = target.getAttribute('p-trigger');
      if (!trigger) return;

      if (trigger === 'color-input') {
        controller.setColor(target.value);
        render();
      }

      if (trigger === 'brush-size') {
        controller.setBrushSize(Number(target.value));
        render();
      }
    });
  };

  render();
};

export const renderSSR = (width = 800, height = 600): string => {
  const controller = createCanvasController(width, height);
  const state = controller.getState();
  const toolbar = controller.getToolbar();

  return createSSR(
    h('div', { id: 'drawing-canvas-root' },
      renderStyles(),
      renderCanvas(state, toolbar),
    )
  );
};

