import type { Layer } from './types'

const generateId = (): string => crypto.randomUUID()

export const createLayer = (name?: string): Layer => ({
  id: generateId(),
  name: name ?? 'Layer',
  visible: true,
  opacity: 1,
  dataUrl: null,
})

export const duplicateLayer = (layer: Layer): Layer => ({
  ...layer,
  id: generateId(),
  name: `${layer.name} copy`,
})

export const toggleLayerVisibility = (layer: Layer): Layer => ({
  ...layer,
  visible: !layer.visible,
})

export const setLayerOpacity = (layer: Layer, opacity: number): Layer => ({
  ...layer,
  opacity: Math.max(0, Math.min(1, opacity)),
})

export const renameLayer = (layer: Layer, name: string): Layer => ({
  ...layer,
  name,
})

export const reorderLayers = (layers: Layer[], fromIndex: number, toIndex: number): Layer[] => {
  const result = [...layers]
  const [moved] = result.splice(fromIndex, 1)
  result.splice(toIndex, 0, moved)
  return result
}

export const mergeLayerData = (layers: Layer[]): Layer[] =>
  layers.filter((l) => l.visible)

import type { ToolKind, Point, DrawAction } from './types'

export type ToolConfig = {
  kind: ToolKind
  label: string
  cursor: string
  usesStroke: boolean
  usesFill: boolean
}

export const TOOLS: Record<ToolKind, ToolConfig> = {
  brush: { kind: 'brush', label: 'Brush', cursor: 'crosshair', usesStroke: true, usesFill: false },
  rectangle: { kind: 'rectangle', label: 'Rectangle', cursor: 'crosshair', usesStroke: true, usesFill: true },
  circle: { kind: 'circle', label: 'Circle', cursor: 'crosshair', usesStroke: true, usesFill: true },
  line: { kind: 'line', label: 'Line', cursor: 'crosshair', usesStroke: true, usesFill: false },
  eraser: { kind: 'eraser', label: 'Eraser', cursor: 'cell', usesStroke: false, usesFill: false },
}

export const createDrawAction = (
  tool: ToolKind,
  points: Point[],
  color: string,
  size: number,
  layerId: string,
): DrawAction => ({
  tool,
  points,
  color,
  size,
  layerId,
})

export const renderAction = (ctx: CanvasRenderingContext2D, action: DrawAction): void => {
  const { tool, points, color, size } = action

  ctx.save()

  if (tool === 'eraser') {
    ctx.globalCompositeOperation = 'destination-out'
    ctx.strokeStyle = 'rgba(0,0,0,1)'
    ctx.lineWidth = size
    ctx.lineCap = 'round'
    ctx.lineJoin = 'round'
    if (points.length > 1) {
      ctx.beginPath()
      ctx.moveTo(points[0].x, points[0].y)
      for (let i = 1; i < points.length; i++) {
        ctx.lineTo(points[i].x, points[i].y)
      }
      ctx.stroke()
    }
    ctx.restore()
    return
  }

  ctx.globalCompositeOperation = 'source-over'
  ctx.strokeStyle = color
  ctx.fillStyle = color
  ctx.lineWidth = size
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'

  switch (tool) {
    case 'brush': {
      if (points.length === 1) {
        ctx.beginPath()
        ctx.arc(points[0].x, points[0].y, size / 2, 0, Math.PI * 2)
        ctx.fill()
      } else {
        ctx.beginPath()
        ctx.moveTo(points[0].x, points[0].y)
        for (let i = 1; i < points.length; i++) {
          const midX = (points[i - 1].x + points[i].x) / 2
          const midY = (points[i - 1].y + points[i].y) / 2
          ctx.quadraticCurveTo(points[i - 1].x, points[i - 1].y, midX, midY)
        }
        ctx.stroke()
      }
      break
    }
    case 'rectangle': {
      if (points.length >= 2) {
        const start = points[0]
        const end = points[points.length - 1]
        const w = end.x - start.x
        const h = end.y - start.y
        ctx.strokeRect(start.x, start.y, w, h)
      }
      break
    }
    case 'circle': {
      if (points.length >= 2) {
        const start = points[0]
        const end = points[points.length - 1]
        const rx = Math.abs(end.x - start.x) / 2
        const ry = Math.abs(end.y - start.y) / 2
        const cx = start.x + (end.x - start.x) / 2
        const cy = start.y + (end.y - start.y) / 2
        ctx.beginPath()
        ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
        ctx.stroke()
      }
      break
    }
    case 'line': {
      if (points.length >= 2) {
        ctx.beginPath()
        ctx.moveTo(points[0].x, points[0].y)
        ctx.lineTo(points[points.length - 1].x, points[points.length - 1].y)
        ctx.stroke()
      }
      break
    }
  }

  ctx.restore()
}

import type { DrawAction } from './types'

export type HistoryStack = {
  entries: DrawAction[][]
  index: number
}

export const createHistory = (): HistoryStack => ({
  entries: [[]],
  index: 0,
})

export const pushHistory = (stack: HistoryStack, actions: DrawAction[]): HistoryStack => {
  const trimmed = stack.entries.slice(0, stack.index + 1)
  return {
    entries: [...trimmed, actions],
    index: trimmed.length,
  }
}

export const undo = (stack: HistoryStack): HistoryStack => ({
  ...stack,
  index: Math.max(0, stack.index - 1),
})

export const redo = (stack: HistoryStack): HistoryStack => ({
  ...stack,
  index: Math.min(stack.entries.length - 1, stack.index + 1),
})

export const canUndo = (stack: HistoryStack): boolean => stack.index > 0

export const canRedo = (stack: HistoryStack): boolean => stack.index < stack.entries.length - 1

export const currentActions = (stack: HistoryStack): DrawAction[] => {
  const result: DrawAction[] = []
  for (let i = 0; i <= stack.index; i++) {
    result.push(...stack.entries[i])
  }
  return result
}

export const clearHistory = (): HistoryStack => createHistory()

import type { DrawingMetadata } from './types'

const DATA_DIR = './data'
const METADATA_PATH = `${DATA_DIR}/drawings.jsonl`

const generateId = (): string => crypto.randomUUID()

export const saveDrawing = async (
  name: string,
  pngBuffer: Uint8Array,
  width: number,
  height: number,
  layerCount: number,
): Promise<DrawingMetadata> => {
  const id = generateId()
  const now = new Date().toISOString()
  const metadata: DrawingMetadata = {
    id,
    name,
    createdAt: now,
    updatedAt: now,
    width,
    height,
    layerCount,
  }

  const pngPath = `${DATA_DIR}/${id}.png`
  await Bun.write(pngPath, pngBuffer)

  const file = Bun.file(METADATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  const line = JSON.stringify(metadata) + '\n'
  await Bun.write(METADATA_PATH, existing + line)

  return metadata
}

export const listDrawings = async (): Promise<DrawingMetadata[]> => {
  const file = Bun.file(METADATA_PATH)
  if (!(await file.exists())) return []

  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as DrawingMetadata)
}

export const loadDrawingPng = async (id: string): Promise<Uint8Array | null> => {
  const pngPath = `${DATA_DIR}/${id}.png`
  const file = Bun.file(pngPath)
  if (!(await file.exists())) return null
  return new Uint8Array(await file.arrayBuffer())
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const drawings = await listDrawings()
  const filtered = drawings.filter((d) => d.id !== id)
  if (filtered.length === drawings.length) return false

  const content = filtered.map((d) => JSON.stringify(d)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(METADATA_PATH, content)

  const pngPath = `${DATA_DIR}/${id}.png`
  const pngFile = Bun.file(pngPath)
  if (await pngFile.exists()) {
    await Bun.$`rm ${pngPath}`
  }

  return true
}

export const updateDrawingMetadata = async (
  id: string,
  updates: Partial<Pick<DrawingMetadata, 'name'>>,
): Promise<DrawingMetadata | null> => {
  const drawings = await listDrawings()
  const index = drawings.findIndex((d) => d.id === id)
  if (index === -1) return null

  const updated: DrawingMetadata = {
    ...drawings[index],
    ...updates,
    updatedAt: new Date().toISOString(),
  }
  drawings[index] = updated

  const content = drawings.map((d) => JSON.stringify(d)).join('\n') + '\n'
  await Bun.write(METADATA_PATH, content)

  return updated
}

import type { CanvasState, Layer, ToolKind, DrawAction, Point } from './types'
import { createLayer } from './layers'
import { createDrawAction, renderAction } from './tools'
import { createHistory, pushHistory, undo, redo, canUndo, canRedo, currentActions, clearHistory } from './history'
import type { HistoryStack } from './history'

export type CanvasEngine = {
  getState: () => CanvasState
  setTool: (tool: ToolKind) => void
  setColor: (color: string) => void
  setBrushSize: (size: number) => void
  addLayer: (name?: string) => void
  removeLayer: (id: string) => void
  setActiveLayer: (id: string) => void
  toggleLayerVisibility: (id: string) => void
  setLayerOpacity: (id: string, opacity: number) => void
  reorderLayer: (fromIndex: number, toIndex: number) => void
  startStroke: (point: Point) => void
  continueStroke: (point: Point) => void
  endStroke: () => void
  undo: () => void
  redo: () => void
  canUndo: () => boolean
  canRedo: () => boolean
  clear: () => void
  getActionsForLayer: (layerId: string) => DrawAction[]
  renderToContext: (ctx: CanvasRenderingContext2D) => void
  getAllActions: () => DrawAction[]
}

export const createCanvasEngine = (width = 800, height = 600): CanvasEngine => {
  const initialLayer = createLayer('Background')

  let state: CanvasState = {
    width,
    height,
    layers: [initialLayer],
    activeLayerId: initialLayer.id,
    history: [[]],
    historyIndex: 0,
    activeTool: 'brush',
    activeColor: '#000000',
    brushSize: 4,
  }

  let historyStack: HistoryStack = createHistory()
  let currentStrokePoints: Point[] = []
  let isDrawing = false

  const getState = (): CanvasState => ({ ...state })

  const setTool = (tool: ToolKind): void => {
    state = { ...state, activeTool: tool }
  }

  const setColor = (color: string): void => {
    state = { ...state, activeColor: color }
  }

  const setBrushSize = (size: number): void => {
    state = { ...state, brushSize: Math.max(1, Math.min(100, size)) }
  }

  const addLayer = (name?: string): void => {
    const layer = createLayer(name ?? `Layer ${state.layers.length + 1}`)
    state = {
      ...state,
      layers: [...state.layers, layer],
      activeLayerId: layer.id,
    }
  }

  const removeLayer = (id: string): void => {
    if (state.layers.length <= 1) return
    const remaining = state.layers.filter((l) => l.id !== id)
    const activeId = state.activeLayerId === id ? remaining[remaining.length - 1].id : state.activeLayerId
    state = { ...state, layers: remaining, activeLayerId: activeId }
  }

  const setActiveLayer = (id: string): void => {
    if (state.layers.some((l) => l.id === id)) {
      state = { ...state, activeLayerId: id }
    }
  }

  const toggleLayerVis = (id: string): void => {
    state = {
      ...state,
      layers: state.layers.map((l) => (l.id === id ? { ...l, visible: !l.visible } : l)),
    }
  }

  const setLayerOp = (id: string, opacity: number): void => {
    state = {
      ...state,
      layers: state.layers.map((l) =>
        l.id === id ? { ...l, opacity: Math.max(0, Math.min(1, opacity)) } : l,
      ),
    }
  }

  const reorderLayer = (fromIndex: number, toIndex: number): void => {
    const layers = [...state.layers]
    const [moved] = layers.splice(fromIndex, 1)
    layers.splice(toIndex, 0, moved)
    state = { ...state, layers }
  }

  const startStroke = (point: Point): void => {
    isDrawing = true
    currentStrokePoints = [point]
  }

  const continueStroke = (point: Point): void => {
    if (!isDrawing) return
    currentStrokePoints.push(point)
  }

  const endStroke = (): void => {
    if (!isDrawing || currentStrokePoints.length === 0) return
    isDrawing = false

    const action = createDrawAction(
      state.activeTool,
      [...currentStrokePoints],
      state.activeColor,
      state.brushSize,
      state.activeLayerId,
    )

    historyStack = pushHistory(historyStack, [action])
    currentStrokePoints = []
  }

  const doUndo = (): void => {
    if (canUndo(historyStack)) {
      historyStack = undo(historyStack)
    }
  }

  const doRedo = (): void => {
    if (canRedo(historyStack)) {
      historyStack = redo(historyStack)
    }
  }

  const doClear = (): void => {
    historyStack = clearHistory()
  }

  const getAllActions = (): DrawAction[] => currentActions(historyStack)

  const getActionsForLayer = (layerId: string): DrawAction[] =>
    getAllActions().filter((a) => a.layerId === layerId)

  const renderToContext = (ctx: CanvasRenderingContext2D): void => {
    ctx.clearRect(0, 0, state.width, state.height)

    for (const layer of state.layers) {
      if (!layer.visible) continue

      ctx.save()
      ctx.globalAlpha = layer.opacity

      const layerActions = getActionsForLayer(layer.id)
      for (const action of layerActions) {
        renderAction(ctx, action)
      }

      ctx.restore()
    }

    // Render in-progress stroke
    if (isDrawing && currentStrokePoints.length > 0) {
      const previewAction = createDrawAction(
        state.activeTool,
        [...currentStrokePoints],
        state.activeColor,
        state.brushSize,
        state.activeLayerId,
      )
      renderAction(ctx, previewAction)
    }
  }

  return {
    getState,
    setTool,
    setColor,
    setBrushSize,
    addLayer,
    removeLayer,
    setActiveLayer,
    toggleLayerVisibility: toggleLayerVis,
    setLayerOpacity: setLayerOp,
    reorderLayer,
    startStroke,
    continueStroke,
    endStroke,
    undo: doUndo,
    redo: doRedo,
    canUndo: () => canUndo(historyStack),
    canRedo: () => canRedo(historyStack),
    clear: doClear,
    getActionsForLayer,
    renderToContext,
    getAllActions,
  }
}

