import type { CanvasEngine } from './canvas'
import type { Point, ToolKind } from './types'

export type ClientBindings = {
  attach: (canvasEl: HTMLCanvasElement) => void
  detach: () => void
}

export const bindCanvas = (engine: CanvasEngine): ClientBindings => {
  let canvasEl: HTMLCanvasElement | null = null
  let ctx: CanvasRenderingContext2D | null = null
  let animFrameId: number | null = null

  const getCanvasPoint = (e: PointerEvent): Point => {
    if (!canvasEl) return { x: 0, y: 0 }
    const rect = canvasEl.getBoundingClientRect()
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    }
  }

  const render = () => {
    if (!ctx) return
    engine.renderToContext(ctx)
    animFrameId = requestAnimationFrame(render)
  }

  const onPointerDown = (e: PointerEvent) => {
    if (!canvasEl) return
    canvasEl.setPointerCapture(e.pointerId)
    engine.startStroke(getCanvasPoint(e))
  }

  const onPointerMove = (e: PointerEvent) => {
    if (!canvasEl?.hasPointerCapture(e.pointerId)) return
    engine.continueStroke(getCanvasPoint(e))
  }

  const onPointerUp = (e: PointerEvent) => {
    if (!canvasEl) return
    canvasEl.releasePointerCapture(e.pointerId)
    engine.endStroke()
  }

  const onKeyDown = (e: KeyboardEvent) => {
    if (e.ctrlKey || e.metaKey) {
      if (e.key === 'z' && !e.shiftKey) {
        e.preventDefault()
        engine.undo()
      } else if (e.key === 'z' && e.shiftKey) {
        e.preventDefault()
        engine.redo()
      } else if (e.key === 'y') {
        e.preventDefault()
        engine.redo()
      }
    }

    // Tool shortcuts
    const toolShortcuts: Record<string, ToolKind> = {
      b: 'brush',
      r: 'rectangle',
      c: 'circle',
      l: 'line',
      e: 'eraser',
    }
    if (!e.ctrlKey && !e.metaKey && !e.altKey && toolShortcuts[e.key]) {
      engine.setTool(toolShortcuts[e.key])
    }
  }

  const exportPng = (): Promise<Blob | null> => {
    if (!canvasEl) return Promise.resolve(null)
    return new Promise((resolve) => {
      canvasEl!.toBlob((blob) => resolve(blob), 'image/png')
    })
  }

  const loadImage = (src: string): Promise<void> => {
    return new Promise((resolve, reject) => {
      if (!ctx || !canvasEl) {
        reject(new Error('Canvas not initialized'))
        return
      }
      const img = new Image()
      img.onload = () => {
        ctx!.drawImage(img, 0, 0, canvasEl!.width, canvasEl!.height)
        resolve()
      }
      img.onerror = reject
      img.src = src
    })
  }

  const attach = (el: HTMLCanvasElement) => {
    canvasEl = el
    ctx = el.getContext('2d')
    if (!ctx) throw new Error('Failed to get 2D context')

    el.addEventListener('pointerdown', onPointerDown)
    el.addEventListener('pointermove', onPointerMove)
    el.addEventListener('pointerup', onPointerUp)
    el.addEventListener('pointercancel', onPointerUp)
    document.addEventListener('keydown', onKeyDown)

    render()
  }

  const detach = () => {
    if (animFrameId !== null) cancelAnimationFrame(animFrameId)
    if (canvasEl) {
      canvasEl.removeEventListener('pointerdown', onPointerDown)
      canvasEl.removeEventListener('pointermove', onPointerMove)
      canvasEl.removeEventListener('pointerup', onPointerUp)
      canvasEl.removeEventListener('pointercancel', onPointerUp)
    }
    document.removeEventListener('keydown', onKeyDown)
    canvasEl = null
    ctx = null
  }

  return { attach, detach }
}

