let layerCounter = 0

export const createLayer = (name?: string): Layer => {
  layerCounter += 1
  return {
    id: `layer-${Date.now()}-${layerCounter}`,
    name: name ?? `Layer ${layerCounter}`,
    visible: true,
    actions: [],
  }
}

export const addActionToLayer = (layer: Layer, action: DrawAction): Layer => ({
  ...layer,
  actions: [...layer.actions, action],
})

export const clearLayer = (layer: Layer): Layer => ({
  ...layer,
  actions: [],
})

export const toggleLayerVisibility = (layer: Layer): Layer => ({
  ...layer,
  visible: !layer.visible,
})

export const renameLayer = (layer: Layer, name: string): Layer => ({
  ...layer,
  name,
})

export const reorderLayers = (layers: Layer[], fromIndex: number, toIndex: number): Layer[] => {
  const result = [...layers]
  const [moved] = result.splice(fromIndex, 1)
  result.splice(toIndex, 0, moved)
  return result
}

import type { SavedDrawing, DrawingsStore } from './types'

const DATA_PATH = new URL('./data/drawings.json', import.meta.url).pathname

const readStore = async (): Promise<DrawingsStore> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return (await file.json()) as DrawingsStore
  }
  return { drawings: [] }
}

const writeStore = async (store: DrawingsStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

export const saveDrawing = async (drawing: SavedDrawing): Promise<void> => {
  const store = await readStore()
  const existing = store.drawings.findIndex((d) => d.id === drawing.id)
  if (existing >= 0) {
    store.drawings[existing] = drawing
  } else {
    store.drawings.push(drawing)
  }
  await writeStore(store)
}

export const loadDrawing = async (id: string): Promise<SavedDrawing | undefined> => {
  const store = await readStore()
  return store.drawings.find((d) => d.id === id)
}

export const listDrawings = async (): Promise<SavedDrawing[]> => {
  const store = await readStore()
  return store.drawings
}

export const deleteDrawing = async (id: string): Promise<void> => {
  const store = await readStore()
  store.drawings = store.drawings.filter((d) => d.id !== id)
  await writeStore(store)
}

