import type { Point, DrawAction, Layer, CanvasState, ToolKind, StrokeStyle } from './types'
import { createLayer, addActionToLayer, clearLayer, toggleLayerVisibility } from './layers'
import { saveDrawing, loadDrawing, listDrawings } from './storage'

const DEFAULT_WIDTH = 900
const DEFAULT_HEIGHT = 600

export const createCanvasState = (): CanvasState => {
  const initialLayer = createLayer('Background')
  return {
    layers: [initialLayer],
    activeLayerId: initialLayer.id,
    undoStack: [],
    redoStack: [],
  }
}

export const getActiveLayer = (state: CanvasState): Layer | undefined =>
  state.layers.find((l) => l.id === state.activeLayerId)

export const pushAction = (state: CanvasState, action: DrawAction): CanvasState => {
  const activeLayer = getActiveLayer(state)
  if (!activeLayer) return state

  const updatedLayer = addActionToLayer(activeLayer, action)
  return {
    ...state,
    layers: state.layers.map((l) => (l.id === activeLayer.id ? updatedLayer : l)),
    undoStack: [...state.undoStack, activeLayer.actions],
    redoStack: [],
  }
}

export const undo = (state: CanvasState): CanvasState => {
  if (state.undoStack.length === 0) return state

  const activeLayer = getActiveLayer(state)
  if (!activeLayer) return state

  const previousActions = state.undoStack[state.undoStack.length - 1]
  return {
    ...state,
    layers: state.layers.map((l) =>
      l.id === activeLayer.id ? { ...l, actions: previousActions } : l
    ),
    undoStack: state.undoStack.slice(0, -1),
    redoStack: [...state.redoStack, activeLayer.actions],
  }
}

export const redo = (state: CanvasState): CanvasState => {
  if (state.redoStack.length === 0) return state

  const activeLayer = getActiveLayer(state)
  if (!activeLayer) return state

  const nextActions = state.redoStack[state.redoStack.length - 1]
  return {
    ...state,
    layers: state.layers.map((l) =>
      l.id === activeLayer.id ? { ...l, actions: nextActions } : l
    ),
    undoStack: [...state.undoStack, activeLayer.actions],
    redoStack: state.redoStack.slice(0, -1),
  }
}

export const clearActiveLayer = (state: CanvasState): CanvasState => {
  const activeLayer = getActiveLayer(state)
  if (!activeLayer) return state

  return {
    ...state,
    layers: state.layers.map((l) =>
      l.id === activeLayer.id ? clearLayer(l) : l
    ),
    undoStack: [...state.undoStack, activeLayer.actions],
    redoStack: [],
  }
}

export const addLayer = (state: CanvasState, name?: string): CanvasState => {
  const newLayer = createLayer(name)
  return {
    ...state,
    layers: [...state.layers, newLayer],
    activeLayerId: newLayer.id,
  }
}

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state

  const filtered = state.layers.filter((l) => l.id !== layerId)
  return {
    ...state,
    layers: filtered,
    activeLayerId:
      state.activeLayerId === layerId ? filtered[filtered.length - 1].id : state.activeLayerId,
  }
}

export const selectLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  activeLayerId: layerId,
  undoStack: [],
  redoStack: [],
})

export const toggleLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? toggleLayerVisibility(l) : l)),
})

// --- Canvas 2D rendering logic ---

export const renderAction = (ctx: CanvasRenderingContext2D, action: DrawAction): void => {
  ctx.save()

  if (action.kind === 'eraser') {
    ctx.globalCompositeOperation = 'destination-out'
    ctx.strokeStyle = 'rgba(0,0,0,1)'
  } else {
    ctx.globalCompositeOperation = 'source-over'
    ctx.strokeStyle = action.style.color
  }

  ctx.lineWidth = action.style.width
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'

  if (action.kind === 'pen' || action.kind === 'eraser') {
    if (action.points.length < 2) {
      ctx.beginPath()
      ctx.arc(action.points[0].x, action.points[0].y, action.style.width / 2, 0, Math.PI * 2)
      ctx.fillStyle = action.kind === 'eraser' ? 'rgba(0,0,0,1)' : action.style.color
      ctx.fill()
    } else {
      ctx.beginPath()
      ctx.moveTo(action.points[0].x, action.points[0].y)
      for (let i = 1; i < action.points.length; i++) {
        const prev = action.points[i - 1]
        const curr = action.points[i]
        const midX = (prev.x + curr.x) / 2
        const midY = (prev.y + curr.y) / 2
        ctx.quadraticCurveTo(prev.x, prev.y, midX, midY)
      }
      const last = action.points[action.points.length - 1]
      ctx.lineTo(last.x, last.y)
      ctx.stroke()
    }
  } else if (action.kind === 'rectangle') {
    const x = Math.min(action.start.x, action.end.x)
    const y = Math.min(action.start.y, action.end.y)
    const w = Math.abs(action.end.x - action.start.x)
    const h = Math.abs(action.end.y - action.start.y)
    ctx.strokeRect(x, y, w, h)
  } else if (action.kind === 'circle') {
    ctx.beginPath()
    ctx.ellipse(action.center.x, action.center.y, action.radiusX, action.radiusY, 0, 0, Math.PI * 2)
    ctx.stroke()
  } else if (action.kind === 'line') {
    ctx.beginPath()
    ctx.moveTo(action.start.x, action.start.y)
    ctx.lineTo(action.end.x, action.end.y)
    ctx.stroke()
  }

  ctx.restore()
}

export const renderLayer = (ctx: CanvasRenderingContext2D, layer: Layer): void => {
  if (!layer.visible) return
  for (const action of layer.actions) {
    renderAction(ctx, action)
  }
}

export const renderAllLayers = (
  ctx: CanvasRenderingContext2D,
  layers: Layer[],
  width: number,
  height: number
): void => {
  ctx.clearRect(0, 0, width, height)
  ctx.fillStyle = '#ffffff'
  ctx.fillRect(0, 0, width, height)
  for (const layer of layers) {
    renderLayer(ctx, layer)
  }
}

// --- PNG export/import helpers ---

export const canvasToDataUrl = (canvas: HTMLCanvasElement): string =>
  canvas.toDataURL('image/png')

export const saveToPng = async (
  canvas: HTMLCanvasElement,
  name: string
): Promise<void> => {
  const dataUrl = canvasToDataUrl(canvas)
  await saveDrawing({
    id: `drawing-${Date.now()}`,
    name,
    dataUrl,
    createdAt: new Date().toISOString(),
    width: canvas.width,
    height: canvas.height,
  })
}

export const downloadPng = (canvas: HTMLCanvasElement, filename: string): void => {
  const link = document.createElement('a')
  link.download = filename
  link.href = canvas.toDataURL('image/png')
  link.click()
}

export const loadImageOntoCanvas = (
  ctx: CanvasRenderingContext2D,
  dataUrl: string,
  width: number,
  height: number
): Promise<void> => {
  return new Promise((resolve, reject) => {
    const img = new Image()
    img.onload = () => {
      ctx.clearRect(0, 0, width, height)
      ctx.drawImage(img, 0, 0, width, height)
      resolve()
    }
    img.onerror = reject
    img.src = dataUrl
  })
}

export { DEFAULT_WIDTH, DEFAULT_HEIGHT }

import type { Point, DrawAction, ToolKind, CanvasState } from './types'
import {
  createCanvasState,
  pushAction,
  undo,
  redo,
  clearActiveLayer,
  addLayer,
  removeLayer,
  selectLayer,
  toggleLayer,
  renderAllLayers,
  renderAction,
  downloadPng,
  loadImageOntoCanvas,
  DEFAULT_WIDTH,
  DEFAULT_HEIGHT,
} from './canvas'

type AppState = {
  canvasState: CanvasState
  activeTool: ToolKind
  color: string
  brushSize: number
  isDrawing: boolean
  currentPoints: Point[]
  startPoint: Point | null
}

const createApp = () => {
  let state: AppState = {
    canvasState: createCanvasState(),
    activeTool: 'pen',
    color: '#000000',
    brushSize: 4,
    isDrawing: false,
    currentPoints: [],
    startPoint: null,
  }

  let mainCanvas: HTMLCanvasElement | null = null
  let ctx: CanvasRenderingContext2D | null = null

  const getCanvasPoint = (e: PointerEvent): Point => {
    if (!mainCanvas) return { x: 0, y: 0 }
    const rect = mainCanvas.getBoundingClientRect()
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    }
  }

  const redraw = () => {
    if (!ctx) return
    renderAllLayers(ctx, state.canvasState.layers, DEFAULT_WIDTH, DEFAULT_HEIGHT)
    updateLayerThumbnails()
  }

  const redrawWithPreview = () => {
    if (!ctx) return
    renderAllLayers(ctx, state.canvasState.layers, DEFAULT_WIDTH, DEFAULT_HEIGHT)

    if (state.isDrawing && state.startPoint) {
      const style = { color: state.color, width: state.brushSize }
      const tool = state.activeTool

      if (tool === 'pen' || tool === 'eraser') {
        const previewAction: DrawAction = {
          kind: tool,
          points: state.currentPoints,
          style,
        }
        renderAction(ctx, previewAction)
      } else if (tool === 'rectangle' && state.currentPoints.length > 0) {
        const end = state.currentPoints[state.currentPoints.length - 1]
        const previewAction: DrawAction = {
          kind: 'rectangle',
          start: state.startPoint,
          end,
          style,
        }
        renderAction(ctx, previewAction)
      } else if (tool === 'circle' && state.currentPoints.length > 0) {
        const end = state.currentPoints[state.currentPoints.length - 1]
        const previewAction: DrawAction = {
          kind: 'circle',
          center: state.startPoint,
          radiusX: Math.abs(end.x - state.startPoint.x),
          radiusY: Math.abs(end.y - state.startPoint.y),
          style,
        }
        renderAction(ctx, previewAction)
      } else if (tool === 'line' && state.currentPoints.length > 0) {
        const end = state.currentPoints[state.currentPoints.length - 1]
        const previewAction: DrawAction = {
          kind: 'line',
          start: state.startPoint,
          end,
          style,
        }
        renderAction(ctx, previewAction)
      }
    }
  }

  const updateLayerThumbnails = () => {
    for (const layer of state.canvasState.layers) {
      const thumbCanvas = document.querySelector(
        `[p-target="thumb-${layer.id}"]`
      ) as HTMLCanvasElement | null
      if (!thumbCanvas) continue

      const thumbCtx = thumbCanvas.getContext('2d')
      if (!thumbCtx) continue

      thumbCtx.clearRect(0, 0, 36, 36)
      thumbCtx.fillStyle = '#ffffff'
      thumbCtx.fillRect(0, 0, 36, 36)

      // Draw a scaled preview of the layer
      thumbCtx.save()
      thumbCtx.scale(36 / DEFAULT_WIDTH, 36 / DEFAULT_HEIGHT)
      if (layer.visible) {
        for (const action of layer.actions) {
          renderAction(thumbCtx, action)
        }
      }
      thumbCtx.restore()
    }
  }

  const finalizeAction = () => {
    if (!state.startPoint) return

    const style = { color: state.color, width: state.brushSize }
    let action: DrawAction | null = null

    if (state.activeTool === 'pen' || state.activeTool === 'eraser') {
      action = {
        kind: state.activeTool,
        points: [...state.currentPoints],
        style,
      }
    } else if (state.activeTool === 'rectangle' && state.currentPoints.length > 0) {
      const end = state.currentPoints[state.currentPoints.length - 1]
      action = {
        kind: 'rectangle',
        start: state.startPoint,
        end,
        style,
      }
    } else if (state.activeTool === 'circle' && state.currentPoints.length > 0) {
      const end = state.currentPoints[state.currentPoints.length - 1]
      action = {
        kind: 'circle',
        center: state.startPoint,
        radiusX: Math.abs(end.x - state.startPoint.x),
        radiusY: Math.abs(end.y - state.startPoint.y),
        style,
      }
    } else if (state.activeTool === 'line' && state.currentPoints.length > 0) {
      const end = state.currentPoints[state.currentPoints.length - 1]
      action = {
        kind: 'line',
        start: state.startPoint,
        end,
        style,
      }
    }

    if (action) {
      state.canvasState = pushAction(state.canvasState, action)
    }

    state.isDrawing = false
    state.currentPoints = []
    state.startPoint = null
    redraw()
  }

  // --- Pointer handlers ---

  const onPointerDown = (e: PointerEvent) => {
    const point = getCanvasPoint(e)
    state.isDrawing = true
    state.startPoint = point
    state.currentPoints = [point]
    mainCanvas?.setPointerCapture(e.pointerId)
  }

  const onPointerMove = (e: PointerEvent) => {
    if (!state.isDrawing) return
    const point = getCanvasPoint(e)
    state.currentPoints.push(point)
    redrawWithPreview()
  }

  const onPointerUp = (_e: PointerEvent) => {
    if (!state.isDrawing) return
    finalizeAction()
  }

  // --- Event delegation ---

  const handleTrigger = (triggerValue: string) => {
    if (triggerValue.startsWith('tool-select:')) {
      state.activeTool = triggerValue.split(':')[1] as ToolKind
      updateToolbarUI()
    } else if (triggerValue === 'undo') {
      state.canvasState = undo(state.canvasState)
      redraw()
    } else if (triggerValue === 'redo') {
      state.canvasState = redo(state.canvasState)
      redraw()
    } else if (triggerValue === 'clear') {
      state.canvasState = clearActiveLayer(state.canvasState)
      redraw()
    } else if (triggerValue === 'add-layer') {
      state.canvasState = addLayer(state.canvasState)
      rebuildLayersPanel()
      redraw()
    } else if (triggerValue.startsWith('select-layer:')) {
      const id = triggerValue.split(':')[1]
      state.canvasState = selectLayer(state.canvasState, id)
      rebuildLayersPanel()
    } else if (triggerValue.startsWith('toggle-visibility:')) {
      const id = triggerValue.split(':')[1]
      state.canvasState = toggleLayer(state.canvasState, id)
      rebuildLayersPanel()
      redraw()
    } else if (triggerValue.startsWith('delete-layer:')) {
      const id = triggerValue.split(':')[1]
      state.canvasState = removeLayer(state.canvasState, id)
      rebuildLayersPanel()
      redraw()
    } else if (triggerValue === 'save-png') {
      if (mainCanvas) {
        downloadPng(mainCanvas, `drawing-${Date.now()}.png`)
      }
    } else if (triggerValue === 'load-png-click') {
      const fileInput = document.querySelector('[p-target="file-input"]') as HTMLInputElement | null
      fileInput?.click()
    } else if (triggerValue === 'load-png') {
      handleFileLoad()
    }
  }

  const handleFileLoad = () => {
    const fileInput = document.querySelector('[p-target="file-input"]') as HTMLInputElement | null
    if (!fileInput?.files?.[0] || !ctx) return

    const file = fileInput.files[0]
    const reader = new FileReader()
    reader.onload = async (e) => {
      const dataUrl = e.target?.result as string
      if (dataUrl && ctx) {
        await loadImageOntoCanvas(ctx, dataUrl, DEFAULT_WIDTH, DEFAULT_HEIGHT)
      }
    }
    reader.readAsDataURL(file)
  }

  const updateToolbarUI = () => {
    const buttons = document.querySelectorAll('[p-trigger^="tool-select:"]')
    buttons.forEach((btn) => {
      const trigger = btn.getAttribute('p-trigger') ?? ''
      const toolKind = trigger.split(':')[1]
      const isActive = toolKind === state.activeTool
      const el = btn as HTMLElement
      el.style.backgroundColor = isActive ? '#e94560' : '#1a1a2e'
      el.style.borderColor = isActive ? '#e94560' : '#0f3460'
      el.style.color = isActive ? '#ffffff' : '#e0e0e0'
    })
  }

  const rebuildLayersPanel = () => {
    const layersList = document.querySelector('[p-target="layers-list"]')
    if (!layersList) return

    layersList.innerHTML = ''
    for (const layer of state.canvasState.layers) {
      const isActive = layer.id === state.canvasState.activeLayerId
      const item = document.createElement('div')
      item.style.cssText = `display:flex;align-items:center;gap:8px;padding:6px 12px;border-bottom:1px solid #0f3460;cursor:pointer;font-size:12px;${isActive ? 'background-color:#0f3460;' : ''}`
      item.setAttribute('p-trigger', `select-layer:${layer.id}`)

      const thumb = document.createElement('canvas')
      thumb.width = 36
      thumb.height = 36
      thumb.style.cssText = 'width:36px;height:36px;border:1px solid #0f3460;border-radius:3px;background:#fff;flex-shrink:0'
      thumb.setAttribute('p-target', `thumb-${layer.id}`)

      const nameSpan = document.createElement('span')
      nameSpan.style.cssText = 'flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap'
      nameSpan.textContent = layer.name

      const visBtn = document.createElement('button')
      visBtn.style.cssText = `padding:2px 6px;border:none;border-radius:3px;background:transparent;color:${layer.visible ? '#e0e0e0' : '#555'};cursor:pointer;font-size:14px`
      visBtn.setAttribute('p-trigger', `toggle-visibility:${layer.id}`)
      visBtn.title = layer.visible ? 'Hide layer' : 'Show layer'
      visBtn.textContent = layer.visible ? '👁' : '👁‍🗨'

      const delBtn = document.createElement('button')
      delBtn.style.cssText = 'padding:2px 6px;border:none;border-radius:3px;background:transparent;color:#e74c3c;cursor:pointer;font-size:14px'
      delBtn.setAttribute('p-trigger', `delete-layer:${layer.id}`)
      delBtn.title = 'Delete layer'
      delBtn.textContent = '✕'

      item.append(thumb, nameSpan, visBtn, delBtn)
      layersList.appendChild(item)
    }

    updateLayerThumbnails()
  }

  // --- Keyboard shortcuts ---

  const onKeyDown = (e: KeyboardEvent) => {
    const ctrl = e.ctrlKey || e.metaKey
    if (ctrl && e.key === 'z' && !e.shiftKey) {
      e.preventDefault()
      state.canvasState = undo(state.canvasState)
      redraw()
    } else if (ctrl && (e.key === 'y' || (e.key === 'z' && e.shiftKey))) {
      e.preventDefault()
      state.canvasState = redo(state.canvasState)
      redraw()
    } else if (e.key === 'b') {
      state.activeTool = 'pen'
      updateToolbarUI()
    } else if (e.key === 'r') {
      state.activeTool = 'rectangle'
      updateToolbarUI()
    } else if (e.key === 'c' && !ctrl) {
      state.activeTool = 'circle'
      updateToolbarUI()
    } else if (e.key === 'l') {
      state.activeTool = 'line'
      updateToolbarUI()
    } else if (e.key === 'e') {
      state.activeTool = 'eraser'
      updateToolbarUI()
    }
  }

  // --- Init ---

  const init = () => {
    mainCanvas = document.querySelector('[p-target="main-canvas"]') as HTMLCanvasElement | null
    if (!mainCanvas) return

    ctx = mainCanvas.getContext('2d')
    if (!ctx) return

    // White background
    ctx.fillStyle = '#ffffff'
    ctx.fillRect(0, 0, DEFAULT_WIDTH, DEFAULT_HEIGHT)

    // Canvas pointer events
    mainCanvas.addEventListener('pointerdown', onPointerDown)
    mainCanvas.addEventListener('pointermove', onPointerMove)
    mainCanvas.addEventListener('pointerup', onPointerUp)
    mainCanvas.addEventListener('pointerleave', onPointerUp)

    // Global event delegation for p-trigger elements
    document.addEventListener('click', (e) => {
      const target = (e.target as HTMLElement).closest('[p-trigger]')
      if (!target) return
      const trigger = target.getAttribute('p-trigger')
      if (trigger) handleTrigger(trigger)
    })

    // Color picker
    document.addEventListener('input', (e) => {
      const target = e.target as HTMLInputElement
      const trigger = target.getAttribute('p-trigger')
      if (trigger === 'color-change') {
        state.color = target.value
      } else if (trigger === 'size-change') {
        state.brushSize = Number(target.value)
        const display = document.querySelector('[p-target="size-display"]')
        if (display) display.textContent = `${state.brushSize}px`
      } else if (trigger === 'load-png') {
        handleFileLoad()
      }
    })

    // Keyboard shortcuts
    document.addEventListener('keydown', onKeyDown)

    // Initial thumbnail render
    updateLayerThumbnails()
  }

  return { init }
}

// Auto-init when DOM is ready
if (typeof document !== 'undefined') {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => createApp().init())
  } else {
    createApp().init()
  }
}

