import { createSSR } from 'plaited'
import { renderApp } from './renderer'
import { DEFAULT_WIDTH, DEFAULT_HEIGHT } from './canvas'
import { listDrawings, saveDrawing, loadDrawing, deleteDrawing } from './storage'
import type { ToolKind } from './types'

const defaultTool: ToolKind = 'pen'
const defaultColor = '#000000'
const defaultBrushSize = 4

const defaultLayers = [
  { id: 'layer-default-1', name: 'Background', visible: true },
]

export const renderPage = (): string => {
  const ssr = createSSR()
  const appHtml = ssr(
    renderApp(
      defaultTool,
      defaultColor,
      defaultBrushSize,
      DEFAULT_WIDTH,
      DEFAULT_HEIGHT,
      defaultLayers,
      defaultLayers[0].id
    )
  )

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Drawing Canvas</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { overflow: hidden; }
    button:hover { opacity: 0.85; }
    input[type="range"] { height: 4px; }
  </style>
</head>
<body>
  ${appHtml}
  <script type="module" src="./client.ts"></script>
</body>
</html>`
}

// HTTP server for serving the drawing canvas
export const serve = () => {
  return Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' || url.pathname === '/index.html') {
        return new Response(renderPage(), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      // API routes for saved drawings
      if (url.pathname === '/api/drawings' && req.method === 'GET') {
        const drawings = await listDrawings()
        return Response.json(drawings)
      }

      if (url.pathname === '/api/drawings' && req.method === 'POST') {
        const body = await req.json()
        await saveDrawing(body)
        return Response.json({ ok: true })
      }

      if (url.pathname.startsWith('/api/drawings/') && req.method === 'GET') {
        const id = url.pathname.split('/').pop() ?? ''
        const drawing = await loadDrawing(id)
        if (!drawing) return new Response('Not found', { status: 404 })
        return Response.json(drawing)
      }

      if (url.pathname.startsWith('/api/drawings/') && req.method === 'DELETE') {
        const id = url.pathname.split('/').pop() ?? ''
        await deleteDrawing(id)
        return Response.json({ ok: true })
      }

      // Serve TypeScript files for Bun's bundler
      if (url.pathname.endsWith('.ts')) {
        const filePath = new URL(`.${url.pathname}`, import.meta.url).pathname
        const file = Bun.file(filePath)
        if (await file.exists()) {
          const built = await Bun.build({
            entrypoints: [filePath],
            target: 'browser',
            format: 'esm',
          })
          if (built.success && built.outputs.length > 0) {
            const text = await built.outputs[0].text()
            return new Response(text, {
              headers: { 'Content-Type': 'application/javascript' },
            })
          }
        }
      }

      return new Response('Not found', { status: 404 })
    },
  })
}

// Start when run directly
if (import.meta.main) {
  const server = serve()
  console.log(`Drawing Canvas running at http://localhost:${server.port}`)
}

{
  "name": "@node/playlist-manager",
  "version": "1.0.0",
  "description": "Music playlist manager with playback controls, drag-to-reorder, shuffle, and repeat modes",
  "main": "index.ts",
  "modnet": {
    "contentType": "entertainment",
    "structure": "list",
    "mechanics": ["sort", "track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

import type { Playlist, Song, AppState, PlaybackState, RepeatMode } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const defaultPlayback: PlaybackState = {
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  progressSeconds: 0,
  shuffle: false,
  repeat: 'off',
  shuffleQueue: [],
}

let state: AppState = {
  playlists: [],
  activePlaylistId: null,
  playback: { ...defaultPlayback },
}

const generateId = (): string => crypto.randomUUID()

const persist = async (): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(state.playlists, null, 2))
}

const load = async (): Promise<void> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    const text = await file.text()
    state.playlists = JSON.parse(text)
  }
}

const getState = (): AppState => state

const getActivePlaylist = (): Playlist | undefined =>
  state.playlists.find((p) => p.id === state.activePlaylistId)

const getPlaybackPlaylist = (): Playlist | undefined =>
  state.playlists.find((p) => p.id === state.playback.currentPlaylistId)

const createPlaylist = async (name: string): Promise<Playlist> => {
  const playlist: Playlist = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
    songs: [],
  }
  state.playlists.push(playlist)
  state.activePlaylistId = playlist.id
  await persist()
  return playlist
}

const deletePlaylist = async (id: string): Promise<void> => {
  state.playlists = state.playlists.filter((p) => p.id !== id)
  if (state.activePlaylistId === id) {
    state.activePlaylistId = state.playlists[0]?.id ?? null
  }
  if (state.playback.currentPlaylistId === id) {
    state.playback = { ...defaultPlayback }
  }
  await persist()
}

const renamePlaylist = async (id: string, name: string): Promise<void> => {
  const playlist = state.playlists.find((p) => p.id === id)
  if (playlist) {
    playlist.name = name
    await persist()
  }
}

const setActivePlaylist = (id: string): void => {
  state.activePlaylistId = id
}

const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>
): Promise<Song> => {
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) throw new Error(`Playlist ${playlistId} not found`)
  const newSong: Song = { id: generateId(), ...song }
  playlist.songs.push(newSong)
  await persist()
  return newSong
}

const removeSong = async (
  playlistId: string,
  songId: string
): Promise<void> => {
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) return
  const songIndex = playlist.songs.findIndex((s) => s.id === songId)
  if (songIndex === -1) return
  playlist.songs.splice(songIndex, 1)
  if (
    state.playback.currentPlaylistId === playlistId &&
    state.playback.currentSongIndex >= playlist.songs.length
  ) {
    state.playback.currentSongIndex = Math.max(0, playlist.songs.length - 1)
  }
  await persist()
}

const reorderSong = async (
  playlistId: string,
  fromIndex: number,
  toIndex: number
): Promise<void> => {
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) return
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) return
  if (toIndex < 0 || toIndex >= playlist.songs.length) return
  const [song] = playlist.songs.splice(fromIndex, 1)
  playlist.songs.splice(toIndex, 0, song)
  if (state.playback.currentPlaylistId === playlistId) {
    const ci = state.playback.currentSongIndex
    if (ci === fromIndex) {
      state.playback.currentSongIndex = toIndex
    } else if (fromIndex < ci && toIndex >= ci) {
      state.playback.currentSongIndex = ci - 1
    } else if (fromIndex > ci && toIndex <= ci) {
      state.playback.currentSongIndex = ci + 1
    }
  }
  await persist()
}

const buildShuffleQueue = (length: number, currentIndex: number): number[] => {
  const indices = Array.from({ length }, (_, i) => i).filter(
    (i) => i !== currentIndex
  )
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return [currentIndex, ...indices]
}

const playSong = (playlistId: string, songIndex: number): void => {
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist || songIndex < 0 || songIndex >= playlist.songs.length) return
  state.playback.currentPlaylistId = playlistId
  state.playback.currentSongIndex = songIndex
  state.playback.isPlaying = true
  state.playback.progressSeconds = 0
  if (state.playback.shuffle) {
    state.playback.shuffleQueue = buildShuffleQueue(
      playlist.songs.length,
      songIndex
    )
  }
}

const togglePlay = (): void => {
  if (state.playback.currentPlaylistId === null) return
  state.playback.isPlaying = !state.playback.isPlaying
}

const skipNext = (): void => {
  const playlist = getPlaybackPlaylist()
  if (!playlist || playlist.songs.length === 0) return

  if (state.playback.repeat === 'one') {
    state.playback.progressSeconds = 0
    return
  }

  if (state.playback.shuffle) {
    const queue = state.playback.shuffleQueue
    const queueIndex = queue.indexOf(state.playback.currentSongIndex)
    if (queueIndex < queue.length - 1) {
      state.playback.currentSongIndex = queue[queueIndex + 1]
    } else if (state.playback.repeat === 'all') {
      state.playback.shuffleQueue = buildShuffleQueue(playlist.songs.length, 0)
      state.playback.currentSongIndex = state.playback.shuffleQueue[0]
    } else {
      state.playback.isPlaying = false
      return
    }
  } else {
    const next = state.playback.currentSongIndex + 1
    if (next < playlist.songs.length) {
      state.playback.currentSongIndex = next
    } else if (state.playback.repeat === 'all') {
      state.playback.currentSongIndex = 0
    } else {
      state.playback.isPlaying = false
      return
    }
  }
  state.playback.progressSeconds = 0
}

const skipPrevious = (): void => {
  const playlist = getPlaybackPlaylist()
  if (!playlist || playlist.songs.length === 0) return

  if (state.playback.progressSeconds > 3) {
    state.playback.progressSeconds = 0
    return
  }

  if (state.playback.shuffle) {
    const queue = state.playback.shuffleQueue
    const queueIndex = queue.indexOf(state.playback.currentSongIndex)
    if (queueIndex > 0) {
      state.playback.currentSongIndex = queue[queueIndex - 1]
    }
  } else {
    const prev = state.playback.currentSongIndex - 1
    if (prev >= 0) {
      state.playback.currentSongIndex = prev
    } else if (state.playback.repeat === 'all') {
      state.playback.currentSongIndex = playlist.songs.length - 1
    }
  }
  state.playback.progressSeconds = 0
}

const toggleShuffle = (): void => {
  state.playback.shuffle = !state.playback.shuffle
  if (state.playback.shuffle) {
    const playlist = getPlaybackPlaylist()
    if (playlist) {
      state.playback.shuffleQueue = buildShuffleQueue(
        playlist.songs.length,
        state.playback.currentSongIndex
      )
    }
  } else {
    state.playback.shuffleQueue = []
  }
}

const cycleRepeat = (): void => {
  const modes: RepeatMode[] = ['off', 'all', 'one']
  const current = modes.indexOf(state.playback.repeat)
  state.playback.repeat = modes[(current + 1) % modes.length]
}

const seekTo = (seconds: number): void => {
  state.playback.progressSeconds = Math.max(0, seconds)
}

const tickProgress = (deltaSeconds: number): void => {
  if (!state.playback.isPlaying) return
  const playlist = getPlaybackPlaylist()
  if (!playlist) return
  const song = playlist.songs[state.playback.currentSongIndex]
  if (!song) return
  state.playback.progressSeconds += deltaSeconds
  if (state.playback.progressSeconds >= song.durationSeconds) {
    skipNext()
  }
}

export const store = {
  load,
  getState,
  getActivePlaylist,
  getPlaybackPlaylist,
  createPlaylist,
  deletePlaylist,
  renamePlaylist,
  setActivePlaylist,
  addSong,
  removeSong,
  reorderSong,
  playSong,
  togglePlay,
  skipNext,
  skipPrevious,
  toggleShuffle,
  cycleRepeat,
  seekTo,
  tickProgress,
}

