export const renderPlaylistContent = (
  playlist: Playlist | undefined,
  playback: PlaybackState
): string => {
  if (!playlist) {
    return h('div', { style: styles.content },
      h('div', { style: styles.emptyState },
        h('p', {}, 'Select a playlist or create a new one to get started.'),
      ),
    )
  }

  const totalDuration = playlist.songs.reduce((t, s) => t + s.durationSeconds, 0)
  const coverArt = playlist.songs[0]?.albumArtUrl

  return h('div', { style: styles.content },
    h('div', { style: styles.playlistHeader },
      coverArt
        ? h('img', { src: coverArt, style: { ...styles.playlistArt, objectFit: 'cover' }, alt: '' })
        : h('div', { style: styles.playlistArt }, '\u266B'),
      h('div', { style: styles.playlistMeta },
        h('span', { style: styles.playlistLabel }, 'Playlist'),
        h('h1', { style: styles.playlistName }, playlist.name),
        h('span', { style: styles.playlistStats },
          `${playlist.songs.length} song${playlist.songs.length !== 1 ? 's' : ''} \u2022 ${formatTime(totalDuration)}`,
        ),
        h('button', {
          style: styles.deleteBtn,
          'p-trigger': 'click:deletePlaylist',
          'data-playlist-id': playlist.id,
        }, 'Delete Playlist'),
      ),
    ),
    renderAddSongForm(playlist.id),
    playlist.songs.length > 0
      ? renderSongList(playlist, playback)
      : h('div', { style: styles.emptyState },
          h('p', {}, 'No songs yet. Add one above!'),
        ),
  )
}

export const renderNowPlayingBar = (
  playback: PlaybackState,
  currentSong: Song | null
): string => {
  const progress = currentSong
    ? (playback.progressSeconds / currentSong.durationSeconds) * 100
    : 0

  return h('div', { style: styles.nowPlayingBar },
    h('div', { style: styles.nowPlayingInfo },
      currentSong
        ? h(Fragment, {},
            currentSong.albumArtUrl
              ? h('img', { src: currentSong.albumArtUrl, style: styles.nowPlayingArt, alt: '' })
              : h('div', { style: styles.nowPlayingArtPlaceholder }, '\u266B'),
            h('div', { style: styles.nowPlayingText },
              h('span', { style: styles.nowPlayingTitle }, currentSong.title),
              h('span', { style: styles.nowPlayingArtist }, currentSong.artist),
            ),
          )
        : h('div', { style: styles.nowPlayingText },
            h('span', { style: { ...styles.nowPlayingTitle, color: '#b3b3b3' } }, 'Nothing playing'),
          ),
    ),
    h('div', { style: styles.controls },
      h('div', { style: styles.controlButtons },
        h('button', {
          style: playback.shuffle ? styles.controlBtnActive : styles.controlBtn,
          'p-trigger': 'click:toggleShuffle',
          title: 'Shuffle',
        }, '\u{1F500}'),
        h('button', {
          style: styles.controlBtn,
          'p-trigger': 'click:skipPrevious',
          title: 'Previous',
        }, '\u23EE'),
        h('button', {
          style: styles.playBtn,
          'p-trigger': 'click:togglePlay',
          title: playback.isPlaying ? 'Pause' : 'Play',
        }, playback.isPlaying ? '\u23F8' : '\u25B6'),
        h('button', {
          style: styles.controlBtn,
          'p-trigger': 'click:skipNext',
          title: 'Next',
        }, '\u23ED'),
        h('button', {
          style: playback.repeat !== 'off' ? styles.controlBtnActive : styles.controlBtn,
          'p-trigger': 'click:cycleRepeat',
          title: `Repeat: ${playback.repeat}`,
        }, repeatLabel(playback.repeat)),
      ),
      h('div', { style: styles.progressContainer },
        h('span', { style: styles.progressTime },
          currentSong ? formatTime(playback.progressSeconds) : '-:--',
        ),
        h('div', {
          style: styles.progressBarOuter,
          'p-trigger': 'click:seek',
          'p-target': 'progressBar',
        },
          h('div', { style: styles.progressBarInner(progress) }),
