  )
}

export const renderApp = (state: AppState): string => {
  const activePlaylist = state.playlists.find((p) => p.id === state.activePlaylistId)
  const playbackPlaylist = state.playlists.find(
    (p) => p.id === state.playback.currentPlaylistId
  )
  const currentSong = playbackPlaylist
    ? playbackPlaylist.songs[state.playback.currentSongIndex] ?? null
    : null

  return h('div', { style: styles.container, 'p-target': 'app' },
    h('div', { style: styles.mainLayout },
      renderSidebar(state.playlists, state.activePlaylistId),
      renderPlaylistContent(activePlaylist, state.playback),
    ),
    renderNowPlayingBar(state.playback, currentSong),
  )
}

import { store } from './store'

export type HandlerContext = {
  rerender: () => void
}

let dragFromIndex: number | null = null
let tickInterval: ReturnType<typeof setInterval> | null = null

const startTick = (ctx: HandlerContext): void => {
  if (tickInterval) return
  tickInterval = setInterval(() => {
    const state = store.getState()
    if (state.playback.isPlaying) {
      store.tickProgress(1)
      ctx.rerender()
    }
  }, 1000)
}

const stopTick = (): void => {
  if (tickInterval) {
    clearInterval(tickInterval)
    tickInterval = null
  }
}

export const createPlaylist = async (ctx: HandlerContext): Promise<void> => {
  const name = `New Playlist ${store.getState().playlists.length + 1}`
  await store.createPlaylist(name)
  ctx.rerender()
}

export const selectPlaylist = (
  ctx: HandlerContext,
  playlistId: string
): void => {
  store.setActivePlaylist(playlistId)
  ctx.rerender()
}

export const deletePlaylist = async (
  ctx: HandlerContext,
  playlistId: string
): Promise<void> => {
  await store.deletePlaylist(playlistId)
  ctx.rerender()
}

export const addSong = async (
  ctx: HandlerContext,
  playlistId: string,
  data: {
    title: string
    artist: string
    album: string
    durationSeconds: number
    albumArtUrl: string
  }
): Promise<void> => {
  await store.addSong(playlistId, data)
  ctx.rerender()
}

export const removeSong = async (
  ctx: HandlerContext,
  playlistId: string,
  songId: string
): Promise<void> => {
  await store.removeSong(playlistId, songId)
  ctx.rerender()
}

export const dragStart = (songIndex: number): void => {
  dragFromIndex = songIndex
}

export const dragOver = (e: { preventDefault: () => void }): void => {
  e.preventDefault()
}

export const drop = async (
  ctx: HandlerContext,
  playlistId: string,
  toIndex: number
): Promise<void> => {
  if (dragFromIndex === null || dragFromIndex === toIndex) return
  await store.reorderSong(playlistId, dragFromIndex, toIndex)
  dragFromIndex = null
  ctx.rerender()
}

export const dragEnd = (): void => {
  dragFromIndex = null
}

export const playSong = (
  ctx: HandlerContext,
  playlistId: string,
  songIndex: number
): void => {
  store.playSong(playlistId, songIndex)
  startTick(ctx)
  ctx.rerender()
}

export const togglePlay = (ctx: HandlerContext): void => {
  store.togglePlay()
  const state = store.getState()
  if (state.playback.isPlaying) {
    startTick(ctx)
  } else {
    stopTick()
  }
  ctx.rerender()
}

export const skipNext = (ctx: HandlerContext): void => {
  store.skipNext()
  const state = store.getState()
  if (!state.playback.isPlaying) {
    stopTick()
  }
  ctx.rerender()
}

export const skipPrevious = (ctx: HandlerContext): void => {
  store.skipPrevious()
  ctx.rerender()
}

export const toggleShuffle = (ctx: HandlerContext): void => {
  store.toggleShuffle()
  ctx.rerender()
}

export const cycleRepeat = (ctx: HandlerContext): void => {
  store.cycleRepeat()
  ctx.rerender()
}

export const seek = (
  ctx: HandlerContext,
  clickX: number,
  barWidth: number
): void => {
  const playlist = store.getPlaybackPlaylist()
  if (!playlist) return
  const song = playlist.songs[store.getState().playback.currentSongIndex]
  if (!song) return
  const pct = Math.max(0, Math.min(1, clickX / barWidth))
  store.seekTo(pct * song.durationSeconds)
  ctx.rerender()
}

export const handlers = {
  createPlaylist,
  selectPlaylist,
  deletePlaylist,
  addSong,
  removeSong,
  dragStart,
  dragOver,
  drop,
  dragEnd,
  playSong,
  togglePlay,
  skipNext,
  skipPrevious,
  toggleShuffle,
  cycleRepeat,
  seek,
}

import { createSSR } from 'plaited'
import { store } from './store'
import { renderApp } from './components'
import { handlers, type HandlerContext } from './handlers'

const PORT = 3000

const renderPage = (): string => {
  const ssr = createSSR()
  const state = store.getState()
  const appHtml = renderApp(state)

  return ssr(
    `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Playlist Manager</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { overflow: hidden; }
    button:hover { opacity: 0.85; }
    [draggable="true"]:hover { background-color: rgba(255,255,255,0.05); }
    input:focus { border-color: #1db954 !important; }
    ::-webkit-scrollbar { width: 8px; }
    ::-webkit-scrollbar-track { background: transparent; }
    ::-webkit-scrollbar-thumb { background: #535353; border-radius: 4px; }
    ::-webkit-scrollbar-thumb:hover { background: #b3b3b3; }
  </style>
</head>
<body>${appHtml}</body>
<script>
  // Client-side drag-and-drop and event handling
  let dragFromIndex = null;

  document.addEventListener('dragstart', (e) => {
    const row = e.target.closest('[data-song-index]');
    if (row) {
      dragFromIndex = parseInt(row.dataset.songIndex, 10);
      e.dataTransfer.effectAllowed = 'move';
      row.style.opacity = '0.5';
    }
  });

  document.addEventListener('dragover', (e) => {
    const row = e.target.closest('[data-song-index]');
    if (row) {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      row.style.borderTop = '2px solid #1db954';
    }
  });

  document.addEventListener('dragleave', (e) => {
    const row = e.target.closest('[data-song-index]');
    if (row) {
      row.style.borderTop = '';
    }
  });

  document.addEventListener('drop', async (e) => {
    e.preventDefault();
    const row = e.target.closest('[data-song-index]');
    if (row && dragFromIndex !== null) {
      const toIndex = parseInt(row.dataset.songIndex, 10);
      const playlistId = row.dataset.playlistId;
      row.style.borderTop = '';
      if (dragFromIndex !== toIndex) {
        await fetch('/api/reorder', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ playlistId, fromIndex: dragFromIndex, toIndex }),
        });
        location.reload();
      }
      dragFromIndex = null;
    }
  });

  document.addEventListener('dragend', (e) => {
    const row = e.target.closest('[data-song-index]');
    if (row) row.style.opacity = '';
    dragFromIndex = null;
  });

  // Double-click to play song
  document.addEventListener('dblclick', async (e) => {
    const row = e.target.closest('[data-song-index]');
    if (row) {
      const index = parseInt(row.dataset.songIndex, 10);
      const playlistId = row.dataset.playlistId;
      await fetch('/api/play', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ playlistId, songIndex: index }),
      });
      location.reload();
    }
  });

  // Delegate click events
  document.addEventListener('click', async (e) => {
    const btn = e.target.closest('[p-trigger]');
    if (!btn) return;
    const triggers = btn.getAttribute('p-trigger');
    if (!triggers) return;

    for (const part of triggers.split('|')) {
      const [eventType, action] = part.split(':');
      if (eventType !== 'click') continue;

      switch (action) {
        case 'createPlaylist':
          await fetch('/api/playlist', { method: 'POST' });
          location.reload();
          break;
        case 'selectPlaylist':
          await fetch('/api/select', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ playlistId: btn.dataset.playlistId }),
          });
          location.reload();
          break;
        case 'deletePlaylist':
          if (confirm('Delete this playlist?')) {
            await fetch('/api/playlist/' + btn.dataset.playlistId, { method: 'DELETE' });
            location.reload();
          }
          break;
        case 'removeSong':
          await fetch('/api/song/' + btn.dataset.playlistId + '/' + btn.dataset.songId, { method: 'DELETE' });
          location.reload();
          break;
        case 'togglePlay':
          await fetch('/api/toggle-play', { method: 'POST' });
          location.reload();
          break;
        case 'skipNext':
          await fetch('/api/skip-next', { method: 'POST' });
          location.reload();
          break;
        case 'skipPrevious':
          await fetch('/api/skip-previous', { method: 'POST' });
          location.reload();
          break;
        case 'toggleShuffle':
          await fetch('/api/toggle-shuffle', { method: 'POST' });
          location.reload();
          break;
        case 'cycleRepeat':
          await fetch('/api/cycle-repeat', { method: 'POST' });
          location.reload();
          break;
        case 'seek': {
          const bar = btn;
          const rect = bar.getBoundingClientRect();
          const x = e.clientX - rect.left;
          await fetch('/api/seek', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ clickX: x, barWidth: rect.width }),
          });
          location.reload();
          break;
        }
      }
    }
  });

  // Form submission
  document.addEventListener('submit', async (e) => {
    const form = e.target.closest('[p-trigger*="addSong"]');
    if (!form) return;
    e.preventDefault();
    const fd = new FormData(form);
    const playlistId = form.dataset.playlistId;
    await fetch('/api/song', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        playlistId,
        title: fd.get('title'),
        artist: fd.get('artist'),
        album: fd.get('album') || 'Unknown Album',
        durationSeconds: parseInt(fd.get('durationSeconds'), 10) || 180,
        albumArtUrl: fd.get('albumArtUrl') || '',
      }),
    });
    location.reload();
  });

  // Progress ticker — polls for progress update every second if playing
  let tickTimer = null;
  const startTick = () => {
    if (tickTimer) return;
    tickTimer = setInterval(async () => {
      await fetch('/api/tick', { method: 'POST' });
      // Soft-reload only the now-playing bar
      const res = await fetch('/');
      const html = await res.text();
      const parser = new DOMParser();
      const doc = parser.parseFromString(html, 'text/html');
      const newBar = doc.querySelector('[style*="grid-template-columns: 1fr 2fr 1fr"]');
      const oldBar = document.querySelector('[style*="grid-template-columns: 1fr 2fr 1fr"]');
      if (newBar && oldBar) oldBar.replaceWith(newBar);
    }, 1000);
  };
  const stopTick = () => {
    if (tickTimer) { clearInterval(tickTimer); tickTimer = null; }
  };

  // Start tick if currently playing
  const checkPlaying = async () => {
    const res = await fetch('/api/state');
    const state = await res.json();
    if (state.playback.isPlaying) startTick();
    else stopTick();
  };
  checkPlaying();
</script>
</html>`
  )
}

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  const rerender = (): void => {}

  const ctx: HandlerContext = { rerender }

  // API routes
  if (path === '/api/state' && method === 'GET') {
    return Response.json(store.getState())
  }

  if (path === '/api/playlist' && method === 'POST') {
    await handlers.createPlaylist(ctx)
    return Response.json({ ok: true })
  }

  if (path.startsWith('/api/playlist/') && method === 'DELETE') {
    const playlistId = path.split('/')[3]
    await handlers.deletePlaylist(ctx, playlistId)
    return Response.json({ ok: true })
  }

  if (path === '/api/select' && method === 'POST') {
    const body = await req.json() as { playlistId: string }
    handlers.selectPlaylist(ctx, body.playlistId)
    return Response.json({ ok: true })
  }

  if (path === '/api/song' && method === 'POST') {
    const body = await req.json() as {
      playlistId: string
      title: string
      artist: string
      album: string
      durationSeconds: number
      albumArtUrl: string
    }
    await handlers.addSong(ctx, body.playlistId, {
      title: body.title,
      artist: body.artist,
      album: body.album,
      durationSeconds: body.durationSeconds,
      albumArtUrl: body.albumArtUrl,
    })
    return Response.json({ ok: true })
  }

  if (path.startsWith('/api/song/') && method === 'DELETE') {
    const parts = path.split('/')
    const playlistId = parts[3]
    const songId = parts[4]
    await handlers.removeSong(ctx, playlistId, songId)
    return Response.json({ ok: true })
  }

  if (path === '/api/reorder' && method === 'POST') {
    const body = await req.json() as {
      playlistId: string
      fromIndex: number
      toIndex: number
    }
    await handlers.drop(ctx, body.playlistId, body.toIndex)
    // Need to set dragFromIndex manually for the handler
    const playlist = store.getState().playlists.find((p) => p.id === body.playlistId)
    if (playlist) {
      await store.reorderSong(body.playlistId, body.fromIndex, body.toIndex)
    }
    return Response.json({ ok: true })
  }

  if (path === '/api/play' && method === 'POST') {
    const body = await req.json() as { playlistId: string; songIndex: number }
    handlers.playSong(ctx, body.playlistId, body.songIndex)
    return Response.json({ ok: true })
  }

  if (path === '/api/toggle-play' && method === 'POST') {
    handlers.togglePlay(ctx)
    return Response.json({ ok: true })
  }

  if (path === '/api/skip-next' && method === 'POST') {
    handlers.skipNext(ctx)
    return Response.json({ ok: true })
  }

  if (path === '/api/skip-previous' && method === 'POST') {
    handlers.skipPrevious(ctx)
    return Response.json({ ok: true })
  }

  if (path === '/api/toggle-shuffle' && method === 'POST') {
    handlers.toggleShuffle(ctx)
    return Response.json({ ok: true })
  }

  if (path === '/api/cycle-repeat' && method === 'POST') {
    handlers.cycleRepeat(ctx)
    return Response.json({ ok: true })
  }

  if (path === '/api/seek' && method === 'POST') {
    const body = await req.json() as { clickX: number; barWidth: number }
    handlers.seek(ctx, body.clickX, body.barWidth)
    return Response.json({ ok: true })
  }

  if (path === '/api/tick' && method === 'POST') {
    store.tickProgress(1)
    return Response.json({ ok: true })
  }

  // Default: serve the app
  return new Response(renderPage(), {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const start = async (): Promise<void> => {
  await store.load()
  Bun.serve({
    port: PORT,
    fetch: handleRequest,
  })
  console.log(`Playlist Manager running at http://localhost:${PORT}`)
}

start()

