import type { Playlist, PlaylistStore, Song } from "./types";

const DATA_PATH = `${import.meta.dir}/data/playlists.json`;

const generateId = (): string => crypto.randomUUID();

const readStore = async (): Promise<PlaylistStore> => {
  const file = Bun.file(DATA_PATH);
  if (await file.exists()) {
    return file.json();
  }
  return { playlists: [] };
};

const writeStore = async (store: PlaylistStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2));
};

export const getPlaylists = async (): Promise<Playlist[]> => {
  const store = await readStore();
  return store.playlists;
};

export const getPlaylist = async (id: string): Promise<Playlist | undefined> => {
  const store = await readStore();
  return store.playlists.find((p) => p.id === id);
};

export const createPlaylist = async (name: string, description = ""): Promise<Playlist> => {
  const store = await readStore();
  const now = new Date().toISOString();
  const playlist: Playlist = {
    id: generateId(),
    name,
    description,
    songs: [],
    createdAt: now,
    updatedAt: now,
  };
  store.playlists.push(playlist);
  await writeStore(store);
  return playlist;
};

export const deletePlaylist = async (id: string): Promise<boolean> => {
  const store = await readStore();
  const idx = store.playlists.findIndex((p) => p.id === id);
  if (idx === -1) return false;
  store.playlists.splice(idx, 1);
  await writeStore(store);
  return true;
};

export const addSong = async (
  playlistId: string,
  song: Omit<Song, "id">
): Promise<Song | null> => {
  const store = await readStore();
  const playlist = store.playlists.find((p) => p.id === playlistId);
  if (!playlist) return null;
  const newSong: Song = { id: generateId(), ...song };
  playlist.songs.push(newSong);
  playlist.updatedAt = new Date().toISOString();
  await writeStore(store);
  return newSong;
};

export const removeSong = async (playlistId: string, songId: string): Promise<boolean> => {
  const store = await readStore();
  const playlist = store.playlists.find((p) => p.id === playlistId);
  if (!playlist) return false;
  const idx = playlist.songs.findIndex((s) => s.id === songId);
  if (idx === -1) return false;
  playlist.songs.splice(idx, 1);
  playlist.updatedAt = new Date().toISOString();
  await writeStore(store);
  return true;
};

export const reorderSong = async (
  playlistId: string,
  fromIndex: number,
  toIndex: number
): Promise<boolean> => {
  const store = await readStore();
  const playlist = store.playlists.find((p) => p.id === playlistId);
  if (!playlist) return false;
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) return false;
  if (toIndex < 0 || toIndex >= playlist.songs.length) return false;
  const [song] = playlist.songs.splice(fromIndex, 1);
  playlist.songs.splice(toIndex, 0, song);
  playlist.updatedAt = new Date().toISOString();
  await writeStore(store);
  return true;
};

import type { PlayerState, RepeatMode, Song } from "./types";
import { getPlaylist } from "./store";

const state: PlayerState = {
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  shuffle: false,
  repeat: "off",
  progress: 0,
  shuffleOrder: [],
};

const generateShuffleOrder = (length: number, currentIndex: number): number[] => {
  const indices = Array.from({ length }, (_, i) => i).filter((i) => i !== currentIndex);
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [indices[i], indices[j]] = [indices[j], indices[i]];
  }
  return [currentIndex, ...indices];
};

export const getPlayerState = (): PlayerState => ({ ...state });

export const getCurrentSong = async (): Promise<Song | null> => {
  if (!state.currentPlaylistId) return null;
  const playlist = await getPlaylist(state.currentPlaylistId);
  if (!playlist || playlist.songs.length === 0) return null;
  const effectiveIndex = state.shuffle
    ? state.shuffleOrder[state.currentSongIndex] ?? 0
    : state.currentSongIndex;
  return playlist.songs[effectiveIndex] ?? null;
};

export const play = async (playlistId: string, songIndex?: number): Promise<Song | null> => {
  const playlist = await getPlaylist(playlistId);
  if (!playlist || playlist.songs.length === 0) return null;

  const isNewPlaylist = state.currentPlaylistId !== playlistId;
  state.currentPlaylistId = playlistId;

  if (songIndex !== undefined) {
    state.currentSongIndex = Math.max(0, Math.min(songIndex, playlist.songs.length - 1));
  } else if (isNewPlaylist) {
    state.currentSongIndex = 0;
  }

  if (isNewPlaylist || state.shuffleOrder.length !== playlist.songs.length) {
    state.shuffleOrder = generateShuffleOrder(playlist.songs.length, state.currentSongIndex);
  }

  state.isPlaying = true;
  state.progress = songIndex !== undefined ? 0 : state.progress;
  return getCurrentSong();
};

export const pause = (): PlayerState => {
  state.isPlaying = false;
  return { ...state };
};

export const resume = (): PlayerState => {
  if (state.currentPlaylistId) {
    state.isPlaying = true;
  }
  return { ...state };
};

export const skip = async (): Promise<Song | null> => {
  if (!state.currentPlaylistId) return null;
  const playlist = await getPlaylist(state.currentPlaylistId);
  if (!playlist || playlist.songs.length === 0) return null;

  if (state.repeat === "one") {
    state.progress = 0;
    return getCurrentSong();
  }

  const nextIndex = state.currentSongIndex + 1;
  if (nextIndex >= playlist.songs.length) {
    if (state.repeat === "all") {
      state.currentSongIndex = 0;
      if (state.shuffle) {
        state.shuffleOrder = generateShuffleOrder(playlist.songs.length, 0);
      }
    } else {
      state.isPlaying = false;
      return getCurrentSong();
    }
  } else {
    state.currentSongIndex = nextIndex;
  }

  state.progress = 0;
  return getCurrentSong();
};

export const previous = async (): Promise<Song | null> => {
  if (!state.currentPlaylistId) return null;
  const playlist = await getPlaylist(state.currentPlaylistId);
  if (!playlist || playlist.songs.length === 0) return null;

  // If more than 3 seconds in, restart current song
  const currentSong = await getCurrentSong();
  if (currentSong && state.progress * currentSong.duration > 3) {
    state.progress = 0;
    return currentSong;
  }

  if (state.currentSongIndex > 0) {
    state.currentSongIndex--;
  } else if (state.repeat === "all") {
    state.currentSongIndex = playlist.songs.length - 1;
  }

  state.progress = 0;
  return getCurrentSong();
};

export const toggleShuffle = async (): Promise<PlayerState> => {
  state.shuffle = !state.shuffle;
  if (state.shuffle && state.currentPlaylistId) {
    const playlist = await getPlaylist(state.currentPlaylistId);
    if (playlist) {
      state.shuffleOrder = generateShuffleOrder(playlist.songs.length, state.currentSongIndex);
    }
  }
  return { ...state };
};

export const cycleRepeat = (): PlayerState => {
  const modes: RepeatMode[] = ["off", "all", "one"];
  const currentIdx = modes.indexOf(state.repeat);
  state.repeat = modes[(currentIdx + 1) % modes.length];
  return { ...state };
};

export const seek = (position: number): PlayerState => {
  state.progress = Math.max(0, Math.min(1, position));
  return { ...state };
};

