const clientScript = (): string => `
(function() {
  let dragSrcIndex = null;

  const api = async (method, path, body) => {
    const opts = { method, headers: { 'Content-Type': 'application/json' } };
    if (body) opts.body = JSON.stringify(body);
    const res = await fetch('/api' + path);
    // Using GET-based API for simplicity in fetch
    return res;
  };

  const post = async (path, body = {}) => {
    const res = await fetch('/api' + path, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    return res.json();
  };

  const patch = async (path, body = {}) => {
    const res = await fetch('/api' + path, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    return res.json();
  };

  const del = async (path) => {
    const res = await fetch('/api' + path, { method: 'DELETE' });
    return res.json();
  };

  const reload = () => window.location.reload();

  const getFormValues = (container) => {
    const inputs = container.querySelectorAll('input');
    const vals = {};
    inputs.forEach(i => vals[i.name] = i.value);
    return vals;
  };

  const parseDuration = (str) => {
    if (!str) return 180;
    const parts = str.split(':');
    if (parts.length === 2) return parseInt(parts[0]) * 60 + parseInt(parts[1]);
    return parseInt(str) || 180;
  };

  // Event delegation
  document.addEventListener('click', async (e) => {
    const target = e.target.closest('[p-trigger]');
    if (!target) return;
    const triggers = target.getAttribute('p-trigger').split(' ');
    const clickTrigger = triggers.find(t => t.startsWith('click:'));
    if (!clickTrigger) return;
    const action = clickTrigger.split(':')[1];

    switch (action) {
      case 'select-playlist': {
        const id = target.dataset.playlistId;
        window.location.href = '/?playlist=' + id;
        break;
      }
      case 'new-playlist': {
        const existing = document.getElementById('new-playlist-form');
        if (existing) { existing.remove(); return; }
        const form = document.createElement('div');
        form.innerHTML = await fetch('/api/ui/new-playlist-form').then(r => r.text());
        const content = document.getElementById('content-area');
        content.insertBefore(form.firstElementChild, content.firstChild);
        break;
      }
      case 'create-playlist': {
        const form = document.getElementById('new-playlist-form');
        const vals = getFormValues(form);
        if (!vals.name?.trim()) { alert('Name is required'); return; }
        await post('/playlists', { name: vals.name.trim(), description: vals.description?.trim() || '' });
        reload();
        break;
      }
      case 'cancel-new-playlist': {
        document.getElementById('new-playlist-form')?.remove();
        break;
      }
      case 'delete-playlist': {
        const id = target.dataset.playlistId;
        if (!confirm('Delete this playlist?')) return;
        await del('/playlists/' + id);
        window.location.href = '/';
        break;
      }
      case 'add-song': {
        const form = document.getElementById('add-song-form');
        const vals = getFormValues(form);
        if (!vals.title?.trim() || !vals.artist?.trim()) { alert('Title and artist are required'); return; }
        const playlistId = target.dataset.playlistId;
        await post('/playlists/' + playlistId + '/songs', {
          title: vals.title.trim(),
          artist: vals.artist.trim(),
          album: vals.album?.trim() || 'Unknown Album',
          duration: parseDuration(vals.duration),
          albumArtUrl: vals.albumArtUrl?.trim() || '',
        });
        reload();
        break;
      }
      case 'remove-song': {
        const songId = target.dataset.songId;
        const playlistId = target.dataset.playlistId;
        await del('/playlists/' + playlistId + '/songs/' + songId);
        reload();
        break;
      }
      case 'play-playlist': {
        const id = target.dataset.playlistId;
        await post('/player/play', { playlistId: id });
        reload();
        break;
      }
      case 'play-pause': {
        const isPlaying = target.textContent.trim() === '${svgIcons.pause}';
        if (isPlaying) {
          await post('/player/pause');
        } else {
          await post('/player/resume');
        }
        reload();
        break;
      }
      case 'skip': {
        await post('/player/skip');
        reload();
        break;
      }
      case 'previous': {
        await post('/player/previous');
        reload();
        break;
      }
      case 'toggle-shuffle': {
        await post('/player/shuffle');
        reload();
        break;
      }
      case 'cycle-repeat': {
        await post('/player/repeat');
        reload();
        break;
      }
      case 'seek': {
        const track = document.getElementById('progress-track');
        const rect = track.getBoundingClientRect();
        const pos = (e.clientX - rect.left) / rect.width;
        await post('/player/seek', { position: Math.max(0, Math.min(1, pos)) });
        reload();
        break;
      }
    }
  });

  // Song row click to play
  document.addEventListener('dblclick', async (e) => {
    const row = e.target.closest('.song-row');
    if (!row) return;
    const playlistId = row.dataset.playlistId;
    const index = parseInt(row.dataset.index);
    await post('/player/play', { playlistId, songIndex: index });
    reload();
  });

  // Drag and drop
  document.addEventListener('dragstart', (e) => {
    const row = e.target.closest('.song-row');
    if (!row) return;
    dragSrcIndex = parseInt(row.dataset.index);
    e.dataTransfer.effectAllowed = 'move';
    row.style.opacity = '0.4';
  });

  document.addEventListener('dragover', (e) => {
    e.preventDefault();
    const row = e.target.closest('.song-row');
    if (!row) return;
    e.dataTransfer.dropEffect = 'move';
    document.querySelectorAll('.song-row').forEach(r => r.classList.remove('drag-over'));
    row.classList.add('drag-over');
  });

  document.addEventListener('drop', async (e) => {
    e.preventDefault();
    const row = e.target.closest('.song-row');
    if (!row || dragSrcIndex === null) return;
    const toIndex = parseInt(row.dataset.index);
    const playlistId = row.dataset.playlistId;
    if (dragSrcIndex !== toIndex) {
      await patch('/playlists/' + playlistId + '/reorder', { fromIndex: dragSrcIndex, toIndex });
      reload();
    }
    dragSrcIndex = null;
  });

  document.addEventListener('dragend', () => {
    document.querySelectorAll('.song-row').forEach(r => {
      r.style.opacity = '1';
      r.classList.remove('drag-over');
    });
    dragSrcIndex = null;
  });

  // Simulate playback progress
  let progressInterval = null;
  const startProgress = () => {
    if (progressInterval) clearInterval(progressInterval);
    progressInterval = setInterval(async () => {
      const res = await fetch('/api/player/state');
      const state = await res.json();
      if (!state.isPlaying) { clearInterval(progressInterval); return; }
      await post('/player/tick');
    }, 1000);
  };

  // Check if playing on load
  fetch('/api/player/state').then(r => r.json()).then(state => {
    if (state.isPlaying) startProgress();
  });
})();
`;

import {
  getPlaylists,
  getPlaylist,
  createPlaylist,
  deletePlaylist,
  addSong,
  removeSong,
  reorderSong,
} from "./store";
import {
  getPlayerState,
  getCurrentSong,
  play,
  pause,
  resume,
  skip,
  previous,
  toggleShuffle,
  cycleRepeat,
  seek,
} from "./player";
import { renderPage, renderNewPlaylistForm } from "./templates";

type RouteHandler = (req: Request, params: Record<string, string>) => Promise<Response>;

const json = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });

const html = (body: string, status = 200): Response =>
  new Response(body, {
    status,
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });

const parseBody = async <T>(req: Request): Promise<T> => {
  try {
    return await req.json();
  } catch {
    return {} as T;
  }
};

const extractParam = (url: URL, pattern: string): Record<string, string> => {
  const patternParts = pattern.split("/");
  const urlParts = url.pathname.split("/");
  const params: Record<string, string> = {};
  for (let i = 0; i < patternParts.length; i++) {
    if (patternParts[i].startsWith(":")) {
      params[patternParts[i].slice(1)] = urlParts[i] ?? "";
    }
  }
  return params;
};

// --- API Routes ---

const apiGetPlaylists: RouteHandler = async () => {
  const playlists = await getPlaylists();
  return json(playlists);
};

const apiCreatePlaylist: RouteHandler = async (req) => {
  const body = await parseBody<{ name: string; description?: string }>(req);
  if (!body.name?.trim()) return json({ error: "Name is required" }, 400);
  const playlist = await createPlaylist(body.name.trim(), body.description?.trim());
  return json(playlist, 201);
};

const apiDeletePlaylist: RouteHandler = async (_req, params) => {
  const deleted = await deletePlaylist(params.id);
  return deleted ? json({ ok: true }) : json({ error: "Not found" }, 404);
};

const apiAddSong: RouteHandler = async (req, params) => {
  const body = await parseBody<{
    title: string;
    artist: string;
    album: string;
    duration: number;
    albumArtUrl?: string;
  }>(req);
  if (!body.title?.trim() || !body.artist?.trim()) {
    return json({ error: "Title and artist are required" }, 400);
  }
  const song = await addSong(params.id, {
    title: body.title.trim(),
    artist: body.artist.trim(),
    album: body.album?.trim() ?? "Unknown Album",
    duration: body.duration ?? 180,
    albumArtUrl: body.albumArtUrl?.trim() ?? "",
  });
  return song ? json(song, 201) : json({ error: "Playlist not found" }, 404);
};

const apiRemoveSong: RouteHandler = async (_req, params) => {
  const removed = await removeSong(params.id, params.songId);
  return removed ? json({ ok: true }) : json({ error: "Not found" }, 404);
};

const apiReorderSong: RouteHandler = async (req, params) => {
  const body = await parseBody<{ fromIndex: number; toIndex: number }>(req);
  if (body.fromIndex === undefined || body.toIndex === undefined) {
    return json({ error: "fromIndex and toIndex are required" }, 400);
  }
  const reordered = await reorderSong(params.id, body.fromIndex, body.toIndex);
  return reordered ? json({ ok: true }) : json({ error: "Invalid indices or playlist not found" }, 400);
};

const apiPlayerPlay: RouteHandler = async (req) => {
  const body = await parseBody<{ playlistId: string; songIndex?: number }>(req);
  if (!body.playlistId) {
    // Resume if no playlist specified
    const state = resume();
    return json(state);
  }
  const song = await play(body.playlistId, body.songIndex);
  return song ? json({ song, state: getPlayerState() }) : json({ error: "Playlist empty or not found" }, 404);
};

const apiPlayerPause: RouteHandler = async () => {
  const state = pause();
  return json(state);
};

const apiPlayerResume: RouteHandler = async () => {
  const state = resume();
  return json(state);
};

const apiPlayerSkip: RouteHandler = async () => {
  const song = await skip();
  return json({ song, state: getPlayerState() });
};

const apiPlayerPrevious: RouteHandler = async () => {
  const song = await previous();
  return json({ song, state: getPlayerState() });
};

const apiPlayerShuffle: RouteHandler = async () => {
  const state = await toggleShuffle();
  return json(state);
};

const apiPlayerRepeat: RouteHandler = async () => {
  const state = cycleRepeat();
  return json(state);
};

const apiPlayerSeek: RouteHandler = async (req) => {
  const body = await parseBody<{ position: number }>(req);
  const state = seek(body.position ?? 0);
  return json(state);
};

const apiPlayerState: RouteHandler = async () => {
  const state = getPlayerState();
  const song = await getCurrentSong();
  return json({ ...state, currentSong: song });
};

const apiPlayerTick: RouteHandler = async () => {
  // Advance progress by ~1 second relative to song duration
  const song = await getCurrentSong();
  if (song) {
    const state = getPlayerState();
    if (state.isPlaying) {
      const increment = 1 / song.duration;
      const newProgress = state.progress + increment;
      if (newProgress >= 1) {
        // Song ended, skip to next
        const nextSong = await skip();
        return json({ song: nextSong, state: getPlayerState() });
      }
      seek(newProgress);
    }
  }
  return json(getPlayerState());
};

const apiNewPlaylistForm: RouteHandler = async () => {
  return html(renderNewPlaylistForm());
};

// --- Router ---

type Route = {
  method: string;
  pattern: string;
  handler: RouteHandler;
};

const routes: Route[] = [
  { method: "GET", pattern: "/api/playlists", handler: apiGetPlaylists },
  { method: "POST", pattern: "/api/playlists", handler: apiCreatePlaylist },
  { method: "DELETE", pattern: "/api/playlists/:id", handler: apiDeletePlaylist },
  { method: "POST", pattern: "/api/playlists/:id/songs", handler: apiAddSong },
  { method: "DELETE", pattern: "/api/playlists/:id/songs/:songId", handler: apiRemoveSong },
  { method: "PATCH", pattern: "/api/playlists/:id/reorder", handler: apiReorderSong },
  { method: "POST", pattern: "/api/player/play", handler: apiPlayerPlay },
  { method: "POST", pattern: "/api/player/pause", handler: apiPlayerPause },
  { method: "POST", pattern: "/api/player/resume", handler: apiPlayerResume },
  { method: "POST", pattern: "/api/player/skip", handler: apiPlayerSkip },
  { method: "POST", pattern: "/api/player/previous", handler: apiPlayerPrevious },
  { method: "POST", pattern: "/api/player/shuffle", handler: apiPlayerShuffle },
  { method: "POST", pattern: "/api/player/repeat", handler: apiPlayerRepeat },
  { method: "POST", pattern: "/api/player/seek", handler: apiPlayerSeek },
  { method: "GET", pattern: "/api/player/state", handler: apiPlayerState },
  { method: "POST", pattern: "/api/player/tick", handler: apiPlayerTick },
  { method: "GET", pattern: "/api/ui/new-playlist-form", handler: apiNewPlaylistForm },
];

const matchRoute = (method: string, pathname: string): { route: Route; params: Record<string, string> } | null => {
  for (const route of routes) {
    if (route.method !== method) continue;
    const routeParts = route.pattern.split("/");
    const urlParts = pathname.split("/");
    if (routeParts.length !== urlParts.length) continue;
    let match = true;
    const params: Record<string, string> = {};
    for (let i = 0; i < routeParts.length; i++) {
      if (routeParts[i].startsWith(":")) {
        params[routeParts[i].slice(1)] = urlParts[i];
      } else if (routeParts[i] !== urlParts[i]) {
        match = false;
        break;
      }
    }
    if (match) return { route, params };
  }
  return null;
};

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);

  // Serve the main page
  if (url.pathname === "/" && req.method === "GET") {
    const playlists = await getPlaylists();
    const activeId = url.searchParams.get("playlist") ?? playlists[0]?.id ?? null;
    const activePlaylist = activeId ? (await getPlaylist(activeId)) ?? null : null;
    const playerState = getPlayerState();
    const currentSong = await getCurrentSong();
    const page = renderPage(playlists, activePlaylist, currentSong, playerState);
    return html(page);
  }

  // API routing
  const matched = matchRoute(req.method, url.pathname);
  if (matched) {
    return matched.route.handler(req, matched.params);
  }

  return json({ error: "Not found" }, 404);
};

import { handleRequest } from "./routes";

const PORT = parseInt(process.env.PORT ?? "3000", 10);

const server = Bun.serve({
  port: PORT,
  fetch: handleRequest,
});

console.log(`Playlist Manager running at http://localhost:${server.port}`);

