# Playlist Manager

A full-featured music playlist manager that lets users organize and play their music.

## Features

- **Create & manage playlists** — Name playlists, add/remove songs, delete playlists
- **Song metadata** — Each song stores title, artist, album, duration, and album art URL
- **Drag-to-reorder** — Rearrange songs within a playlist via drag-and-drop
- **Playback controls** — Play, pause, skip forward, skip backward with a seek-able progress bar
- **Now playing** — Displays current song info with album art
- **Shuffle mode** — Randomize playback order
- **Repeat mode** — Cycle through off, repeat-all, and repeat-one

## Usage

```ts
import { createApp } from "./index";

const app = createApp();

// Create a playlist
app.createPlaylist("Road Trip");

// Add a song
app.addSong("Road Trip", {
  title: "Bohemian Rhapsody",
  artist: "Queen",
  album: "A Night at the Opera",
  duration: 354,
  albumArtUrl: "https://example.com/art.jpg",
});

// Playback
app.play("Road Trip", 0);
app.pause();
app.skip();
app.previous();
app.toggleShuffle();
app.cycleRepeat();
```

## Data

Playlists are persisted as JSON in `data/playlists.json`.

export type Song = {
  id: string;
  title: string;
  artist: string;
  album: string;
  duration: number; // seconds
  albumArtUrl: string;
};

export type Playlist = {
  id: string;
  name: string;
  songs: Song[];
  createdAt: string;
  updatedAt: string;
};

export type RepeatMode = "off" | "all" | "one";

export type PlayerState = {
  currentPlaylistId: string | null;
  currentSongIndex: number;
  isPlaying: boolean;
  shuffle: boolean;
  repeat: RepeatMode;
  elapsed: number; // seconds into current song
  shuffleOrder: number[];
};

export type AppState = {
  playlists: Playlist[];
  player: PlayerState;
};

import type { Playlist } from "./types";

const DATA_PATH = new URL("./data/playlists.json", import.meta.url).pathname;

export const loadPlaylists = async (): Promise<Playlist[]> => {
  try {
    const file = Bun.file(DATA_PATH);
    const exists = await file.exists();
    if (!exists) return [];
    const text = await file.text();
    return JSON.parse(text) as Playlist[];
  } catch {
    return [];
  }
};

export const savePlaylists = async (playlists: Playlist[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(playlists, null, 2));
};

import type { Playlist, Song } from "./types";
import { loadPlaylists, savePlaylists } from "./store";

const generateId = (): string => crypto.randomUUID();

export const createPlaylist = async (name: string): Promise<Playlist> => {
  const playlists = await loadPlaylists();
  const now = new Date().toISOString();
  const playlist: Playlist = {
    id: generateId(),
    name,
    songs: [],
    createdAt: now,
    updatedAt: now,
  };
  playlists.push(playlist);
  await savePlaylists(playlists);
  return playlist;
};

export const deletePlaylist = async (playlistId: string): Promise<boolean> => {
  const playlists = await loadPlaylists();
  const idx = playlists.findIndex((p) => p.id === playlistId);
  if (idx === -1) return false;
  playlists.splice(idx, 1);
  await savePlaylists(playlists);
  return true;
};

export const renamePlaylist = async (
  playlistId: string,
  name: string
): Promise<Playlist | null> => {
  const playlists = await loadPlaylists();
  const playlist = playlists.find((p) => p.id === playlistId);
  if (!playlist) return null;
  playlist.name = name;
  playlist.updatedAt = new Date().toISOString();
  await savePlaylists(playlists);
  return playlist;
};

export const addSong = async (
  playlistId: string,
  song: Omit<Song, "id">
): Promise<Song | null> => {
  const playlists = await loadPlaylists();
  const playlist = playlists.find((p) => p.id === playlistId);
  if (!playlist) return null;
  const newSong: Song = { id: generateId(), ...song };
  playlist.songs.push(newSong);
  playlist.updatedAt = new Date().toISOString();
  await savePlaylists(playlists);
  return newSong;
};

export const removeSong = async (
  playlistId: string,
  songId: string
): Promise<boolean> => {
  const playlists = await loadPlaylists();
  const playlist = playlists.find((p) => p.id === playlistId);
  if (!playlist) return false;
  const idx = playlist.songs.findIndex((s) => s.id === songId);
  if (idx === -1) return false;
  playlist.songs.splice(idx, 1);
  playlist.updatedAt = new Date().toISOString();
  await savePlaylists(playlists);
  return true;
};

export const reorderSong = async (
  playlistId: string,
  fromIndex: number,
  toIndex: number
): Promise<boolean> => {
  const playlists = await loadPlaylists();
  const playlist = playlists.find((p) => p.id === playlistId);
  if (!playlist) return false;
  if (
    fromIndex < 0 ||
    fromIndex >= playlist.songs.length ||
    toIndex < 0 ||
    toIndex >= playlist.songs.length
  ) {
    return false;
  }
  const [song] = playlist.songs.splice(fromIndex, 1);
  playlist.songs.splice(toIndex, 0, song);
  playlist.updatedAt = new Date().toISOString();
  await savePlaylists(playlists);
  return true;
};

export const getPlaylist = async (
  playlistId: string
): Promise<Playlist | null> => {
  const playlists = await loadPlaylists();
  return playlists.find((p) => p.id === playlistId) ?? null;
};

export const getPlaylistByName = async (
  name: string
): Promise<Playlist | null> => {
  const playlists = await loadPlaylists();
  return playlists.find((p) => p.name === name) ?? null;
};

export const getAllPlaylists = async (): Promise<Playlist[]> => {
  return loadPlaylists();
};

import type { PlayerState, RepeatMode, Playlist } from "./types";

const createShuffleOrder = (length: number): number[] => {
  const order = Array.from({ length }, (_, i) => i);
  for (let i = order.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [order[i], order[j]] = [order[j], order[i]];
  }
  return order;
};

export const createPlayerState = (): PlayerState => ({
  currentPlaylistId: null,
  currentSongIndex: -1,
  isPlaying: false,
  shuffle: false,
  repeat: "off",
  elapsed: 0,
  shuffleOrder: [],
});

export const play = (
  state: PlayerState,
  playlist: Playlist,
  songIndex?: number
): PlayerState => {
  const index = songIndex ?? state.currentSongIndex;
  if (index < 0 || index >= playlist.songs.length) return state;

  const needsNewShuffle =
    state.currentPlaylistId !== playlist.id ||
    state.shuffleOrder.length !== playlist.songs.length;

  return {
    ...state,
    currentPlaylistId: playlist.id,
    currentSongIndex: index,
    isPlaying: true,
    elapsed: songIndex !== undefined ? 0 : state.elapsed,
    shuffleOrder:
      state.shuffle && needsNewShuffle
        ? createShuffleOrder(playlist.songs.length)
        : state.shuffleOrder,
  };
};

export const pause = (state: PlayerState): PlayerState => ({
  ...state,
  isPlaying: false,
});

export const resume = (state: PlayerState): PlayerState => ({
  ...state,
  isPlaying: true,
});

export const togglePlayPause = (
  state: PlayerState,
  playlist: Playlist
): PlayerState => {
  if (state.isPlaying) return pause(state);
  if (state.currentSongIndex === -1 && playlist.songs.length > 0) {
    return play(state, playlist, 0);
  }
  return resume(state);
};

const resolveIndex = (state: PlayerState, logicalIndex: number): number => {
  if (state.shuffle && state.shuffleOrder.length > 0) {
    return state.shuffleOrder[logicalIndex] ?? logicalIndex;
  }
  return logicalIndex;
};

const findLogicalIndex = (state: PlayerState): number => {
  if (!state.shuffle) return state.currentSongIndex;
  return state.shuffleOrder.indexOf(state.currentSongIndex);
};

export const skip = (
  state: PlayerState,
  playlist: Playlist
): PlayerState => {
  if (playlist.songs.length === 0) return state;

  if (state.repeat === "one") {
    return { ...state, elapsed: 0, isPlaying: true };
  }

  const logicalCurrent = findLogicalIndex(state);
  const nextLogical = logicalCurrent + 1;

  if (nextLogical >= playlist.songs.length) {
    if (state.repeat === "all") {
      const newShuffleOrder = state.shuffle
        ? createShuffleOrder(playlist.songs.length)
        : state.shuffleOrder;
      return {
        ...state,
        currentSongIndex: resolveIndex(
          { ...state, shuffleOrder: newShuffleOrder },
          0
        ),
        elapsed: 0,
        isPlaying: true,
        shuffleOrder: newShuffleOrder,
      };
    }
    return { ...state, isPlaying: false, elapsed: 0 };
  }

  return {
    ...state,
    currentSongIndex: resolveIndex(state, nextLogical),
    elapsed: 0,
    isPlaying: true,
  };
};

export const previous = (
  state: PlayerState,
  playlist: Playlist
): PlayerState => {
  if (playlist.songs.length === 0) return state;

  // If more than 3 seconds in, restart current song
  if (state.elapsed > 3) {
    return { ...state, elapsed: 0 };
  }

  const logicalCurrent = findLogicalIndex(state);
  const prevLogical = logicalCurrent - 1;

  if (prevLogical < 0) {
    if (state.repeat === "all") {
      return {
        ...state,
        currentSongIndex: resolveIndex(state, playlist.songs.length - 1),
        elapsed: 0,
        isPlaying: true,
      };
    }
    return { ...state, elapsed: 0 };
  }

  return {
    ...state,
    currentSongIndex: resolveIndex(state, prevLogical),
    elapsed: 0,
    isPlaying: true,
  };
};

export const toggleShuffle = (
  state: PlayerState,
  songCount: number
): PlayerState => {
  const newShuffle = !state.shuffle;
  return {
    ...state,
    shuffle: newShuffle,
    shuffleOrder: newShuffle ? createShuffleOrder(songCount) : [],
  };
};

export const cycleRepeat = (state: PlayerState): PlayerState => {
  const modes: RepeatMode[] = ["off", "all", "one"];
  const currentIdx = modes.indexOf(state.repeat);
  const nextIdx = (currentIdx + 1) % modes.length;
  return { ...state, repeat: modes[nextIdx] };
};

export const seek = (
  state: PlayerState,
  seconds: number,
  playlist: Playlist
): PlayerState => {
  const song = playlist.songs[state.currentSongIndex];
  if (!song) return state;
  const clamped = Math.max(0, Math.min(seconds, song.duration));
  return { ...state, elapsed: clamped };
};

export const tick = (
  state: PlayerState,
  playlist: Playlist
): PlayerState => {
  if (!state.isPlaying || state.currentSongIndex === -1) return state;
  const song = playlist.songs[state.currentSongIndex];
  if (!song) return state;

  const newElapsed = state.elapsed + 1;
  if (newElapsed >= song.duration) {
    return skip({ ...state, elapsed: song.duration }, playlist);
  }
  return { ...state, elapsed: newElapsed };
};

