const repeatLabel = (mode: RepeatMode): string => {
  switch (mode) {
    case "off": return "\u{1F501}";
    case "all": return "\u{1F501}\u{FE0F}";
    case "one": return "\u{1F502}";
  }
};

export const renderSongRow = (
  song: Song,
  index: number,
  isCurrentSong: boolean,
  playlistId: string
): string => {
  const rowStyle = isCurrentSong
    ? { ...styles.songRow, ...styles.songRowPlaying }
    : styles.songRow;
  const titleStyle = isCurrentSong
    ? { ...styles.songTitle, ...styles.songTitlePlaying }
    : styles.songTitle;

  return h(
    "div",
    {
      style: rowStyle,
      draggable: "true",
      "data-index": String(index),
      "data-playlist-id": playlistId,
      "p-trigger": `dragstart:song-drag-start dragover:song-drag-over drop:song-drop`,
    },
    h("span", { style: styles.songNumber }, isCurrentSong ? "\u{266B}" : String(index + 1)),
    h("img", {
      style: styles.songArt,
      src: song.albumArtUrl,
      alt: `${song.album} art`,
      loading: "lazy",
    }),
    h("div", null,
      h("div", { style: titleStyle }, song.title),
      h("div", { style: styles.songArtist }, song.artist)
    ),
    h("div", { style: styles.songArtist }, song.album),
    h("div", { style: styles.songDuration }, formatDuration(song.duration)),
    h(
      "button",
      {
        style: styles.removeBtn,
        "p-trigger": "click:remove-song",
        "data-song-id": song.id,
        "data-playlist-id": playlistId,
        "aria-label": "Remove song",
      },
      "\u00D7"
    )
  );
};

