export const renderSongList = (
  playlist: Playlist,
  playerState: PlayerState
): string => {
  if (playlist.songs.length === 0) {
    return h(
      "div",
      { style: styles.emptyState },
      h("p", null, "No songs yet. Add one above!")
    );
  }

  return h(
    "div",
    { style: styles.songList, "p-target": "song-list" },
    ...playlist.songs.map((song, i) =>
      renderSongRow(
        song,
        i,
        playerState.currentPlaylistId === playlist.id &&
          playerState.currentSongIndex === i,
        playlist.id
      )
    )
  );
};

export const renderNowPlaying = (
  song: Song | null,
  playerState: PlayerState
): string => {
  const shuffleStyle = playerState.shuffle
    ? { ...styles.controlBtn, ...styles.controlBtnActive }
    : styles.controlBtn;
  const repeatStyle = playerState.repeat !== "off"
    ? { ...styles.controlBtn, ...styles.controlBtnActive }
    : styles.controlBtn;

  const duration = song?.duration ?? 0;
  const progress = duration > 0 ? (playerState.elapsed / duration) * 100 : 0;

  return h(
    "div",
    { style: styles.nowPlaying, "p-target": "now-playing" },
    // Left: song info
    h(
      "div",
      { style: styles.nowPlayingInfo },
      song
        ? h(Fragment, null,
            h("img", {
              style: styles.nowPlayingArt,
              src: song.albumArtUrl,
              alt: `${song.album} art`,
            }),
            h("div", { style: styles.nowPlayingText },
              h("div", { style: styles.nowPlayingTitle }, song.title),
              h("div", { style: styles.nowPlayingArtist }, `${song.artist} — ${song.album}`)
            )
          )
        : h("div", { style: styles.nowPlayingText },
            h("div", { style: { ...styles.nowPlayingTitle, color: "#a0a0a0" } }, "Nothing playing")
          )
    ),
    // Center: controls + progress
    h(
      "div",
      { style: styles.controls },
      h(
        "div",
        { style: styles.controlButtons },
        h("button", { style: shuffleStyle, "p-trigger": "click:toggle-shuffle", "aria-label": "Shuffle" }, "\u{1F500}"),
        h("button", { style: styles.controlBtn, "p-trigger": "click:previous", "aria-label": "Previous" }, "\u{23EE}"),
        h(
          "button",
          { style: styles.playBtn, "p-trigger": "click:play-pause", "aria-label": playerState.isPlaying ? "Pause" : "Play" },
          playerState.isPlaying ? "\u{23F8}" : "\u{25B6}"
        ),
        h("button", { style: styles.controlBtn, "p-trigger": "click:skip", "aria-label": "Next" }, "\u{23ED}"),
        h("button", { style: repeatStyle, "p-trigger": "click:cycle-repeat", "aria-label": "Repeat" }, repeatLabel(playerState.repeat))
      ),
      h(
        "div",
        { style: styles.progressContainer },
        h("span", { style: styles.progressTime }, formatDuration(playerState.elapsed)),
        h(
          "div",
          { style: styles.progressBar, "p-trigger": "click:seek", "p-target": "progress-bar" },
          h("div", {
            style: { ...styles.progressFill, width: `${progress}%` },
            "p-target": "progress-fill",
          })
        ),
        h("span", { style: styles.progressTime }, formatDuration(duration))
      )
    ),
    // Right: extra controls
    h(
      "div",
      { style: styles.extraControls },
      h("audio", {
        "p-target": "audio-element",
        preload: "none",
        style: { display: "none" },
      })
    )
  );
