import {
  createPlaylist,
  deletePlaylist,
  renamePlaylist,
  addSong,
  removeSong,
  reorderSong,
  getPlaylist,
  getPlaylistByName,
  getAllPlaylists,
} from "./playlist";
import {
  createPlayerState,
  play,
  pause,
  resume,
  togglePlayPause,
  skip,
  previous,
  toggleShuffle,
  cycleRepeat,
  seek,
  tick,
} from "./player";
import { renderApp } from "./ui";

export type PlaylistManagerApp = {
  // Playlist management
  createPlaylist: (name: string) => Promise<Playlist>;
  deletePlaylist: (playlistId: string) => Promise<boolean>;
  renamePlaylist: (playlistId: string, name: string) => Promise<Playlist | null>;
  addSong: (playlistIdOrName: string, song: Omit<Song, "id">) => Promise<Song | null>;
  removeSong: (playlistId: string, songId: string) => Promise<boolean>;
  reorderSong: (playlistId: string, from: number, to: number) => Promise<boolean>;
  getPlaylist: (playlistId: string) => Promise<Playlist | null>;
  getAllPlaylists: () => Promise<Playlist[]>;

  // Player controls
  play: (playlistIdOrName: string, songIndex: number) => Promise<void>;
  pause: () => void;
  togglePlayPause: () => Promise<void>;
  skip: () => Promise<void>;
  previous: () => Promise<void>;
  toggleShuffle: () => Promise<void>;
  cycleRepeat: () => void;
  seek: (seconds: number) => Promise<void>;

  // State
  getPlayerState: () => PlayerState;
  getState: () => Promise<AppState>;

  // Rendering
  render: (activePlaylistId?: string | null) => Promise<string>;

  // Lifecycle
  startTicker: () => void;
  stopTicker: () => void;
};

export const createApp = (): PlaylistManagerApp => {
  let playerState = createPlayerState();
  let tickerInterval: ReturnType<typeof setInterval> | null = null;
  let activePlaylistId: string | null = null;

  const resolvePlaylist = async (idOrName: string): Promise<Playlist | null> => {
    const byId = await getPlaylist(idOrName);
    if (byId) return byId;
    return getPlaylistByName(idOrName);
  };

  const getCurrentPlaylist = async (): Promise<Playlist | null> => {
    if (!playerState.currentPlaylistId) return null;
    return getPlaylist(playerState.currentPlaylistId);
  };

  const app: PlaylistManagerApp = {
    createPlaylist: async (name) => {
      const pl = await createPlaylist(name);
      activePlaylistId = pl.id;
      return pl;
    },

    deletePlaylist: async (playlistId) => {
      const result = await deletePlaylist(playlistId);
      if (result && playerState.currentPlaylistId === playlistId) {
        playerState = createPlayerState();
      }
      if (activePlaylistId === playlistId) {
        activePlaylistId = null;
      }
      return result;
    },

    renamePlaylist: (playlistId, name) => renamePlaylist(playlistId, name),

    addSong: async (playlistIdOrName, song) => {
      const pl = await resolvePlaylist(playlistIdOrName);
      if (!pl) return null;
      return addSong(pl.id, song);
    },

    removeSong: async (playlistId, songId) => {
      const pl = await getPlaylist(playlistId);
      if (!pl) return false;

      const songIdx = pl.songs.findIndex((s) => s.id === songId);
      const result = await removeSong(playlistId, songId);

      if (result && playerState.currentPlaylistId === playlistId) {
        if (songIdx === playerState.currentSongIndex) {
          playerState = { ...playerState, isPlaying: false, currentSongIndex: -1, elapsed: 0 };
        } else if (songIdx < playerState.currentSongIndex) {
          playerState = { ...playerState, currentSongIndex: playerState.currentSongIndex - 1 };
        }
      }
      return result;
    },

    reorderSong: (playlistId, from, to) => reorderSong(playlistId, from, to),

    getPlaylist: (playlistId) => getPlaylist(playlistId),

    getAllPlaylists: () => getAllPlaylists(),

    play: async (playlistIdOrName, songIndex) => {
      const pl = await resolvePlaylist(playlistIdOrName);
      if (!pl) return;
      activePlaylistId = pl.id;
      playerState = play(playerState, pl, songIndex);
    },

    pause: () => {
      playerState = pause(playerState);
    },

    togglePlayPause: async () => {
      const pl = await getCurrentPlaylist();
      if (!pl) {
        // Try active playlist
        if (activePlaylistId) {
          const activePl = await getPlaylist(activePlaylistId);
          if (activePl && activePl.songs.length > 0) {
            playerState = {
              ...playerState,
              currentPlaylistId: activePl.id,
            };
            playerState = togglePlayPause(playerState, activePl);
            return;
          }
        }
        return;
      }
      playerState = togglePlayPause(playerState, pl);
    },

    skip: async () => {
      const pl = await getCurrentPlaylist();
      if (!pl) return;
      playerState = skip(playerState, pl);
    },

    previous: async () => {
      const pl = await getCurrentPlaylist();
      if (!pl) return;
      playerState = previous(playerState, pl);
    },

    toggleShuffle: async () => {
      const pl = await getCurrentPlaylist();
      const songCount = pl?.songs.length ?? 0;
      playerState = toggleShuffle(playerState, songCount);
    },

    cycleRepeat: () => {
      playerState = cycleRepeat(playerState);
    },

    seek: async (seconds) => {
      const pl = await getCurrentPlaylist();
      if (!pl) return;
      playerState = seek(playerState, seconds, pl);
    },

    getPlayerState: () => playerState,

    getState: async () => ({
      playlists: await getAllPlaylists(),
      player: playerState,
    }),

    render: async (overridePlaylistId) => {
      const playlists = await getAllPlaylists();
      const targetId = overridePlaylistId ?? activePlaylistId;
      const activePl = targetId ? await getPlaylist(targetId) : null;
      if (activePl) activePlaylistId = activePl.id;
      return renderApp(playlists, activePl, playerState);
    },

    startTicker: () => {
      if (tickerInterval) return;
      tickerInterval = setInterval(async () => {
        const pl = await getCurrentPlaylist();
        if (!pl) return;
        playerState = tick(playerState, pl);
      }, 1000);
    },

    stopTicker: () => {
      if (tickerInterval) {
        clearInterval(tickerInterval);
        tickerInterval = null;
      }
    },
  };

  return app;
};

