export type StatResult = {
  mean: number
  median: number
  mode: number[]
  stdDev: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
  count: number
  sorted: number[]
}

export type NamedDataset = {
  name: string
  data: number[]
  stats: StatResult
}

const sortAsc = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const sum = (arr: number[]): number => arr.reduce((a, b) => a + b, 0)

const calcMean = (arr: number[]): number => sum(arr) / arr.length

const calcMedian = (sorted: number[]): number => {
  const mid = Math.floor(sorted.length / 2)
  return sorted.length % 2 !== 0
    ? sorted[mid]
    : (sorted[mid - 1] + sorted[mid]) / 2
}

const calcMode = (arr: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of arr) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  if (maxFreq === 1) return [] // no mode
  const modes: number[] = []
  for (const [k, v] of freq) {
    if (v === maxFreq) modes.push(k)
  }
  return modes.sort((a, b) => a - b)
}

const calcQuartile = (sorted: number[], q: 0.25 | 0.75): number => {
  const pos = (sorted.length - 1) * q
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  if (lo === hi) return sorted[lo]
  return sorted[lo] + (sorted[hi] - sorted[lo]) * (pos - lo)
}

const calcVariance = (arr: number[], mean: number): number =>
  sum(arr.map((v) => (v - mean) ** 2)) / arr.length

export const computeStats = (data: number[]): StatResult => {
  const sorted = sortAsc(data)
  const mean = calcMean(sorted)
  const variance = calcVariance(sorted, mean)
  const q1 = calcQuartile(sorted, 0.25)
  const q3 = calcQuartile(sorted, 0.75)

  return {
    mean,
    median: calcMedian(sorted),
    mode: calcMode(sorted),
    stdDev: Math.sqrt(variance),
    variance,
    min: sorted[0],
    max: sorted[sorted.length - 1],
    range: sorted[sorted.length - 1] - sorted[0],
    q1,
    q3,
    iqr: q3 - q1,
    count: sorted.length,
    sorted,
  }
}

export const parseInput = (raw: string): number[] => {
  const trimmed = raw.trim()
  if (trimmed.startsWith('[')) {
    const parsed = JSON.parse(trimmed) as unknown[]
    return parsed.map(Number).filter((n) => !Number.isNaN(n))
  }
  return trimmed
    .split(',')
    .map((s) => Number(s.trim()))
    .filter((n) => !Number.isNaN(n) && s.trim() !== '')
}

const filterValid = (parts: string[]): number[] =>
  parts
    .map((s) => s.trim())
    .filter((s) => s !== '')
    .map(Number)
    .filter((n) => !Number.isNaN(n))

export const parseInputSafe = (raw: string): number[] => {
  const trimmed = raw.trim()
  if (trimmed.startsWith('[')) {
    try {
      const parsed = JSON.parse(trimmed) as unknown[]
      return parsed.map(Number).filter((n) => !Number.isNaN(n))
    } catch {
      return []
    }
  }
  return filterValid(trimmed.split(','))
}

export const formatNum = (n: number): string =>
  Number.isInteger(n) ? String(n) : n.toFixed(4)

