// ── Box plot (SVG) ──────────────────────────────────────────────

const BOX_SVG_WIDTH = 600
const BOX_SVG_PAD = 60
const BOX_ROW_HEIGHT = 50
const BOX_BAR_HEIGHT = 24

export const renderBoxPlot = (datasets: NamedDataset[]): string => {
  const allValues = datasets.flatMap((ds) => ds.data)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const spread = globalMax - globalMin || 1
  const svgHeight = datasets.length * BOX_ROW_HEIGHT + 40

  const scale = (v: number): number =>
    BOX_SVG_PAD + ((v - globalMin) / spread) * (BOX_SVG_WIDTH - BOX_SVG_PAD * 2)

  const ticks = buildTicks(globalMin, globalMax, 6)

  const rows = datasets.map((ds, i) => {
    const s = ds.stats
    const y = i * BOX_ROW_HEIGHT + 20
    const cy = y + BOX_BAR_HEIGHT / 2
    const color = colorFor(i)

    return h(
      Fragment,
      {},
      // whisker line
      h('line', {
        x1: String(scale(s.min)),
        y1: String(cy),
        x2: String(scale(s.max)),
        y2: String(cy),
        stroke: color,
        'stroke-width': '1.5',
      }),
      // min cap
      h('line', {
        x1: String(scale(s.min)),
        y1: String(y + 4),
        x2: String(scale(s.min)),
        y2: String(y + BOX_BAR_HEIGHT - 4),
        stroke: color,
        'stroke-width': '1.5',
      }),
      // max cap
      h('line', {
        x1: String(scale(s.max)),
        y1: String(y + 4),
        x2: String(scale(s.max)),
        y2: String(y + BOX_BAR_HEIGHT - 4),
        stroke: color,
        'stroke-width': '1.5',
      }),
      // box Q1-Q3
      h('rect', {
        x: String(scale(s.q1)),
        y: String(y),
        width: String(Math.max(scale(s.q3) - scale(s.q1), 1)),
        height: String(BOX_BAR_HEIGHT),
        fill: color,
        opacity: '0.25',
        stroke: color,
        'stroke-width': '1.5',
        rx: '3',
      }),
      // median line
      h('line', {
        x1: String(scale(s.median)),
        y1: String(y),
        x2: String(scale(s.median)),
        y2: String(y + BOX_BAR_HEIGHT),
        stroke: color,
        'stroke-width': '2.5',
      }),
      // label
      h(
        'text',
        {
          x: '4',
          y: String(cy + 4),
          'font-size': '11',
          'font-family': 'system-ui, sans-serif',
          fill: '#333',
        },
        ds.name,
      ),
    )
  })

  const tickMarks = ticks.map((t) =>
    h(
      Fragment,
      {},
      h('line', {
        x1: String(scale(t)),
        y1: String(svgHeight - 18),
        x2: String(scale(t)),
        y2: String(svgHeight - 14),
        stroke: '#adb5bd',
        'stroke-width': '1',
      }),
      h(
        'text',
        {
          x: String(scale(t)),
          y: String(svgHeight - 4),
          'text-anchor': 'middle',
          'font-size': '10',
          'font-family': 'system-ui, sans-serif',
          fill: '#868e96',
        },
        formatNum(t),
      ),
    ),
  )

  return h(
    'svg',
    {
      width: String(BOX_SVG_WIDTH),
      height: String(svgHeight),
      viewBox: `0 0 ${BOX_SVG_WIDTH} ${svgHeight}`,
      xmlns: 'http://www.w3.org/2000/svg',
      style: { backgroundColor: '#fff', borderRadius: '8px', border: '1px solid #dee2e6' },
    },
    // axis line
    h('line', {
      x1: String(BOX_SVG_PAD),
      y1: String(svgHeight - 18),
      x2: String(BOX_SVG_WIDTH - BOX_SVG_PAD),
      y2: String(svgHeight - 18),
      stroke: '#adb5bd',
      'stroke-width': '1',
    }),
    ...tickMarks,
    ...rows,
  ) as unknown as string
}

// ── Histogram (SVG) ─────────────────────────────────────────────

const HIST_WIDTH = 600
const HIST_HEIGHT = 250
const HIST_PAD_L = 50
const HIST_PAD_R = 20
const HIST_PAD_T = 20
const HIST_PAD_B = 40

export const renderHistogram = (datasets: NamedDataset[], binCount = 10): string => {
  const allValues = datasets.flatMap((ds) => ds.data)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const spread = globalMax - globalMin || 1
  const binWidth = spread / binCount

  type BinData = { bins: number[]; maxFreq: number }

  const binnedSets: BinData[] = datasets.map((ds) => {
    const bins = new Array<number>(binCount).fill(0)
    for (const v of ds.data) {
      let idx = Math.floor((v - globalMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      bins[idx]++
    }
    return { bins, maxFreq: Math.max(...bins) }
  })

  const globalMaxFreq = Math.max(...binnedSets.map((b) => b.maxFreq), 1)
  const plotW = HIST_WIDTH - HIST_PAD_L - HIST_PAD_R
  const plotH = HIST_HEIGHT - HIST_PAD_T - HIST_PAD_B
  const barGroupW = plotW / binCount
  const barW = barGroupW / datasets.length

  const scaleY = (v: number): number =>
    HIST_PAD_T + plotH - (v / globalMaxFreq) * plotH

  const bars = datasets.flatMap((ds, di) =>
    binnedSets[di].bins.map((freq, bi) => {
      const x = HIST_PAD_L + bi * barGroupW + di * barW
      const barHeight = (freq / globalMaxFreq) * plotH
      return h('rect', {
        x: String(x),
        y: String(HIST_PAD_T + plotH - barHeight),
        width: String(Math.max(barW - 1, 1)),
        height: String(barHeight),
        fill: colorFor(di),
        opacity: '0.7',
      })
    }),
  )

  const xTicks = Array.from({ length: binCount + 1 }, (_, i) => {
    const val = globalMin + i * binWidth
    const x = HIST_PAD_L + i * barGroupW
    return h(
      Fragment,
      {},
      h('line', {
        x1: String(x),
        y1: String(HIST_PAD_T + plotH),
        x2: String(x),
        y2: String(HIST_PAD_T + plotH + 4),
        stroke: '#adb5bd',
        'stroke-width': '1',
      }),
      h(
        'text',
        {
          x: String(x),
          y: String(HIST_PAD_T + plotH + 18),
          'text-anchor': 'middle',
          'font-size': '10',
          'font-family': 'system-ui, sans-serif',
          fill: '#868e96',
        },
        formatNum(val),
      ),
    )
  })

  const yTickCount = 5
  const yTicks = Array.from({ length: yTickCount + 1 }, (_, i) => {
    const val = Math.round((globalMaxFreq / yTickCount) * i)
    const y = scaleY(val)
    return h(
      Fragment,
      {},
      h('line', {
        x1: String(HIST_PAD_L - 4),
        y1: String(y),
        x2: String(HIST_PAD_L),
        y2: String(y),
        stroke: '#adb5bd',
        'stroke-width': '1',
      }),
      h(
        'text',
        {
          x: String(HIST_PAD_L - 8),
          y: String(y + 3),
          'text-anchor': 'end',
          'font-size': '10',
          'font-family': 'system-ui, sans-serif',
          fill: '#868e96',
        },
        String(val),
      ),
    )
  })

  const legend = datasets.map((ds, i) =>
    h(
      Fragment,
      {},
      h('rect', {
        x: String(HIST_PAD_L + i * 100),
        y: '4',
        width: '12',
        height: '12',
        fill: colorFor(i),
