  renderStatsTable,
  renderComparisonTable,
  renderBoxPlot,
  renderHistogram,
} from './render.js'

// ── State ───────────────────────────────────────────────────────

const datasets: NamedDataset[] = []

const DATA_FILE = 'data/datasets.json'

// ── Persistence ─────────────────────────────────────────────────

const saveDatasets = async (): Promise<void> => {
  const serializable = datasets.map((ds) => ({
    name: ds.name,
    data: ds.data,
  }))
  await Bun.write(DATA_FILE, JSON.stringify(serializable, null, 2))
}

const loadDatasets = async (): Promise<void> => {
  const file = Bun.file(DATA_FILE)
  if (await file.exists()) {
    const raw = await file.json() as { name: string; data: number[] }[]
    datasets.length = 0
    for (const entry of raw) {
      datasets.push({
        name: entry.name,
        data: entry.data,
        stats: computeStats(entry.data),
      })
    }
  }
}

// ── Public API ──────────────────────────────────────────────────

export const addDataset = async (
  name: string,
  input: string,
): Promise<{ success: boolean; error?: string }> => {
  const data = parseInputSafe(input)
  if (data.length === 0) {
    return { success: false, error: 'No valid numbers found in input.' }
  }
  if (data.length < 2) {
    return { success: false, error: 'At least 2 data points are required.' }
  }

  const existing = datasets.findIndex((ds) => ds.name === name)
  const entry: NamedDataset = { name, data, stats: computeStats(data) }

  if (existing >= 0) {
    datasets[existing] = entry
  } else {
    datasets.push(entry)
  }
  await saveDatasets()
  return { success: true }
}

export const removeDataset = async (name: string): Promise<boolean> => {
  const idx = datasets.findIndex((ds) => ds.name === name)
  if (idx < 0) return false
  datasets.splice(idx, 1)
  await saveDatasets()
  return true
}

export const clearDatasets = async (): Promise<void> => {
  datasets.length = 0
  await saveDatasets()
}

export const getDatasets = (): NamedDataset[] => [...datasets]

export const getDatasetByName = (name: string): NamedDataset | undefined =>
  datasets.find((ds) => ds.name === name)

// ── Quick compute (no persistence) ─────────────────────────────

export const calculate = (input: string): StatResult | null => {
  const data = parseInputSafe(input)
  if (data.length < 2) return null
  return computeStats(data)
}

