import type { Dataset } from './types'

const CSV_PATTERN = /^[\d\s,.\-eE+]+$/

export const parseInput = (name: string, raw: string): Dataset => {
  const trimmed = raw.trim()
  let values: number[]

  if (trimmed.startsWith('[')) {
    const parsed = JSON.parse(trimmed)
    if (!Array.isArray(parsed)) {
      throw new Error('JSON input must be an array of numbers')
    }
    values = parsed.map((v: unknown) => {
      const n = Number(v)
      if (Number.isNaN(n)) throw new Error(`Invalid number in JSON array: ${v}`)
      return n
    })
  } else if (CSV_PATTERN.test(trimmed)) {
    values = trimmed
      .split(',')
      .map((s) => s.trim())
      .filter((s) => s.length > 0)
      .map((s) => {
        const n = Number(s)
        if (Number.isNaN(n)) throw new Error(`Invalid number: "${s}"`)
        return n
      })
  } else {
    throw new Error(
      'Unrecognized format. Provide comma-separated numbers or a JSON array.'
    )
  }

  if (values.length === 0) {
    throw new Error('Dataset must contain at least one number')
  }

  return { name: name.trim() || 'Untitled', values }
}

import type { Stats, HistogramBin } from './types'

const sorted = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const percentile = (sortedArr: number[], p: number): number => {
  if (sortedArr.length === 1) return sortedArr[0]
  const index = (p / 100) * (sortedArr.length - 1)
  const lower = Math.floor(index)
  const upper = Math.ceil(index)
  if (lower === upper) return sortedArr[lower]
  const weight = index - lower
  return sortedArr[lower] * (1 - weight) + sortedArr[upper] * weight
}

export const computeStats = (values: number[]): Stats => {
  const n = values.length
  const s = sorted(values)

  const sum = s.reduce((acc, v) => acc + v, 0)
  const mean = sum / n

  const median = percentile(s, 50)
  const q1 = percentile(s, 25)
  const q3 = percentile(s, 75)
  const iqr = q3 - q1

  const varianceSum = s.reduce((acc, v) => acc + (v - mean) ** 2, 0)
  const variance = n > 1 ? varianceSum / (n - 1) : 0
  const standardDeviation = Math.sqrt(variance)

  const min = s[0]
  const max = s[n - 1]
  const range = max - min

  // Mode: values with highest frequency
  const freq = new Map<number, number>()
  for (const v of s) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  const mode =
    maxFreq === 1
      ? [] // no mode when all values appear once
      : [...freq.entries()].filter(([, c]) => c === maxFreq).map(([v]) => v)

  return { count: n, mean, median, mode, standardDeviation, variance, min, max, range, q1, q3, iqr }
}

export const computeHistogramBins = (values: number[], binCount = 10): HistogramBin[] => {
  const s = sorted(values)
  const min = s[0]
  const max = s[s.length - 1]

  if (min === max) {
    return [{ lower: min, upper: max, count: values.length }]
  }

  const binWidth = (max - min) / binCount
  const bins: HistogramBin[] = Array.from({ length: binCount }, (_, i) => ({
    lower: min + i * binWidth,
    upper: min + (i + 1) * binWidth,
    count: 0,
  }))

  for (const v of s) {
    let idx = Math.floor((v - min) / binWidth)
    if (idx >= binCount) idx = binCount - 1
    bins[idx].count++
  }

  return bins
}

export const round = (v: number, decimals = 4): number =>
  Math.round(v * 10 ** decimals) / 10 ** decimals

import type { Dataset, StoredDatasets } from './types'

const DATA_PATH = new URL('./data/datasets.json', import.meta.url).pathname

export const loadDatasets = async (): Promise<Dataset[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) {
    await Bun.write(DATA_PATH, JSON.stringify({ datasets: [] } satisfies StoredDatasets))
    return []
  }
  const data: StoredDatasets = await file.json()
  return data.datasets
}

export const saveDatasets = async (datasets: Dataset[]): Promise<void> => {
  const data: StoredDatasets = { datasets }
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const addDataset = async (dataset: Dataset): Promise<Dataset[]> => {
  const datasets = await loadDatasets()
  const existingIdx = datasets.findIndex((d) => d.name === dataset.name)
  if (existingIdx >= 0) {
    datasets[existingIdx] = dataset
  } else {
    datasets.push(dataset)
  }
  await saveDatasets(datasets)
  return datasets
}

export const removeDataset = async (name: string): Promise<Dataset[]> => {
  const datasets = (await loadDatasets()).filter((d) => d.name !== name)
  await saveDatasets(datasets)
  return datasets
}

