// ── Box Plot (SVG) ───────────────────────────────────────────────

const renderBoxPlot = (items: DatasetWithStats[]) => {
  const allValues = items.flatMap((i) => i.dataset.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const padding = (globalMax - globalMin) * 0.05 || 1

  const plotMin = globalMin - padding
  const plotMax = globalMax + padding
  const plotRange = plotMax - plotMin

  const svgWidth = 600
  const plotLeft = 20
  const plotRight = svgWidth - 20
  const plotW = plotRight - plotLeft

  const rowHeight = 48
  const labelHeight = 30
  const svgHeight = items.length * rowHeight + labelHeight + 20

  const x = (v: number): number => plotLeft + ((v - plotMin) / plotRange) * plotW

  // Tick marks
  const tickCount = 8
  const tickStep = plotRange / tickCount
  const ticks: number[] = Array.from({ length: tickCount + 1 }, (_, i) =>
    round(plotMin + i * tickStep, 2)
  )

  return h('svg', {
    width: String(svgWidth),
    height: String(svgHeight),
    viewBox: `0 0 ${svgWidth} ${svgHeight}`,
    style: { display: 'block', margin: '0 auto' },
  },
    // Axis line
    h('line', {
      x1: String(plotLeft), y1: String(svgHeight - labelHeight),
      x2: String(plotRight), y2: String(svgHeight - labelHeight),
      stroke: '#ccd5e0', 'stroke-width': '1',
    }),
    // Tick labels
    ...ticks.map((t) =>
      h('text', {
        x: String(x(t)), y: String(svgHeight - 6),
        'text-anchor': 'middle', 'font-size': '10', fill: '#6c7a8d',
      }, String(round(t, 1)))
    ),
    // Box plots per dataset
    ...items.flatMap((item, i) => {
      const s = item.stats
      const cy = i * rowHeight + rowHeight / 2 + 4
      const boxH = 24
      const top = cy - boxH / 2
      const color = colorFor(i)

      const whiskerLow = Math.max(s.min, s.q1 - 1.5 * s.iqr)
      const whiskerHigh = Math.min(s.max, s.q3 + 1.5 * s.iqr)

      // Outliers
      const outliers = item.dataset.values.filter(
        (v) => v < whiskerLow || v > whiskerHigh
      )

      return [
        // Dataset label
        h('text', {
          x: String(plotLeft), y: String(top - 4),
          'font-size': '11', fill: color, 'font-weight': '600',
        }, item.dataset.name),
        // Whisker line
        h('line', {
          x1: String(x(whiskerLow)), y1: String(cy),
          x2: String(x(whiskerHigh)), y2: String(cy),
          stroke: color, 'stroke-width': '1.5',
        }),
        // Whisker caps
        h('line', {
          x1: String(x(whiskerLow)), y1: String(top + 4),
          x2: String(x(whiskerLow)), y2: String(top + boxH - 4),
          stroke: color, 'stroke-width': '1.5',
        }),
        h('line', {
          x1: String(x(whiskerHigh)), y1: String(top + 4),
          x2: String(x(whiskerHigh)), y2: String(top + boxH - 4),
          stroke: color, 'stroke-width': '1.5',
        }),
        // Box
        h('rect', {
          x: String(x(s.q1)), y: String(top),
          width: String(Math.max(x(s.q3) - x(s.q1), 1)),
          height: String(boxH),
          fill: color, 'fill-opacity': '0.2',
          stroke: color, 'stroke-width': '1.5',
          rx: '3',
        }),
        // Median line
        h('line', {
          x1: String(x(s.median)), y1: String(top),
          x2: String(x(s.median)), y2: String(top + boxH),
          stroke: color, 'stroke-width': '2.5',
        }),
        // Mean dot
        h('circle', {
          cx: String(x(s.mean)), cy: String(cy),
          r: '3.5', fill: '#fff', stroke: color, 'stroke-width': '1.5',
        }),
        // Outliers
        ...outliers.map((v) =>
          h('circle', {
            cx: String(x(v)), cy: String(cy),
            r: '2.5', fill: color, 'fill-opacity': '0.5',
          })
        ),
      ]
    })
  )
}

// ── Histogram (SVG) ──────────────────────────────────────────────

const renderHistogram = (items: DatasetWithStats[]) => {
  const binCount = Math.min(20, Math.max(5, Math.ceil(Math.sqrt(
    Math.max(...items.map((i) => i.dataset.values.length))
  ))))

  const allValues = items.flatMap((i) => i.dataset.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const padding = (globalMax - globalMin) * 0.02 || 0.5
  const bMin = globalMin - padding
  const bMax = globalMax + padding
  const binWidth = (bMax - bMin) / binCount

  // Compute bins per dataset using shared boundaries
  const allBins: HistogramBin[][] = items.map((item) => {
    const bins: HistogramBin[] = Array.from({ length: binCount }, (_, i) => ({
      lower: bMin + i * binWidth,
      upper: bMin + (i + 1) * binWidth,
      count: 0,
    }))
    for (const v of item.dataset.values) {
      let idx = Math.floor((v - bMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      if (idx < 0) idx = 0
      bins[idx].count++
    }
    return bins
  })

  const maxCount = Math.max(...allBins.flat().map((b) => b.count), 1)

  const svgWidth = 600
  const svgHeight = 280
  const plotLeft = 40
  const plotRight = svgWidth - 20
  const plotTop = 20
  const plotBottom = svgHeight - 36
  const plotW = plotRight - plotLeft
  const plotH = plotBottom - plotTop

  const barGroupWidth = plotW / binCount
  const barWidth = barGroupWidth / items.length
  const yScale = plotH / maxCount

  // Y-axis ticks
  const yTicks = 5
  const yTickStep = maxCount / yTicks
  const yTickValues = Array.from({ length: yTicks + 1 }, (_, i) =>
    Math.round(i * yTickStep)
  )

  // X-axis ticks (every other bin boundary)
  const xTicks = allBins[0]
    .filter((_, i) => i % Math.max(1, Math.floor(binCount / 8)) === 0)
    .map((b) => ({ value: b.lower, x: plotLeft + ((b.lower - bMin) / (bMax - bMin)) * plotW }))

  return h('svg', {
    width: String(svgWidth),
    height: String(svgHeight),
    viewBox: `0 0 ${svgWidth} ${svgHeight}`,
    style: { display: 'block', margin: '0 auto' },
  },
    // Y-axis
    h('line', {
      x1: String(plotLeft), y1: String(plotTop),
      x2: String(plotLeft), y2: String(plotBottom),
      stroke: '#ccd5e0', 'stroke-width': '1',
    }),
    // X-axis
    h('line', {
      x1: String(plotLeft), y1: String(plotBottom),
      x2: String(plotRight), y2: String(plotBottom),
      stroke: '#ccd5e0', 'stroke-width': '1',
    }),
    // Y tick labels
    ...yTickValues.map((t) =>
      h('text', {
        x: String(plotLeft - 6), y: String(plotBottom - t * yScale + 4),
        'text-anchor': 'end', 'font-size': '10', fill: '#6c7a8d',
      }, String(t))
    ),
    // X tick labels
    ...xTicks.map(({ value, x: xPos }) =>
      h('text', {
        x: String(xPos), y: String(plotBottom + 16),
        'text-anchor': 'middle', 'font-size': '10', fill: '#6c7a8d',
      }, String(round(value, 1)))
    ),
    // Bars
    ...allBins.flatMap((bins, di) =>
      bins.map((bin, bi) => {
        const barH = bin.count * yScale
        const xPos = plotLeft + bi * barGroupWidth + di * barWidth
        return h('rect', {
          x: String(xPos),
          y: String(plotBottom - barH),
          width: String(Math.max(barWidth - 1, 1)),
          height: String(barH),
          fill: colorFor(di),
          'fill-opacity': '0.65',
          rx: '1',
        })
      })
    ),
    // Legend
    ...items.map((item, i) =>
      h(Fragment, {},
        h('rect', {
          x: String(plotLeft + i * 120),
          y: '4',
          width: '10',
          height: '10',
          fill: colorFor(i),
          rx: '2',
        }),
        h('text', {
          x: String(plotLeft + i * 120 + 14),
          y: '13',
          'font-size': '11',
          fill: '#1a1a2e',
          'font-weight': '500',
        }, item.dataset.name)
      )
    )
  )
}

