import type { DatasetWithStats } from './types'
import { parseInput } from './parse'
import { computeStats } from './stats'
import { loadDatasets, addDataset, removeDataset } from './storage'
import { renderPage } from './render'

const buildItems = async (): Promise<DatasetWithStats[]> => {
  const datasets = await loadDatasets()
  return datasets.map((dataset) => ({
    dataset,
    stats: computeStats(dataset.values),
  }))
}

const htmlResponse = (html: string, status = 200): Response =>
  new Response(`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8"/>
  <meta name="viewport" content="width=device-width, initial-scale=1"/>
  <title>Statistics Calculator</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #eef1f6; padding: 24px; }
  </style>
</head>
<body>${html}</body>
</html>`, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data, null, 2), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const errorPage = (message: string): Response =>
  htmlResponse(`<div style="max-width:600px;margin:80px auto;text-align:center;font-family:system-ui;">
    <h2 style="color:#ea4335;margin-bottom:12px;">Error</h2>
    <p>${message}</p>
    <a href="/" style="display:inline-block;margin-top:16px;color:#4285f4;">Back</a>
  </div>`, 400)

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)

    // ── GET / — render the dashboard ──────────────────────────
    if (url.pathname === '/' && req.method === 'GET') {
      const items = await buildItems()
      return htmlResponse(renderPage(items))
    }

    // ── POST /add — add a dataset ─────────────────────────────
    if (url.pathname === '/add' && req.method === 'POST') {
      const contentType = req.headers.get('content-type') ?? ''
      let name: string
      let data: string

      if (contentType.includes('application/json')) {
        const body = (await req.json()) as Record<string, string>
        name = body.name ?? ''
        data = body.data ?? ''
      } else {
        const form = await req.formData()
        name = String(form.get('name') ?? '')
        data = String(form.get('data') ?? '')
      }

      try {
        const dataset = parseInput(name, data)
        await addDataset(dataset)
      } catch (err) {
        return errorPage((err as Error).message)
      }

      // Redirect back to dashboard for form submissions
      if (!contentType.includes('application/json')) {
        return Response.redirect(new URL('/', url.origin).toString(), 303)
      }

      const items = await buildItems()
      return jsonResponse(items)
    }

    // ── GET /remove?name=X — remove a dataset ─────────────────
    if (url.pathname === '/remove') {
      const name = url.searchParams.get('name')
      if (name) await removeDataset(name)
      return Response.redirect(new URL('/', url.origin).toString(), 303)
    }

    // ── GET /api/stats — JSON API ─────────────────────────────
    if (url.pathname === '/api/stats' && req.method === 'GET') {
      const items = await buildItems()
      return jsonResponse(items)
    }

    // ── POST /api/calculate — stateless calculation ───────────
    if (url.pathname === '/api/calculate' && req.method === 'POST') {
      const body = (await req.json()) as Record<string, string>
      try {
        const dataset = parseInput(body.name ?? 'Untitled', body.data ?? '')
        const stats = computeStats(dataset.values)
        return jsonResponse({ dataset, stats })
      } catch (err) {
        return jsonResponse({ error: (err as Error).message }, 400)
      }
    }

    return new Response('Not Found', { status: 404 })
  },
})

