export type ParseResult =
  | { ok: true; values: number[] }
  | { ok: false; error: string }

export const parseDataset = (input: string): ParseResult => {
  const trimmed = input.trim()
  if (!trimmed) {
    return { ok: false, error: 'Input is empty' }
  }

  let raw: unknown[]

  if (trimmed.startsWith('[')) {
    try {
      const parsed = JSON.parse(trimmed)
      if (!Array.isArray(parsed)) {
        return { ok: false, error: 'JSON input must be an array' }
      }
      raw = parsed
    } catch {
      return { ok: false, error: 'Invalid JSON array' }
    }
  } else {
    raw = trimmed.split(',').map((s) => s.trim())
  }

  const values: number[] = []
  for (const item of raw) {
    const n = Number(item)
    if (!Number.isFinite(n)) {
      return { ok: false, error: `"${String(item)}" is not a finite number` }
    }
    values.push(n)
  }

  if (values.length === 0) {
    return { ok: false, error: 'Dataset contains no values' }
  }

  return { ok: true, values }
}

export type Stats = {
  count: number
  mean: number
  median: number
  mode: number[]
  stddev: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
}

const sortAsc = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const quantile = (sorted: number[], q: number): number => {
  const pos = (sorted.length - 1) * q
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  if (lo === hi) return sorted[lo]
  return sorted[lo] + (sorted[hi] - sorted[lo]) * (pos - lo)
}

export const computeStats = (values: number[]): Stats => {
  const sorted = sortAsc(values)
  const n = sorted.length

  const sum = sorted.reduce((a, b) => a + b, 0)
  const mean = sum / n

  const median = quantile(sorted, 0.5)

  const freqMap = new Map<number, number>()
  let maxFreq = 0
  for (const v of sorted) {
    const f = (freqMap.get(v) ?? 0) + 1
    freqMap.set(v, f)
    if (f > maxFreq) maxFreq = f
  }
  const mode = maxFreq > 1
    ? [...freqMap.entries()].filter(([, f]) => f === maxFreq).map(([v]) => v)
    : []

  const variance = sorted.reduce((acc, v) => acc + (v - mean) ** 2, 0) / n
  const stddev = Math.sqrt(variance)

  const min = sorted[0]
  const max = sorted[n - 1]
  const range = max - min

  const q1 = quantile(sorted, 0.25)
  const q3 = quantile(sorted, 0.75)
  const iqr = q3 - q1

  return { count: n, mean, median, mode, stddev, variance, min, max, range, q1, q3, iqr }
}

export const formatNum = (v: number): string =>
  Number.isInteger(v) ? String(v) : v.toFixed(4)

import { computeStats } from './stats'
import type { Stats } from './stats'

export type Dataset = {
  name: string
  values: number[]
  stats: Stats
}

export type Store = {
  datasets: Dataset[]
}

const DATA_PATH = new URL('./data/datasets.json', import.meta.url).pathname

export const loadStore = async (): Promise<Store> => {
  try {
    const file = Bun.file(DATA_PATH)
    if (await file.exists()) {
      const raw = await file.json()
      return raw as Store
    }
  } catch {
    // fall through to default
  }
  return { datasets: [] }
}

export const saveStore = async (store: Store): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

export const addDataset = async (name: string, values: number[]): Promise<Store> => {
  const store = await loadStore()
  const stats = computeStats(values)
  const existing = store.datasets.findIndex((d) => d.name === name)
  if (existing >= 0) {
    store.datasets[existing] = { name, values, stats }
  } else {
    store.datasets.push({ name, values, stats })
  }
  await saveStore(store)
  return store
}

export const removeDataset = async (name: string): Promise<Store> => {
  const store = await loadStore()
  store.datasets = store.datasets.filter((d) => d.name !== name)
  await saveStore(store)
  return store
}

export const clearStore = async (): Promise<Store> => {
  const store: Store = { datasets: [] }
  await saveStore(store)
  return store
}

