// --- Box Plot SVG ---

const renderBoxPlot = (datasets: Dataset[]) => {
  const allValues = datasets.flatMap((d) => d.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const padding = (globalMax - globalMin) * 0.05 || 1
  const domainMin = globalMin - padding
  const domainMax = globalMax + padding
  const domainRange = domainMax - domainMin

  const svgW = 700
  const marginLeft = 60
  const marginRight = 20
  const plotW = svgW - marginLeft - marginRight
  const rowH = 50
  const marginTop = 30
  const marginBottom = 40
  const svgH = marginTop + datasets.length * rowH + marginBottom

  const scaleX = (v: number): number =>
    marginLeft + ((v - domainMin) / domainRange) * plotW

  // Tick marks
  const tickCount = 8
  const ticks: number[] = []
  for (let i = 0; i <= tickCount; i++) {
    ticks.push(domainMin + (domainRange * i) / tickCount)
  }

  const tickElements = ticks.map((t) =>
    h('g', {},
      h('line', {
        x1: String(scaleX(t)), y1: String(marginTop),
        x2: String(scaleX(t)), y2: String(svgH - marginBottom),
        stroke: '#e0e0e0', 'stroke-width': '1',
      }),
      h('text', {
        x: String(scaleX(t)), y: String(svgH - marginBottom + 16),
        'text-anchor': 'middle', 'font-size': '11', fill: '#666',
      }, formatNum(t))
    )
  )

  const boxElements = datasets.map((ds, i) => {
    const s = ds.stats
    const y = marginTop + i * rowH
    const midY = y + rowH / 2
    const boxTop = y + 10
    const boxBot = y + rowH - 10
    const boxH = boxBot - boxTop
    const color = colorFor(i)

    // whisker lines from min to Q1 and Q3 to max
    const whiskerMin = Math.max(s.min, s.q1 - 1.5 * s.iqr)
    const whiskerMax = Math.min(s.max, s.q3 + 1.5 * s.iqr)

    // outliers
    const outliers = ds.values.filter((v) => v < whiskerMin || v > whiskerMax)

    return h('g', {},
      // left whisker line
      h('line', {
        x1: String(scaleX(whiskerMin)), y1: String(midY),
        x2: String(scaleX(s.q1)), y2: String(midY),
        stroke: color, 'stroke-width': '2',
      }),
      // right whisker line
      h('line', {
        x1: String(scaleX(s.q3)), y1: String(midY),
        x2: String(scaleX(whiskerMax)), y2: String(midY),
        stroke: color, 'stroke-width': '2',
      }),
      // whisker caps
      h('line', {
        x1: String(scaleX(whiskerMin)), y1: String(boxTop),
        x2: String(scaleX(whiskerMin)), y2: String(boxBot),
        stroke: color, 'stroke-width': '2',
      }),
      h('line', {
        x1: String(scaleX(whiskerMax)), y1: String(boxTop),
        x2: String(scaleX(whiskerMax)), y2: String(boxBot),
        stroke: color, 'stroke-width': '2',
      }),
      // box
      h('rect', {
        x: String(scaleX(s.q1)), y: String(boxTop),
        width: String(scaleX(s.q3) - scaleX(s.q1)), height: String(boxH),
        fill: color, 'fill-opacity': '0.25',
        stroke: color, 'stroke-width': '2',
        rx: '3',
      }),
      // median line
      h('line', {
        x1: String(scaleX(s.median)), y1: String(boxTop),
        x2: String(scaleX(s.median)), y2: String(boxBot),
        stroke: color, 'stroke-width': '3',
      }),
      // mean diamond
      h('polygon', {
        points: `${scaleX(s.mean)},${boxTop} ${scaleX(s.mean) + 5},${midY} ${scaleX(s.mean)},${boxBot} ${scaleX(s.mean) - 5},${midY}`,
        fill: color,
      }),
      // outlier dots
      ...outliers.map((v) =>
        h('circle', {
          cx: String(scaleX(v)), cy: String(midY), r: '3',
          fill: 'none', stroke: color, 'stroke-width': '1.5',
        })
      ),
      // label
      h('text', {
        x: String(marginLeft - 8), y: String(midY + 4),
        'text-anchor': 'end', 'font-size': '12', 'font-weight': '600', fill: color,
      }, ds.name)
    )
  })

  return h('div', { style: styles.svgContainer },
    h('svg', {
      width: String(svgW), height: String(svgH),
      viewBox: `0 0 ${svgW} ${svgH}`,
      xmlns: 'http://www.w3.org/2000/svg',
    },
      ...tickElements,
      ...boxElements
    )
  )
}

// --- Histogram SVG ---

const renderHistogram = (datasets: Dataset[]) => {
  const allValues = datasets.flatMap((d) => d.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const padding = (globalMax - globalMin) * 0.05 || 1
  const domainMin = globalMin - padding
  const domainMax = globalMax + padding

  const binCount = Math.max(5, Math.min(30, Math.ceil(Math.sqrt(allValues.length))))
  const binWidth = (domainMax - domainMin) / binCount

  // compute bins per dataset
  const datasetBins: number[][] = datasets.map((ds) => {
    const bins = new Array<number>(binCount).fill(0)
    for (const v of ds.values) {
      let idx = Math.floor((v - domainMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      if (idx < 0) idx = 0
      bins[idx]++
    }
    return bins
  })

  const maxBin = Math.max(...datasetBins.flat(), 1)

  const svgW = 700
  const marginLeft = 50
  const marginRight = 20
  const marginTop = 20
  const marginBottom = 50
  const plotW = svgW - marginLeft - marginRight
  const plotH = 200
  const svgH = marginTop + plotH + marginBottom

  const barGroupW = plotW / binCount
  const barW = barGroupW / datasets.length - 1

  const scaleY = (v: number): number =>
    marginTop + plotH - (v / maxBin) * plotH

  // x-axis ticks
  const xTicks: { label: string; x: number }[] = []
  const tickStep = Math.max(1, Math.floor(binCount / 8))
  for (let i = 0; i <= binCount; i += tickStep) {
    xTicks.push({
      label: formatNum(domainMin + i * binWidth),
      x: marginLeft + i * barGroupW,
    })
  }

  // y-axis ticks
  const yTickCount = 5
  const yTicks: { label: string; y: number }[] = []
  for (let i = 0; i <= yTickCount; i++) {
    const val = (maxBin * i) / yTickCount
    yTicks.push({ label: String(Math.round(val)), y: scaleY(val) })
  }

  const barElements = datasetBins.flatMap((bins, di) =>
    bins.map((count, bi) => {
      const x = marginLeft + bi * barGroupW + di * (barW + 1)
      const barHeight = (count / maxBin) * plotH
      return h('rect', {
        x: String(x), y: String(marginTop + plotH - barHeight),
        width: String(Math.max(barW, 1)), height: String(barHeight),
        fill: colorFor(di), 'fill-opacity': '0.7',
        rx: '1',
      })
    })
  )

  return h('div', { style: styles.svgContainer },
    h('svg', {
      width: String(svgW), height: String(svgH),
      viewBox: `0 0 ${svgW} ${svgH}`,
      xmlns: 'http://www.w3.org/2000/svg',
    },
      // y-axis grid + labels
      ...yTicks.map((t) =>
        h('g', {},
          h('line', {
            x1: String(marginLeft), y1: String(t.y),
            x2: String(svgW - marginRight), y2: String(t.y),
            stroke: '#e0e0e0', 'stroke-width': '1',
          }),
          h('text', {
            x: String(marginLeft - 8), y: String(t.y + 4),
            'text-anchor': 'end', 'font-size': '11', fill: '#666',
          }, t.label)
        )
      ),
      // x-axis labels
      ...xTicks.map((t) =>
        h('text', {
          x: String(t.x), y: String(svgH - marginBottom + 18),
          'text-anchor': 'middle', 'font-size': '11', fill: '#666',
        }, t.label)
      ),
      // bars
      ...barElements,
      // axis label
      h('text', {
        x: String(marginLeft + plotW / 2), y: String(svgH - 4),
        'text-anchor': 'middle', 'font-size': '12', fill: '#444',
      }, 'Value'),
      h('text', {
        x: String(12), y: String(marginTop + plotH / 2),
        'text-anchor': 'middle', 'font-size': '12', fill: '#444',
        transform: `rotate(-90 12 ${marginTop + plotH / 2})`,
      }, 'Frequency')
    )
  )
}

