import { parseDataset } from './parse'
import { loadStore, addDataset, removeDataset, clearStore } from './store'
import { renderPage } from './render'

const PORT = Number(Bun.env.PORT ?? 3000)

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)

  if (req.method === 'GET' && url.pathname === '/') {
    const store = await loadStore()
    const html = renderPage(store)
    return new Response(wrapHtml(html), {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  if (req.method === 'POST' && url.pathname === '/add') {
    const form = await req.formData()
    const name = String(form.get('datasetName') ?? '').trim()
    const rawValues = String(form.get('datasetValues') ?? '').trim()

    if (!name) {
      const store = await loadStore()
      const html = renderPage(store, 'Dataset name is required')
      return new Response(wrapHtml(html), {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    const result = parseDataset(rawValues)
    if (!result.ok) {
      const store = await loadStore()
      const html = renderPage(store, result.error)
      return new Response(wrapHtml(html), {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    const store = await addDataset(name, result.values)
    const html = renderPage(store)
    return new Response(wrapHtml(html), {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  if (req.method === 'POST' && url.pathname === '/remove') {
    const form = await req.formData()
    const name = String(form.get('name') ?? '').trim()
    const store = await removeDataset(name)
    const html = renderPage(store)
    return new Response(wrapHtml(html), {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  if (req.method === 'POST' && url.pathname === '/clear') {
    const store = await clearStore()
    const html = renderPage(store)
    return new Response(wrapHtml(html), {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  // API endpoint: POST JSON
  if (req.method === 'POST' && url.pathname === '/api/calculate') {
    const body = await req.json() as { name?: string; values?: string }
    const name = (body.name ?? 'default').trim()
    const raw = body.values ?? ''

    const result = parseDataset(raw)
    if (!result.ok) {
      return Response.json({ error: result.error }, { status: 400 })
    }

    const store = await addDataset(name, result.values)
    const ds = store.datasets.find((d) => d.name === name)
    return Response.json({ datasets: store.datasets.map((d) => ({ name: d.name, stats: d.stats })), current: ds })
  }

  if (req.method === 'GET' && url.pathname === '/api/datasets') {
    const store = await loadStore()
    return Response.json({ datasets: store.datasets.map((d) => ({ name: d.name, stats: d.stats, values: d.values })) })
  }

  return new Response('Not found', { status: 404 })
}

const wrapHtml = (body: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Statistics Calculator</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #fafafa; }
  </style>
</head>
<body>
  ${body}
  <script>
    // Wire up form submission and button actions
    document.addEventListener('DOMContentLoaded', () => {
      const form = document.querySelector('form')
      if (form) {
        form.addEventListener('submit', async (e) => {
          e.preventDefault()
          const fd = new FormData(form)
          const res = await fetch('/add', { method: 'POST', body: fd })
          document.documentElement.innerHTML = await res.text()
        })
      }

      // Clear all button
      document.querySelectorAll('[p-trigger*="clearAll"]').forEach((btn) => {
        btn.addEventListener('click', async () => {
          const res = await fetch('/clear', { method: 'POST' })
          document.documentElement.innerHTML = await res.text()
        })
      })

      // Remove dataset buttons
      document.querySelectorAll('[p-trigger*="remove:"]').forEach((btn) => {
        const trigger = btn.getAttribute('p-trigger') ?? ''
        const match = trigger.match(/remove:(.+)$/)
        if (match) {
          const name = match[1]
          btn.addEventListener('click', async () => {
            const fd = new FormData()
            fd.set('name', name)
            const res = await fetch('/remove', { method: 'POST', body: fd })
            document.documentElement.innerHTML = await res.text()
          })
        }
      })
    })
  </script>
</body>
</html>`

Bun.serve({
  port: PORT,
  fetch: handleRequest,
})

console.log(`Statistics Calculator running at http://localhost:${PORT}`)

