export type PendulumParams = {
  length: number
  gravity: number
  initialAngle: number
}

export type PendulumState = {
  angle: number
  angularVelocity: number
  angularAcceleration: number
  position: Vec2
}

export type ProjectileParams = {
  angle: number
  initialVelocity: number
  gravity: number
}

export type ProjectileState = {
  position: Vec2
  velocity: Vec2
  acceleration: Vec2
  trajectory: Vec2[]
  landed: boolean
}

export type SpringParams = {
  springConstant: number
  mass: number
  initialDisplacement: number
}

export type SpringState = {
  displacement: number
  velocity: number
  acceleration: number
}

export type PhysicsReadout = {
  position: string
  velocity: string
  acceleration: string
}

import type {
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  PhysicsReadout,
} from './types'

// --- Pendulum ---

export const createPendulumState = (params: PendulumParams): PendulumState => ({
  angle: params.initialAngle,
  angularVelocity: 0,
  angularAcceleration: -(params.gravity / params.length) * Math.sin(params.initialAngle),
  position: {
    x: params.length * Math.sin(params.initialAngle),
    y: -params.length * Math.cos(params.initialAngle),
  },
})

export const updatePendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number
): PendulumState => {
  // Use Runge-Kutta 4th order for accuracy
  const { length, gravity } = params
  const accelFn = (theta: number): number => -(gravity / length) * Math.sin(theta)

  const k1v = accelFn(state.angle) * dt
  const k1x = state.angularVelocity * dt

  const k2v = accelFn(state.angle + k1x / 2) * dt
  const k2x = (state.angularVelocity + k1v / 2) * dt

  const k3v = accelFn(state.angle + k2x / 2) * dt
  const k3x = (state.angularVelocity + k2v / 2) * dt

  const k4v = accelFn(state.angle + k3x) * dt
  const k4x = (state.angularVelocity + k3v) * dt

  const angle = state.angle + (k1x + 2 * k2x + 2 * k3x + k4x) / 6
  const angularVelocity = state.angularVelocity + (k1v + 2 * k2v + 2 * k3v + k4v) / 6
  const angularAcceleration = accelFn(angle)

  return {
    angle,
    angularVelocity,
    angularAcceleration,
    position: {
      x: length * Math.sin(angle),
      y: -length * Math.cos(angle),
    },
  }
}

export const getPendulumReadout = (state: PendulumState): PhysicsReadout => ({
  position: `θ = ${(state.angle * 180 / Math.PI).toFixed(2)}°`,
  velocity: `ω = ${state.angularVelocity.toFixed(3)} rad/s`,
  acceleration: `α = ${state.angularAcceleration.toFixed(3)} rad/s²`,
})

// --- Projectile ---

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const angleRad = (params.angle * Math.PI) / 180
  return {
    position: { x: 0, y: 0 },
    velocity: {
      x: params.initialVelocity * Math.cos(angleRad),
      y: params.initialVelocity * Math.sin(angleRad),
    },
    acceleration: { x: 0, y: -params.gravity },
    trajectory: [{ x: 0, y: 0 }],
    landed: false,
  }
}

export const updateProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number
): ProjectileState => {
  if (state.landed) return state

  const newVx = state.velocity.x
  const newVy = state.velocity.y - params.gravity * dt

  const newX = state.position.x + state.velocity.x * dt
  let newY = state.position.y + state.velocity.y * dt - 0.5 * params.gravity * dt * dt

  const landed = newY <= 0 && state.position.y > 0
  if (landed) newY = 0

  const newPos = { x: newX, y: Math.max(0, newY) }
  const trajectory = [...state.trajectory, { ...newPos }]

  return {
    position: newPos,
    velocity: { x: newVx, y: landed ? 0 : newVy },
    acceleration: { x: 0, y: landed ? 0 : -params.gravity },
    trajectory,
    landed,
  }
}

export const getProjectileReadout = (state: ProjectileState): PhysicsReadout => {
  const speed = Math.sqrt(state.velocity.x ** 2 + state.velocity.y ** 2)
  return {
    position: `x = ${state.position.x.toFixed(2)} m, y = ${state.position.y.toFixed(2)} m`,
    velocity: `v = ${speed.toFixed(2)} m/s (vx=${state.velocity.x.toFixed(2)}, vy=${state.velocity.y.toFixed(2)})`,
    acceleration: `a = ${Math.abs(state.acceleration.y).toFixed(2)} m/s² (gravity)`,
  }
}

// --- Spring-Mass ---

export const createSpringState = (params: SpringParams): SpringState => ({
  displacement: params.initialDisplacement,
  velocity: 0,
  acceleration: -(params.springConstant / params.mass) * params.initialDisplacement,
})

export const updateSpring = (
  state: SpringState,
  params: SpringParams,
  dt: number
): SpringState => {
  // Simple harmonic motion with RK4
  const { springConstant, mass } = params
  const omega2 = springConstant / mass
  const accelFn = (x: number): number => -omega2 * x

  const k1v = accelFn(state.displacement) * dt
  const k1x = state.velocity * dt

  const k2v = accelFn(state.displacement + k1x / 2) * dt
  const k2x = (state.velocity + k1v / 2) * dt

  const k3v = accelFn(state.displacement + k2x / 2) * dt
  const k3x = (state.velocity + k2v / 2) * dt

  const k4v = accelFn(state.displacement + k3x) * dt
  const k4x = (state.velocity + k3v) * dt

  const displacement = state.displacement + (k1x + 2 * k2x + 2 * k3x + k4x) / 6
  const velocity = state.velocity + (k1v + 2 * k2v + 2 * k3v + k4v) / 6
  const acceleration = accelFn(displacement)

  return { displacement, velocity, acceleration }
}

export const getSpringReadout = (state: SpringState): PhysicsReadout => ({
  position: `x = ${state.displacement.toFixed(4)} m`,
  velocity: `v = ${state.velocity.toFixed(4)} m/s`,
  acceleration: `a = ${state.acceleration.toFixed(4)} m/s²`,
})

import { createSSR } from 'plaited'
import type {
  SimState,
  SimulationType,
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  PhysicsReadout,
} from './types'
import {
  createPendulumState,
  updatePendulum,
  getPendulumReadout,
  createProjectileState,
  updateProjectile,
  getProjectileReadout,
  createSpringState,
  updateSpring,
  getSpringReadout,
} from './physics'
import {
  renderSimulator,
  renderPendulumSVG,
  renderProjectileSVG,
  renderSpringSVG,
  renderPendulumParams,
  renderProjectileParams,
  renderSpringParams,
} from './renderer'

const CANVAS_WIDTH = 800
const CANVAS_HEIGHT = 600
const DT = 1 / 60

// --- Default Parameters ---

const defaultPendulumParams: PendulumParams = {
  length: 1.5,
  gravity: 9.81,
  initialAngle: (30 * Math.PI) / 180,
}

const defaultProjectileParams: ProjectileParams = {
  angle: 45,
  initialVelocity: 20,
  gravity: 9.81,
}

const defaultSpringParams: SpringParams = {
  springConstant: 10,
  mass: 1,
  initialDisplacement: 0.5,
}

// --- Simulation Manager ---

type SimulationStore = {
  simState: SimState
  pendulumParams: PendulumParams
  pendulumState: PendulumState
  projectileParams: ProjectileParams
  projectileState: ProjectileState
  springParams: SpringParams
  springState: SpringState
  animationFrame: number | null
}

const createStore = (): SimulationStore => ({
  simState: {
    time: 0,
    isRunning: false,
    speed: 1,
    activeSimulation: 'pendulum',
  },
  pendulumParams: { ...defaultPendulumParams },
  pendulumState: createPendulumState(defaultPendulumParams),
  projectileParams: { ...defaultProjectileParams },
  projectileState: createProjectileState(defaultProjectileParams),
  springParams: { ...defaultSpringParams },
  springState: createSpringState(defaultSpringParams),
  animationFrame: null,
})

const getCurrentSVG = (store: SimulationStore): string => {
  switch (store.simState.activeSimulation) {
    case 'pendulum':
      return renderPendulumSVG(store.pendulumState, store.pendulumParams, CANVAS_WIDTH, CANVAS_HEIGHT)
    case 'projectile':
      return renderProjectileSVG(store.projectileState, store.projectileParams, CANVAS_WIDTH, CANVAS_HEIGHT)
    case 'spring':
      return renderSpringSVG(store.springState, store.springParams, CANVAS_WIDTH, CANVAS_HEIGHT)
  }
}

const getCurrentReadout = (store: SimulationStore): PhysicsReadout => {
  switch (store.simState.activeSimulation) {
    case 'pendulum':
      return getPendulumReadout(store.pendulumState)
    case 'projectile':
      return getProjectileReadout(store.projectileState)
    case 'spring':
      return getSpringReadout(store.springState)
  }
}

const getCurrentParamsHTML = (store: SimulationStore): string => {
  switch (store.simState.activeSimulation) {
    case 'pendulum':
      return renderPendulumParams(store.pendulumParams)
    case 'projectile':
      return renderProjectileParams(store.projectileParams)
    case 'spring':
      return renderSpringParams(store.springParams)
  }
}

const stepSimulation = (store: SimulationStore): void => {
  const dt = DT * store.simState.speed

  switch (store.simState.activeSimulation) {
    case 'pendulum':
      store.pendulumState = updatePendulum(store.pendulumState, store.pendulumParams, dt)
      break
    case 'projectile':
      store.projectileState = updateProjectile(store.projectileState, store.projectileParams, dt)
      break
    case 'spring':
      store.springState = updateSpring(store.springState, store.springParams, dt)
      break
  }

  store.simState.time += dt
}

// --- Event Handlers ---

const handleTabChange = (store: SimulationStore, tab: SimulationType): SimulationStore => {
  if (store.animationFrame !== null) {
    cancelAnimationFrame(store.animationFrame)
  }
  return {
    ...store,
    simState: {
      ...store.simState,
      activeSimulation: tab,
      isRunning: false,
      time: 0,
    },
    pendulumState: createPendulumState(store.pendulumParams),
    projectileState: createProjectileState(store.projectileParams),
    springState: createSpringState(store.springParams),
    animationFrame: null,
  }
}

const handleParamChange = (
  store: SimulationStore,
  paramId: string,
  value: number
): SimulationStore => {
  const updated = { ...store }

  switch (store.simState.activeSimulation) {
    case 'pendulum': {
      const params = { ...store.pendulumParams }
      if (paramId === 'length') params.length = value
      else if (paramId === 'gravity') params.gravity = value
      else if (paramId === 'initialAngle') params.initialAngle = (value * Math.PI) / 180
      updated.pendulumParams = params
      updated.pendulumState = createPendulumState(params)
      break
    }
    case 'projectile': {
      const params = { ...store.projectileParams }
      if (paramId === 'angle') params.angle = value
      else if (paramId === 'initialVelocity') params.initialVelocity = value
      else if (paramId === 'gravity') params.gravity = value
      updated.projectileParams = params
      updated.projectileState = createProjectileState(params)
      break
    }
    case 'spring': {
      const params = { ...store.springParams }
      if (paramId === 'springConstant') params.springConstant = value
      else if (paramId === 'mass') params.mass = value
      else if (paramId === 'initialDisplacement') params.initialDisplacement = value
      updated.springParams = params
      updated.springState = createSpringState(params)
      break
    }
  }

  updated.simState = { ...updated.simState, time: 0, isRunning: false }
  return updated
}

const handleReset = (store: SimulationStore): SimulationStore => {
  if (store.animationFrame !== null) {
    cancelAnimationFrame(store.animationFrame)
  }
  return {
    ...store,
    simState: { ...store.simState, time: 0, isRunning: false },
    pendulumState: createPendulumState(store.pendulumParams),
    projectileState: createProjectileState(store.projectileParams),
    springState: createSpringState(store.springParams),
    animationFrame: null,
  }
}

// --- Server-Side Rendering ---

export const renderInitialPage = (): string => {
  const store = createStore()
  const svg = getCurrentSVG(store)
  const readout = getCurrentReadout(store)
  const paramsHTML = getCurrentParamsHTML(store)
  return renderSimulator(store.simState, svg, readout, paramsHTML)
}

// --- Client-Side Animation Loop ---

export const createSimulationController = () => {
  let store = createStore()

  const getFullHTML = (): string => {
    const svg = getCurrentSVG(store)
    const readout = getCurrentReadout(store)
    const paramsHTML = getCurrentParamsHTML(store)
    return renderSimulator(store.simState, svg, readout, paramsHTML)
  }

  const tick = (updateDOM: (html: string) => void): void => {
    if (!store.simState.isRunning) return

    stepSimulation(store)
    updateDOM(getFullHTML())

    store.animationFrame = requestAnimationFrame(() => tick(updateDOM))
  }

  return {
    getHTML: getFullHTML,

    play: (updateDOM: (html: string) => void): void => {
      store.simState.isRunning = true
      updateDOM(getFullHTML())
      tick(updateDOM)
    },

    pause: (updateDOM: (html: string) => void): void => {
      store.simState.isRunning = false
      if (store.animationFrame !== null) {
        cancelAnimationFrame(store.animationFrame)
        store.animationFrame = null
      }
      updateDOM(getFullHTML())
    },

    reset: (updateDOM: (html: string) => void): void => {
      store = handleReset(store)
      updateDOM(getFullHTML())
    },

    changeTab: (tab: SimulationType, updateDOM: (html: string) => void): void => {
      store = handleTabChange(store, tab)
      updateDOM(getFullHTML())
    },

    changeParam: (paramId: string, value: number, updateDOM: (html: string) => void): void => {
      store = handleParamChange(store, paramId, value)
      updateDOM(getFullHTML())
    },

    changeSpeed: (speed: number, updateDOM: (html: string) => void): void => {
      store.simState.speed = speed
      updateDOM(getFullHTML())
    },

    getStore: (): SimulationStore => store,
  }
}

