import type { PhysicsState, PendulumParams, ProjectileParams, SpringParams, Vec2 } from './types'

export const createInitialState = (): PhysicsState => ({
  position: { x: 0, y: 0 },
  velocity: { x: 0, y: 0 },
  acceleration: { x: 0, y: 0 },
  time: 0,
})

// --- Pendulum Physics ---
// θ'' = -(g/L)*sin(θ) - damping*θ'
// Uses Runge-Kutta 4th order integration

export const pendulumStep = (
  theta: number,
  omega: number,
  params: PendulumParams,
  dt: number
): { theta: number; omega: number; state: PhysicsState } => {
  const { length, gravity, damping } = params

  const accelFn = (th: number, om: number): number =>
    -(gravity / length) * Math.sin(th) - damping * om

  // RK4 integration
  const k1v = accelFn(theta, omega)
  const k1x = omega

  const k2v = accelFn(theta + 0.5 * dt * k1x, omega + 0.5 * dt * k1v)
  const k2x = omega + 0.5 * dt * k1v

  const k3v = accelFn(theta + 0.5 * dt * k2x, omega + 0.5 * dt * k2v)
  const k3x = omega + 0.5 * dt * k2v

  const k4v = accelFn(theta + dt * k3x, omega + dt * k3v)
  const k4x = omega + dt * k3v

  const newTheta = theta + (dt / 6) * (k1x + 2 * k2x + 2 * k3x + k4x)
  const newOmega = omega + (dt / 6) * (k1v + 2 * k2v + 2 * k3v + k4v)
  const angularAccel = accelFn(newTheta, newOmega)

  const px = length * Math.sin(newTheta)
  const py = length * Math.cos(newTheta)
  const tangentialVel = length * newOmega
  const tangentialAccel = length * angularAccel

  return {
    theta: newTheta,
    omega: newOmega,
    state: {
      position: { x: px, y: py },
      velocity: {
        x: tangentialVel * Math.cos(newTheta),
        y: -tangentialVel * Math.sin(newTheta),
      },
      acceleration: {
        x: tangentialAccel * Math.cos(newTheta),
        y: -tangentialAccel * Math.sin(newTheta),
      },
      time: 0,
    },
  }
}

// --- Projectile Physics ---
// x = v0*cos(α)*t, y = v0*sin(α)*t - 0.5*g*t²

export const projectileAt = (
  params: ProjectileParams,
  t: number
): PhysicsState => {
  const rad = (params.angle * Math.PI) / 180
  const vx = params.velocity * Math.cos(rad)
  const vy = params.velocity * Math.sin(rad)
  const g = params.gravity

  return {
    position: {
      x: vx * t,
      y: vy * t - 0.5 * g * t * t,
    },
    velocity: {
      x: vx,
      y: vy - g * t,
    },
    acceleration: {
      x: 0,
      y: -g,
    },
    time: t,
  }
}

export const projectileFlightTime = (params: ProjectileParams): number => {
  const rad = (params.angle * Math.PI) / 180
  return (2 * params.velocity * Math.sin(rad)) / params.gravity
}

export const projectileMaxRange = (params: ProjectileParams): number => {
  const rad = (params.angle * Math.PI) / 180
  const vx = params.velocity * Math.cos(rad)
  return vx * projectileFlightTime(params)
}

export const projectileMaxHeight = (params: ProjectileParams): number => {
  const rad = (params.angle * Math.PI) / 180
  const vy = params.velocity * Math.sin(rad)
  return (vy * vy) / (2 * params.gravity)
}

// --- Spring-Mass Physics ---
// x'' = -(k/m)*x - damping*x'
// Uses RK4 integration

export const springStep = (
  x: number,
  v: number,
  params: SpringParams,
  dt: number
): { x: number; v: number; state: PhysicsState } => {
  const { springK, mass, damping } = params

  const accelFn = (pos: number, vel: number): number =>
    -(springK / mass) * pos - (damping / mass) * vel

  const k1v = accelFn(x, v)
  const k1x = v

  const k2v = accelFn(x + 0.5 * dt * k1x, v + 0.5 * dt * k1v)
  const k2x = v + 0.5 * dt * k1v

  const k3v = accelFn(x + 0.5 * dt * k2x, v + 0.5 * dt * k2v)
  const k3x = v + 0.5 * dt * k2v

  const k4v = accelFn(x + dt * k3x, v + dt * k3v)
  const k4x = v + dt * k3v

  const newX = x + (dt / 6) * (k1x + 2 * k2x + 2 * k3x + k4x)
  const newV = v + (dt / 6) * (k1v + 2 * k2v + 2 * k3v + k4v)
  const newA = accelFn(newX, newV)

  return {
    x: newX,
    v: newV,
    state: {
      position: { x: newX, y: 0 },
      velocity: { x: newV, y: 0 },
      acceleration: { x: newA, y: 0 },
      time: 0,
    },
  }
}

export const springPeriod = (k: number, m: number): number =>
  2 * Math.PI * Math.sqrt(m / k)

export const springFrequency = (k: number, m: number): number =>
  1 / springPeriod(k, m)

export const magnitude = (v: Vec2): number =>
  Math.sqrt(v.x * v.x + v.y * v.y)

