const clientScript = `
(function() {
  const SIMS = ['pendulum', 'projectile', 'spring'];
  let activeSim = 'pendulum';
  let playing = false;
  let speed = 1;
  let lastFrame = 0;

  // --- Pendulum State ---
  let pTheta = Math.PI / 4;
  let pOmega = 0;
  let pLength = 1.5;
  let pGravity = 9.81;
  const pDamping = 0.002;
  let pTime = 0;
  let pTrail = [];

  // --- Projectile State ---
  let prAngle = 45;
  let prVelocity = 25;
  const prGravity = 9.81;
  let prTime = 0;
  let prPath = [];
  let prDone = false;

  // --- Spring State ---
  let spX = 1.0;
  let spV = 0;
  let spK = 20;
  let spMass = 3;
  const spDamping = 0.1;
  let spTime = 0;
  let spTrail = [];

  // DOM refs
  const tabs = document.querySelectorAll('.tab');
  const simPanels = document.querySelectorAll('.sim-panel');
  const svgPendulum = document.getElementById('svg-pendulum');
  const svgProjectile = document.getElementById('svg-projectile');
  const svgSpring = document.getElementById('svg-spring');
  const btnPlay = document.getElementById('btn-play');
  const btnReset = document.getElementById('btn-reset');
  const speedSlider = document.getElementById('speed-slider');
  const speedVal = document.getElementById('speed-val');

  // Readouts
  const rPos = document.getElementById('r-pos');
  const rVel = document.getElementById('r-vel');
  const rAcc = document.getElementById('r-acc');
  const rTime = document.getElementById('r-time');

  // Info rows
  const infoExtra1 = document.getElementById('info-extra1');
  const infoExtra2 = document.getElementById('info-extra2');

  // --- Tab Switching ---
  tabs.forEach(tab => {
    tab.addEventListener('click', () => {
      const sim = tab.dataset.sim;
      activeSim = sim;
      tabs.forEach(t => t.classList.toggle('active', t.dataset.sim === sim));
      simPanels.forEach(p => p.classList.toggle('active', p.dataset.sim === sim));
      document.querySelectorAll('.canvas-area svg').forEach(s => s.style.display = 'none');
      document.getElementById('svg-' + sim).style.display = 'block';
      resetSim();
    });
  });

  // --- Controls ---
  btnPlay.addEventListener('click', () => {
    playing = !playing;
    btnPlay.textContent = playing ? 'Pause' : 'Play';
    btnPlay.classList.toggle('primary', playing);
    if (playing) { lastFrame = performance.now(); requestAnimationFrame(loop); }
  });

  btnReset.addEventListener('click', resetSim);

  speedSlider.addEventListener('input', () => {
    speed = parseFloat(speedSlider.value);
    speedVal.textContent = speed.toFixed(2) + 'x';
  });

  // --- Parameter Sliders ---
  const bindSlider = (id, cb) => {
    const el = document.getElementById(id);
    if (!el) return;
    el.addEventListener('input', () => { cb(parseFloat(el.value)); });
  };

  bindSlider('p-length', v => {
    pLength = v;
    document.getElementById('p-length-val').textContent = v.toFixed(1) + ' m';
    resetSim();
  });
  bindSlider('p-gravity', v => {
    pGravity = v;
    document.getElementById('p-gravity-val').textContent = v.toFixed(1) + ' m/s\\u00B2';
    resetSim();
  });
  bindSlider('pr-angle', v => {
    prAngle = v;
    document.getElementById('pr-angle-val').textContent = v + '\\u00B0';
    resetSim();
  });
  bindSlider('pr-velocity', v => {
    prVelocity = v;
    document.getElementById('pr-velocity-val').textContent = v + ' m/s';
    resetSim();
  });
  bindSlider('sp-k', v => {
    spK = v;
    document.getElementById('sp-k-val').textContent = v + ' N/m';
    resetSim();
  });
  bindSlider('sp-mass', v => {
    spMass = v;
    document.getElementById('sp-mass-val').textContent = v.toFixed(1) + ' kg';
    resetSim();
  });

  // --- Preset Buttons ---
  document.querySelectorAll('.preset-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const data = JSON.parse(btn.dataset.preset);
      const sim = btn.dataset.sim;
      if (sim === 'pendulum') {
        pLength = data.length; pGravity = data.gravity;
        document.getElementById('p-length').value = data.length;
        document.getElementById('p-gravity').value = data.gravity;
        document.getElementById('p-length-val').textContent = data.length.toFixed(1) + ' m';
        document.getElementById('p-gravity-val').textContent = data.gravity.toFixed(1) + ' m/s\\u00B2';
      } else if (sim === 'projectile') {
        prAngle = data.angle; prVelocity = data.velocity;
        document.getElementById('pr-angle').value = data.angle;
        document.getElementById('pr-velocity').value = data.velocity;
        document.getElementById('pr-angle-val').textContent = data.angle + '\\u00B0';
        document.getElementById('pr-velocity-val').textContent = data.velocity + ' m/s';
      } else if (sim === 'spring') {
        spK = data.springK; spMass = data.mass;
        document.getElementById('sp-k').value = data.springK;
        document.getElementById('sp-mass').value = data.mass;
        document.getElementById('sp-k-val').textContent = data.springK + ' N/m';
        document.getElementById('sp-mass-val').textContent = data.mass.toFixed(1) + ' kg';
      }
      resetSim();
    });
  });

  function resetSim() {
    playing = false;
    btnPlay.textContent = 'Play';
    btnPlay.classList.remove('primary');

    if (activeSim === 'pendulum') {
      pTheta = Math.PI / 4; pOmega = 0; pTime = 0; pTrail = [];
      drawPendulum();
    } else if (activeSim === 'projectile') {
      prTime = 0; prPath = []; prDone = false;
      drawProjectile();
    } else if (activeSim === 'spring') {
      spX = 1.0; spV = 0; spTime = 0; spTrail = [];
      drawSpring();
    }
    updateReadout();
  }

  // --- Physics ---
  function stepPendulum(dt) {
    const accel = (th, om) => -(pGravity / pLength) * Math.sin(th) - pDamping * om;
    const k1v = accel(pTheta, pOmega), k1x = pOmega;
    const k2v = accel(pTheta + 0.5*dt*k1x, pOmega + 0.5*dt*k1v), k2x = pOmega + 0.5*dt*k1v;
    const k3v = accel(pTheta + 0.5*dt*k2x, pOmega + 0.5*dt*k2v), k3x = pOmega + 0.5*dt*k2v;
    const k4v = accel(pTheta + dt*k3x, pOmega + dt*k3v), k4x = pOmega + dt*k3v;
    pTheta += (dt/6)*(k1x + 2*k2x + 2*k3x + k4x);
    pOmega += (dt/6)*(k1v + 2*k2v + 2*k3v + k4v);
    pTime += dt;
    const bx = pLength * Math.sin(pTheta);
    const by = pLength * Math.cos(pTheta);
    pTrail.push({x: bx, y: by});
    if (pTrail.length > 200) pTrail.shift();
  }

  function stepProjectile(dt) {
    if (prDone) return;
    prTime += dt;
    const rad = prAngle * Math.PI / 180;
    const y = prVelocity * Math.sin(rad) * prTime - 0.5 * prGravity * prTime * prTime;
    const x = prVelocity * Math.cos(rad) * prTime;
    if (y < 0 && prTime > 0.01) { prDone = true; return; }
    prPath.push({x, y});
  }

  function stepSpring(dt) {
    const accel = (pos, vel) => -(spK / spMass) * pos - (spDamping / spMass) * vel;
    const k1v = accel(spX, spV), k1x = spV;
    const k2v = accel(spX + 0.5*dt*k1x, spV + 0.5*dt*k1v), k2x = spV + 0.5*dt*k1v;
    const k3v = accel(spX + 0.5*dt*k2x, spV + 0.5*dt*k2v), k3x = spV + 0.5*dt*k2v;
    const k4v = accel(spX + dt*k3x, spV + dt*k3v), k4x = spV + dt*k3v;
    spX += (dt/6)*(k1x + 2*k2x + 2*k3x + k4x);
    spV += (dt/6)*(k1v + 2*k2v + 2*k3v + k4v);
    spTime += dt;
    spTrail.push({x: spTime, y: spX});
    if (spTrail.length > 400) spTrail.shift();
  }

  // --- Drawing ---
  const W = 600, H = 450;
  const ns = 'http://www.w3.org/2000/svg';
  function svgEl(tag, attrs, parent) {
    const el = document.createElementNS(ns, tag);
    for (const [k,v] of Object.entries(attrs)) el.setAttribute(k, v);
    if (parent) parent.appendChild(el);
    return el;
  }
  function clearSvg(svg) { while (svg.firstChild) svg.removeChild(svg.firstChild); }

  function drawPendulum() {
    clearSvg(svgPendulum);
    const cx = W/2, cy = 60;
    const scale = 130;
    const bx = cx + pLength * Math.sin(pTheta) * scale;
    const by = cy + pLength * Math.cos(pTheta) * scale;

    // Trail
    if (pTrail.length > 1) {
      let d = 'M ' + (cx + pTrail[0].x * scale) + ' ' + (cy + pTrail[0].y * scale);
      for (let i = 1; i < pTrail.length; i++) {
        d += ' L ' + (cx + pTrail[i].x * scale) + ' ' + (cy + pTrail[i].y * scale);
      }
      svgEl('path', {d, stroke: '#4ecdc4', 'stroke-width': '1.5', fill: 'none', class: 'trail', opacity: '0.4'}, svgPendulum);
    }

    // Pivot
    svgEl('circle', {cx, cy, r: '5', fill: '#6c9eff'}, svgPendulum);

    // Rod
    svgEl('line', {x1: cx, y1: cy, x2: bx, y2: by, stroke: '#888', 'stroke-width': '2'}, svgPendulum);

    // Bob
    svgEl('circle', {cx: bx, cy: by, r: '18', fill: '#4ecdc4', stroke: '#3ba89f', 'stroke-width': '2'}, svgPendulum);

    // Velocity vector
    const vMag = pLength * pOmega;
    const vx = vMag * Math.cos(pTheta) * 20;
    const vy = -vMag * Math.sin(pTheta) * 20;
    svgEl('line', {x1: bx, y1: by, x2: bx + vx, y2: by + vy, stroke: '#ffe66d', 'stroke-width': '2', 'marker-end': 'url(#arrow-vel)'}, svgPendulum);

    // Acceleration vector
    const aAngular = -(pGravity / pLength) * Math.sin(pTheta);
    const ax = aAngular * pLength * Math.cos(pTheta) * 8;
    const ay = -aAngular * pLength * Math.sin(pTheta) * 8;
    svgEl('line', {x1: bx, y1: by, x2: bx + ax, y2: by + ay, stroke: '#ff6b6b', 'stroke-width': '2', 'marker-end': 'url(#arrow-acc)'}, svgPendulum);

    addArrowDefs(svgPendulum);

    // Angle arc
    if (Math.abs(pTheta) > 0.02) {
      const arcR = 30;
      const startX = cx, startY = cy + arcR;
      const endX = cx + arcR * Math.sin(pTheta);
      const endY = cy + arcR * Math.cos(pTheta);
      const sweep = pTheta > 0 ? 1 : 0;
      svgEl('path', {
        d: 'M ' + startX + ' ' + startY + ' A ' + arcR + ' ' + arcR + ' 0 0 ' + sweep + ' ' + endX + ' ' + endY,
        stroke: '#c084fc', 'stroke-width': '1.5', fill: 'none', opacity: '0.7'
      }, svgPendulum);
    }

    // Ground line
    svgEl('line', {x1: 50, y1: H - 20, x2: W - 50, y2: H - 20, stroke: '#333', 'stroke-width': '1', 'stroke-dasharray': '4,4'}, svgPendulum);
  }

  function drawProjectile() {
    clearSvg(svgProjectile);
    const ox = 50, oy = H - 50;
    const rad = prAngle * Math.PI / 180;
    const flightTime = (2 * prVelocity * Math.sin(rad)) / prGravity;
    const maxRange = prVelocity * Math.cos(rad) * flightTime;
    const maxH = (prVelocity * Math.sin(rad))**2 / (2 * prGravity);
    const scaleX = (W - 100) / Math.max(maxRange, 1);
    const scaleY = (H - 100) / Math.max(maxH, 1);
    const scale = Math.min(scaleX, scaleY) * 0.9;

    // Ground
    svgEl('line', {x1: 30, y1: oy, x2: W - 20, y2: oy, stroke: '#444', 'stroke-width': '1'}, svgProjectile);

    // Reference trajectory (dotted)
    let refD = '';
    for (let t = 0; t <= flightTime; t += flightTime/100) {
      const rx = prVelocity * Math.cos(rad) * t;
      const ry = prVelocity * Math.sin(rad) * t - 0.5 * prGravity * t * t;
      const px = ox + rx * scale;
      const py = oy - ry * scale;
      refD += (t === 0 ? 'M ' : ' L ') + px + ' ' + py;
    }
    svgEl('path', {d: refD, stroke: '#333', 'stroke-width': '1', fill: 'none', 'stroke-dasharray': '4,4'}, svgProjectile);

    // Actual path
    if (prPath.length > 1) {
      let d = 'M ' + (ox + prPath[0].x * scale) + ' ' + (oy - prPath[0].y * scale);
      for (let i = 1; i < prPath.length; i++) {
        d += ' L ' + (ox + prPath[i].x * scale) + ' ' + (oy - prPath[i].y * scale);
      }
      svgEl('path', {d, stroke: '#4ecdc4', 'stroke-width': '2.5', fill: 'none'}, svgProjectile);
    }

    // Current position
    const curX = prVelocity * Math.cos(rad) * prTime;
    const curY = Math.max(0, prVelocity * Math.sin(rad) * prTime - 0.5 * prGravity * prTime * prTime);
    const px = ox + curX * scale;
    const py = oy - curY * scale;
    svgEl('circle', {cx: px, cy: py, r: '8', fill: '#4ecdc4', stroke: '#3ba89f', 'stroke-width': '2'}, svgProjectile);

    // Velocity vector
    const vx = prVelocity * Math.cos(rad);
    const vy = prVelocity * Math.sin(rad) - prGravity * prTime;
    const vScale = 2;
    addArrowDefs(svgProjectile);
    svgEl('line', {x1: px, y1: py, x2: px + vx*vScale, y2: py - vy*vScale, stroke: '#ffe66d', 'stroke-width': '2', 'marker-end': 'url(#arrow-vel)'}, svgProjectile);

    // Acceleration vector (always down)
    svgEl('line', {x1: px, y1: py, x2: px, y2: py + 30, stroke: '#ff6b6b', 'stroke-width': '2', 'marker-end': 'url(#arrow-acc)'}, svgProjectile);

    // Labels
    svgEl('text', {x: W - 70, y: oy + 18, fill: '#666', 'font-size': '11'}, svgProjectile).textContent = 'Range';
    svgEl('text', {x: 12, y: 25, fill: '#666', 'font-size': '11'}, svgProjectile).textContent = 'Height';

    // Launch angle indicator
    const angLen = 40;
    svgEl('line', {x1: ox, y1: oy, x2: ox + angLen * Math.cos(rad), y2: oy - angLen * Math.sin(rad), stroke: '#c084fc', 'stroke-width': '1.5', opacity: '0.7'}, svgProjectile);
  }

  function drawSpring() {
    clearSvg(svgSpring);
    const wallX = 60, cy = H / 2;
    const eqX = W / 2;
    const scale = 100;
    const massX = eqX + spX * scale;
    const massR = 20;

    // Wall
    svgEl('line', {x1: wallX, y1: cy - 80, x2: wallX, y2: cy + 80, stroke: '#666', 'stroke-width': '3'}, svgSpring);
    for (let i = -80; i < 80; i += 12) {
      svgEl('line', {x1: wallX - 8, y1: cy + i + 12, x2: wallX, y2: cy + i, stroke: '#555', 'stroke-width': '1'}, svgSpring);
    }

    // Spring coils
    const coils = 12;
    const springStart = wallX + 5;
    const springEnd = massX - massR;
    const segLen = (springEnd - springStart) / (coils * 2);
    let springD = 'M ' + springStart + ' ' + cy;
    for (let i = 0; i < coils * 2; i++) {
      const sx = springStart + segLen * (i + 1);
      const sy = cy + (i % 2 === 0 ? -18 : 18);
      springD += ' L ' + sx + ' ' + sy;
    }
    springD += ' L ' + springEnd + ' ' + cy;
    svgEl('path', {d: springD, stroke: '#6c9eff', 'stroke-width': '2', fill: 'none'}, svgSpring);

    // Mass
    svgEl('rect', {
      x: massX - massR, y: cy - massR, width: massR * 2, height: massR * 2,
      rx: '4', fill: '#4ecdc4', stroke: '#3ba89f', 'stroke-width': '2'
    }, svgSpring);

    // Equilibrium line
    svgEl('line', {x1: eqX, y1: cy - 60, x2: eqX, y2: cy + 60, stroke: '#444', 'stroke-width': '1', 'stroke-dasharray': '4,4'}, svgSpring);
    svgEl('text', {x: eqX - 8, y: cy + 78, fill: '#666', 'font-size': '10'}, svgSpring).textContent = 'x=0';

    // Velocity vector
    addArrowDefs(svgSpring);
    svgEl('line', {x1: massX, y1: cy, x2: massX + spV * 20, y2: cy, stroke: '#ffe66d', 'stroke-width': '2', 'marker-end': 'url(#arrow-vel)'}, svgSpring);

    // Force/acceleration vector
    const acc = -(spK / spMass) * spX;
    svgEl('line', {x1: massX, y1: cy + 30, x2: massX + acc * 8, y2: cy + 30, stroke: '#ff6b6b', 'stroke-width': '2', 'marker-end': 'url(#arrow-acc)'}, svgSpring);

    // Displacement graph (trail)
    if (spTrail.length > 1) {
      const gx = 60, gy = H - 70, gw = W - 120, gh = 50;
      svgEl('rect', {x: gx, y: gy - gh, width: gw, height: gh * 2, fill: '#12141f', rx: '4', stroke: '#2a2d3a', 'stroke-width': '1'}, svgSpring);
      svgEl('line', {x1: gx, y1: gy, x2: gx + gw, y2: gy, stroke: '#333', 'stroke-width': '1'}, svgSpring);

      const tMin = spTrail[0].x, tMax = spTrail[spTrail.length-1].x;
      const tRange = Math.max(tMax - tMin, 0.1);
      let d = '';
      for (let i = 0; i < spTrail.length; i++) {
        const tx = gx + ((spTrail[i].x - tMin) / tRange) * gw;
        const ty = gy - spTrail[i].y * (gh * 0.8);
        d += (i === 0 ? 'M ' : ' L ') + tx + ' ' + ty;
      }
      svgEl('path', {d, stroke: '#4ecdc4', 'stroke-width': '1.5', fill: 'none'}, svgSpring);
      svgEl('text', {x: gx + gw / 2 - 30, y: gy + gh + 18, fill: '#666', 'font-size': '10'}, svgSpring).textContent = 'displacement vs time';
    }

    // Ground
    svgEl('line', {x1: 50, y1: cy + 40, x2: W - 50, y2: cy + 40, stroke: '#333', 'stroke-width': '1', 'stroke-dasharray': '4,4'}, svgSpring);
  }

  function addArrowDefs(svg) {
    if (svg.querySelector('defs')) return;
    const defs = svgEl('defs', {}, svg);
    const mkMarker = (id, color) => {
      const m = svgEl('marker', {id, viewBox: '0 0 10 10', refX: '9', refY: '5', markerWidth: '6', markerHeight: '6', orient: 'auto-start-reverse'}, defs);
      svgEl('path', {d: 'M 0 0 L 10 5 L 0 10 z', fill: color}, m);
    };
    mkMarker('arrow-vel', '#ffe66d');
    mkMarker('arrow-acc', '#ff6b6b');
  }

  // --- Readout ---
  function updateReadout() {
    let pos, vel, acc, time;
    if (activeSim === 'pendulum') {
      const bx = pLength * Math.sin(pTheta);
      const by = pLength * Math.cos(pTheta);
      const v = pLength * pOmega;
      const a = pLength * (-(pGravity/pLength) * Math.sin(pTheta));
      pos = Math.sqrt(bx*bx + by*by).toFixed(3);
      vel = Math.abs(v).toFixed(3);
      acc = Math.abs(a).toFixed(3);
      time = pTime.toFixed(2);
      const period = 2 * Math.PI * Math.sqrt(pLength / pGravity);
      infoExtra1.innerHTML = '<span>Period (est.)</span><span class="info-val">' + period.toFixed(3) + ' s</span>';
      infoExtra2.innerHTML = '<span>Angle</span><span class="info-val">' + (pTheta * 180 / Math.PI).toFixed(1) + '\\u00B0</span>';
    } else if (activeSim === 'projectile') {
      const rad = prAngle * Math.PI / 180;
      const x = prVelocity * Math.cos(rad) * prTime;
      const y = Math.max(0, prVelocity * Math.sin(rad) * prTime - 0.5 * prGravity * prTime * prTime);
      const vx = prVelocity * Math.cos(rad);
      const vy = prVelocity * Math.sin(rad) - prGravity * prTime;
      pos = '(' + x.toFixed(1) + ', ' + y.toFixed(1) + ')';
      vel = Math.sqrt(vx*vx + vy*vy).toFixed(2);
      acc = prGravity.toFixed(2);
      time = prTime.toFixed(2);
      const maxH = (prVelocity * Math.sin(rad))**2 / (2 * prGravity);
      const range = prVelocity * Math.cos(rad) * (2 * prVelocity * Math.sin(rad)) / prGravity;
      infoExtra1.innerHTML = '<span>Max Height</span><span class="info-val">' + maxH.toFixed(1) + ' m</span>';
      infoExtra2.innerHTML = '<span>Range</span><span class="info-val">' + range.toFixed(1) + ' m</span>';
    } else {
      const acc_v = -(spK / spMass) * spX;
      pos = spX.toFixed(4);
      vel = Math.abs(spV).toFixed(4);
      acc = Math.abs(acc_v).toFixed(4);
      time = spTime.toFixed(2);
      const period = 2 * Math.PI * Math.sqrt(spMass / spK);
      const freq = 1 / period;
      infoExtra1.innerHTML = '<span>Period</span><span class="info-val">' + period.toFixed(3) + ' s</span>';
      infoExtra2.innerHTML = '<span>Frequency</span><span class="info-val">' + freq.toFixed(3) + ' Hz</span>';
    }
    rPos.textContent = pos;
    rVel.textContent = vel;
    rAcc.textContent = acc;
    rTime.textContent = time + ' s';
  }

  // --- Animation Loop ---
  const physDt = 0.001;
  function loop(ts) {
    if (!playing) return;
    const elapsed = Math.min((ts - lastFrame) / 1000, 0.05) * speed;
    lastFrame = ts;
    const steps = Math.floor(elapsed / physDt);

    for (let i = 0; i < steps; i++) {
      if (activeSim === 'pendulum') stepPendulum(physDt);
      else if (activeSim === 'projectile') stepProjectile(physDt);
      else stepSpring(physDt);
    }

    if (activeSim === 'pendulum') drawPendulum();
    else if (activeSim === 'projectile') drawProjectile();
    else drawSpring();

    updateReadout();
    requestAnimationFrame(loop);
  }

  // Initial draw
  document.getElementById('svg-projectile').style.display = 'none';
  document.getElementById('svg-spring').style.display = 'none';
  resetSim();
})();
`

