import { renderPage } from './renderer'
import type { Presets } from './types'

const DATA_PATH = new URL('../data/presets.json', import.meta.url).pathname

const loadPresets = async (): Promise<Presets> => {
  const file = Bun.file(DATA_PATH)
  return file.json()
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)

    if (url.pathname === '/' || url.pathname === '/index.html') {
      const presets = await loadPresets()
      const html = renderPage(presets)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (url.pathname === '/api/presets') {
      const presets = await loadPresets()
      return new Response(JSON.stringify(presets), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    if (url.pathname === '/api/presets' && req.method === 'POST') {
      const body = await req.json() as Presets
      await Bun.write(DATA_PATH, JSON.stringify(body, null, 2))
      return new Response(JSON.stringify({ ok: true }), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

