// Core simulation engine using RK4 integration for accuracy

export type DerivativeFn = (state: number[], t: number) => number[]

/**
 * 4th-order Runge-Kutta integrator for accurate physics simulation.
 * Takes current state vector, time, timestep, and derivative function.
 * Returns the new state vector after one integration step.
 */
export const rk4Step = (
  state: number[],
  t: number,
  dt: number,
  derivs: DerivativeFn
): number[] => {
  const k1 = derivs(state, t)
  const k2 = derivs(
    state.map((s, i) => s + 0.5 * dt * k1[i]),
    t + 0.5 * dt
  )
  const k3 = derivs(
    state.map((s, i) => s + 0.5 * dt * k2[i]),
    t + 0.5 * dt
  )
  const k4 = derivs(
    state.map((s, i) => s + dt * k3[i]),
    t + dt
  )

  return state.map(
    (s, i) => s + (dt / 6) * (k1[i] + 2 * k2[i] + 2 * k3[i] + k4[i])
  )
}

/**
 * Clamp a value between min and max
 */
export const clamp = (value: number, min: number, max: number): number =>
  Math.min(Math.max(value, min), max)

/**
 * Round to N decimal places for display
 */
export const roundTo = (value: number, decimals: number): number => {
  const factor = 10 ** decimals
  return Math.round(value * factor) / factor
}

import { rk4Step } from './sim-engine'
import type { PendulumParams, PendulumState } from './types'

/**
 * Simple pendulum simulation using the exact nonlinear equation of motion:
 *   θ'' = -(g/L) sin(θ) - b θ'
 * where θ is angle from vertical, g is gravity, L is length, b is damping.
 *
 * State vector: [θ, θ']
 */

const DT = 0.001 // Fixed internal timestep for stability

const pendulumDerivatives = (params: PendulumParams) =>
  (state: number[], _t: number): number[] => {
    const [theta, omega] = state
    const { length, gravity, damping } = params
    const alpha = -(gravity / length) * Math.sin(theta) - damping * omega
    return [omega, alpha]
  }

export const createPendulumState = (params: PendulumParams): PendulumState => ({
  time: 0,
  angle: params.initialAngle,
  angularVelocity: 0,
  angularAcceleration: -(params.gravity / params.length) * Math.sin(params.initialAngle),
  bobPosition: {
    x: params.length * Math.sin(params.initialAngle),
    y: params.length * Math.cos(params.initialAngle),
  },
})

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  frameDt: number
): PendulumState => {
  const derivs = pendulumDerivatives(params)
  let stateVec = [state.angle, state.angularVelocity]
  let t = state.time

  // Sub-step with fixed DT for numerical stability
  let remaining = frameDt
  while (remaining > 0) {
    const step = Math.min(DT, remaining)
    stateVec = rk4Step(stateVec, t, step, derivs)
    t += step
    remaining -= step
  }

  const [angle, angularVelocity] = stateVec
  const angularAcceleration =
    -(params.gravity / params.length) * Math.sin(angle) - params.damping * angularVelocity

  return {
    time: t,
    angle,
    angularVelocity,
    angularAcceleration,
    bobPosition: {
      x: params.length * Math.sin(angle),
      y: params.length * Math.cos(angle),
    },
  }
}

/**
 * Compute theoretical period: T = 2π√(L/g) (small-angle approximation)
 */
export const pendulumPeriod = (params: PendulumParams): number =>
  2 * Math.PI * Math.sqrt(params.length / params.gravity)

import type { ProjectileParams, ProjectileState, Vec2 } from './types'

/**
 * Projectile motion under constant gravitational acceleration.
 * Uses analytical solution (no drag):
 *   x(t) = v₀ cos(θ) t
 *   y(t) = v₀ sin(θ) t - ½ g t²
 *   vx(t) = v₀ cos(θ)
 *   vy(t) = v₀ sin(θ) - g t
 */

const TRAIL_INTERVAL = 0.05 // seconds between trail points

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const angleRad = (params.angle * Math.PI) / 180
  return {
    time: 0,
    position: { x: 0, y: 0 },
    velocity: {
      x: params.initialVelocity * Math.cos(angleRad),
      y: params.initialVelocity * Math.sin(angleRad),
    },
    acceleration: { x: 0, y: -params.gravity },
    trail: [{ x: 0, y: 0 }],
    landed: false,
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  frameDt: number
): ProjectileState => {
  if (state.landed) return state

  const angleRad = (params.angle * Math.PI) / 180
  const v0x = params.initialVelocity * Math.cos(angleRad)
  const v0y = params.initialVelocity * Math.sin(angleRad)
  const g = params.gravity

  const t = state.time + frameDt

  const x = v0x * t
  const y = v0y * t - 0.5 * g * t * t

  // Check if projectile has landed
  if (y <= 0 && t > 0) {
    // Find exact landing time: 0 = v0y * t_land - 0.5 * g * t_land^2
    // t_land = 2 * v0y / g
    const tLand = (2 * v0y) / g
    const xLand = v0x * tLand

    const trail = [...state.trail, { x: xLand, y: 0 }]
    return {
      time: tLand,
      position: { x: xLand, y: 0 },
      velocity: { x: v0x, y: -v0y },
      acceleration: { x: 0, y: -g },
      trail,
      landed: true,
    }
  }

  const position: Vec2 = { x, y }
  const velocity: Vec2 = { x: v0x, y: v0y - g * t }

  // Add trail points at regular intervals
  const lastTrailTime = (state.trail.length - 1) * TRAIL_INTERVAL
  const trail =
    t - lastTrailTime >= TRAIL_INTERVAL
      ? [...state.trail, { ...position }]
      : [...state.trail]

  return {
    time: t,
    position,
    velocity,
    acceleration: { x: 0, y: -g },
    trail,
    landed: false,
  }
}

/**
 * Compute flight statistics analytically
 */
export const projectileStats = (params: ProjectileParams) => {
  const angleRad = (params.angle * Math.PI) / 180
  const v0 = params.initialVelocity
  const g = params.gravity

  const timeOfFlight = (2 * v0 * Math.sin(angleRad)) / g
  const maxHeight = (v0 * v0 * Math.sin(angleRad) ** 2) / (2 * g)
  const range = (v0 * v0 * Math.sin(2 * angleRad)) / g

  return { timeOfFlight, maxHeight, range }
}

