}

const defaultSpringMassParams: SpringMassParams = {
  springConstant: 20,
  mass: 1.0,
  initialDisplacement: 1.0,
  damping: 0,
}

// --- State Management ---

const createInitialState = (): AppState => ({
  activeTab: 'pendulum',
  playback: 'stopped',
  speed: 1,
  pendulumParams: { ...defaultPendulumParams },
  projectileParams: { ...defaultProjectileParams },
  springMassParams: { ...defaultSpringMassParams },
  pendulumState: createPendulumState(defaultPendulumParams),
  projectileState: createProjectileState(defaultProjectileParams),
  springMassState: createSpringMassState(defaultSpringMassParams),
})

export type ActionHandler = (state: AppState, payload?: Record<string, unknown>) => AppState

const actions: Record<string, ActionHandler> = {
  onPlay: (state) => ({ ...state, playback: 'playing' as PlaybackState }),

  onPause: (state) => ({ ...state, playback: 'paused' as PlaybackState }),

  onReset: (state) => ({
    ...state,
    playback: 'stopped' as PlaybackState,
    pendulumState: createPendulumState(state.pendulumParams),
    projectileState: createProjectileState(state.projectileParams),
    springMassState: createSpringMassState(state.springMassParams),
  }),

  onTabChange: (state, payload) => ({
    ...state,
    activeTab: (payload?.tab as SimulationType) ?? state.activeTab,
  }),

  onSpeedChange: (state, payload) => ({
    ...state,
    speed: (payload?.speed as number) ?? state.speed,
  }),

  onParamChange: (state, payload) => {
    const { id, value } = payload as { id: string; value: number }

    if (id === 'pendulum-length') {
      const params = { ...state.pendulumParams, length: value }
      return { ...state, pendulumParams: params, pendulumState: createPendulumState(params), playback: 'stopped' as PlaybackState }
    }
    if (id === 'pendulum-gravity') {
      const params = { ...state.pendulumParams, gravity: value }
      return { ...state, pendulumParams: params, pendulumState: createPendulumState(params), playback: 'stopped' as PlaybackState }
    }
    if (id === 'pendulum-angle') {
      const params = { ...state.pendulumParams, initialAngle: (value * Math.PI) / 180 }
      return { ...state, pendulumParams: params, pendulumState: createPendulumState(params), playback: 'stopped' as PlaybackState }
    }
    if (id === 'projectile-angle') {
      const params = { ...state.projectileParams, angle: value }
      return { ...state, projectileParams: params, projectileState: createProjectileState(params), playback: 'stopped' as PlaybackState }
    }
    if (id === 'projectile-velocity') {
      const params = { ...state.projectileParams, initialVelocity: value }
      return { ...state, projectileParams: params, projectileState: createProjectileState(params), playback: 'stopped' as PlaybackState }
    }
    if (id === 'projectile-gravity') {
      const params = { ...state.projectileParams, gravity: value }
      return { ...state, projectileParams: params, projectileState: createProjectileState(params), playback: 'stopped' as PlaybackState }
    }
    if (id === 'spring-k') {
      const params = { ...state.springMassParams, springConstant: value }
      return { ...state, springMassParams: params, springMassState: createSpringMassState(params), playback: 'stopped' as PlaybackState }
    }
    if (id === 'spring-mass') {
      const params = { ...state.springMassParams, mass: value }
      return { ...state, springMassParams: params, springMassState: createSpringMassState(params), playback: 'stopped' as PlaybackState }
    }
    if (id === 'spring-disp') {
      const params = { ...state.springMassParams, initialDisplacement: value }
      return { ...state, springMassParams: params, springMassState: createSpringMassState(params), playback: 'stopped' as PlaybackState }
    }

    return state
  },

  tick: (state, payload) => {
    const dt = ((payload?.dt as number) ?? 16) / 1000 * state.speed

    if (state.playback !== 'playing') return state

    return {
      ...state,
      pendulumState:
        state.activeTab === 'pendulum'
          ? stepPendulum(state.pendulumState, state.pendulumParams, dt)
          : state.pendulumState,
      projectileState:
        state.activeTab === 'projectile'
          ? stepProjectile(state.projectileState, state.projectileParams, dt)
          : state.projectileState,
      springMassState:
        state.activeTab === 'springMass'
          ? stepSpringMass(state.springMassState, state.springMassParams, dt)
          : state.springMassState,
    }
  },
}

// --- Application Controller ---

export const createApp = () => {
  let state = createInitialState()
  let animFrameId: number | null = null
  let lastFrameTime = 0

  const dispatch = (action: string, payload?: Record<string, unknown>) => {
    const handler = actions[action]
    if (handler) {
      state = handler(state, payload)
    }
  }

  const getState = (): AppState => state

  const render = (): string => renderApp(state)

  const renderSSR = () => {
    const ssr = createSSR()
    return ssr(renderApp(state))
  }

  const startLoop = (updateCallback: (html: string) => void) => {
    const frame = (timestamp: number) => {
      const dt = lastFrameTime ? timestamp - lastFrameTime : 16
      lastFrameTime = timestamp

      dispatch('tick', { dt })
      updateCallback(render())

      animFrameId = requestAnimationFrame(frame)
    }
    animFrameId = requestAnimationFrame(frame)
  }

  const stopLoop = () => {
    if (animFrameId !== null) {
      cancelAnimationFrame(animFrameId)
      animFrameId = null
    }
    lastFrameTime = 0
  }

  return { dispatch, getState, render, renderSSR, startLoop, stopLoop }
}

// --- Server entry point ---

export const handleRequest = async (req: Request): Promise<Response> => {
  const app = createApp()
  const html = app.render()

  const fullPage = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Newton's Laws Simulator</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #0f1117; overflow-x: hidden; }
    input[type="range"] {
      -webkit-appearance: none;
      appearance: none;
      background: #2a2d3a;
      border-radius: 4px;
      outline: none;
      height: 4px;
    }
    input[type="range"]::-webkit-slider-thumb {
      -webkit-appearance: none;
      appearance: none;
      width: 16px; height: 16px;
      border-radius: 50%;
      background: #4f8ff7;
      cursor: pointer;
    }
    button:hover { opacity: 0.85; transform: scale(0.98); }
    button:active { transform: scale(0.95); }
  </style>
</head>
<body>
  <div id="root">${html}</div>
  <script>
    (() => {
      let state = ${JSON.stringify(app.getState())};
      const root = document.getElementById('root');

      // Lightweight client-side simulation loop
      const SPEEDS = [0.25, 0.5, 1, 2, 4];
      let playback = 'stopped';
      let speed = 1;
      let activeTab = 'pendulum';
      let lastTime = 0;

      // Physics state stored per simulation
      const pendulum = { angle: state.pendulumState.angle, omega: state.pendulumState.angularVelocity };
      const projectile = { time: 0, landed: false, trail: [] };
      const spring = { x: state.springMassState.displacement, v: state.springMassState.velocity };

      const params = {
        pendulum: { ...state.pendulumParams },
        projectile: { ...state.projectileParams },
        springMass: { ...state.springMassParams },
      };

      // Re-render by fetching updated HTML from server or updating DOM
      // For this client-side version, we post state updates back
      const postUpdate = async (action, payload) => {
        // Client-side state management
        if (action === 'play') playback = 'playing';
        if (action === 'pause') playback = 'paused';
        if (action === 'reset') {
          playback = 'stopped';
          resetSim();
        }
        if (action === 'tab') activeTab = payload.tab;
        if (action === 'speed') speed = payload.speed;
      };

      const resetSim = () => {
        pendulum.angle = params.pendulum.initialAngle;
        pendulum.omega = 0;
        projectile.time = 0;
        projectile.landed = false;
        projectile.trail = [{x:0,y:0}];
        spring.x = params.springMass.initialDisplacement;
        spring.v = 0;
      };

      // Delegate events
      document.addEventListener('click', (e) => {
        const trigger = e.target.closest('[p-trigger]');
        if (!trigger) return;
        const action = trigger.getAttribute('p-trigger').split(':')[1];
        if (action === 'onPlay') postUpdate('play');
        if (action === 'onPause') postUpdate('pause');
        if (action === 'onReset') postUpdate('reset');
        if (action === 'onTabChange') {
          postUpdate('tab', { tab: trigger.dataset.tab });
          playback = 'stopped';
          resetSim();
          requestRefresh();
        }
        if (action === 'onSpeedChange') {
          postUpdate('speed', { speed: parseFloat(trigger.dataset.speed) });
          requestRefresh();
        }
      });

      document.addEventListener('input', (e) => {
        const trigger = e.target.closest('[p-trigger]');
        if (!trigger) return;
        const id = trigger.id;
        const val = parseFloat(trigger.value);
        if (id === 'pendulum-length') params.pendulum.length = val;
        if (id === 'pendulum-gravity') params.pendulum.gravity = val;
        if (id === 'pendulum-angle') params.pendulum.initialAngle = val * Math.PI / 180;
        if (id === 'projectile-angle') params.projectile.angle = val;
        if (id === 'projectile-velocity') params.projectile.initialVelocity = val;
        if (id === 'projectile-gravity') params.projectile.gravity = val;
        if (id === 'spring-k') params.springMass.springConstant = val;
        if (id === 'spring-mass') params.springMass.mass = val;
        if (id === 'spring-disp') params.springMass.initialDisplacement = val;
        playback = 'stopped';
        resetSim();
        requestRefresh();
      });

      // RK4 integration
      const rk4 = (state, t, dt, derivs) => {
        const k1 = derivs(state, t);
        const k2 = derivs(state.map((s,i)=>s+0.5*dt*k1[i]), t+0.5*dt);
        const k3 = derivs(state.map((s,i)=>s+0.5*dt*k2[i]), t+0.5*dt);
        const k4 = derivs(state.map((s,i)=>s+dt*k3[i]), t+dt);
        return state.map((s,i)=>s+(dt/6)*(k1[i]+2*k2[i]+2*k3[i]+k4[i]));
      };

      let simTime = { pendulum: 0, projectile: 0, springMass: 0 };

      const stepSim = (dt) => {
        if (playback !== 'playing') return;
        const frameDt = dt * speed;

        if (activeTab === 'pendulum') {
          const p = params.pendulum;
          const derivs = (s) => [s[1], -(p.gravity/p.length)*Math.sin(s[0])];
          let sv = [pendulum.angle, pendulum.omega];
          let rem = frameDt;
          while (rem > 0) {
            const step = Math.min(0.001, rem);
            sv = rk4(sv, simTime.pendulum, step, derivs);
            simTime.pendulum += step;
            rem -= step;
          }
          pendulum.angle = sv[0];
          pendulum.omega = sv[1];
        }

        if (activeTab === 'projectile' && !projectile.landed) {
          const p = params.projectile;
          const rad = p.angle * Math.PI / 180;
          const v0x = p.initialVelocity * Math.cos(rad);
          const v0y = p.initialVelocity * Math.sin(rad);
          projectile.time += frameDt;
          const t = projectile.time;
          const y = v0y * t - 0.5 * p.gravity * t * t;
          if (y <= 0 && t > 0) {
            projectile.landed = true;
            projectile.time = 2 * v0y / p.gravity;
          }
          const px = v0x * projectile.time;
          const py = Math.max(v0y * projectile.time - 0.5 * p.gravity * projectile.time * projectile.time, 0);
          if (projectile.trail.length === 0 || projectile.time - (projectile.trail.length-1)*0.05 >= 0.05) {
            projectile.trail.push({x:px,y:py});
          }
          simTime.projectile = projectile.time;
        }

        if (activeTab === 'springMass') {
          const p = params.springMass;
          const derivs = (s) => [s[1], -(p.springConstant/p.mass)*s[0]];
          let sv = [spring.x, spring.v];
          let rem = frameDt;
          while (rem > 0) {
            const step = Math.min(0.001, rem);
            sv = rk4(sv, simTime.springMass, step, derivs);
            simTime.springMass += step;
            rem -= step;
          }
          spring.x = sv[0];
          spring.v = sv[1];
        }
      };

      // Refresh via server round-trip for consistent rendering
      let refreshPending = false;
      const requestRefresh = async () => {
        if (refreshPending) return;
        refreshPending = true;
        // Build state for server render
        const p = params.pendulum;
        const pr = params.projectile;
        const sp = params.springMass;
        const rad = pr.angle * Math.PI / 180;

        const appState = {
          activeTab, playback, speed,
          pendulumParams: p,
          projectileParams: pr,
          springMassParams: sp,
          pendulumState: {
            time: simTime.pendulum,
            angle: pendulum.angle,
            angularVelocity: pendulum.omega,
            angularAcceleration: -(p.gravity/p.length)*Math.sin(pendulum.angle),
            bobPosition: { x: p.length*Math.sin(pendulum.angle), y: p.length*Math.cos(pendulum.angle) }
          },
          projectileState: {
            time: projectile.time,
            position: {
              x: pr.initialVelocity*Math.cos(rad)*projectile.time,
              y: Math.max(pr.initialVelocity*Math.sin(rad)*projectile.time - 0.5*pr.gravity*projectile.time*projectile.time, 0)
            },
            velocity: {
              x: pr.initialVelocity*Math.cos(rad),
              y: pr.initialVelocity*Math.sin(rad) - pr.gravity*projectile.time
            },
            acceleration: { x: 0, y: -pr.gravity },
            trail: projectile.trail,
            landed: projectile.landed
          },
          springMassState: {
            time: simTime.springMass,
            displacement: spring.x,
            velocity: spring.v,
            acceleration: -(sp.springConstant/sp.mass)*spring.x
          }
        };

        try {
          const resp = await fetch('/render', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(appState)
          });
          if (resp.ok) {
            root.innerHTML = await resp.text();
          }
        } catch {}
        refreshPending = false;
      };

      // Animation loop — update canvas SVG directly for performance
      const updateCanvas = () => {
        const canvas = document.querySelector('[p-target="canvas"]');
        if (!canvas) return;
        // Re-render via server for accurate SVG
        requestRefresh();
      };

      const loop = (timestamp) => {
        const dt = lastTime ? Math.min((timestamp - lastTime) / 1000, 0.05) : 0.016;
        lastTime = timestamp;
        stepSim(dt);
        if (playback === 'playing') updateCanvas();
        requestAnimationFrame(loop);
      };
      requestAnimationFrame(loop);
    })();
  </script>
</body>
</html>`

  return new Response(fullPage, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

// --- Bun server ---

export const startServer = (port = 3000) => {
  const app = createApp()

  return Bun.serve({
    port,
    fetch: async (req: Request) => {
      const url = new URL(req.url)

      if (url.pathname === '/render' && req.method === 'POST') {
        const state = await req.json() as AppState
        const html = renderApp(state)
        return new Response(html, {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      return handleRequest(req)
    },
  })
}

// Auto-start if run directly
if (import.meta.main) {
  const port = parseInt(Bun.env.PORT ?? '3000', 10)
  startServer(port)
  console.log(`Newton's Laws Simulator running at http://localhost:${port}`)
}

