const CLIENT_JS = `
  const elements = JSON.parse(document.getElementById('elements-data').textContent);
  const panel = document.getElementById('detail-panel');
  const content = document.getElementById('detail-content');
  const closeBtn = document.getElementById('detail-close');
  const searchInput = document.getElementById('search-input');
  const cells = document.querySelectorAll('.element-cell');
  const catBtns = document.querySelectorAll('.cat-btn');

  let activeCategory = 'all';

  const categoryLabels = {
    'alkali-metal': 'Alkali Metal',
    'alkaline-earth-metal': 'Alkaline Earth Metal',
    'transition-metal': 'Transition Metal',
    'post-transition-metal': 'Post-Transition Metal',
    'metalloid': 'Metalloid',
    'nonmetal': 'Nonmetal',
    'halogen': 'Halogen',
    'noble-gas': 'Noble Gas',
    'lanthanide': 'Lanthanide',
    'actinide': 'Actinide',
  };

  const formatTemp = (k) => {
    if (k === null || k === undefined) return 'Unknown';
    const c = (k - 273.15).toFixed(1);
    return k.toFixed(1) + ' K (' + c + ' °C)';
  };

  const showDetail = (el) => {
    const cat = el.category;
    const catColor = getComputedStyle(
      document.querySelector('[data-category="' + cat + '"]')
    ).backgroundColor;
    content.innerHTML =
      '<div class="detail-header">' +
        '<div class="detail-symbol" style="background:' + catColor + '">' + el.symbol + '</div>' +
        '<div class="detail-title">' +
          '<h2>' + el.name + '</h2>' +
          '<p>#' + el.atomicNumber + ' · ' + (categoryLabels[el.category] || el.category) + '</p>' +
        '</div>' +
      '</div>' +
      '<div class="detail-grid">' +
        '<div class="detail-item"><div class="label">Atomic Mass</div><div class="value">' + el.atomicMass + ' u</div></div>' +
        '<div class="detail-item"><div class="label">Electron Config</div><div class="value">' + el.electronConfiguration + '</div></div>' +
        '<div class="detail-item"><div class="label">Oxidation States</div><div class="value">' + el.oxidationStates.join(', ') + '</div></div>' +
        '<div class="detail-item"><div class="label">Discovery Year</div><div class="value">' + (el.discoveryYear || 'Ancient') + '</div></div>' +
        '<div class="detail-item"><div class="label">Melting Point</div><div class="value">' + formatTemp(el.meltingPoint) + '</div></div>' +
        '<div class="detail-item"><div class="label">Boiling Point</div><div class="value">' + formatTemp(el.boilingPoint) + '</div></div>' +
      '</div>' +
      '<div class="detail-description">' + el.description + '</div>';
    panel.classList.remove('hidden');
  };

  cells.forEach((cell) => {
    cell.addEventListener('click', () => {
      const num = parseInt(cell.dataset.atomic);
      const el = elements.find((e) => e.atomicNumber === num);
      if (el) showDetail(el);
    });
  });

  closeBtn.addEventListener('click', () => panel.classList.add('hidden'));

  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') panel.classList.add('hidden');
  });

  const applyFilters = () => {
    const query = searchInput.value.toLowerCase().trim();
    cells.forEach((cell) => {
      const matchesCat = activeCategory === 'all' || cell.dataset.category === activeCategory;
      const matchesSearch =
        !query ||
        cell.dataset.name.includes(query) ||
        cell.dataset.symbol.includes(query) ||
        cell.dataset.atomic === query;
      if (matchesCat && matchesSearch) {
        cell.classList.remove('dimmed');
      } else {
        cell.classList.add('dimmed');
      }
    });
  };

  searchInput.addEventListener('input', applyFilters);

  catBtns.forEach((btn) => {
    btn.addEventListener('click', () => {
      catBtns.forEach((b) => b.classList.remove('active'));
      btn.classList.add('active');
      activeCategory = btn.dataset.cat;
      applyFilters();
    });
  });
`;

