const loadElements = async (): Promise<Element[]> => {
  const file = Bun.file(new URL('./data/elements.json', import.meta.url).pathname)
  return JSON.parse(await file.text())
}

const searchElements = (elements: Element[], query: string): Element[] => {
  const q = query.toLowerCase().trim()
  if (!q) return elements
  return elements.filter(
    (el) =>
      el.name.toLowerCase().includes(q) ||
      el.symbol.toLowerCase().includes(q) ||
      el.number.toString() === q
  )
}

const filterByCategory = (elements: Element[], category: ElementCategory | 'all'): Element[] => {
  if (category === 'all') return elements
  return elements.filter((el) => el.category === category)
}

const formatMass = (mass: number): string => {
  if (Number.isInteger(mass)) return `(${mass})`
  return mass.toFixed(mass < 100 ? 3 : 2)
}

const formatOxidationStates = (states: (number | null)[]): string => {
  if (!states.length) return 'Unknown'
  return states
    .filter((s): s is number => s !== null)
    .map((s) => (s > 0 ? `+${s}` : `${s}`))
    .join(', ') || 'Unknown'
}

