const renderToHTML = async (options: RenderOptions = {}): Promise<string> => {
  const elements = await loadElements()
  const template = renderPeriodicTable(elements, options)
  const ssr = createSSR()
  return ssr(template)
}

export {
  loadElements,
  searchElements,
  filterByCategory,
  renderPeriodicTable,
  renderDetailPanel,
  renderToHTML,
  CATEGORY_COLORS,
  CATEGORY_LABELS,
  ALL_CATEGORIES,
}

