const styleToString = (style: Record<string, string | number>): string =>
  Object.entries(style)
    .map(([key, value]) => {
      const cssKey = key.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${cssKey}: ${value}`
    })
    .join('; ')

const isElementVisible = (el: Element, filter: FilterState): boolean => {
  const { searchQuery, activeCategory } = filter
  const matchesCategory = activeCategory === 'all' || el.category === activeCategory
  if (!searchQuery) return matchesCategory
  const q = searchQuery.toLowerCase()
  const matchesSearch =
    el.name.toLowerCase().includes(q) ||
    el.symbol.toLowerCase().includes(q) ||
    String(el.number) === q
  return matchesCategory && matchesSearch
}

const renderElementCell = (el: Element, filter: FilterState) => {
  const visible = isElementVisible(el, filter)
  const isSelected = filter.selectedElement === el.number
  const bg = CATEGORY_COLORS[el.category]
  const cellStyle = {
    ...styles.cell,
    backgroundColor: bg,
    ...(visible ? {} : styles.cellDimmed),
    ...(isSelected ? styles.cellSelected : {}),
  }

  return h(
    'div',
    {
      style: styleToString(cellStyle),
      'data-number': String(el.number),
      'p-trigger': 'click:selectElement',
      title: `${el.name} (${el.symbol})`,
    },
    h('span', { style: styleToString(styles.cellNumber) }, String(el.number)),
    h('span', { style: styleToString(styles.cellSymbol) }, el.symbol),
    h('span', { style: styleToString(styles.cellName) }, el.name),
    h('span', { style: styleToString(styles.cellMass) }, el.atomicMass.toFixed(el.atomicMass % 1 === 0 ? 0 : 2)),
  )
}

