export const renderPeriodicTable = (elements: Element[], filter: FilterState) => {
  const elementGrid = new Map<string, Element>()
  elements.forEach((el) => {
    elementGrid.set(`${el.row}-${el.col}`, el)
  })

  const gridCells: ReturnType<typeof h>[] = []

  for (let row = 1; row <= 7; row++) {
    for (let col = 1; col <= TOTAL_COLS; col++) {
      const el = elementGrid.get(`${row}-${col}`)
      if (el) {
        gridCells.push(renderElementCell(el, filter))
      } else {
        gridCells.push(h('div', { style: styleToString(styles.spacer) }))
      }
    }
  }

  const lanthanideRow: ReturnType<typeof h>[] = []
  lanthanideRow.push(h('div', { style: styleToString(styles.lanthanideLabel) }, 'Lanthanides'))
  for (let col = 3; col <= TOTAL_COLS; col++) {
    const el = elementGrid.get(`9-${col}`)
    if (el) {
      lanthanideRow.push(renderElementCell(el, filter))
    } else {
      lanthanideRow.push(h('div', { style: styleToString(styles.spacer) }))
    }
  }

  const actinideRow: ReturnType<typeof h>[] = []
  actinideRow.push(h('div', { style: styleToString(styles.actinideLabel) }, 'Actinides'))
  for (let col = 3; col <= TOTAL_COLS; col++) {
    const el = elementGrid.get(`10-${col}`)
    if (el) {
      actinideRow.push(renderElementCell(el, filter))
    } else {
      actinideRow.push(h('div', { style: styleToString(styles.spacer) }))
    }
  }

  const selectedElement = filter.selectedElement
    ? elements.find((el) => el.number === filter.selectedElement) ?? null
    : null

  const categories: Category[] = [
    'alkali-metal', 'alkaline-earth-metal', 'transition-metal',
    'post-transition-metal', 'metalloid', 'nonmetal',
    'halogen', 'noble-gas', 'lanthanide', 'actinide',
  ]

  return h(
    'div',
    { style: styleToString(styles.container) },
    h(
      'div',
      { style: styleToString(styles.header) },
      h('h1', { style: styleToString(styles.title) }, 'Periodic Table of Elements'),
      h(
        'div',
        { style: styleToString(styles.controls) },
        h('input', {
          type: 'text',
          placeholder: 'Search by name, symbol, or number...',
          value: filter.searchQuery,
          style: styleToString(styles.searchInput),
          'p-trigger': 'input:onSearch',
          'p-target': 'searchInput',
        }),
        h(
          'select',
          {
            style: styleToString(styles.filterSelect),
            'p-trigger': 'change:onCategoryFilter',
            'p-target': 'categorySelect',
          },
          h('option', { value: 'all' }, 'All Categories'),
          ...categories.map((cat) =>
            h(
              'option',
              {
                value: cat,
                ...(filter.activeCategory === cat ? { selected: '' } : {}),
              },
              CATEGORY_LABELS[cat],
            ),
          ),
        ),
      ),
      renderLegend(),
    ),
    h(
      'div',
      { style: styleToString(styles.tableGrid), 'p-target': 'tableGrid' },
      ...gridCells,
    ),
    h('div', { style: styleToString(styles.gapRow) }),
    h(
      'div',
      { style: styleToString(styles.tableGrid), 'p-target': 'lanthanideGrid' },
      ...lanthanideRow,
    ),
    h(
      'div',
      { style: styleToString(styles.tableGrid), 'p-target': 'actinideGrid' },
      ...actinideRow,
    ),
    selectedElement ? renderDetailPanel(selectedElement) : h(Fragment, null),
  )
}

import { createSSR } from '@plaited/template/ssr'
import type { Element, FilterState, Category } from './types'
import { renderPeriodicTable } from './render'

const DATA_PATH = `${import.meta.dir}/data/elements.json`

const loadElements = async (): Promise<Element[]> => {
  const file = Bun.file(DATA_PATH)
  const data = await file.json()
  return data as Element[]
}

const createInitialState = (): FilterState => ({
  searchQuery: '',
  activeCategory: 'all',
  selectedElement: null,
})

export const handleSearch = (state: FilterState, query: string): FilterState => ({
  ...state,
  searchQuery: query.trim(),
})

export const handleCategoryFilter = (state: FilterState, category: string): FilterState => ({
  ...state,
  activeCategory: category as Category | 'all',
})

export const handleSelectElement = (state: FilterState, elementNumber: number): FilterState => ({
  ...state,
  selectedElement: state.selectedElement === elementNumber ? null : elementNumber,
})

export const handleCloseDetail = (state: FilterState): FilterState => ({
  ...state,
  selectedElement: null,
})

export const render = async (state?: FilterState): Promise<string> => {
  const elements = await loadElements()
  const filterState = state ?? createInitialState()
  const template = renderPeriodicTable(elements, filterState)
  const ssr = createSSR()
  return ssr(template)
}

export const getElement = async (number: number): Promise<Element | undefined> => {
  const elements = await loadElements()
  return elements.find((el) => el.number === number)
}

export const searchElements = async (query: string): Promise<Element[]> => {
  const elements = await loadElements()
  const q = query.toLowerCase()
  return elements.filter(
    (el) =>
      el.name.toLowerCase().includes(q) ||
      el.symbol.toLowerCase().includes(q) ||
      String(el.number) === q,
  )
}

export const getElementsByCategory = async (category: Category): Promise<Element[]> => {
  const elements = await loadElements()
  return elements.filter((el) => el.category === category)
}

export { loadElements, createInitialState }
export type { Element, FilterState, Category }
